
interface ActionDescriptor {
    type:string;
    data?:any;
}

/**
 * Use to pass actions across the view architecture.
 * @class ActionData
 * @memberof jibo.face
 */
class ActionData {

    /**
     * The type of the action.
     * Supported types are this class's constants.
     * @name jibo.face.ActionData#type
     * @type {String}
     */
    public type:string = "";

    /**
     * The data Object that is passed with the action.
     * Not all action types require data.
     * Refer to this class's constants for action type requirements.
     * @name jibo.face.ActionData#data
     * @type {Object}
     */
    public data:any = null;

    /**
     * Change view by specifying view change options.
     * Data requirements include [ChangeOptions]{@link jibo.face.ViewManager#ChangeOptions}
     * @example
     * <caption>JSON format</caption>
     * "action": {
     *     "type": "changeView",
     *     "data": {
     *       "options": {
     *          "removeAll": true,
     *          "leaveEmpty": true
     *       }
     *     }
     * }
     * @constant jibo.face.ActionData.CHANGE_VIEW
     * @type {String}
     */
    public static get CHANGE_VIEW():string {return "changeView";}

    /**
     * Add a view.
     * Data requirements include a path to view configuration to be opened.
     * @example
     * <caption>JSON format</caption>
     * "action": {
     *     "type": "openView",
     *     "data": {
     *       "configPath": "resources/menus/myMenu.json"
     *     }
     * }
     * @constant jibo.face.ActionData.OPEN_VIEW
     * @type {String}
     * @readOnly
     */
    public static get OPEN_VIEW():string {return "openView";}

    /**
     * Remove the current view.
     * This action has no data requirements.
     * @example
     * <caption>JSON format</caption>
     * "action": {
     *     "type": "closeView",
     * }
     * @constant jibo.face.ActionData.CLOSE_VIEW
     * @type {String}
     * @readOnly
     */
    public static get CLOSE_VIEW():string {return "closeView";}

    /**
     * Remove the current view and not open the next view in the hierarchy.
     * Will leave the display empty and the current view equal to null.
     * This action has no data requirements.
     * @example
     * <caption>JSON format</caption>
     * "action": {
     *     "type": "closeViewEmpty",
     * }
     * @constant jibo.face.ActionData.CLOSE_VIEW_EMPTY
     * @type {String}
     * @readOnly
     */
    public static get CLOSE_VIEW_EMPTY():string {return "closeViewEmpty";}

    /**
     * Remove all the views up to, but not including, the root view.
     * @example
     * <caption>JSON format</caption>
     * "action": {
     *     "type": "closeAll"
     * }
     * @constant jibo.face.ActionData.CLOSE_ALL
     * @type {String}
     * @readOnly
     */
    public static get CLOSE_ALL():string {return "closeAll";}

    /**
     * Remove all the views and clear hierarchy up to but not including root, then add view.
     * Added view will be one above the root view.
     * Data requirements include a path to view configuration to be opened.
     * @example
     * <caption>JSON format</caption>
     * "action": {
     *     "type": "closeAllOpen",
     *     "data": {
     *       "configPath": "resources/menus/myMenu.json"
     *     }
     * }
     * @constant jibo.face.ActionData.CLOSE_ALL_OPEN
     * @type {String}
     * @readOnly
     */
    public static get CLOSE_ALL_OPEN():string {return "closeAllOpen";}

    /**
     * Close all the views and clear hierarchy up to but not including root,
     * but do not add the root view to the display.
     * Added view will be one above the root view.
     * Data requirements include a path to view configuration to be opened.
     * @example
     * <caption>JSON format</caption>
     * "action": {
     *     "type": "closeAllEmpty"
     * }
     * @constant jibo.face.ActionData.CLOSE_ALL_EMPTY
     * @type {String}
     * @readOnly
     */
    public static get CLOSE_ALL_EMPTY():string {return "closeAllEmpty";}

    /**
     * Emulate a swipe right gesture.
     * @example
     * <caption>JSON format</caption>
     * "action": {
     *     "type": "swipeRight"
     * }
     * @constant jibo.face.ActionData.SWIPE_RIGHT
     * @type {String}
     * @readOnly
     */
    public static get SWIPE_RIGHT():string {return "swipeRight";}

    /**
     * Emulate a swipe left gesture.
     * @example
     * <caption>JSON format</caption>
     * "action": {
     *     "type": "swipeLeft"
     * }
     * @constant jibo.face.ActionData.SWIPE_LEFT
     * @type {String}
     * @readOnly
     */
    public static get SWIPE_LEFT():string {return "swipeLeft";}

    /**
     * Emulate a swipe down.
     * @example
     * <caption>JSON format</caption>
     * "action": {
     *     "type": "swipeDown"
     * }
     * @constant jibo.face.ActionData.SWIPE_DOWN
     * @type {String}
     * @readOnly
     */
    public static get SWIPE_DOWN():string {return  "swipeDown";}

    /**
     * Go to first page of a list.
     * Enact action on [List]{@link @method jibo.face.List} to take effect.
     * @example
     * <caption>JSON format</caption>
     * "action": {
     *     "type": "goToBeginning"
     * }
     * @constant jibo.face.ActionData.GO_TO_BEGINNING
     * @type {String}
     * @readOnly
     */
    public static get GO_TO_BEGINNING():string {return "goToBeginning";}

    /**
     * Go to last page of a list.
     * Enact action on [List]{@link @method jibo.face.List} to take effect.
     * @example
     * <caption>JSON format</caption>
     * "action": {
     *     "type": "goToEnd"
     * }
     * @constant jibo.face.ActionData.GO_TO_END
     * @type {String}
     * @readOnly
     */
    public static get GO_TO_END():string {return "goToEnd";}

    /**
     * Emit an event from the owning View when triggered.
     * Required data is an event string.
     *
     * @example
     * <caption>JSON format</caption>
     * "action": {
     *     "type": "event",
     *     "data": {
     *       "event": "danceParty"
     *     }
     * }
     *
     * @example
     * <caption> To listen for these events just add a listener to
     * the View that contains the action. </caption>
     *
     * myView.on('danceParty', getDown);
     *
     * @example
     * <caption>You must specify the event string for the event to fire,
     * but can include as much additional data as needed.
     * The entire data Object is returned when the event is fired.
     * Here we add another value to the data Object in JSON:</caption>
     *
     * "action": {
     *     "type": "event",
     *     "data": {
     *       "event": "danceParty"
     *       "dance": "funkyChicken"
     *     }
     * }
     *
     * @example
     * <caption>Then in your code you can listen for the event,
     * which will pass back the data Object:</caption>
     *
     * myView.on('danceParty', (eventData) => {
     *          if(eventData.dance === 'funkyChicken'){
     *              console.log('Booo');
     *          }
     *      });
     *
     * @constant jibo.face.ActionData.EVENT
     * @type {String}
     * @readOnly
     */
    public static get EVENT():string {return "event";}

    /**
     * Play a sound.
     * Within data, provide either the type of sound or the URI for the sound file.
     * @example
     *
     * <caption>JSON format. Playing a preloaded or gloabl sound by giving the the ID.</caption>
     * "action": {
     *     "type": "sound",
     *     "data": {
     *       "id": "button"
     *     }
     * }
     * @example
     * <caption>JSON format. Playing sound by just giving src of sound asset.</caption>
     * "action": {
     *     "type": "sound",
     *     "data": {
     *       "src": "resources/sfx/button_sfx.m4a"
     *     }
     * }
     * @example
     * <caption>JSON format. Loading a sound and giving it an ID for repeat usage.</caption>
     * "action": {
     *     "type": "sound",
     *     "data": {
     *      "id": "unique_sound"
     *       "src": "resources/sfx/button_sfx.m4a"
     *     }
     * }
     *
     * @name jibo.face.ActionData#SOUND
     * @type {String}
     * @readOnly
     */
    public static get SOUND():string {return "sound";}

    /**
     * Spoof an utterance that will be processed by Global Listen Service.
     * 'Hey Jibo' utterances are not accepted.
     * @example
     * <caption>JSON format</caption>
     * "action": {
     *     "type": "utterance",
     *     "data": {
     *       "utterance": "What's the weather?"
     *     }
     * }
     * @constant jibo.face.ActionData.UTTERANCE
     * @type {String}
     * @readOnly
     */
    public static get UTTERANCE():string {return "utterance";}

    /**
     * Results passed from the MIM systems.
     * @example
     * <caption>JSON format for select elements on a page</caption>
     * "action": {
     *     "type": "verbalCommand",
     *     "data": {
     *       "intent": "selectItem",
     *       "itemPosition": "first",
     *     }
     * }
     *
     * <caption>JSON format tp control pages</caption>
     * "action": {
     *     "type": "verbalCommand",
     *     "data": {
     *       "intent": "right",
     *     }
     * }
     *
     *
     * @constant jibo.face.ActionData.VERBAL_COMMAND
     * @type {String}
     * @readOnly
     */
    public static get VERBAL_COMMAND():string {return "verbalCommand";}
    
    /**
     * Immediately end the currently active MIM.
     * @example
     * <caption>JSON format for ending a MIM</caption>
     * "action": {
     *     "type": "mimEnd"
     * }
     *
     * @constant jibo.face.ActionData.MIM_END
     * @type {String}
     * @readOnly
     */
    public static get MIM_END():string {return "mimEnd";}
    
    /**
     * Immediately show the available GUI for the currently active MIM.
     * @example
     * <caption>JSON format for showing a MIM's GUI</caption>
     * "action": {
     *     "type": "mimShowGUI"
     * }
     *
     * @constant jibo.face.ActionData.MIM_SHOW_GUI
     * @type {String}
     * @readOnly
     */
    public static get MIM_SHOW_GUI():string {return "mimShowGUI";}

    /**
     * Call a method when action is triggered.
     * Not something easily defined via JSON; more likely to be defined in code.
     * @example
     * new ActionData( ActionData.CALLBACK, {
     *    callback: this.foo.bind(this)
     * });
     * @constant jibo.face.ActionData.CALLBACK
     * @type {String}
     * @readOnly
     */
    public static get CALLBACK():string {return "callback";}

    /**
     * Create an ActionData object from a configuration Object.
     * Generally derived from JSON.
     * @method jibo.face.ActionData.createFromConfig
     * @example
     * <caption>JSON format</caption>
     * {
     *      "type": "openView",
     *      "data": {
     *          "configPath": "assets/menu/myMenu.json"
     *      }
     * }
     * @param {ActionDescriptor} configData Object defining the action.
     * @returns {jibo.face.ActionData} A new ActionData with values specified by given configuration.
     */
    public static createFromConfig(configData:ActionDescriptor):ActionData
    {
        let actionData:ActionData = new ActionData();
        actionData.applyConfig(configData);
        return actionData;
    }

    /**
     * Constructor for ActionData.
     * @param {String} [type] The type of action.
     * @param {Object} [data] The data Object with action values.
     */
    constructor(type?:string, data?:any)
    {
        this.type = type;
        this.data = data;
    }

    /**
     * Apply the configuration Object's values to this ActionData class.
     * @method jibo.face.ActionData#applyConfig
     * @param {ActionDescriptor} configData Object defining the action.
     */
    public applyConfig(configData:ActionDescriptor):void
    {
        if(configData.hasOwnProperty("type")){
            this.type = configData.type;
        }
        if(configData.hasOwnProperty("data")){
            this.data = configData.data;
        }
    }


}

export default ActionData;
