import Behavior from '../Behavior';
import Status from '../Status';
import PathUtils from '../../utils/PathUtils';
import Runtime from '../../Runtime';
import Sound from '../../sound/Sound';

/**
 * @class PlayAudio
 * @extends jibo.bt.Behavior
 * @memberof jibo.bt.behaviors
 * @description Plays the audio specified by `audioPath`. Succeeds when the audio file is finished playing.
 * @param {Object} options See {@link jibo.bt.Behavior|Behavior} for all options.
 * @param {String} options.audioPath The path to any audo file format supported by HTML5 Audio. This behaviuor assumes `${project}/audio`
 *                           is the root for all the audio files.
 * @param {Boolean} options.cache=true `true` to cache the audio. `false` to play once and destroy.
 */
export default class PlayAudio extends Behavior {
    private status:Status;
    private alias:string;
    private cache:boolean;
    private sound:Sound;
    
    constructor(options) {
        super(options);

        //backward support
        if (typeof this.options.cache === 'undefined') {
            this.options.cache = true;
        }

        this.status = Status.INVALID;
        this.alias = this.options.audioPath;
        this.cache = this.options.cache;
        this.sound = null;
    }
    public start() {
        this.status = Status.IN_PROGRESS;
        const sound = Runtime.instance.loader.cached(this.alias);
        if (this.cache && sound) {
            this.onLoaded(null, sound);
        }
        else {
            Runtime.instance.loader.load({
                type: 'sound',
                id: this.alias,
                src: PathUtils.getAudioUri(this.alias, this.assetPack),
                cache: true,
                complete: this.onLoaded.bind(this)
            });
        }
        return true;
    }

    public stop():Promise<void> {
        if (this.sound) {
            this.sound.stop();
            this.sound = null;
        }
        if (!this.cache) {
            Runtime.instance.loader.unload(this.alias);
        }
        return Promise.resolve();
    }
    public update() {
        return this.status;
    }
    public destroy() {
        this.stop();
        if (Runtime.instance.loader.cached(this.alias)) {
            Runtime.instance.loader.unload(this.alias);
        }
        super.destroy();
        this.status = null;
    }
    
    private onLoaded(err, sound:Sound) {
        if (err) {
            throw err;
        }
        //if status is not in progress, then behavior was stopped or destroyed
        if (this.status !== Status.IN_PROGRESS) {
            if (!this.cache) {
                Runtime.instance.loader.unload(this.alias);
            }
            return;
        }
        this.sound = sound;
        this.sound.play(() => {
            this.stop();
            this.status = Status.SUCCEEDED;
        });
    }
}
