import Decorator from '../Decorator';
import Status from '../Status';

/**
 * @class StartOnEvent
 * @extends jibo.bt.Decorator
 * @memberof jibo.bt.decorators
 * @description
 * Prevents the behavior it's decorating from starting until an event is emitter from a behavior tree's
 * global `emitter`.
 * @param {Object} options See {@link jibo.bt.Decorator|Decorator} for all options.
 * @param {String} options.eventName - The name of the event to listen for.
 * @param {Function} options.onEvent - called when the event is fired. Any payload with the event is passed in.
 */
export default class StartOnEvent extends Decorator {
    private didStart:boolean;
    
    constructor(options) {
        super(options);
        this._onEvent = this._onEvent.bind(this);
    }
    public start():boolean|Status.WAIT {
        this.emitter.once(this.options.eventName, this._onEvent);
        this.didStart = false;
        return Status.WAIT;
    }
    public stop() {
        this.emitter.removeListener(this.options.eventName, this._onEvent);
        return Promise.resolve();
    }
    public update(result:Status):Status {
        if(this.didStart) {
            return result;
        }
        else {
            return Status.WAIT;
        }
    }
    public destroy() {
        super.destroy();
        this._onEvent = null;
    }
    private _onEvent() {
        this.options.onEvent.apply(null, arguments);
        this.didStart = true;
    }
}
