import Callback from '../../LoaderCallback';

/**
 * Abstraction for loading files.
 * @private
 * @class Resource
 * @param {String} type The load type
 * @param {String} url Full URL
 * @param {Function} callback when complete
 * @param {Object} [options] Optional options
 */
abstract class Resource {

    public onComplete:Function;
    public result:any;

    constructor(public type:string, public url:string, public callback:Callback, public options?:any) {
        this.options = options || {};
    }

    /**
     * Begin the load
     * @method jibo.loader.Resource#start
     */
    public start(): void {
        // override
    }

    /**
     * Call when completed
     * @private
     */
    protected complete(err?:any):void {
        this.onComplete(err, this);
        this.destroy();
    }

    /**
     * Handle a timeout
     * @protected
     */
    protected onTimeout() {
        this.complete('Request timed out.');
    }

    /**
     * Destroy and don't use after this
     * @protected
     */
    protected destroy() {
        this.onComplete = null;
        this.callback = null;
        this.result = null;
        this.options = null;
        this.url = null;
        this.type = null;
    }
}

export default Resource;
