import MimConfig, {MimTypes} from './MimConfig';
import PathUtils from '../../utils/PathUtils';

/**
 * Define how an individual repeat request should be handled.
 * @class MimRepeat
 * @memberof jibo.mim
 * @private
 */
type MimRepeat = {
    /**
     * Prepend prompt to whatever Jibo repeats. Play alone if it's the last repeat allowed.
     * @name jibo.mim.MimRepeat#result
     * @type {String}
     * @readOnly
     */
    prompt: string;
    /**
     * Take specified action after prompt is played. If 'cached', use exact prompt played when Mim
     * was entered. If 'verbose', play verbose prompt or fall back to cached prompt. If 'exit', do
     * not play a prompt & quit skill.
     * @name jibo.mim.MimRepeat#result
     * @type {String}
     * @readOnly
     */
    action: string;
};

/**
 * Manage how Mim repeat requests are handled.
 * Instantiate this class to start loading the Announcement Mims to use when Jibo is asked to repeat
 * himself.
 * @class MimRepeatManager
 * @memberof jibo.mim
 * @private
 */
export default class MimRepeatManager {
    /**
     * Maximum number of repeats allowed before before skill should exit.
     * @name jibo.mim.MimRepeatManager#maxRepeat
     * @type {Number}
     * @readOnly
     */
    public maxRepeat = 10;
    
    private repeatMimQ:MimConfig[];
    private repeatMimANOR:MimConfig[];
    private repeatActionQ:string[];
    private repeatActionANOR:string[];
    
    constructor() {
        this.repeatMimQ = [];
        this.repeatMimQ.length = 10;
        this.repeatMimQ.fill(null, 0, 10);
        this.repeatMimANOR = [];
        this.repeatMimANOR.length = 10;
        this.repeatMimANOR.fill(null, 0, 10);
        //first repeat uses cached entry prompt, all following ones use the
        //verbose prompt if present, until we quit on the 10th
        this.repeatActionQ = ['cached'];
        this.repeatActionQ.length = 10;
        this.repeatActionQ.fill('verbose', 1, 8);
        this.repeatActionQ[9] = 'exit';
        //all repeats use cached entry prompt, until we quit on the 10th
        this.repeatActionANOR = [];
        this.repeatActionANOR.length = 10;
        this.repeatActionANOR.fill('cached', 0, 8);
        this.repeatActionANOR[9] = 'exit';
        
        //preload all the mims we could need
        let promises:any[] = [
            'core://mims/en-us/globals/RepeatORANFirst.mim',
            'core://mims/en-us/globals/RepeatORANSecond.mim',
            'core://mims/en-us/globals/RepeatORANThird.mim',
            'core://mims/en-us/globals/RepeatORANNoMore.mim',
            'core://mims/en-us/globals/RepeatQuestionFirst.mim',
            'core://mims/en-us/globals/RepeatQuestionSecond.mim',
            'core://mims/en-us/globals/RepeatQuestionThird.mim',
            'core://mims/en-us/globals/RepeatQuestionNoMore.mim',
        ];
        for(let i = 0; i < promises.length; ++i) {
            promises[i] = MimConfig.load(PathUtils.getAssetUri(promises[i]));
        }
        
        Promise.all(promises).then((results:MimConfig[]) => {
            //RepeatORANFirst for first request
            this.repeatMimANOR[0] = results[0];
            //RepeatORANSecond for second request
            this.repeatMimANOR[1] = results[1];
            //RepeatORANThird for third -> ninth requests
            this.repeatMimANOR.fill(results[2], 2, 8);
            //RepeatORANNoMore for tenth request
            this.repeatMimANOR[9] = results[3];
            
            //RepeatQuestionFirst for first request
            this.repeatMimQ[0] = results[4];
            //RepeatQuestionSecond for second request
            this.repeatMimQ[1] = results[5];
            //RepeatQuestionThird for third request
            this.repeatMimQ[2] = results[6];
            //4th-9th requests don't have a short extra prompt
            //RepeatQuestionNoMore for tenth request
            this.repeatMimQ[9] = results[7];
        });
    }
    
    /**
     * Starts loading the default list SFX, for use by lists and Mim GUIs.
     * @method jibo.mim.MimRepeatManager~getRepeat
     * @param {String} mimType The type of the current Mim (question, announcement, optional-response).
     * @param {Number} repeatCount The number of times that the user has requested a repeat (starting at 1 for the first time).
     * @returns {jibo.mim.MimRepeat} Information on how to handle the repeat request.
     */
    public getRepeat(mimType:string, repeatCount:number):MimRepeat {
        const mims = mimType === MimTypes.QUESTION ? this.repeatMimQ : this.repeatMimANOR;
        const actions = mimType === MimTypes.QUESTION ? this.repeatActionQ : this.repeatActionANOR;
        let prompt:string;
        if (mims[repeatCount - 1]) {
            prompt = mims[repeatCount - 1].getPromptText(null, null) + ' ';
        } else {
            prompt = '';
        }
        return {
            action: actions[repeatCount - 1],
            prompt
        };
    }
}