import Element from './Element';
import Timeline from '../../animation/Timeline';

/**
 * Clip to manage timelines and images.
 *
 * @class Clip
 * @extends jibo.face.Element
 * @memberof jibo.face
 */
class Clip extends Element
{
    /**
     * The default class identifier.
     * Generally used to register the class.
     * @name jibo.face.Clip.DEFAULT_TYPE
     * @type {String}
     * @readOnly
     * @internal
     */
    public static get DEFAULT_TYPE():string {return 'Clip';}

    /**
     * Timeline for the display content.
     * @name jibo.face.Clip#timeline
     * @type {Timeline}
     */
    public timeline:Timeline = null;

    /**
     * MovieClip for the display content, the instance of the Timeline.
     * @name jibo.face.Clip#movieClip
     * @type {PIXI.animate.MovieClip}
     */
    public movieClip:PIXI.animate.MovieClip = null;

    /**
     * The Class name as a string.
     * @name jibo.face.Clip#_type
     * @type {String}
     * @protected
     * @internal
     */
    protected _type:string = Clip.DEFAULT_TYPE;

    /**
     * Create a Clip from a configuration Object derived from JSON.
     * @method jibo.face.Clip#createFromConfig
     * @param configData Object derived from JSON, must be a specific format refer to examples.
     * @returns {jibo.face.Clip} Returns the created Clip.
     */
    public static createFromConfig(configData:any):Clip
    {
        const clip:Clip = new Clip();
        clip.assignConfig(configData);
        return clip;
    }

    /**
     * Create a Clip object by passing the DisplayObject.
     * This allows for a more direct way to create Clips that is not reliant on the configuration data.
     * @method jibo.face.Clip#createFromDisplayObject
     * @param {PIXI.DisplayObject} displayObject The DisplayObject with the button assets.
     * @param {PIXI.Container} [container] Display container for the button.
     * @returns {jibo.face.Clip} Returns the created Clip.
     */
    public static createFromDisplayObject(displayObject:PIXI.DisplayObject, container?:PIXI.Container):Clip {

        const clip:Clip = new Clip();

        clip.display = new PIXI.Container();
        if(container){
            container.addChild(clip.display );
        }
        else if(displayObject.parent) {
            displayObject.parent.addChild(clip.display);
        }

        clip.display.addChild(displayObject);
        return clip;
    }

    /**
     * Set up the display.
     * Assign assets, set timelines, etc.
     * @method jibo.face.Clip#setupDisplay
     * @param {Object} [assets] Object passed back from loader namespace load method,
     *        refer to {@link jibo.loader} for detail
     */
    public setupDisplay(assets?:any):void {
        // using asset descriptors identified which asset(s) within given assets should be added to display
        let asset:any;
        let assetDscrpt:any;
        for(let i:number = 0; i<this._assetDescriptors.length; i++)
        {
            assetDscrpt = this._assetDescriptors[i];
            asset = assets[assetDscrpt.id];
            if(assetDscrpt.hasOwnProperty("type"))
            {
                switch (assetDscrpt.type)
                {
                    case "texture":
                        this.display.addChild(new PIXI.Sprite(asset));
                        break;
                    case "timeline":
                        this.timeline = <Timeline>asset;
                        this.movieClip = new this.timeline.library.stage();
                        this.display.addChild(<PIXI.DisplayObject>this.movieClip);
                        break;
                    default:
                        // not an asset type that demands a local reference
                        break;
                }
            }
            else
            {
                // TODO :: This doesn't work, how should we deal with HTMLImageElements?
                console.log("Clip :: assignAssets : no type given for asset: " + asset + " assuming bitmap");
                let texture:PIXI.Texture = new PIXI.Texture(asset);
                this.display.addChild(new PIXI.Sprite(texture));
            }
        }
    }

    /**
     * Destroy
     * @method jibo.face./Clip#destroy
     * @internal
     */
    public destroy():void {
        this.movieClip = null;
        this.timeline = null;
        super.destroy();
    }
}

export default Clip;
