import path = require('path');
import Button from './Button';
import Timeline from '../../animation/Timeline';
import TweenManager from '../../tween/TweenManager';
import ActionData from '../actions/ActionData';
import ViewManager from '../ViewManager';

interface ButtonData {
    assetPath:string;
    dimensions:PIXI.Point;
}

export const Colors = {
    DEFAULT: 'default',
    CONFIRM: 'confirm',
    CANCEL: 'cancel'
};
// Button colors:
const DEFAULT_COLORS = {
    // blue (neutral action)
    [Colors.DEFAULT]: [0x25F2FB, 0x107799],
    // green (confirmation action)
    [Colors.CONFIRM]: [0xA3FF4A, 0x2A7922],
    // red (destructive action)
    [Colors.CANCEL]: [0xFD362F, 0x990024]
};

/**
 * Menu button.
 *
 * @class MenuButton
 * @extends jibo.face.Button
 * @memberof jibo.face
 */
class MenuButton extends Button
{
    /**
     * The default class identifier.
     * MenuButton uses variants, so this should be defined specifically at
     * Generally used to register the class.
     * @name jibo.face.MenuButton.DEFAULT_TYPE
     * @type {String}
     * @readOnly
     * @internal
     */
    public static get DEFAULT_TYPE():string {return 'SkillButton';}

    /**
     * The Class type variant.
     * The MenuButton allows for type variants within it.
     * @name jibo.face.MenuButton#_type
     * @type {String}
     * @protected
     * @internal
     */
    protected _type:string = MenuButton.SKILL;

    /**
     * The id for the asset corresponding to the MenuButton base timeline.
     * @name jibo.face.MenuButton#timelineId
     * @type {String}
     * @internal
     */
    public timelineId:string = '';

    /**
     * The id for the asset corresponding to the MenuButton's icon.
     * @name jibo.face.MenuButton#iconId
     * @type {String}
     * @internal
     */
    public iconId:string = '';

    /**
     * Text to appear below the MenuButton
     * @name jibo.face.MenuButton#label
     * @type {String}
     * @internal
     */
    public label:string = '';

    /**
     * Optional sender information, for MenuView subclasses to use.
     * @name jibo.face.MenuButton#sender
     * @type {Object}
     * @internal
     */
    public sender:any;

    /**
     * The dimensions of the button used for the list.
     * Defining dimensions here allows them to be accessible prior to the button asset being loaded.
     * @name jibo.face.MenuButton#_dimensions
     * @type {PIXI.Point}
     * @protected
     * @internal
     */
    protected _dimensions:PIXI.Point = null;

    /**
     * The predefined dimensions of the button.
     * This only returns the dimensions that have been explicitly set,
     * it does not return the dimensions of the display itself.
     * @name jibo.face.MenuButton#dimensions
     * @type {PIXI.Point}
     * @readOnly
     */
    public get dimensions():PIXI.Point
    {
        return this._dimensions;
    }

    /**
     * The content of the button.
     * Contents are nested within the display to allow for visual transforms without effected button position.
     * @name jibo.face.MenuButton#_content
     * @type {PIXI.Container}
     * @protected
     * @internal
     */
    protected _content:PIXI.Container = null;

    /**
     * Mappping for button-specific data.
     * @name jibo.face.MenuButton#_buttonURIs
     * @type {Object}
     * @protected
     * @internal
     */
    protected _buttonDatas:{[type:string]:{assetPath:string, dimensions:PIXI.Point}} = {
        [MenuButton.SKILL]: {
            assetPath: 'core://resources/buttons/skillButton.js',
            dimensions: new PIXI.Point(330, 300)
        },
        [MenuButton.ACTION]: {
            assetPath: 'core://resources/buttons/actionButton.js',
            dimensions: new PIXI.Point(264, 264)
        },
        [MenuButton.ACTION_BIG]: {
            assetPath: 'core://resources/buttons/bigActionButton.js',
            dimensions: new PIXI.Point(330, 330)
        }
    };

    /**
     * Array of 2 colors to be applied to button base.
     * @name jibo.face.MenuButton#_colors
     * @type number[]
     * @private
     */
    private _colors:Array<number> = null;

    /**
     * Scale value for down state of button.
     * @name jibo.face.MenuButton#DOWN_SCALE
     * @type {number}
     * @private
     */
    private DOWN_SCALE:number = .9;

    /**
     * Scale value for activate state of button.
     * @name jibo.face.MenuButton#ACTIVATE_SCALE
     * @type {number}
     * @private
     */
    private ACTIVATE_SCALE:number = 1.15;

    /**
     * Duration of tweens for button state changes.
     * @name jibo.face.MenuButton#TWEEN_TIME
     * @type {number}
     * @private
     */
    private TWEEN_TIME:number = 300;

    /**
     * String identifier for skill button.
     * @name jibo.face.MenuButton.SKILL
     * @type {string}
     * @readOnly
     */
    public static get SKILL():string    {return 'SkillButton';}

    /**
     * String identifier for action button.
     * @name jibo.face.MenuButton.ACTION
     * @type {string}
     * @readOnly
     */
    public static get ACTION():string   {return 'ActionButton';}

    /**
     * String identifier for large action button.
     * @name jibo.face.MenuButton.ACTION_BIG
     * @type {string}
     * @readOnly
     */
    public static get ACTION_BIG():string   {return 'ActionBigButton';}

    /**
     * Create a MenuButton from a configuration Object derived from JSON.
     * @method jibo.face.MenuButton.createFromConfig
     * @param {Object} configData Object derived from JSON, must be a specific format refer to examples.
     * @returns {jibo.face.MenuButton} Returns the MenuButton created from the given configuration.
     * @internal
     */
    public static createFromConfig(configData:any):MenuButton {
        let btn:MenuButton = new MenuButton();
        btn.assignConfig(configData);
        return btn;
    }

    /**
     * Array of 2 colors to be applied to button base. If set to a value of `default`, `confirm`,
     * or `cancel` uses the global color for that button type.
     * @name jibo.face.MenuButton#colors
     * @type {number[]}
     */
    public get colors() { return this._colors; }
    public set colors(value:number[]|string) {
        if (typeof value === 'string') {
            this._colors = DEFAULT_COLORS[value];
        } else {
            this._colors = value;
        }
        if (!this._colors) {
            this._colors = DEFAULT_COLORS[Colors.DEFAULT];
        }
    }

    /**
     * Applies data contained within the given configData Object (generally derived
     * from JSON) to the class.
     * Checks for icon and timeline assets descriptors and stores their id for later retrieval.
     * @method jibo.face.MenuButton#assignConfig
     * @param {Object} configData The configuration Object for the
     * @internal
     */
    public assignConfig(configData:any):void {
        if(configData){
            super.assignConfig(configData);

            this.sender = configData.sender;

            // set the MenuButton type if specified, as it can be used to specify variation - handled by Component

            // look for colors
            if(configData.hasOwnProperty('colors')) {
                this.colors = configData.colors;
            }
            else{
                console.warn('WARNING :: MenuButton :: assignAssets : colors were not defined.');
            }

            this.id = configData.id;
            this.label = configData.label;

            // add asset descriptor for icon, most MenuButtons should have an icon
            if (configData.iconSrc) {
                this.iconId = this.id || path.basename(configData.iconSrc, path.extname(configData.iconSrc));
                this.addAssetDescriptor(this.iconId, configData.iconSrc, 'texture');
            }

            // Swap general ids for more specific ids derived from ids, store references to those new ids
            let assetDescriptor:any;
            let descriptorClone:any;
            for(let i:number = 0; this._assetDescriptors && i<this._assetDescriptors.length; i++) {

                assetDescriptor = this._assetDescriptors[i];
                if(assetDescriptor.id === 'icon') {
                    //derive unique id from asset src
                    this.iconId = path.parse(assetDescriptor.src).name;
                    descriptorClone = JSON.parse(JSON.stringify(this._assetDescriptors[i]));
                    descriptorClone.id = this.iconId;
                    this._assetDescriptors[i] = descriptorClone;
                }
            }
        }

        // create an asset descriptor for the button base that corresponds to _type
        this.applyButtonType();
    }


    /**
     * Create and add a button asset descriptor that corresponds with the type value.
     * If `type` is provided as a parameter, it is applied to the internal type variable.
     * Add an asset descriptor for the looper's photo, if defined.
     * @method jibo.face.MenuButton#applyButtonType
     * @param {String} [type] If defined, applied to [MenuButton#_type]{@link jibo.face.MenuButton#_type},
     *          which is then used to determine which timeline assets to use for the button.
     * @internal
     */
    public applyButtonType(type?:string):void{

        // set type if defined
        if(type){
            this._type = type;
        }
        const buttonData:ButtonData = this._buttonDatas[this._type];

        // create assetDescriptor for button asset
        const src:string = buttonData.assetPath;
        this.timelineId = path.parse(src).name;
        super.addAssetDescriptorObject(
            {
                id:this.timelineId,
                src:src,
                type:'timeline',
                cache:ViewManager.GLOBAL_CACHE
            }
        );

        // set button dimensions
        this._dimensions = buttonData.dimensions;

        // add button sound to front of action array
        this.addAction(new ActionData(ActionData.SOUND, {id:'button'}),false, true);
    }

    /**
     * Set up the display.
     * Assign assets, set timelines, etc.
     * @method jibo.face.MenuButton#setupDisplay
     * @param {Object} [assets] Object passed back from loader namespace load method,
     *        refer to {@link jibo.loader} for detail.
     */
    public setupDisplay(assets?:any):void {
        this.setupTimeline(assets);
        this.setupHitArea();
        this.setupInteractions();
    }

    /**
     * Set up the timeline asset associated with the button.
     * @method jibo.face.MenuButton#setupTimeline
     * @protected
     * @internal
     */
    protected setupTimeline(assets:any):void {

        if(assets.hasOwnProperty(this.timelineId)) {
            let stageInstance:any = new (assets[this.timelineId] as Timeline).library.stage();
            this._content = stageInstance['content'];
            if(this.colors) {
                this._content['background'].children[0].tint = this.colors[0];
                this._content['gradient'].children[0].tint = this.colors[1];
            }

            if(assets.hasOwnProperty(this.iconId)) {
                // TODO :: check for image
                let icon:PIXI.Sprite = new PIXI.Sprite(assets[this.iconId]);
                icon.x -= icon.width/2;
                icon.y -= icon.height/2;
                this._content['icon'].addChild(icon);    // expect that there is a symbol named 'icon'
            }
            else if (this.iconId) {
                console.warn('WARNING :: MenuButton :: createDisplay : icon with id of: ' + this.iconId + ' not found in assets.');
            }
            this.display.addChild(stageInstance);
        }
        else {
            console.warn('WARNING :: MenuButton :: createDisplay : timeline not found in assets');
        }
    }

    /**
     * Define the interactive hit area of the display.
     * The DisplayObject.hitArea is what Pixi uses to define the interactive area.
     * @method jibo.face.MenuButton#setupHitArea
     * @param {PIXI.Rectangle} [bounds] optionally specify the bounds for the hit area,
     *  if not defined defaults to using the display's bounds.
     * @internal
     */
    public setupHitArea(bounds?:PIXI.Rectangle):void {
        if(this.display){
            if(bounds){
                this.display.hitArea = bounds;
            }
            else if (this._dimensions) {
                this.display.hitArea = new PIXI.Rectangle(0, 0, this._dimensions.x, this._dimensions.y);
            }
            else{
                bounds = this.display.getBounds();
                // set x and y position back to zero as getBounds() returns stage relative position
                bounds.x = bounds.y = 0;
                this.display.hitArea = bounds;
            }
        }
    }

    /**
     * Destroy.
     * @method jibo.face.MenuButton#destroy
     * @internal
     */
    public destroy():void {
        this._dimensions = null;
        this.colors = null;
        this._buttonDatas = null;
        if(this._content){
            TweenManager.stop(this._content);
            this._content = null;
        }
        super.destroy();
    }

    /**
     * Handler for out touch input.
     * @method jibo.face.MenuButton#out
     * @param {any} mouseData Returned from Pixi.
     * @protected
     * @internal
     */
    protected out(mouseData?:any) {
        this.up();
    }

    /**
     * Handler for down touch input.
     * @method jibo.face.MenuButton#down
     * @param {any} mouseData Returned from Pixi
     * @protected
     * @internal
     */
    protected down(mouseData?:any) {
        if(!this._isDown)
        {
            this._isDown = true;
            TweenManager.stop(this._content);
            TweenManager.play(this._content,
                {
                    to: {
                        'scale.x': this.DOWN_SCALE,
                        'scale.y': this.DOWN_SCALE
                    },
                    duration: this.TWEEN_TIME,
                    ease: 'backOut'
                }
            );
        }
    }

    /**
     * Handler for up touch input.
     * @method jibo.face.MenuButton#up
     * @param {any} mouseData Returned from Pixi
     * @protected
     * @internal
     */
    protected up(mouseData?:any){
        if(this._isDown){
            this._isDown = false;
            TweenManager.stop(this._content);
            TweenManager.play(this._content,
                {
                    to: {
                        'scale.x': 1,
                        'scale.y': 1
                    },
                    duration: this.TWEEN_TIME/2,
                    ease: 'backOut'
                }
            );

        }
    }

    /**
     * Activate the button, used for non-touch input.
     * @method jibo.face.MenuButton#activate
     * @protected
     */
    public activate():void{

        TweenManager.stop(this._content);
        TweenManager.play(this._content,
            {
                to: {
                    'scale.x': this.ACTIVATE_SCALE,
                    'scale.y': this.ACTIVATE_SCALE
                },
                duration: this.TWEEN_TIME,
                ease: 'sineOut'
            },
            () => {
                TweenManager.play(this._content,
                    {
                        to: {
                            'scale.x': 1,
                            'scale.y': 1
                        },
                        duration: this.TWEEN_TIME,
                        ease: 'backOut'
                    }
                );
            }
        );
    }
}

export default MenuButton;
