import Behavior from '../Behavior';
import Status from '../Status';
import Runtime from '../../Runtime';
import PathUtils from '../../utils/PathUtils';
import KeysAnimation from '../../rendering/animation/KeysAnimation';

/**
 * @class PlayAnimation
 * @extends jibo.bt.Behavior
 * @memberof jibo.bt.behaviors
 * @description Plays the animation specified by `animPath`. Succeeds when the animation is finished playing. Playing an
 *              animation consists of two phases: the transition phase and the play phase. The transition phase will
 *              transition Jibo from his current position to the start position this the specified animation. The play
 *              phase, plays the animation with the current configuration.
 * @param {Object} options See {@link jibo.bt.Behavior|Behavior} for all options.
 * @param {String} options.animPath The path to the `.keys` file. This behaviuor assumes `${project}/animations` is the root for
 *                          all the animations.
 * @param {Function} options.config Called and passed a {@link AnimationBuilder} object for configuration purposes. Do not call
 *                          {@link AnimationBuilder#play}. This is done automatically by the behavior.
 * @param {Boolean} [options.cache=true] `true` to cache the animation. `false` to play once and destroy.
 */
export default class PlayAnimation extends Behavior {
    private alias:string;
    private animation:KeysAnimation;
    private instance:any;
    private status:Status;
    private cache:boolean;
    
    constructor(options) {
        super(options);

        //backward support
        if (typeof this.options.cache === 'undefined') {
            this.options.cache = true;
        }

        //backward support
        if (typeof this.options.upload === 'undefined') {
            this.options.upload = true;
        }

        //first default this asset to the 'animations' folder
        this.alias = PathUtils.setDefaultPath('animations', options.animPath);

        // Reference to the builder
        this.animation = null;
        this.instance = null;

        // Bound function
        this.onEvent = this.onEvent.bind(this);
        this.onStopped = this.onStopped.bind(this);
        this.status = Status.INVALID;
        this.cache = this.options.cache;
    }

    public start() {
        this.status = Status.IN_PROGRESS;
        const animation = Runtime.instance.loader.cached(this.alias);

        // Don't reload the animation, it's already cached
        if (this.cache && animation) {
            animation.reset();
            this.onKeysLoaded(null, animation);
        }
        // Load the animation
        else {
            const src = PathUtils.getAssetUri(this.alias, this.assetPack);
            Runtime.instance.loader.load({
                id: this.alias,
                cache: true,
                src: src,
                upload: this.options.upload,
                root: PathUtils.findRoot(src),
                type: 'keys',
                complete: this.onKeysLoaded.bind(this)
            });
        }
        return true;
    }

    public update() {
        return this.status;
    }
    
    public stop():Promise<void> {
        if (this.instance) {
            this.instance.stop();
        }
        this.reset();
        return Promise.resolve();
    }

    public destroy() {
        this.reset();
        super.destroy();
        this.onEvent = null;
        this.onStopped = null;
        this.status = null;
    }
    
    private onKeysLoaded(err, animation)
    {
        if (err) {
            throw err;
        }
        //if status is not in progress, then behavior was stopped or destroyed
        if (this.status !== Status.IN_PROGRESS) {
            if (!this.cache) {
                Runtime.instance.loader.unload(this.alias);
            }
            return;
        }
        // Add the animation to the face
        this.animation = Runtime.instance.face.eye.animation = animation;

        // Listen for stopped event
        this.animation.on(KeysAnimation.STOPPED, this.onStopped);

        // Listen for cancelled event
        this.animation.on(KeysAnimation.CANCELLED, this.onStopped);

        // register for all events
        this.animation.on(KeysAnimation.EVENT, this.onEvent);

        if (this.options.config) {
            this.options.config(this.animation);
        }
        this.instance = this.animation.builder.play();
    }

    private reset() {
        if (this.animation) {
            Runtime.instance.face.eye.animation = null;
            this.animation.removeAllListeners();
        }
        this.animation = null;
        this.instance = null;
        if (!this.cache) {
            Runtime.instance.loader.unload(this.alias);
        }
    }

    private onStopped() {
        this.reset();
        this.status = Status.SUCCEEDED;
    }

    private onEvent(eventType, animInstance, payload) {
        Runtime.instance.behaviorEmitter.emit(
            payload.eventName,
            animInstance,
            payload.payload
        );
    }
}
