import Behavior from '../Behavior';
import Status from '../Status';
import Null from './Null';
import TimeoutSucceedJs from '../decorators/TimeoutSucceedJs';


/**
 * @callback jibo.bt.behaviors.TimeoutJs~GetTime
 * @returns {number} Time in milliseconds until the behavior succeeds.
 */

/**
 * @class TimeoutJs
 * @extends jibo.bt.Behavior
 * @memberof jibo.bt.behaviors
 * @description
 * Succeeds only after the specified amount of time.
 * @param {Object} options See {@link jibo.bt.Behavior|Behavior} for all options.
 * @param {jibo.bt.behaviors.TimeoutJs~GetTime} options.getTime - Time in milliseconds until `TimeoutJs` succeeds.
 */
export default class TimeoutJs extends Behavior {
    private behavior:Null;
    private status:Status;
    
    constructor(options) {
        super(options);
        let decorator = new TimeoutSucceedJs({
            getTime: options.getTime
        });
        this.behavior = new Null({
            decorators: [decorator]
        });
        this.status = Status.INVALID;
    }
    public start() {
        this.status = Status.IN_PROGRESS;
        return this.behavior._start();
    }
    public stop():Promise<void> {
        return this.behavior._stop();
    }
    public update() {
        this.status = this.behavior._update();
        return this.status;
    }
    public destroy() {
        super.destroy();
        if (this.behavior) {
            this.behavior.destroy();
            this.behavior = null;
        }
    }
}
