import {EventEmitter} from 'events';
import {Event, EmitterMode} from 'jibo-typed-events';
import Runtime from '../../Runtime';
import {DEFAULT_AUDIO} from './GenerateListConfig';
import MimRepeatManager from './MimRepeatManager';

import GlobalListenDelegate from './delegates/GlobalListenDelegate';
import BasicSpeakDelegate from './delegates/BasicSpeakDelegate';

/*
 * Interface for how a listener instance is used by MIMs. All ListenDelegates must produce one of
 * these with their create() functions.
 */
export interface Listener {
    stop(unsubscribe?:boolean):void;
    on(type:string, callback:Function):void;
}

export type ListenModeOptions = 'NORMAL'|'OPTIONAL_RESPONSE'|'NO_BODY'|'UI';
interface ListenDelegate {
    cleanupHandler?: (done:(error?)=>void)=>void;
    setMode(mode:ListenModeOptions):void;
    create(options:any, rulePath:string):Listener;
    create(options:any, handle:{rule:string, type:'handle'}):Listener;
}
interface SpeakDelegate {
    speak(options:any):Promise<any>;
    stop():void;
}

class SingletonEnforcer {}

/**
 * Singleton for hooking into the MIM system.
 * @namespace jibo.mim
 */
//NOTE: This is the only class in the MIM code that is exposed outside of the jibo module, and
//should be considered mostly internal to Jibo, with potentially a few development features.
class MimManager extends EventEmitter {

    private static _instance:MimManager;
    
    /**
     * End the currently active MIM.
     * @name jibo.mim#end
     * @type {Event}
     * @internal
     */
    public end:Event<any>;
    /**
     * Open the GUI for the currently active MIM.
     * @name jibo.mim#openGUI
     * @type {Event}
     * @internal
     */
    public openGUI:Event<void>;
    /**
     * In the currently active MIM, handle a spoofed utterance.
     * @name jibo.mim#handleSpeech
     * @type {Event}
     * @internal
     */
    public handleSpeech:Event<string>;

    /**
     * If `true`, Question MIMs time out after the specfied `timeout` when run in the simulator.
     * If `false` (default), time out when `enter` key is pressed.
     * @name jibo.mim~timeoutIgnoresSimulator
     * @type {Boolean}
     */
    public timeoutIgnoresSimulator:boolean = false;

    public repeat: MimRepeatManager;
    
    //internal, not for general use
    public ListenMode:{NORMAL:'NORMAL', OPTIONAL_RESPONSE:'OPTIONAL_RESPONSE', NO_BODY:'NO_BODY', UI:'UI'} = {
        NORMAL: 'NORMAL',
        OPTIONAL_RESPONSE: 'OPTIONAL_RESPONSE',
        NO_BODY: 'NO_BODY',
        UI: 'UI'
    };
    
    /**
     * The default listen delegate class, for extending to make more advanced delegates.
     * @name jibo.mim~GlobalListenDelegate
     * @type {jibo.mim.GlobalListener}
     * @private
     */
    public GlobalListenDelegate: typeof GlobalListenDelegate = GlobalListenDelegate;

    //These delegates allow us to hook up Embodied speech/listening from skills, as those aren't
    //part of the jibo module yet. In the future, we may find it useful for the purposes for
    //quickly dropping all mims down to more basic speech/listening behaviors to
    //test bugs/compare performance
    private _listenDelegate:ListenDelegate;
    private _speakDelegate:SpeakDelegate;

    constructor(enforcer:SingletonEnforcer) {
        super();
        this._listenDelegate = GlobalListenDelegate;
        this._speakDelegate = new BasicSpeakDelegate();
        
        this.end = new Event<any>('End MIM');
        this.end.setMode(EmitterMode.LAST_HANDLER);
        this.openGUI = new Event<void>('Open MIM GUI');
        this.openGUI.setMode(EmitterMode.LAST_HANDLER);
        this.handleSpeech = new Event<string>('Handle Spoofed Utterance');
        this.handleSpeech.setMode(EmitterMode.LAST_HANDLER);
    }

    public static get instance():MimManager {
        if (!MimManager._instance) {
            MimManager._instance = new MimManager(new SingletonEnforcer());
        }
        return MimManager._instance;
    }

    /**
     * Listen delegate to be used by all MIMs to handle listening.
     * @name jibo.mim~listenDelegate
     * @type {ListenDelegate}
     * @private
     */
    public get listenDelegate():ListenDelegate {
        return this._listenDelegate;
    }
    public set listenDelegate(delegate:ListenDelegate) {
        this._listenDelegate = delegate;
    }

    /**
     * Speaking delegate to be used by all MIMs to handle speech.
     * @name jibo.mim~speakDelegate
     * @type {SpeakDelegate}
     * @private
     */
    public get speakDelegate():SpeakDelegate {
        return this._speakDelegate;
    }
    public set speakDelegate(delegate:SpeakDelegate) {
        this._speakDelegate = delegate;
    }
    
    /**
     * Start loading any assets the Mims need. Called on creation of the first Mim. Mim does not
     * wait for asset load to complete before continuing.
     * @method jibo.mim~loadMimAssets
     * @private
     */
    public loadMimAssets() {
        this.loadDefaultListAudio();
        if (!this.repeat) {
            this.repeat = new MimRepeatManager();
        }
    };

    /**
     * Starts loading the default list SFX, for use by lists and Mim GUIs.
     * @method jibo.mim~loadDefaultListAudio
     * @private
     */
    private loadDefaultListAudio() {
        const sound = Runtime.instance.sound;
        if (!sound.exists(DEFAULT_AUDIO.swipe.alias)) {
            sound.add(DEFAULT_AUDIO.swipe.alias, DEFAULT_AUDIO.swipe);
        }
        if (!sound.exists(DEFAULT_AUDIO.end.alias)) {
            sound.add(DEFAULT_AUDIO.end.alias, DEFAULT_AUDIO.end);
        }
    }
}

export default MimManager;
