interface GestureEvent {
    mousePos:PIXI.Point;
    direction:number;
    deltaX:number;
}

interface PhysicsObject {
    element:Element;
    targetPosition:PIXI.Point;
    velocity:PIXI.Point;
    targetOffset?:number;
}

interface DynamicElement {
    loaded:boolean;
    active:boolean;
}

enum Movement {
    NONE,
    PAN,
    SWIPE
}

enum PanDirection {
    NONE = 1,
    RIGHT = 2,
    LEFT = 3
}

enum PanCase {
    STILL,
    DYNAMIC,
    CLAMP_LEFT,
    CLAMP_RIGHT
}

