import {EventEmitter} from "events";
import {RegistrationRecord, WSClient} from 'jibo-client-framework';
import {Plugin, PluginCallback} from '../Plugin';
import Runtime from '../Runtime';

class IPC extends EventEmitter {
    constructor() {
        super();
    }

    public send(channel:string, ...args) {
        this.emit(`send-${channel}`, args);
    }
}

const ipc = Runtime.ipcRenderer || new IPC();

class Lifecycle extends EventEmitter implements Plugin {

    private _skillServiceHost:string;
    private _client:WSClient;

    constructor() {
        super();
        this.onShutdown = this.onShutdown.bind(this);
        this.onMessage = this.onMessage.bind(this);
        ipc.on('shutdown', this.onShutdown);
    }

    public init(done:PluginCallback): void {

        const jibo:Runtime = Runtime.instance;

        // Ignore services if runing in 
        if (jibo.runMode === jibo.RunMode.UNIT_TESTS) {
            return done();
        }
        const records:RegistrationRecord[] = jibo.records;

        //find the skills service host first
        for(let i:number = 0; i < records.length; i++) {
            let record:RegistrationRecord = records[i];
            if(record.name === 'skills-service') {
                this._skillServiceHost = `ws://127.0.0.1:${record.port}`;
                break;
            }
        }

        if(!this._skillServiceHost) {
            done('Skills Service is down');
        }

        //create the lifecycle connection
        this._client = new WSClient(this._skillServiceHost);
        this._client.once('open', () => {
            this._client.send({
                command: 'initDone'
            });
        });

        //listen for messages
        this._client.on('message', this.onMessage);

        // When complete
        this.once('init', done);
    }

    /**
     * Call when skill is done and wants to exit
     */
    public finished(): void {
        this._client.send({
            command: 'finished'
        });
        ipc.send('finished');
    }

    /**
     * Called from skills manager
     * @param command
     */
    private onMessage(command:any): void {
        //console.log('command', command, command.command === 'show');
        if(command.command === 'shutdown') {
            this.emit('shutdown');
            setTimeout(() => {
                ipc.send('finished');
            }, 100);
        }
        else if(command.command === 'show') {
            ipc.send('show');
            this.emit('init');
        }
    }

    private onShutdown() {
        this._client.send({
            command: 'shutdown'
        });
    }
}

Runtime.registerPlugin(Lifecycle, 'lifecycle', {
    api: true,
    depends: ['service-records']
});

export default Lifecycle;
