import View from './View';
import ViewManager from '../ViewManager';
import Runtime from '../../../Runtime';

/**
 * View class that serves as a container for the Eye.
 *
 * @class EyeView
 * @extends jibo.face.View
 * @memberof jibo.face
 */
class EyeView extends View
{
    /**
     * The default class identifier.
     * Generally used to register the class.
     * @name jibo.face.EyeView.DEFAULT_TYPE
     * @type {String}
     * @readOnly
     * @internal
     */
    public static get DEFAULT_TYPE():string {return 'EyeView';}

    /**
     * The Class name as a string.
     * @name jibo.face.EyeView#_type
     * @type {String}
     * @protected
     * @internal
     */
    protected _type:string = EyeView.DEFAULT_TYPE;

    //////////////////////// CONSTRUCTION ////////////////////////

    /**
     * Construct View
     */
    constructor () {
        super();
        this.id = 'eyeView';
        this.soundSet = 'main';
        this._category = View.CATEGORY_EYE;
    }

    /**
     * Adds eye to the container, and setups listener on screen click.
     * Disable swipe down.
     * @method jibo.face.EyeView#createDisplay
     * @param {PIXI.Container} container Parent Container which all DisplayObject
     *        created within this Component should be added to.
     * @param {Object} assets Object passed back from loader namespace load method,
     *        refer to {@link jibo.loader} module within jibo for details.
     * @internal
     */
    public createDisplay(container:PIXI.Container, assets:any):void {

        // We want to listen for screen clicks
        super.setupScreenClick();

        const eye = Runtime.instance.face.eye;
        eye.active = true;

        container.addChild(eye);

        // don't need to register for a swipe down since EyeView should be the root view
        this.closeOnSwipeDown = false;
    }

    /**
     * Destroy, removes listeners, removes eye.
     * @method jibo.face.EyeView#destroy
     * @internal
     */
    public destroy():void {
        const eye = Runtime.instance.face.eye;
        eye.active = false;
        if(this.stage) {
            this.stage.removeChild(eye);
        }
        super.destroy();
    }

    /**
     * Adjust provided transition before calling inherited method.
     * @method jibo.face.EyeView#open
     * @param {Function} [callback] - Callback fired when close is complete, can also listen for View.OPENED event.
     * @param {String} [transitionType] - This will be ignored as EyeView defines its own transition types.
     * @internal
     */
    public open(callback?:Function, transitionType?:string):void {
        // TODO :: This logic will probably get more complicated as we deal with unique transitions
        if(transitionType !== ViewManager.TRANS_NONE){
            transitionType = ViewManager.TRANS_IN;
        }
        super.open(callback, transitionType);
    }

    /**
     * We want to override the close transition type for EyeView
     * @method jibo.face.EyeView#close
     * @param {Function} [callback] - Callback fired when close is complete, can also listen for View.CLOSED event.
     * @param {String} [transitionType] - This will be ignored as EyeView defines its own transition types.
     * @internal
     */
    public close(callback?:Function, transitionType?:string):void {

        // TODO :: This logic will probably get more complicated as we deal with unique transitions
        if(transitionType !== ViewManager.TRANS_NONE){
            transitionType = ViewManager.TRANS_OUT;
        }
        super.close(callback, transitionType);
    }
}

export default EyeView;
