import { ClientDialogListener } from '../../../services/gl/ClientDialogListener';
import { EventEmitter } from 'events';
import ListenEvent from './ListenEvent';
import Runtime from '../../../Runtime';
import PathUtils from '../../../utils/PathUtils';
import {ListenModeOptions} from '../MimManager';
import * as fs from 'fs';
import * as path from 'path';

/*
 * A standard callback function type
 */
export type Callback = (error?:any) => void;

/**
 * Delegate for MimManager to use global listening for all listening.
 * @class GlobalListener
 * @memberof jibo.mim
 * @private
 */
export default class GlobalListener extends EventEmitter {

    /**
     * Optional async cleanup function for listeners
     * @name jibo.mim.GlobalListener#cleanupHandler
     * @type {Function}
     * @param {Function} done Callback for notifying when cleaning up is completed
     * @static
     */
    public static cleanupHandler: (done:Callback) => void;

    private listener:ClientDialogListener;
    private unsubscribed = false;

    /**
     * Sets the listen mode. On GlobalListener this is a no-op.
     * @method jibo.mim.GlobalListener#setMode
     * @param {string} mode Option from {jibo.mim.GlobalListener#ListenMode} to set the mode to.
     * @static
     */
    public static setMode(mode:ListenModeOptions):void {
        //noop
    }

    /**
     * Create a GlobalListener instance to use.
     * @method jibo.mim.GlobalListener#create
     * @param {any} options The listening options.
     * @param {string} rulePath The path to the rule file (currently .rule only).
     * @returns {GlobalListener} The GlobalListener instance.
     * @static
     */
    public static create(options:any, rulePath:string):GlobalListener;
    public static create(options:any, handle:{rule:string, type:'handle'}):GlobalListener;
    public static create(options:any, rule:string|{rule:string, type:string}):GlobalListener {
        let checkedRule;
        if (typeof rule === 'string') {
            checkedRule = {
                rule: rule,
                type:'path'
            };
        } else {
            checkedRule = rule;
        }
        return new GlobalListener(options, checkedRule);
    }

    constructor(options:any, rule:{rule:string, type:string}) {
        super();
        this._init(options, rule);
    }

    /**
     * Stop listening.
     * @param {Boolean} [unsubscribe] The listener should unsubscribe from the Global Listen Service.
     * @method jibo.mim.GlobalListener#stop
     */
    public stop(unsubscribe = true):void {
        this.removeAllListeners();
        // Don't need to unsubscribe if we've gotten the message.
        if (!this.unsubscribed && this.listener) {
            if (unsubscribe) {
                Runtime.instance.gl.unsubscribe(this.listener, () => {/*noop*/});
            }
        }
        this.listener = null;
    }

    private _init(options:any, rule:{rule:string, type:string}):void {
        let type:string = rule.type;
        //get rule file path
        let uri: string;
        if (rule.type !== 'handle') {
            if (rule.rule.indexOf('://') > -1) {
                uri = PathUtils.getAssetUri(PathUtils.setDefaultPath('rules', rule.rule));
            } else {
                uri = rule.rule;
            }
        }

        let ruleLoaded = (err, data) => {
            if(err || !data) {
                console.error('Rule file does not exist: ' + uri);
            }

            this.listener = Runtime.instance.gl.createDialogListener(options, {rule:data, type});

            let stopHandler = this._stopInternal.bind(this);

            this.listener.events.incremental.on((data) => {
                this.emit(ListenEvent.INCREMENTAL, data, stopHandler);
            });

            this.listener.events.interrupted.on(() => {
                this._stopInternal(false);
            });

            this.listener.events.unsubscribed.on(() => {
                this.unsubscribed = true;
            });

            this.listener.events.cloudReceived.on((data) => {
                this.emit(ListenEvent.CLOUD, data.result, data.speakerId);
                this._stopInternal(false);
            });

            this.listener.events.ruleCompiled.on((ruleUri) => {
                this.emit(ListenEvent.RULE_COMPILED, ruleUri);
            });
            Runtime.instance.gl.subscribe(this.listener, (err:string, response:any) => {
                if(err) {
                    throw new Error(err);
                }
            });
        };

        if (rule.type === 'handle') {
            ruleLoaded(null, rule.rule);
        } else {
            // Handle unextensioned rule path names, preferentially using the .fst file if it exists.
            if (path.extname(uri) === '') {
                for (let ext of ['.fst','.rule']) {
                    if (fs.existsSync(uri + ext)) {
                        uri += ext;
                        break;
                    }
                }
            }
            if(path.extname(uri) === '.fst') {
                type = 'fst';
                //pass FST files through to GlobalListen, it will load and compile it for us
                ruleLoaded(null, uri);
            } else {
                type = 'text';
                //read rule file text
                fs.readFile(uri, 'utf8', ruleLoaded);
            }
        }
    }

    private _stopInternal(unsubscribe = true):void {
        const stop = (error?:any) => {
            if (error) {
                console.error(error);
            }
            this.emit(ListenEvent.FINISHED);
            this.stop(unsubscribe);
            this.removeAllListeners();
        };

        this.listener = null;

        if (GlobalListener.cleanupHandler) {
            GlobalListener.cleanupHandler(stop);
        }
        else {
            stop();
        }
    }
}
