import Runtime from '../Runtime';
import {Plugin, PluginCallback} from '../Plugin';
import GlobalPerfTimer from '../utils/perf/GlobalPerfTimer';
import SerialTimer from '../utils/perf/SerialTimer';
import {body, LEDOutput} from "animation-utilities";

/**
 * Animation utility function.
 * @namespace jibo.animUtils
 * @internal
 */
class AnimUtilsPlugin implements Plugin {
    
    private _bodyService:any;
    private _bodyOutput:any;
    private _ledOutput:any;

    init(done:PluginCallback): void {
        const jibo:Runtime = Runtime.instance;
        if (jibo.runMode === jibo.RunMode.UNIT_TESTS) {
            return done();
        }
        this.initUtilities(done, false);
    }

    /**
     * Initializes the body service.
     * @method jibo.animUtils#initOutput
     */
    public initOutput(service) {
        this._bodyService = service;
    }

    /**
     * Attaches the output from the body service.
     * @method jibo.animUtils#attachOutput
     * @internal
     */
    public attachOutput() {
        const jibo:Runtime = Runtime.instance;
        const uri:string = "ws:" + this._bodyService.host + ":" + this._bodyService.port;
        this._bodyOutput = new body.BodyPosVelOutput(
            jibo.visualize.timeline.getClock(),
            jibo.visualize.robotInfo,
            uri,
            true,
            33
        );

        // needed for indexing
        jibo.system.output = this._bodyOutput;

        this._ledOutput = new LEDOutput(
            jibo.visualize.timeline.getClock(),
            jibo.visualize.robotInfo,
            uri,
            true,
            33
        );
        jibo.visualize.timeline.addOutput(this._bodyOutput);
        jibo.visualize.timeline.addOutput(this._ledOutput);
    }

    /**
     * Detaches the output from the body service.
     * @method jibo.animUtils#detachOutput
     * @internal
     */
    public detachOutput() {

        const jibo:Runtime = Runtime.instance;
        this._bodyOutput.setEnabled(false);
        jibo.system.output = null;

        this._ledOutput.setEnabled(false);
        jibo.visualize.timeline._outputs = [];
        this._bodyOutput.dispose();
        this._ledOutput.dispose();
    }

    /**
     * Initialize the Animation Utilities.
     * @method jibo.animUtils#initUtilities
     * @param {Function} done When complete
     * @param {Boolean} [headless=false] Run headlessly
     * @internal
     */
    public initUtilities(done, headless:boolean = false): void {
        const jibo:Runtime = Runtime.instance;
        const initAnimateTimer = new SerialTimer("initAnimate", GlobalPerfTimer.get());
        jibo.utils.AnimationUtils.init(jibo.animate, function() {
            initAnimateTimer.stop();
            done();
        }, headless);
    }
}

Runtime.registerPlugin(AnimUtilsPlugin, 'anim-utils', {
    api: true,
    name: 'animUtils'
});

export default AnimUtilsPlugin; 