    /**
     * Create a pronunciation listener.
     * @param {jibo.gl.PronunciationOptions} pronunciationOptions Information about pronunciation
     * @param {string} pronunciationOptions.word Word to be pronounced
     * @param {string} pronunciationOptions.action Action for listener to perform. Either `generateG2P` to generate the model, or `collectExample` to collect acoustic example.
     * @param {string} pronunciationOptions.collectExample Automatically collect acoustic example after generating g2p model. Defaults to true.
     * @method jibo.gl#createPronunciationListener
     * @returns {jibo.gl.PronunciationListener}
     * @internal
     */
    public createPronunciationListener(pronunciationOptions):PronunciationListener {
        // pass in old pronunciation options for backwards compatibility; used to accept strings.
        if(typeof pronunciationOptions === 'string') {
            pronunciationOptions = {word: pronunciationOptions};
        }
        let options = Object.assign(new PronunciationOptions(pronunciationOptions), pronunciationOptions);
        let pronunciationListener = new PronunciationListener(options);
        // Cache listener
        this._listeners.set(pronunciationListener._listenerId, pronunciationListener);
        return pronunciationListener;
    }

