    /**
     * Send utterance to ASR service to pretend Jibo just "heard it" through ASR.
     * The utterance will go through ALL global processing. However, the string
     * is cleaned before being sent, and NO "hey jibo" (global) commands will be sent.
     * All ASR messages returned like this will include a member {spoofed: true}.
     * @param options {Object} Options for utterance to be sent.
     * @param options.utterance {string} Utterance to be sent and "heard" through ASR.
     * @param [options.speakerId] {string} Optional speaker Id to identify phrase.
     * @param callback {jibo.gl~Callback} Callback with response from GLService.
     * @method jibo.gl#spoofUtterance
     * @internal
     */
    public spoofUtterance(options:any, callback?:Callback):void {
        if(typeof options === "string") {
            options = new UtteranceOptions(options, "");
        }

        let request = new XMLHttpRequest();
        request.open("POST", this.httpInterface + '/spoof', true);

        if(callback) {
            if(this.startsWithHJ(options.utterance)) {
                callback('Utterance may not begin with "Hey Jibo"');
                return;
            }

            request.onreadystatechange = () => {
                if(request.readyState === 4 && request.status === 200) {
                    let response = JSON.parse(request.response);
                    if(response.status === 'OK') {
                        if(callback){
                            callback(null, response);
                        }
                    }
                    else {
                        if(callback){
                            callback(response.moreinfo);
                        }
                    }
                }
                else if(request.readyState === 4 && request.status === 0) {
                    callback("GLService is unavailable");
                }
            };
        }

        request.send(JSON.stringify(options));
        return;
    }


