    /**
     * Return `true `if string starts with Hey Jibo, `false` otherwise.
     * @param {word} word String to search for hey jibo.
     * @private
     */
    private startsWithHJ(word:string):boolean {
        word = word.trim().toLowerCase();
        if(word.substr(0, 8) === "hey jibo") {
            return true;
        }
        return false;
    }


    private processMessages():void {
        while(this.messages.length) {
            let msg:{data:WSResponse} = this.messages.shift();
            this.processNextMessage(msg);
        }
    }

    private processNextMessage(data:any):void {
        if(this.verbose) {
            console.log("GLSERVICE DATA", data);
        }
        if(data.status !== "OK") {
            console.warn("GLService returned status", data.status);
        }
        else {
            let handler = this.listenEventHandlers[data.message];
            if(handler) {
                handler(data);
            }
        }
    }

    /**
     * Called when ws with message 'cloud' is received.
     * @param {any} JSON Data received from websocket.
     * @method jibo.GLService#onCloud
     * @private
     */
    private onCloud(data:WSResponse) {
        // GLOBAL.jibo.AsrToEmitTimer.stop();
        // console.log(GLOBAL.jibo.AsrToEmitTimer.getTimings());
        Runtime.instance.performance.log('JiboCloudReturnSkill', data.result.result.Input);
        const listenData = new ListenResults(data.result.result, null, data.result.otherResults);
        if(data.id) {
            let listener = this._getListener(data.id);
            if(listener) {
                listener.events.cloudReceived.emit(listenData);
            }
            return;
        }
       this.events.cloudReceived.emit(listenData);
    }

