    /**
     * Called when ws received `global-command`.
     * @param data {jibo.gl#WSResponse} Data received by ListenService.
     * @param data.moreinfo {Array} More information about data from Listen Service.
     * @method jibo.gl#onGlobal
     * @private
     */
    private onGlobal(data:WSResponse) {
        this.events.global.emit(data);
        // action must resovle to 'stop', 'help', 'repeat', or 'cancel'
        // to be caught by event stack
        const action = data.result.result.NLParse.intent;

        // check to see if this is a global event we want to handle
        // by emitting to last subscriber -- allows fine-granularity
        // control of events by Be/Skills/MIMs.
        let globalEvent:Event<any> = this.globalEventStacks.get(action);
        if(globalEvent) {
            globalEvent.emit(data.result);
            return;
        }

        Runtime.instance.system.getMasterVolume((err, currentVolume:number) => {
            if(err) {
                console.warn(err);
            }
            let newVolume;
            switch(action) {
                case 'volumeUp':
                    newVolume = Math.min(currentVolume + VOLUME_STEP, MAX_VOLUME);
                    this.setVolume(newVolume);
                    break;
                case 'volumeDown':
                    newVolume = Math.max(currentVolume - VOLUME_STEP, MIN_VOLUME);
                    this.setVolume(newVolume);
                    break;
                case 'volumeToValue':
                    newVolume = (data.result.result.NLParse.volumeLevel / USER_MAX_VOLUME);
                    this.setVolume(newVolume);
                    break;
            }
        });
        this.events.global.emit(data.result);
    }

    /**
     * Set volume through jibo audio module.
     * @param setVolumeTo {number} Number to set volume to.
     * @method jibo.gl#setVolume
     * @private
     */
    private setVolume(setVolumeTo:number) {
        Runtime.instance.system.setMasterVolume(setVolumeTo, (err) => {
            // TODO: sound effects in here
            if(this.verbose) {
                console.log("you set the volume to", setVolumeTo);
            }
        });
    }

    private _getListener(listenerId:string) {
        let listener = this._listeners.get(listenerId);
        if (!listener) {
            console.error(`No listener of id '${listenerId}' subscribed`);
        }

        return listener;
    }

     private _removeListener(listener:ClientDialogListener) {
        this._listeners.delete(listener._listenerId);
        listener.events.removeAllListeners();
    }

