import {EventEmitter} from 'events';
import eases = require('eases');

export interface TweenOptions {
    to:any;
    from?:any;
    duration?:number;
    ease?:string;
    delay?:number;
}

/**
 * Abstract Tween base object.
 * Uses `ease npm` for all ease functions.
 * For ease types, refer to [ease APIs]{@link https://www.npmjs.com/package/eases}.
 * @class Tween
 * @memberof jibo.face
 */
class Tween extends EventEmitter {

    /**
     * `true` if the tween is to be paused.
     * @name jibo.face.Tween#paused
     * @type {Boolean}
     */
    public paused:boolean;

    /**
     * The local lerp value for just this tween.
     * @name jibo.face.Tween#_time
     * @type {Number}
     * @protected
     */
    protected _time:number;

    /**
     * Duration in milliseconds.
     * @name jibo.face.Tween#_duration
     * @type {Number}
     * @protected
     */
    protected _duration:number;

    /**
     * Finished callback
     * @name jibo.face.Tween#_complete
     * @type {Function}
     * @private
     */
    private _complete:Function = null;

    /**
     * Flag used to block tween from being manually stopped.
     * @name jibo.face.Tween#_inProcess
     * @type {Boolean}
     * @private
     */
    private _inProcess:boolean = false;

    /**
     * the number of milliseconds to delay this tween from playing from the time it was added to the TweenMgr
     * @name jibo.face.Tween#_delay
     * @type {Number}
     * @private
     */
    private _delay:number;

    /**
     * Elapsed time in milliseconds
     * @name jibo.face.Tween#_elapsed
     * @type {Number}
     * @private
     */
    private _elapsed:number;

    /**
     * Starting value
     * @name jibo.face.Tween#_start
     * @type {Object}
     * @private
     */
    private _start:any;

    /**
     * Ending value
     * @name jibo.face.Tween#_end
     * @type {Object}
     * @private
     */
    private _end:any;

    /**
     * Ease callback.
     * @name jibo.face.Tween#_ease
     * @type {Function}
     * @private
     */
    private _ease:Function;

    /**
     * Target for tweening.
     * @name jibo.face.Tween#_target
     * @type {Object}
     * @private
     */
    private _target:any;

    /**
     * Initial the tween.
     * @method jibo.face.Tween#init
     * @param {*} [target] The thing to tween.
     * @param {Object} options Options for tweening.
     * @param {Object} options.to The values to tween the object to.
     * @param {Object} [options.from] The initial values to set the object to.
     * @param {String} [options.ease='linear'] The ease function to use.
     * @param {int} [options.delay=0] The delay to start.
     * @param {int} [options.duration=500] Length of tween, in millseconds.
     * @param {Function} [complete] Callback function, if any.
     */
    public init(target:any, options:TweenOptions, complete?:Function) {

        options = Object.assign({
            duration: 500,
            ease: 'linear',
            delay: 0,
            to: null,
            from: null
        }, options || {});

        if (!eases[options.ease]) {
            throw new Error(`'${options.ease}' is not a defined ease.`);
        }

        this._target = target;
        this._end = options.to;
        this._start = !options.from ? this.startDefaults() : options.from;

        if (!this._end || !this._start || !this.validate(this._end, this._start)) {
            console.error("to: %O, from: %O", this._end, this._start);
            throw new Error('Start and end values for tween are incompatible.');
        }

        this._time = 0;
        this._elapsed = 0;
        this._ease = eases[options.ease];
        this._delay = options.delay;
        this._duration = options.duration;
        this._complete = complete;

        // Set the initial position
        this.assign(this._start);

        // Emit the first change event, wait for the next tick
        // so that event handler can be set after initing
        process.nextTick(() => {
            this.emit('change', this._target);
        });
    }

    /**
     * Update the tween value.
     * @method jibo.face.Tween#reset
     * @param {Number} v0 start number
     * @param {Number} v1 end number
     * @param {Number} t Time
     * @private
     */
    public reset(): void {
        this.removeAllListeners();
        this._complete = null;
        this._target = null;
        this._ease = null;
        this._time = 0;
        this._delay = 0;
        this._elapsed = 0;
        this._duration = 0;
        this.paused = false;
        this._inProcess = false;
    }

    /**
     * The delay of start of tween in milliseconds.
     * @name jibo.face.Tween#delay
     * @type {Number}
     */
    public get delay():number {
        return this._delay;
    }
    public set delay(value) {
        this._delay = value;
    }

    /**
     * The duration of this tween.
     * @name jibo.face.Tween#duration
     * @type {Number}
     * @readOnly
     */
    public get duration():number {
        return this._duration;
    }

    /**
     * The current time from 0 to 1.
     * @name jibo.face.Tween#time
     * @type {Number}
     * @readOnly
     */
    public get time():number {
        return this._time;
    }

    /**
     * The target to tween.
     * @name jibo.face.Tween#target
     * @type {any}
     * @readOnly
     */
    public get target():any {
        return this._target;
    }

    /**
     * Flag indicating if tween is in a process that should not be manually stopped.
     * @name jibo.face.Tween#inProcess
     * @type {Boolean}
     * @readOnly
     */
    public get inProcess():boolean {
        return this._inProcess;
    }

    /**
     * Call the finished callback.
     * @method jibo.face.Tween#completed
     */
    public completed(): void {
        this._inProcess = true;
        // Send the final positions/settings
        this.assign(this._end);

        if (this._complete) {
            this._complete();
            this._complete = null;
        }

        /**
         * Event when tween is completed.
         * @event jibo.face.Tween#complete
         * @param {*} target The target of tween.
         */
        this.emit('complete', this._target);
    }

    /**
     * Update the tween value.
     * @method jibo.face.Tween#update
     * @param {Number} elapsed Milliseconds since the last update.
     */
    public update(elapsed:number):void {

        if (this.paused) {
            return;
        }

        this._elapsed += elapsed;
        const startTime = this._elapsed - this._delay;
        const localElapsedTime = Math.max(0, Math.min(startTime, this._duration));

        if (localElapsedTime >= 0 && localElapsedTime <= this._duration) {
            this._time = localElapsedTime / this._duration;
        }

        const modified = this._ease(this._time);

        // Calculate for each property
        for (let prop in this._start) {
            // Ignore non-numbers from lerping
            // makes it possible to set booleans
            // and other fields in start and/or end
            if (typeof this._start[prop] !== 'number') {
                continue;
            }

            this.assignValue(prop, this.lerp(
                this._start[prop],
                this._end[prop],
                modified
            ));
        }

        /**
         * Event when tween value has changed.
         * @event jibo.face.Tween#change
         * @param {*} value The value or values set.
         * @param {*} target The target of tween.
         */
        this.emit('change', this._target);
    }

    /**
     * Assign a collection of properties.
     * @method jibo.face.Tween#assign
     * @param {Object} values Map of properties to set
     * @private
     */
    private assign(values:any): void {
        for (let prop in values) {
            this.assignValue(prop, values[prop]);
        }
    }

    /**
     * Assign a specific property and value to the target.
     * @method jibo.face.Tween#assignValue
     * @param {String} prop Property name.
     * @param {Number|String} value Value to set.
     * @private
     */
    private assignValue(prop:string, value:number|string): void {
        if (prop.indexOf('.') < 0) {
            this._target[prop] = value;
        }
        else {
            const parts = prop.split('.');
            let target = this._target;
            while (parts.length > 1) {
                target = target[parts.shift()];
                if (!target) {
                    throw new Error(`Property '${prop}' is invalid on target.`);
                }
            }
            target[parts.shift()] = value;
        }
    }

    /**
     * Update the tween value.
     * @method jibo.face.Tween#lerp
     * @param {Number} v0 start number
     * @param {Number} v1 end number
     * @param {Number} t Time
     * @private
     */
    private lerp(v0:number, v1:number, t:number):number {
        return (1.0 - t) * v0 + t * v1;
    }


    /**
     * Auto-generate the start key values.
     * @method jibo.face.Tween#startDefaults
     * @private
     * @return {Object} Default start keys
     */
    private startDefaults(): any {
        const start = {};
        for(let prop in this._end) {
            if (prop.indexOf('.') < 0) {
                start[prop] = this._target[prop];
            }
            else {
                const parts = prop.split('.');
                let target = this._target;
                while (parts.length > 1) {
                    target = target[parts.shift()];
                    if (!target) {
                        throw new Error(`Property '${prop}' is invalid on target.`);
                    }
                }
                start[prop] = target[parts.shift()];
            }
        }
        return start;
    }

    /**
     * Check that both objects have the same keys.
     * @method jibo.face.Tween#validate
     * @private
     * @param {Object|Number} obj1 Object 1 to compare
     * @param {Object|Number} obj2 Object 2 to compare
     * @return {Boolean} `true` if both have the same keys.
     */
    private validate(obj1, obj2) {
        const a1 = Object.keys(obj1);
        const a2 = Object.keys(obj2);
        const result = a1.filter((val) => {
            return a2.indexOf(val) < 0;
        });
        return result.length === 0;
    }
 }

export default Tween;
