import Runtime from '../Runtime';
import {Plugin, PluginCallback} from '../Plugin';
import PathUtils from '../utils/PathUtils';
import semver = require("semver");

/**
 * Versions for ssm, platform, jibo.
 * @namespace jibo.versions
 */
class VersionsPlugin implements Plugin {

    /**
     * The current version of jibo.
     * @name jibo.versions#jibo
     * @type {String}
     */
    public jibo:string;

    /**
     * The current version of skills-service-manager.
     * @name jibo.versions#ssm
     * @type {String}
     */
    public ssm:string;

    /**
     * The content of the current jibo's package.json.
     * @name jibo.versions#platform
     * @type {String}
     */
    public platform:string;

    /**
     * The current version of platform.
     * @name jibo.versions#_packageInfo
     * @type {Object}
     * @private
     */
    private _packageInfo:any;

    constructor() {

        const jibo:Runtime = Runtime.instance;
        const dir:string = PathUtils.findRoot(__dirname);
        this._packageInfo = require(`${dir}/package.json`);

        // Set the version the same
        this.jibo = this._packageInfo.version;

        // Update the current jibo version
        jibo.version = this.jibo;
    }

    /**
     * Initializes the versions API.
     * @private
     * @param {Function} done Callback when completed.
     */
    init(done:PluginCallback): void {

        const jibo:Runtime = Runtime.instance;

        if (jibo.runMode === jibo.RunMode.UNIT_TESTS) {
            return done();
        }

        if (Runtime.electron) {
            for (let i = 0; i < jibo.records.length; i++) {
                const service = jibo.records[i];
                if (service.name === 'skills-service') {
                    this._getSSMVersion(service, done);
                    break;
                }
            }
        }
        else {
            done();
        }
    }

    /**
     * Check to see if the current version is supported on this platform.
     * @method jibo.versions#supported
     * @param {String} currentPlatformVersion The current platform version.
     * @return {Boolean} `true` if this `jibo` supports the current platform version.
     */
    public supported(currentPlatformVersion:string):boolean {
        const jiboVersion:string = this.requiresPlatform;
        this.platform = currentPlatformVersion;
        return semver.satisfies(currentPlatformVersion, jiboVersion);
    }

    /**
     * The Semver on the platform needed to run this `jibo`.
     * @name jibo.versions#requiresPlatform
     * @type {String}
     */
    public get requiresPlatform(): string {
        return this._packageInfo.platform;
    }

    /**
     * The content of the current jibo's `package.json`.
     * @name jibo.versions#packageInfo
     * @type {Object}
     */
    public get packageInfo(): any {
        return this._packageInfo;
    }

    /**
     * Returns a JSON representation of the current versions.
     * @method jibo.versions#toJSON
     * @internal
     * @return {Object} JSON representation of version API.
     */
    public toJSON():any {
        return {
            jibo: this.jibo,
            ssm: this.ssm,
            platform: this.platform
        };
    }

    /**
     * Internally get the SSM version.
     * @method jibo.versions#_getSSMVersion
     * @private
     * @param {Object} service Current service object for skils.
     * @param {Function} done Callback when complete.
     */
    private _getSSMVersion(service:any, done:PluginCallback): void {
        const url:string = "http://" + service.host + ":" + service.port + '/version';
        const request = new XMLHttpRequest();
        request.open("GET", url, true);
        request.onload = () => {
            if (request.status === 200) {
                const response = JSON.parse(request.response);
                this.ssm = response.version;
            }
            else {
                console.warn('Unable to request SSM version');
            }
            done();
        };
        request.send();
    }
}

Runtime.registerPlugin(VersionsPlugin, 'versions', {
    depends: ['services'],
    api: true
});

export default VersionsPlugin;
