import ParentBehavior from '../ParentBehavior';
import Status from '../Status';

/**
 * @class Sequence
 * @extends jibo.bt.ParentBehavior
 * @memberof jibo.bt.behaviors
 * @description `Sequence` Runs its child nodes in sequence until one fails. Fails if one of the children fails
 * and succeeds if all its children succeeded.
 * @param {Object} options See {@link jibo.bt.Behavior|Behavior} for all options.
 * @param {Array<jibo.bt.Behavior>} [options.children=[]] - An array of child behaviors.
 */
export default class Sequence extends ParentBehavior {
    private current:number;
    
    constructor(options) {
        super(options);
        this.current = -1;
    }
    public start() {
        if (this.children.length === 0) {
            return true;
        }
        this.current = 0;
        const success = this.children[this.current]._start();
        this.current = success ? this.current : -1;
        return success;
    }
    public stop():Promise<void> {
        let rtn:Promise<void>;
        if(this.current !== -1 && this.current < this.children.length) {
            rtn = this.children[this.current]._stop();
            this.current = -1;
        }
        return rtn || Promise.resolve();
    }
    public update() {
        if (this.children.length === 0) {
            return Status.SUCCEEDED;
        }
        while (this.current !== -1 && this.current < this.children.length) {
            const childStatus = this.children[this.current]._update();
            if (childStatus === Status.SUCCEEDED) {
                this.current++;
                if (this.current < this.children.length) {
                    const startSuccess = this.children[this.current]._start();
                    if (!startSuccess) {
                        return Status.FAILED;
                    }
                } else {
                    return Status.SUCCEEDED;
                }
            } else if (childStatus === Status.IN_PROGRESS || childStatus === Status.PAUSED) {
                return Status.IN_PROGRESS;
            } else {
                return Status.FAILED;
            }
        }
        return Status.SUCCEEDED;
    }
}
