export function configurable(value: boolean):PropertyDecorator {
    return function (target: any, propertyKey: string) {
        let descriptor = Object.getOwnPropertyDescriptor(target, propertyKey);
        descriptor.configurable = value;
        Object.defineProperty(target, propertyKey, descriptor);
    };
}

export function writable(value: boolean):PropertyDecorator {
    return function (target: any, propertyKey: string) {
        let descriptor = Object.getOwnPropertyDescriptor(target, propertyKey);
        descriptor.writable = value;
        Object.defineProperty(target, propertyKey, descriptor);
    };
}

export function enumerable(value: boolean):PropertyDecorator {
    return function (target: any, propertyKey: string) {
        let descriptor = Object.getOwnPropertyDescriptor(target, propertyKey);
        descriptor.enumerable = value;
        Object.defineProperty(target, propertyKey, descriptor);
    };
}

export function constant(target: any, propertyKey: string) {
    let descriptor = Object.getOwnPropertyDescriptor(target, propertyKey);
    descriptor.writable = false;
    descriptor.configurable = false;
    Object.defineProperty(target, propertyKey, descriptor);
};