import PathUtils from '../../utils/PathUtils';
import AbstractLoader, {FILETYPE} from './AbstractLoader';
import Callback from '../LoaderCallback';
import path = require('path');
import fs = require('fs');

module MIMETYPE {
    export const jpg = 'image/jpeg';
    export const jpeg = 'image/jpeg';
    export const gif = 'image/gif';
    export const png = 'image/png';
    export const bmp = 'image/bmp';
    export const webp = 'image/webp';
}

/**
 * Loads all assets to a skill,
 * including images, data, code. LocalLoader supports cache-busting
 * in the browser using dynamic query string parameters.
 * @class LocalLoader
 * @memberof jibo.loader
 */
class LocalLoader extends AbstractLoader {

    /**
     * Base to append to all file requests.
     * @type {String}
     * @name jibo.loader.LocalLoader#basePath
     */
    public basePath:string = '';

    /**
     * Prepare the URI request to be absolute. Also, applies asset pack requests.
     * @method jibo.loader.Loader#prepare
     * @param {String} uri The relative or absolute file to load.
     * @return {String} The absolute URI.
     */
    public prepare(uri:string):string
    {
        // Exclude absolute URIs and URLs
        if (!path.isAbsolute(uri) && !/^(https?|file)\:\/\//.test(uri))
        {
            //if uri is an asset pack, get that correct path, otherwise prepend the base path
            uri = PathUtils.getAssetUri(uri, undefined, this.basePath);
            //make 100% sure that we have an absolute path
            uri = path.resolve(uri);
        }
        return uri;
    }

    /**
     * Loads the asset file.
     * @method jibo.loader.LocalLoader#internalLoad
     * @protected
     * @param {String} uri The file to load.
     * @param {Function} callback Callback when complete.
     * @param {Object} [options] Optional load options
     */
    protected internalLoad(type:string, uri:string, callback:Callback, options?:any): void
    {
        if (!path.isAbsolute(uri)) {
            //if uri is an asset pack, get that correct path, otherwise prepend the base path
            uri = PathUtils.getAssetUri(uri, undefined, this.basePath);
            //make 100% sure that we have an absolute path
            uri = path.resolve(uri);
        }
        
        fs.readFile(uri, this.getEncodingType(type), (err, data) => {
            if (err) {
                return callback(this.createError(err, uri, `Unable to read ${type} file`));
            }
            switch(type) {
                // Handle images as base64 data
                case FILETYPE.IMAGE: 
                    const mimeType = this.getImageMimeType(uri);
                    const result = new Image();
                    result.src = `data:${mimeType};base64,${data}`;
                    callback(null, result);
                    break;
                // Use require to load javascript
                case FILETYPE.JAVASCRIPT: 
                    try {
                        const result:any = require(uri);
                        callback(null, result);
                    }
                    catch(e) {
                        callback(this.createError(e, uri, 'Unable to read JavaScript file'));
                    } 
                    break;
                // Everything else use the standard post process
                default: 
                    this.internalDone(type, uri, <string>data, callback);
                    break;
            }
        });
    }

    /**
     * Get the Node fs.readFile encoding type
     * @method jibo.loader.LocalLoader#getEncodingType
     * @private
     * @param {String} type The file type to load
     * @return {String} Encoding type for fs.readFile
     */
    private getEncodingType(type:string):string {
        switch(type) {
            case FILETYPE.IMAGE:
                return 'base64';
            case FILETYPE.JSON:
            case FILETYPE.CSS:
            case FILETYPE.XML:
            case FILETYPE.SVG:
            case FILETYPE.HTML:
            case FILETYPE.TEXT:
            default:
                return 'utf8';
        }
    }

    /**
     * Gets a mime type by uri.
     * @method jibo.loader.LocalLoader#getImageMimeType
     * @private
     * @param {String} uri The file uri.
     * @return {String} The mime type.
     */
    private getImageMimeType(uri:string):string
    {
        let extension = path.extname(uri).toLowerCase();
        if (extension) {
            extension = extension.substr(1);
        }
        return MIMETYPE[extension] || null;
    }
}
export default LocalLoader;
