/**
 * The mesh of the eye.
 * @class EyeMesh
 * @extends PIXI.mesh.Mesh
 * @memberof jibo.face
 * @param {PIXI.Texture} texture
 */
class EyeMesh extends PIXI.mesh.Mesh {

    /**
     * The points for DOF transforms.
     * @name jibo.face.EyeMesh#points
     * @type {Array<PIXI.Point>}
     */
    public points:Array<PIXI.Point>;

    constructor(texture:PIXI.Texture) {

        super(texture, null, null, null, PIXI.mesh.Mesh.DRAW_MODES.TRIANGLES);

        this.uvs = <any>new Float32Array([
            0,   0,
            0.5, 0,
            1,   0,
            0,   0.5,
            0.5, 0.5,
            1,   0.5,
            0,   1,
            0.5, 1,
            1,   1
        ]);

        this.vertices = <any>new Float32Array(this.uvs.length * 2);

        this.points = [];
        for(let i:number = 0; i < this.uvs.length; i += 2) {
            this.points.push(new PIXI.Point(
                this.uvs[i],
                this.uvs[i + 1]
            ));
        }

        this.indices = <any>new Uint16Array([
            0,1,3,
            1,3,4,
            1,4,5,
            2,5,1,
            3,4,7,
            7,6,3,
            4,5,7,
            5,7,8
        ]);
    }

    updateTransform() {
        for (let i:number = 0; i < this.points.length; i++) {
            const point:PIXI.Point = this.points[i];
            const index:number = i * 2;
            this.vertices[index] = point.x;
            this.vertices[index + 1] = point.y;
        }
        this.containerUpdateTransform();
    }
}

export default EyeMesh;
