/**
 * Measuring performance of different calls.
 * @namespace jibo.performance
 * @private
 */
/**
 * Class to measure performance with the Skills Service Manager.
 * @class PerformanceService
 * @private
 * @memberof jibo.performance
 */
class PerformanceService {

    private httpInterface:string;
    private initialized:boolean = false;

    /**
     * Initialize the performance module for `jibo.init`.
     * @method jibo.performance#init
     * @param service {Object} The service options
     * @param service.host {String} host name
     * @param service.port {String} port number
     * @param callback {Function} callback
     */
    public init(service:{host:string; port:string}, callback:(err?:Error) => void):void {
        this.httpInterface = "http://" + service.host + ":" + service.port;
        this.initialized = true;
        callback();
    }

    /**
     * Post a log to the performance service.
     * @method jibo.performance#log
     * @param type {string} The event type
     * @param description {string} Description
     */
    public log(type:string, description:string = ''):void {
        if(!this.initialized) {
            return;
        }
        let request:XMLHttpRequest = new XMLHttpRequest();
        request.open("POST", this.httpInterface + '/log', true);
        request.send(JSON.stringify({
            time: Date.now(), type, description
        }));
    }
}

export default PerformanceService;
