/*
 * This is a sister class to ClientDialogListener
 * It has its own set of events, specifically for Enrollment
 * It also has the ability to directly POST to the ListenService, to tell it to pause GlobalListen and start enrollment
 */
import { Event } from 'jibo-typed-events';
import { ClientDialogListener, ListenerEvents } from './ClientDialogListener';
import Runtime from "../../Runtime";
import { ListenOptions, Callback } from "./DataTypes";

let UUID = require('uuid');

/**
 * @class EnrollmentEvents
 * @description Typed Events for enroller (`{@link jibo.gl.EnrollmentListener} events`)
 * @extends jibo.gl.ListenerEvents
 * @memberof jibo.gl
 * @internal
 */
export class EnrollmentEvents extends ListenerEvents {
  public startedEnrollment: Event<any>;
  public heardHeyJibo: Event<SpeakerIdStatusResult>;
  public finishedEnrollment: Event<SpeakerIdStatusResult>;
  public stoppedEnrollment: Event<any>;
  public failedEnrollment: Event<any>;

  constructor() {
    super();
    /**
     * Emit event when enrollment starts.
     * @name jibo.gl.EnrollmentEvents#startedEnrollment
     * @type {Event}
     * @readOnly
     */
    this.startedEnrollment = new Event<any>('Enrollment Started');
    /**
     * Emit after "hey jibo" is heard by enroller.
     * @name jibo.gl.EnrollmentEvents#heardHeyJibo
     * @type {jibo.gl.EnrollmentEvents~SpeakerIdStatusResult}
     * @readOnly
     */
    this.heardHeyJibo = new Event<SpeakerIdStatusResult>('Heard a Hey Jibo sample'); //TODO: post beta-1, will provide handle to audio data
    /**
     * Emit event when enroller has successfully finished.
     * @name jibo.gl.EnrollmentEvents#finishedEnrollment
     * @type {jibo.gl.EnrollmentEvents~SpeakerIdStatusResult}
     * @readOnly
     */
    this.finishedEnrollment = new Event<any>('Enrollment Done');
    /**
     * Emit event when enroller is explicitly stopped.
     * @name jibo.gl.EnrollmentEvents#stoppedEnrollment
     * @type {Event}
     * @readOnly
     */
    this.stoppedEnrollment = new Event<any>('Enrollment Stopped');
    /**
     * Emit event when enroller fails to start.
     * @name jibo.gl.EnrollmentEvents#failedEnrollment
     * @type {Event}
     * @readOnly
     */
    this.failedEnrollment = new Event<any>('Enrollment Failed to start');
  }

}


/**
 * @class EnrollmentOptions
 * @memberof jibo.gl
 * @description Options to subscribe enroller.
 * @param {String} [speakerId] - Listen for a specific speaker.
 * @param {String} [enollmentType] - Listen for a specific enrollmentType.
 * @internal
 */
export class EnrollmentOptions extends ListenOptions {
  public speakerId: string;
  public enrollmentType: string;
  public listenerId: string;
  public action: string;

  constructor(speakerId?: string, enrollmentType?: string) {
    super();
    /**
     * Specify the ID of user to be enrolled.
     * @name jibo.gl.EnrollmentOptions#speakerId
     * @type {String}
     */
    this.speakerId = speakerId;
    /**
     * Specify the type of enrollement to use.
     * `text-dependent` (default) to enroll with "hey jibo" || `text-independent` to enroll with free speech.
     * @name jibo.gl.EnrollmentOptions#enrollmentType
     * @type {String}
     */
    this.enrollmentType = enrollmentType || "text-dependent";
    /**
     * Universally unique identifier (UUID) of enroller listener.
     * @name jibo.gl.EnrollmentOptions#listenerId
     * @type {String}
     * @readOnly
     */
    this.listenerId = "";
    /**
     * Set by calling `start` or `stop` on EnrollmentListener.
     * @name jibo.gl.EnrollmentOptions#action
     * @type {String}
     * @readOnly
     */
    this.action = "start";
  }
}

export type UTTStatus =
    "SAVING_AUDIO" |
    "ENROLLMENT-DONE" |
    "ENROLLMENT-STARTED" |
    "NEED-4-MORE-UTTS" |
    "NEED-3-MORE-UTTS" |
    "NEED-2-MORE-UTTS" |
    "NEED-1-MORE-UTT";

/**
 * @interface SpeakerIdStatusResult
 * @name jibo.gl.EnrollmentEvents~SpeakerIdStatusResult
 * @description Type of result from enrollment events.
 * @prop {String} status - The status of enrollment result.
 * @prop {Boolean} noisy - `true` if noisy audio from "hey jibo"
 * @prop {String} loudness - The loudness signal (if applicable) from enrollment result.
 * @prop {Boolean} badAudio - `true` if audio quality is not acceptable to enroll.
 * @prop {Number} snrValue - The signal-to-noise ratio of audio.
 * @prop {Number} [numRequired] - The number of "Hey Jibos" still required (if applicable).
 */
export interface SpeakerIdStatusResult {
    status: UTTStatus;
    noisy: boolean;
    loudness: string;
    badAudio: boolean;
    snrValue: number;
    numRequired?: number;
};

/**
 * @class EnrollmentListener
 * @param enrollOptions {jibo.gl.EnrollmentOptions} Options for enrollment.
 * @param {String} enrollOptions.speakerId ID of user to enroll
 * @param {String} [enrollOptions.enollmentType] Listen for a specific enrollmentType. `text-dependent` or `text-independent`. Defaults to `text-dependent`.
 * @description Enroller for voice enrollment on Jibo Robot.
 * Listens for "Hey Jibo."
 * Is unsubscribed from the listening service.
 * ```
 *    let enroller = jibo.gl.createEnrollmentListener({
 *      speakerId: <IdOfSpeakerToEnroll>,
 *      enrollmentType: "text-dependent"
 *    }, () => { /* cool callback function \/* });
 *    enroller.events.heardHeyJibo((data: SpeakerIdStatusResult) => {
 *        // Emits after a Hey Jibo sample is heard.
 *        // A good place to do another enroller.collectSample();
 *    });
 *    enroller.events.finishedEnrollment((data: SpeakerIdStatusResult) => {
 *        //Enrollment was successfully completed.
 *    });
 *    enroller.events.stoppedEnrollment(() => {
 *         //Enrollment was explicitly stopped (with enroller.stop()).
 *    });
 *    enroller.collectSample();  // begin collecting samples.
 * ```
 * @memberof jibo.gl
 * @internal
 * @extends jibo.gl.ClientDialogListener
 */
export class EnrollmentListener extends ClientDialogListener{

  public events :EnrollmentEvents;
  public listenerId: string = UUID.v1(); //used to identify it to the GLService
  public userId : string;
  public options : EnrollmentOptions;
  private started: boolean;

  /**
   * @param enrollOptions {jibo.gl.EnrollmentOptions} Options for enrollment.
   * @param {String} enrollOptions.speakerId ID of user to enroll
   * @param {String} enrollOptions.enollmentType Listen for a specific enrollmentType. `text-dependent` or `text-independent`. Defaults to `text-dependent`.
   * @param [callback] {Function} Callback with Global Listen response.
   * @method jibo.gl.EnrollmentListener#constructor
   * @public
   */
  constructor(options?) {
    // can we tell who is calling this?
    // it'd be nice if we could warn people not to do it directly, only through jibo.GL.createEnrollmentListener()
    super(new ListenOptions(),""); //TODO: Does this do anything?

    /**
     * LoopId of user to enroll
     * @name jibo.gl.EnrollmentListener#userId
     * @type {String}
     */
    this.userId = "";
    /**
     * Enrollment Listener ID
     * @name jibo.gl.EnrollmentListener#listenerId
     * @type {String}
     * @readOnly
     */
    this.listenerId = UUID.v1();
    /**
     * Typed events of EnrollmentListener module.
     * @name jibo.gl.EnrollmentListener#events
     * @type {jibo.gl.EnrollmentEvents}
     */
    this.events = new EnrollmentEvents();
    /**
     * Options for enrollment.
     * @name jibo.gl.EnrollmentListener#options
     * @type {jibo.gl.EnrollmentOptions}
     */
    this.options = Object.assign(new EnrollmentOptions(), options);
    this.options.listenerId = this.listenerId;
  }

  /**
   * Explicitly stop enroller.
   * @param callback {Function} Callback with Global Listen response.
   * @method jibo.gl.EnrollmentListener#stop
   * @public
   */
  public stop(callback?:Callback) {
    this.options.action = "stop";
    Runtime.instance.gl.enroll(this.options, callback);
  }

  /**
   * Collect a "hey jibo" utterance without trying to enroll.
   * @param callback {Function} Callback with Global Listen response.
   * @method jibo.gl.EnrollmentListener#collectSample
   * @public
   */
  public collectSample(callback?:Callback) {
    this.options.action = "collectSample";
    Runtime.instance.gl.enroll(this.options, callback);
  }

  /**
   * Collect a "hey jibo" utterance while attempting to enroll.
   * @param callback {Function} Callback with Global Listen response.
   * @method jibo.gl.EnrollmentListener#collectAndEnroll
   * @public
   */
  public collectAndEnroll(callback?:Callback) {
    this.options.action = "collectAndEnroll";
    Runtime.instance.gl.enroll(this.options, callback);
  }

  /**
   * Clear out all temporary previous enrollment data and collect next. 
   * @param callback {Function} Callback with Global Listen response.
   * @method jibo.gl.EnrollmentListener#clearData
   * @public
   */
  public clearAndEnroll(callback?:Callback) {
    this.options.action = "clearAndEnroll";
    Runtime.instance.gl.enroll(this.options, callback);
  }

  /**
   * Clear out all temporary previous enrollment data. 
   * @param callback {Function} Callback with Global Listen response.
   * @method jibo.gl.EnrollmentListener#clearData
   * @public
   */
  public clearData(callback?:Callback) {
    this.options.action = "clearData";
    Runtime.instance.gl.enroll(this.options, callback);
  }

  /**
   * Set speaker ID of enroller. Not necessary if ID was set in constructor.
   * @param speakerId {string} ID of speaker to enroll
   * @method jibo.gl.EnrollmentListener#setSpeakerId
   * @public
   */
  public setSpeakerId(speakerId:string) {
    this.userId = speakerId;
  }

  /**
   * Start the enroller.
   * IT IS NOT NECESSARY to start enroller before calling enroller.collectSample().
   * @param enrollOptions {jibo.gl.EnrollmentOptions} Options for enrollment.
   * @param {String} enrollOptions.speakerId ID of user to enroll
   * @param {String} enrollOptions.enollmentType Listen for a specific enrollmentType. `text-dependent` or `text-independent`. Defaults to `text-dependent`.
   * @param {String} enrollOptions.action `start` or `stop` to start or stop enrollment.
   * @param [callback] {Function} Callback with Global Listen response.
   * @method jibo.gl.EnrollmentListener#start
   * @private
   */
  public start(options?: any, callback?:Callback) {
    this.started = true;
    this.options = Object.assign(new EnrollmentOptions(), options);
    this.options.action = "start";
    if(!this.options.speakerId && callback) {
      callback("No speaker Id provided to enroller");
      return;
    }
    Runtime.instance.gl.enroll(this.options, callback);
  }

}
