import Status from './Status';
import BaseElement from './BaseElement';
import ParentBehavior from "./ParentBehavior";
import Decorator from './Decorator';

/**
 * @class Behavior
 * @memberof jibo.bt
 * @description The baseclass to all behaviors.
 *
 * Subclasses: {@link jibo.bt.behaviors}
 * @param {Object} [options] Options for the behavior
 * @param {String} [options.name=''] Name of the behavior instance
 * @param {Array<jibo.bt.Decorator>} [options.decorators=[]] Decorators
 * @param {jibo.bt.Blackboard} [options.blackboard=null] Blackboard instance
 * @param {jibo.bt.BehaviorEmitter} [options.emitter=null] Emitter instance
 * @param {String} [options.assetPack=''] Name of the asset pack
 * @param {Object} [defaultOptions] Defaults for options
 */
abstract class Behavior extends BaseElement {
    parent:ParentBehavior;
    waitDecorators:Array<Decorator>;
    waitDecoratorsLength:number;
    _decorators:Array<Decorator>;
    previousStatus:Status;

    constructor(options:any, defaultOptions:any={}){
        super(options, Object.assign({
            decorators: []
        }, defaultOptions || {}));

        // Set the decorators
        this.decorators = this.options.decorators;

        /**
         * Reference to the composite parent behavior
         * @name jibo.bt.Behavior#parent
         * @type {jibo.bt.ParentBehavior}
         * @readOnly
         */
        this.parent = null;

        /**
         * List of decorators to wait on start
         * @name jibo.bt.Behavior#waitDecorators
         * @type {Array<jibo.bt.Decorator>}
         * @private
         */
        this.waitDecorators = [];

        /**
         * Number of wait decorators
         * @name jibo.bt.Behavior#waitDecoratorsLength
         * @type {int}
         * @private
         */
        this.waitDecoratorsLength = 0;
    }

    /**
     * Destroy this
     */
    destroy(): void {
        if (this._decorators) {
            this._decorators.forEach((decorator: Decorator) => {
                decorator.destroy();
            });
        }
        this.parent = null;
        this._decorators = null;
        this.waitDecorators = null;
        super.destroy();
    }

    /**
     * Collection of decorators
     * @name jibo.bt.Behavior#decorators
     * @type {Array<jibo.bt.Decorator>}
     * @readOnly
     */
    get decorators():Array<Decorator> { return this._decorators; }
    set decorators(decorators:Array<Decorator>) {
        this._decorators = decorators;
        if (decorators) {
            decorators.forEach((decorator:Decorator) => {
                decorator.behavior = this;
            });
        }
    }
    
    /**
     * Starts the behavior or decorator
     * @method jibo.bt.Behavior#start
     * @returns {Boolean} `true` if this element is started successfully. `false` otherwise.
     */
    start():boolean {
        return true;
    }

    /**
     * Called every frame. Must be overridden in subclass.
     * @method jibo.bt.Behavior#update
     * @returns {jibo.bt.Status} The current status of this behavior.
     */
    abstract update(result?:Status):Status;

    /**
     * Internal pause the behavior
     * @method jibo.bt.Behavior#_pause
     * @private
     */
    _pause():void {
        this.previousStatus = this._currentStatus;
        this._currentStatus = Status.PAUSED;
    }

    /**
     * Internal unpause the behavior
     * @method jibo.bt.Behavior#_unpause
     * @private
     */
    _unpause():void {
        this._currentStatus = this.previousStatus;
    }

    /**
     * Internal start the behavior
     * @method jibo.bt.Behavior#_start
     * @private
     * @return {Boolean} Status result
     */
    _start():boolean {
        if (this._currentStatus === Status.IN_PROGRESS) {
            return false;
        }

        this.waitDecorators.length = this.waitDecoratorsLength = 0;
        if (this._decorators.length) {
            for(let i = 0; i < this._decorators.length; i++) {
                let success:any = this._decorators[i]._start();
                if (success === Status.WAIT) {
                    this.waitDecorators.push(this._decorators[i]);
                    this.waitDecoratorsLength++;
                }
                else if (!success) {
                    this._currentStatus = Status.FAILED;
                    this._stop();
                    return false;
                }
            }
        }
        if (this.waitDecorators.length === 0) {
            let success:any = this.start(); // actually call start
            this._currentStatus = success ? Status.IN_PROGRESS : Status.FAILED;
            if (!success) {
                this._stop();
            }
            return success;
        }
        else {
            this._currentStatus = Status.IN_PROGRESS;
            return true;
        }
    }

    /**
     * Internal stop the behavior
     * @method jibo.bt.Behavior#_stop
     * @return {Promise<void>} A promise that resolves after any asynchronous cleanup has been performed.
     * @private
     */
    _stop():Promise<void> {
        const promises:Promise<void>[] = [];
        //stop the decorators
        if (this._decorators.length) {
            this._decorators.forEach(function(decorator) {
                if (decorator.currentStatus === Status.IN_PROGRESS) {
                    promises.push(decorator._stop());
                }
            });
        }

        if (this._currentStatus === Status.IN_PROGRESS) {
            this._currentStatus = Status.INTERRUPTED;
            promises.push(this.stop()); // actually call stop
        }
        
        if (promises.length === 0) {
            return Promise.resolve();
        } else if (promises.length === 1) {
            return promises[0];
        }
        //apparently Promise<void[]> can't be assigned to Promise<void>
        return <any>Promise.all(promises);
    }

    /**
     * Internal update the behavior
     * @method jibo.bt.Behavior#_update
     * @private
     * @return {jibo.bt.Status} Resulting status
     */
    _update():Status {
        if (this.waitDecoratorsLength > 0) {
            for(let i = 0; i < this.waitDecorators.length; i++) {
                if (this.waitDecorators[i]) {
                    let status:Status = this.waitDecorators[i]._update(this._currentStatus);
                    if (status !== Status.WAIT) {
                        this.waitDecoratorsLength--;
                        this.waitDecorators[i] = null;
                    }
                }
            }
            if (this.waitDecoratorsLength === 0) {
                let success:boolean = this.start(); // actually call start
                this._currentStatus = success ? Status.IN_PROGRESS : Status.FAILED;
                if (!success) {
                    this._stop();
                }
            }
            else {
                return Status.IN_PROGRESS;
            }
        }
        if (this._currentStatus === Status.PAUSED) {
            let status:Status = this._currentStatus;
            if (this._decorators.length) {
                for(let i = 0; i < this._decorators.length; i++) {
                    status = this._decorators[i]._update(this._currentStatus);
                    if (status !== Status.IN_PROGRESS) {
                        this._stop();
                        return status;
                    }
                }
            }
            return this._currentStatus;
        }
        else if (this._currentStatus === Status.IN_PROGRESS) {
            let tempStatus:Status = this.update(); // actually call update
            if (tempStatus !== Status.IN_PROGRESS) {
                this._currentStatus = tempStatus;
                this._stop();
            }
            //update the decorators
            if (this._decorators.length) {
                for(let i = 0; i < this._decorators.length; i++) {
                    tempStatus = this._decorators[i]._update(this._currentStatus);
                    if (tempStatus !== Status.IN_PROGRESS) {
                        this._stop();
                        this._currentStatus = tempStatus;
                        return this._currentStatus;
                    }
                }
            }
            return this._currentStatus;
        }
        else if (this._currentStatus === Status.SUCCEEDED) {
            return Status.SUCCEEDED;
        }
        else {
            return Status.FAILED;
        }
    }
}

export default Behavior;
