import Component from './Component';
import ComponentCreator from './ComponentCreator';
import ActionData from './actions/ActionData';
import {AssetDescriptor} from './ViewManager';
import async = require('async');

/**
 * Base class for GUI elements that can have child elements.
 * Classes that extend ComponentGroup are ones that need to manage the relationship
 * between multiple child elements (e.g. views, lists).
 *
 * @class ComponentGroup
 * @extends jibo.face.Component
 * @memberof jibo.face
 * @internal
 */
abstract class ComponentGroup extends Component
{
    /**
     * Object serving as hash table for child Components using the Component's id variable as a key.
     * @name jibo.face.ComponentGroup#_componentLibrary
     * @type {Object}
     * @protected
     * @internal
     */
    protected _componentLibrary:any = {};

    /**
     * Array of child Components.
     * @name jibo.face.ComponentGroup#_componentList
     * @type {jibo.face.Component[]}
     * @protected
     * @internal
     */
    protected _componentList:Array<Component> = [];

    /**
     * Array of config Objects (generally derived from JSON).
     * @name jibo.face.ComponentGroup#_componentConfigs
     * @type {any[]}
     * @protected
     * @internal
     */
    protected _componentConfigs:Array<any>;

    /**
     * List of Components that have registered to be updated.
     * @name jibo.face.ComponentGroup#_updateRegistry
     * @type {jibo.face.Component[]}
     * @protected
     * @internal
     */
    protected _updateRegistry:Array<Component>;

    /**
     * Container for displays.
     * Container is sent as a parameter within [createDisplay()]{@link jibo.face.Component#createDisplay}
     * where a reference is then made.
     * @name jibo.face.ComponentGroup#_container
     * @type {PIXI.Container}
     * @protected
     * @internal
     */
    protected _container:PIXI.Container;

    /**
     *
     * Flag to lock (`true`) and unlock (`false`) component's response to input.
     * Status is propagate down to child [Component]{@link jibo.face.Component}.
     * @name jibo.face.ComponentGroup#inputLocked
     * @type {Boolean}
     */
    public set inputLocked(flag:boolean)
    {
        this._inputLocked = flag;
        if(this._componentList) {
            let component:Component;
            let length:number = this._componentList.length;
            for(let i:number=0; i<length; i++) {
                component = this._componentList[i];
                component.inputLocked = flag;
            }
        }
    }

    /**
     * Viewport hit area defined in ViewManager.
     * @name jibo.face.ComponentGroup#hitArea
     * @type {PIXI.Container}
     * @readOnly
     * @internal
     */
    public get hitArea():PIXI.Container {
        if(this.parentGroup){
            return this.parentGroup.hitArea;
        }
        else {
            return null;
        }

    }

    //////////////////////// CONSTRUCTION & SETUP ////////////////////////

    /**
     * Update configuration Object to reflect the current configuration state.
     * This ensures that when the Component is recreated from its configuration it reflects its last state.
     * @method jibo.face.ComponentGroup#updateConfig
     * @param {Object} configObject
     * @returns {any} - Returns the given configuration Object with any required values updates applied.
     * @internal
     */
    public updateConfig(configObject?:any):any
    {
        if(this.updateComponentConfigs())
        {
            this._stateChanged = true;
            // TODO :: Not sure we want Object.assign, maybe only assign value if it is already present within config?
            Object.assign(configObject,{"componentConfigs":this._componentConfigs});
        }
        return configObject;
    }

    /**
     * Update config with any relevant changes to the Component's state, call updateConfig on all child Components.
     * Returns true is there was a state change in this Component or any of its children.
     * @method jibo.face.ComponentGroup#updateComponentConfigs
     * @returns {boolean} `true` if the state of this Component has changed,
     *                     and/or if the state in any of the child components has changed.
     * @protected
     * @internal
     */
    protected updateComponentConfigs():boolean
    {
        let componentChanged:boolean = false;
        // iterate through components for value updates that will effect the config
        if (this._componentList && this._componentConfigs)
        {
            let length:number = this._componentList.length;
            let component:Component;
            for (let i:number = 0; i < length; i++)
            {
                component = this._componentList[i];
                if (component.stateChanged)
                {
                    componentChanged = true;
                    component.updateConfig(this._componentConfigs[i]);  // TODO :: If anyone adds a component dynamically this gets wacky, need to address
                }
            }
        }
        return componentChanged;
    }

    /**
     * Iterates through array of component configs to create Components (data aspects only).
     * Adds each component to the view's component library.
     * @method jibo.face.ComponentGroup#createComponentsFromConfigs
     * @param {any[]} componentConfigs Array of component configuration Objects.
     * @protected
     * @internal
     */
    protected createComponentsFromConfigs(componentConfigs:Array<any>):void {
        if(componentConfigs) {
            let creator:ComponentCreator = ComponentCreator.instance;  //should only bother making thsi
            let component:Component;
            let length:number = componentConfigs.length;
            for(let i:number=0; i<length; i++)
            {
                // parse Object created from JSON into Component
                component = creator.createComponentFromConfig(componentConfigs[i]);
                if(component)
                {
                    this.addComponent(component);
                }
            }
        }
    }

    /**
     * Add component to this ComponentGroup, allows parent and child to reference to each other.
     * @method jibo.face.ComponentGroup#addComponent
     * @param {jibo.face.Component} component The Component to add this group's component list and library.
     * @param {String} [componentId] The id to assign to the Component, if specified will overwrite existing id,
     *                  if none is specified an id will be automatically generated and assigned.
     * @returns {jibo.face.Component} - Returns the given Component.
     */
    public addComponent(component:Component, componentId?:string):Component {
        // components need unique ids, if none was specified auto assign one
        // TODO :: Do we need to make sure no one has manual assigned the same id within a single GUIView?

        if(component) {
            component.parentGroup = this;
            if(!this._componentLibrary) {
                this._componentLibrary = {};
            }
            if(!this._componentList) {
                this._componentList = [];
            }
            if(componentId) {
                component.id = componentId;
            }

            // possible id was set manually, so we use another if check
            if(!component.id) {
                let j:number = 1;
                // just make sure there aren't any duplciate ids
                while (this._componentLibrary.hasOwnProperty(String(component.type + j))) {
                    j++;
                }
                this._componentLibrary[String(component.type + j)] = component;
                this._componentList.push(component);
            }
            else {
                // TODO :: Might want to add some checking to see if it is overwriting an existing component and send a log
                this._componentLibrary[component.id] = component;
                this._componentList.push(component);
            }
        }
        return component;
    }

    /**
     * Retrieve a child Component by its id.
     * @method jibo.face.ComponentGroup#getComponentById
     * @param {String} componentId The ID of the component to retrieve.
     * @returns {jibo.face.Component}
     */
    public getComponentById(componentId:string):Component {
        if(this._componentLibrary) {
            return this._componentLibrary[componentId];
        }
        else {
            console.log("ComponentGroup :: getComponentById : this._componentLibrary is undefined, meaning no components have been added");
        }
    }

    /**
     * Retrieve a child Component by its index.
     * @method jibo.face.ComponentGroup#getComponentByIndex
     * @param {number} index The index of the component to retrieve.
     * @returns {jibo.face.Component}
     */
    public getComponentByIndex(index:number):Component {
        if(this._componentList) {
            if(index > -1 && index < this._componentList.length){
                return this._componentList[index];
            }
            else {
                console.warn("ComponentGroup :: getComponentByIndex : index is out of bounds");
            }
        }
        else {
            console.warn("ComponentGroup :: getComponentByIndex : this._componentList is undefined, meaning no components have been added");
        }
        return null;
    }

    /**
     * Get the number of child components.
     * @name jibo.face.ComponentGroup#componentsTotal
     * @type {number}
     * @readOnly
     */
    public get componentsTotal():number {
        if(this._componentList){
            return this._componentList.length;
        }
        return 0;
    }

    //////////////////////////// ASSET LOADING ////////////////////////////

    /**
     * List of assets required by the ComponentGroup and its Component children.
     * @name jibo.face.ComponentGroup#assetDescriptors
     * @type {jibo.face.ViewManager#AssetDescriptor[]}
     * @readOnly
     * @internal
     */
    public get assetDescriptors():Array<AssetDescriptor> {
        // NOTE :: moved implementation into a separate method, because TypeScript doesn't usage of super for getters/setters
        return this.groupAssetDescriptors;
    }

    /**
     * Compiles together required assets for the ComponentGroup and its children.
     * @name jibo.face.ComponentGroup#groupAssetDescriptors
     * @type {jibo.face.ViewManager#AssetDescriptor[]}
     * @protected
     * @internal
     */
    protected get groupAssetDescriptors():Array<AssetDescriptor> {

        let groupAssetDescriptors:Array<AssetDescriptor> = (this._assetDescriptors) ? this._assetDescriptors.slice(0) : [];

        // iterate through children for their asset queues
        if(this._componentList) {
            let i:number = 0;
            let length:number = this._componentList.length;
            let component:Component;
            let nextAssetDescriptors:Array<AssetDescriptor>;
            for(i; i<length; i++) {
                // TODO :: Might be better to cull duplicate assets at this level?  Sort of safer to do it at the last step, but doing it here would decrease array size earlier
                component = this._componentList[i];
                nextAssetDescriptors = component.assetDescriptors;
                if(nextAssetDescriptors) {
                    groupAssetDescriptors = groupAssetDescriptors.concat(nextAssetDescriptors);
                }
            }
        }
        return groupAssetDescriptors;
    }

    //////////////////////////// DISPLAY MANAGEMENT ////////////////////////////

    /**
     * Frame enter loop update.
     * Calls update method of any child that has registered for updates.
     * @method jibo.face.ComponentGroup#update
     * @param {number} elapsed Time in milliseconds since the last frame update.
     * @internal
     */
    public update(elapsed:number):void {
        if (this._updateRegistry) {
            let length:number = this._updateRegistry.length;
            for (let i:number = 0; i < length; i++) {
                this._updateRegistry[i].update(elapsed);
            }
        }
    }

    /**
     * Register for the given component's update method to be called.
     * @method jibo.face.ComponentGroup#registerComponentUpdate
     * @param {jibo.face.Component} component The component to update.
     * @internal
     */
    public registerComponentUpdate(component:Component):void {
        if(!this._updateRegistry){
            this._updateRegistry = [];
        }
        this._updateRegistry.push(component);
    }

    /**
     * Stop the given component's update method from getting called.
     * @method jibo.face.ComponentGroup#unregisterComponentUpdate
     * @param {jibo.face.Component} component The Component to stop providing updates to.
     * @internal
     */
    public unregisterComponentUpdate(component:Component):void {
        if(this._updateRegistry){
            for(let i:number = 0; i<this._updateRegistry.length; i++) {
                if(this._updateRegistry[i] === component) {
                    this._updateRegistry.splice(i,1);
                }
            }
        }
    }

    /**
     * Create this Component's display as well as calling createDisplay on all child Components.
     * This method should should 'visualize' the component, creating DisplayObjects and adding them the container.
     * @method jibo.face.ComponentGroup#createDisplay
     * @param {PIXI.Container} container Is ultimately a child of the stage.
     * @param {any} assets Object passed back from loader namespace load method,
     *        refer to loader namespace within jibo for details.
     * @internal
     */
    public createDisplay(container:PIXI.Container, assets:any):void
    {
        this._container = container;
        if (this._componentList) {
            const length = this._componentList.length;
            for (let i:number = 0; i < length; i++) {
                this._componentList[i].createDisplay(container, assets);
            }
        }
    }

    /**
     * @description Called by parent ComponentGroup once parent has finished its loading and setup,
     * calls ready on all child Components.
     * Allows opportunity to do additional setup that may depend on other components.
     *
     * ATTENTION: This should not be called directly, the top level View {@link jibo.face.View}
     * will call this, which will recurse through Component tree.
     * @method jibo.face.ComponentGroup#ready
     */
    public ready():void {
        // any component dependent setup would happen here, prior to calling ready on children
        if (this._componentList) {
            const length = this._componentList.length;
            for (let i:number = 0; i < length; i++) {
                this._componentList[i].ready();
            }
        }
    }

    /**
     * Method for 'open' transition.
     * Iterates through components and calls their open method.
     * Method is responsible for calling the callback in all situations.
     *
     * ATTENTION : This should not be called directly, the {@link jibo.face.ViewManager}
     * will manage when Components should open during the view process.
     * @method jibo.face.ComponentGroup#open
     * @param {Function} callback Function to be called once open is complete.
     * @param {String} transitionType String used to determine way Component opens,
     *        refer to ViewManager for constants used
     * @internal
     */
    public open(callback:Function, transitionType?:string):void {

        if(this._componentList) {
            let transitionArray:Array<any> = [];
            let i:number = 0;
            let length:number = this._componentList.length;
            for(i; i<length; i++) {
                let component:Component = this._componentList[i];   // create a new pointer on each iteration, as pointer was getting overwritten within async
                transitionArray.push( function(subCallback:Function) {
                    component.open(subCallback, transitionType);
                });
            }

            if(transitionArray.length > 0) {
                async.parallel( transitionArray, function(err:Error, results:Array<any>) {
                    if(err){
                        console.error(err);
                    }
                    this.transitionComplete(callback, err, results);
                }.bind(this));
            }
            else {
                this.transitionComplete(callback);
            }
        }
        else {
            // no components to open, callback immediately
            this.transitionComplete(callback);
        }
    }

    /**
     * Method for 'close' transition.
     * Iterates through components and calls their close method.
     * Method is responsible for calling the callback in all situations.
     *
     * ATTENTION : This should not be called directly, the {@link jibo.face.ViewManager}
     * will manage when Components should close during the view process.
     * @method jibo.face.ComponentGroup#close
     * @param {Function} callback Function to be called once open is complete.
     * @param {String} [transitionType] String used to determine way Component closes,
     *        refer to ViewManager for constants used.
     * @internal
     */
    public close(callback:Function, transitionType?:string):void{

        if(this._componentList) {
            let transitionArray:Array<any> = [];
            let i:number = 0;
            let length:number = this._componentList.length;
            for(i; i<length; i++) {
                let component:Component = this._componentList[i];   // create a new pointer on each iteration, as pointer was getting overwritten within async
                transitionArray.push( function(subCallback:Function) {
                    component.close(subCallback, transitionType);
                });
            }

            if(transitionArray.length > 0) {
                async.parallel( transitionArray, function(err:Error, results:Array<any>)
                {
                    this.transitionComplete(callback, err, results);
                }.bind(this) );

            }
            else {
                this.transitionComplete(callback);
            }
        }
        else {
            // no components to close, callback immediately
            this.transitionComplete(callback);
        }
    }

    /**
     * Handler for when transitions are all complete.
     * @method jibo.face.ComponentGroup#transitionComplete
     * @param {Function} callback The callback triggered once all components have completed their transitions.
     * @param {Error} [err] Error returns if there is an issue with the asynchronous method.
     * @param {Array<any>} [results] Results returned from asynchronous method, will be empty.
     * @protected
     * @internal
     */
    protected transitionComplete(callback:Function, err?:Error, results?:Array<any>):void {
        //deal with errors, parse results
        if(err) {
            console.log('ComponentGroup :: Error during transition: error: ' + err);
            if(results){
                console.log('ComponentGroup :: Error during transition: results: ' + results.toString());
            }
        }
        callback();
    }

    //////////////////////////// ACTIONS ////////////////////////////

    /**
     * Method to bubble actions up from Components.
     * Actions pass through this method up to next ComponentGroup parent, ultimately reaching the ViewManager.
     * Passing action up through parents allows each to augment or block the action if desired.
     * @method jibo.face.ComponentGroup#actionHandler
     * @param {jibo.face.ActionData} action Contains string for type of action and data Object
     *                                      with any pertinent data dependent on action type.
     * @param {jibo.face.Component} [fromComponent] The component that triggered the action (if applicable).
     */
    public actionHandler(action:ActionData, fromComponent?:Component):void {
        this.parentGroup.actionHandler(action, fromComponent);
    }

    /**
     * Method to pass actions downward to Components.
     * Passing actions through parent chain allows parents to interrupt and augment actions.
     * @method jibo.face.ComponentGroup#actionEnactor
     * @param {jibo.face.ActionData} action Contains string for type of action and data Object
     *                                      with any pertinent data dependent on action type.
     * @return {boolean} Returns true if action is acted on by this ComponentGroup or any of its ComponentGroup children.
     */
    public actionEnactor(action:ActionData):boolean {

        // TODO :: should we block actions is inputLocked is true?  If you interrupt a transition bad stuff can happen, so for now seems safer to block
        let actionActedOn:boolean = false;
        if(!this._inputLocked) {
            if (this._componentList) {
                let component:Component;
                let length:number = this._componentList.length;
                for (let i:number = 0; i < length; i++) {
                    component = this._componentList[i];
                    if (component instanceof ComponentGroup) {
                        if(component.actionEnactor(action)){
                            actionActedOn = true;
                        }
                    }
                }
            }
        }
        return actionActedOn;
    }

    //////////////////////////// CLEAN UP ////////////////////////////

    /**
     * Destroy method, remove listeners, call destroy on child components.
     * @method jibo.face.ComponentGroup#destroy
     * @internal
     */
    public destroy():void {
        // call destroy on all children first
        if (this._componentList) {
            let length:number = this._componentList.length;
            for (let i:number = 0; i < length; i++) {
                this._componentList[i].destroy();
            }
        }
        this._container = null;
        this._componentLibrary = null;
        this._componentList = null;
        this._componentConfigs = null;
        this._updateRegistry = null;
        super.destroy();
    }
}

export default ComponentGroup;
