enum State {
    IN_PROGRESS, // activity is running, send it updates
    DONE,        // activity is done, collect return values and transition
    READY,       // ready to execute activity
    EXITED,      // fsm has exited, no further stepping allowed.
    PAUSED       // flow is paused, due to hitting an exception or is waiting for asynchronous stopping. Callbacks will set the state to ready, done, or exited as appropirate
}

export default State;