/**
 * Individual prompt within a MIM. Generated by MimConfig from the .mim file.
 * @class MimPrompt
 * @memberof jibo.mim
 * @private
 */
export default class MimPrompt {

    public id: string;
    public promptCategory: string;
    public promptSubCategory: string;
    public index: number;
    public condition: string;
    public prompt: string;
    public media: string;
    public weight: number;

    constructor(data) {
        this.id = data.prompt_id;
        this.promptCategory = data.prompt_category;
        this.promptSubCategory = data.prompt_sub_category;
        this.index = parseInt(data.index);
        this.condition = data.condition;
        this.prompt = data.prompt;
        this.media = data.media;

        if (data.weight && parseFloat(data.weight) === 0) {
            this.weight = 0; //zero is the only falsey number, so we have to handle it explicitly
        } else {
            this.weight = parseFloat(data.weight) || 1; //not all prompts will have a weight, set default to 1 for backcompatibility
        }

    }

    /**
     * Get prompt data. Returns the prompt property.
     * @method jibo.mim.MimPrompt~getPromptText
     * @returns {String} The prompt
     */
    public getPromptText():string {
        let result = this.prompt;
        return result;
    }
}
