import Shapes from './Shapes';
import Spritesheet from './Spritesheet';

const Texture = PIXI.Texture;

interface Library {
    stage:any;
    background:number;
    width:number;
    height:number;
    framerate:number;
    totalFrames:number;
    library:any;
}

/**
 * The object returned by the TimelineTask. Represents a PIXI animation.
 * @class Timeline
 * @private
 * @memberof jibo.rendering.animation
 */
class Timeline
{
    public instance:any;
    public shapes:Shapes;
    public library:Library;
    private textures:Array<string>;

    constructor()
    {
        this.textures = [];
    }

    /**
     * Adds a texture for the Timeline.
     * @method jibo.rendering.animation.Timeline#addTexture
     * @private
     * @param {PIXI.Texture} texture Texture reference.
     * @param {String} id The id name of texture in cache.
     */
    addTexture(texture:PIXI.Texture, id:string):void
    {
        Texture.addTextureToCache(texture, id);
        this.textures.push(id);
    }

    /**
     * Adds shapes to the Timeline.
     * @method jibo.rendering.animation.Timeline#addShapes
     * @private
     * @param {jibo.rendering.animation.Shapes} shapes Texture reference.
     */
    addShapes(shapes:Shapes): void
    {
        this.shapes = shapes;
    }

    /**
     * Adds spritesheet to the Timeline.
     * @method jibo.rendering.animation.Timeline#addSpritesheet
     * @private
     * @param {jibo.rendering.animation.Spritesheet} spritesheet Spritesheet reference.
     */
    addSpritesheet(spritesheet:Spritesheet): void
    {
        for(let id in spritesheet.frames)
        {
            this.addTexture(spritesheet.frames[id], id);
        }
        // Clear the spritesheet object
        spritesheet.frames = null;
    }

    /**
     * Creates the instance of the stage.
     * @method jibo.rendering.animation.Timeline#addInstance
     * @private
     */
    addInstance(): void
    {
        const instance = new this.library.stage();
        instance.framerate = this.library.framerate;
        this.instance = instance;
    }

    /**
     * Uploads all the textures and graphics to the GPU.
     * @method jibo.rendering.animation.Timeline#upload
     * @param {PIXI.WebGLRenderer} renderer Reference to face renderer.
     * @param {Function} callback Callback when complete.
     */
    upload(renderer:PIXI.WebGLRenderer, callback:any): void
    {
        PIXI.animate.utils.upload(renderer, this.instance, callback);
    }

    /**
     * Destroys Timeline object.
     * @method jibo.rendering.animation.Timeline#destroy
     */
    destroy()
    {
        this.textures.forEach((id) =>
        {
            Texture.removeTextureFromCache(id);
        });
        this.textures = null;

        if (this.shapes)
        {
            this.shapes.destroy();
            this.shapes = null;
        }

        if (this.instance) {
            if (this.instance.parent) {
                this.instance.parent.removeChild(this.instance);
            }
            this.instance.destroy(true);
            this.instance = null;
        }
        this.library = null;
    }
}

export default Timeline;
