import Runtime from '../Runtime';
import {Plugin, PluginCallback} from '../Plugin';

/**
 * Registers tasks with the loader related to rendering
 */
class RenderingPlugin implements Plugin {
    constructor() {
        // Add tasks from other modules
        const jibo:Runtime = Runtime.instance;
        jibo.loader
            .register(jibo.rendering.tasks.ColorAlphaTask, 40)
            .register(jibo.rendering.tasks.TimelineTask, 60)
            .register(jibo.rendering.tasks.ShapesTask, 70)
            .register(jibo.rendering.tasks.KeysTask, 80)
            .register(jibo.rendering.tasks.SpritesheetTask, 90)
            .register(jibo.rendering.tasks.TextureTask, 30);
    }

    init(done:PluginCallback): void {
        done();
    }
}

Runtime.registerPlugin(RenderingPlugin, 'rendering', {
    depends: ['loader'],
    electron: true
});

export default RenderingPlugin; 