import Behavior from '../Behavior';
import Status from '../Status';
import Runtime from '../../Runtime';
import PathUtils from '../../utils/PathUtils';

/**
 * @class Subtree
 * @extends jibo.bt.Behavior
 * @memberof jibo.bt.behaviors
 * @description Encapsulates an external subtree file (`.bt` file) into a single behavior. This behavior fails if the
 * `.bt` tree fails, and succeeds if that tree succeeds.
 * @param {Object} options See {@link jibo.bt.Behavior|Behavior} for all options.
 * @param {String} options.behaviorPath The path to the `.bt` file this behavior encapsulates. This assumes the root
 *                          of all `.bt` files is in `${project}/behaviors`.
 * @param {Function} options.getNotepad Returns an object that will become this referenced tree's notepad. Think of this as the
 *                              arguments to this subtree.
 * @param {Function} options.onResult Called when the external tree either fails or succeeds. A result object is passed as an argument.
 *                            This result object is populated by the external tree. Think of this as the return value.
 */
export default class Subtree extends Behavior {

    public root:any;
    private status:Status;

    constructor(options:any) {
        super(options);

        if (typeof options.behaviorPath === 'string') {
            this.behaviorPath = options.behaviorPath;
        }
        this.status = Status.INVALID;
        this.root = null;
    }

    public set behaviorPath(behaviorPath:string) {
        this.options.behaviorPath = PathUtils.setDefaultPath('behaviors', behaviorPath);
    }

    public start():boolean {
        this.status = Status.IN_PROGRESS;
        let tree;
        if(typeof this.options.behaviorPath === 'function') {
            tree = this.options.behaviorPath();
        }
        else {
            tree = PathUtils.getAssetUri(this.options.behaviorPath, this.assetPack);
        }
        this.root = Runtime.instance.bt.create(tree, {
            notepad: this.options.getNotepad(),
            blackboard: this.blackboard,
            assetPack: this.assetPack
        });
        this.status = this.root.start() ? this.status : Status.FAILED;
        return true;
    }

    public stop():Promise<void> {
        if (this.root) {
            return this.root.stop();
        }
        return Promise.resolve();
    }
    public update():Status {
        if (this.status === Status.FAILED) {
            this.root.destroy();
            this.root = null;
            return this.status;
        }
        if (!this.root) {
            return this.status;
        }
        let status:Status = this.root.update();

        if (status === Status.SUCCEEDED || status === Status.FAILED) {
            this.options.onResult(this.root.result);
            this.root.destroy();
            this.root = null;
        }
        return status;
    }
    public destroy() {
        super.destroy();
        if (this.root) {
            this.root.destroy();
            this.root = null;
        }
    }
}
