import Runtime from '../../Runtime';
import View from './views/View';
import ViewState from './ViewState';
import Component from './Component';

interface ComponentClass {
    DEFAULT_TYPE?:string;
}

/**
 * Handles creation of GUI components and views.
 * @class ComponentCreator
 * @memberof jibo.face
 * @internal
 */
class ComponentCreator
{
    /**
     * Instance used for singleton.
     * @name jibo.face.ComponentCreator._instance
     * @type {jibo.face.ComponentCreator}
     * @private
     */
    private static _instance:ComponentCreator;

    /**
     * Hash table for registered classes.
     * To be able to create Classes dynamically must first keep reference to them
     * that can later be retrieved by key value pairing.
     * @name jibo.face.ComponentCreator#_classRegistry
     * @type {any}
     * @private
     */
    private _classRegistry:any = {};

    /**
     * Default view to create if none is specified in creation methods.
     * @name jibo.face.ComponentCreator.DEFAULT_VIEW
     * @type {String}
     * @default 'View'
     * @readonly
     * @internal
     */
    private get DEFAULT_VIEW():string {return 'View';}

    /**
     * Gets singleton instance of ComponentCreator.
     * @method jibo.face.ComponentCreator#instance
     * @type {jibo.face.ComponentCreator}
     * @readonly
     * @internal
     */
    public static get instance():ComponentCreator {
        return ComponentCreator._instance;
    }

    ///////////////////////////// CONSTRUCTION /////////////////////////////

    /**
     * Constructor for ComponentCreator.
     * @internal
     */
    constructor() {
        // Check for singleton, if undefined define
        if (!ComponentCreator._instance) {
            ComponentCreator._instance = this;
        }
    }

    ///////////// VIEW CREATION /////////////

    // TODO :: This method is incomplete
    /**
     * Create a View from its class and configuration data.
     * @method jibo.face.ComponentCreator#createView
     * @param {any} [viewClass] Can be the class Object or the string name of the class (name must match class names in registry).
     * @param {any} [config] Can config as an Object or a string of the path the JSON config file.
     * @returns {jibo.face.View} Returns the View created.
     */
    public createView(viewClass?:any, config?:any):View {
        return this.createViewFromState(this.createViewState(viewClass, config));
    }

    /**
     * Creates a view from a config.
     * @method jibo.face.ComponentCreator#createViewFromConfigObject
     * @param {Object} config The configuration Object for the Component.
     * @returns {jibo.face.View} Returns the View created.
     */
    public createViewFromConfigObject(config:Object):View {

        // should be able to create view from config
        if(config) {

            // determine how and if config was sent and assign to state appropriately
            // TODO :: could we pass only a config, without specifying the View class? As long as config was already an JS object we could pull out the class name...
            const viewState:ViewState = new ViewState();
            viewState.applyConfig(config);
            return this.createViewFromState(viewState);
        }
        else {
            console.warn('WARNING :: ComponentCreator :: createViewFromConfigObject : config Object given as undefined');
            return null;    // TODO :: Fail gracefully?
        }
    }


    /**
     * Create a View from its configuration path.
     * This process requires a load, the {@link jibo.face.View} will be returned within the given callback
     * @method jibo.face.ComponentCreator#createViewFromConfigPath.
     * @param {String} configPath Path to the configuration file defining the View to create.
     * @param {Function(View)} callback Method to be called when View is created,
     *              will return the View as the first parameter
     */
    public createViewFromConfigPath(configPath:string, callback:(view:View) => any):void
    {
        // should be able to create view from config
        if(configPath)
        {
            // TODO :: how do we return View in this case?
            Runtime.instance.loader.load(configPath, (err, configResult) => {
                if (err) {
                    console.error(err.message);
                    console.error('ERROR :: ComponentCreator :: createViewFromConfigPath : error loading configuration JSON, cannot make View.');
                }
                else if(configResult)
                {
                    const view:View = this.createViewFromConfigObject(configResult);
                    callback(view);
                }
            });
        }
        else
        {
            console.error('ERROR :: ComponentCreator :: createViewFromConfigPath : config path given as undefined, cannot make View.');
        }
    }

    /**
     * Creates a {@link jibo.face.ViewState} that represent a {@link jibo.face.View}.
     * ComponentCreator keeps a registry of known View classes, which allows the classes to be constructed.
     * @method jibo.face.ComponentCreator#createViewState
     * @param {Object|String} viewClass Can be View class or string name of View class.
     * @param {Object|String} [config] Can be configuration Object or the path to JSON config file.
     * @returns {jibo.face.ViewState} Returns the created ViewState.
     */
    public createViewState(viewClass:any, config?:any):ViewState {

        let viewState:ViewState;
        // TODO :: Probably want to check for valid strings?
        if(typeof viewClass === 'string') {
            if(this._classRegistry.hasOwnProperty(viewClass)) {
                viewState = new ViewState(viewClass);
            }
            else {
                viewState = new ViewState(this.DEFAULT_VIEW);
            }
        }
        // TODO :: Really want to check to make sure this is a class that extends View...
        else if(viewClass && (typeof viewClass === 'object' || typeof viewClass === 'function')) {
            // attempt to register class, just in case someone passed a unique class
            // TODO :: Might have to keep an eye on registry for clean up, make sure it gets cleaned of unique classes when GUIManger closes a hierarchy chain...
            this.registerClass(viewClass);
            viewState = new ViewState(viewClass.name);
        }
        else {
            viewState = new ViewState(this.DEFAULT_VIEW);
        }

        // determine how an dif config was sent and assign to state appropriately
        if(typeof config === 'string') {
            // we have the path to the config, but not the config JSON itself, when do we want to load this?
            viewState.configPath = config;
        }
        if(typeof config === 'object') {
            viewState.applyConfig(config);
        }

        return viewState;
    }

    /**
     * Create a {@link jibo.face.View} from a {@link jibo.face.ViewState}.
     * @method jibo.face.ComponentCreator#createViewFromState
     * @param {jibo.face.viewState} viewState The ViewState associated with the View to create.
     * @returns {jibo.face.View} Returns the created View.
     */
    public createViewFromState(viewState:ViewState):View {
        if(viewState){
            let viewClass:any = this.getClassFromRegistry(viewState.viewClassName);
            if(viewClass !== null) {
                let view:View = new viewClass();
                view.applyState(viewState);
                return view;
            }
            else {
                console.error('ERROR :: ComponentCreator :: createViewFromState : class ' +  viewState.viewClassName +
                    ' not found in registry, make sure class is registered before trying to create it.');
                return null;
            }
        }
        else{
            console.error('ERROR :: ComponentCreator :: createViewFromState : provided viewState was null, must provide a valid ViewState');
            return null;
        }
    }

    ///////////// GUI COMPONENT CREATION /////////////

    /**
     * Create a {@link jibo.face.Component} from configuration data.
     * @method jibo.face.ComponentCreator#createComponentFromConfig
     * @param {Object} componentConfig Configuration Object for the Component, generally derived from JSON.
     * @returns {jibo.face.Component} Returns the Component defined by the configuration Object.
     */
    public createComponentFromConfig(componentConfig:any):Component {
        if (componentConfig.hasOwnProperty('type')) {
            let componentClass:any = this._classRegistry[componentConfig.type];
            if(componentClass) {
                return componentClass.createFromConfig(componentConfig);
            }
            else {
                console.warn('WARNING :: ComponentCreator :: createComponentFromConfig : invalid component type given: ' + componentConfig.type);
                return null;
            }
        }
        else {
            console.warn('WARNING :: ComponentCreator :: createComponentFromConfig : type was not specified.');
            return null;
        }
    }

    ///////////// CLASS REGISTRY /////////////

    /**
     * Register class so it can be referenced later for dynamic creation.
     * A `key` must be provided to retrieve the class, if none is provided
     * then the method looks for a `DEFAULT_TYPE` property on the class.
     * When creating a custom class it is helpful to define `DEFAULT_TYPE`.
     * This `key` is also used within the JSON configuration to specify the component Class.
     * @method jibo.face.ComponentCreator#registerClass
     * @param {any} componentClass The Class to register.  Class must be or extend {@link jibo.face.View}.
     * @param {String} [classType] If specified the given string will be used as the registry key,
     *              otherwise registry key is derived from the Class's name.
     *              classNameOverride allows for multiple registries for the same Class,
     *              which can be used for type variation within the same Class.
     * @example
     * static public static get DEFAULT_TYPE():string {return 'YourClassName';}
     */
    public registerClass(componentClass:ComponentClass, classType?:string):void {

        let classKey:string = classType;
        if(!classKey && componentClass.hasOwnProperty('DEFAULT_TYPE')){
            classKey = componentClass.DEFAULT_TYPE;
        }

        if(classKey){
            if(!this._classRegistry.hasOwnProperty(classKey)) {
                this._classRegistry[classKey] = componentClass;
            }
            else {
                console.warn('ComponentCreator :: registryClass : class was already registered for name: ' + classKey);
            }
        }else {
            console.error('Error :: ComponentCreator :: registerClass : No valid class key was given: ' + classKey +
            'Attempting to register a class without providing a key will cause a failure when attempting to retrieve/use that class later');
        }
    }

    /**
     * Unregister a class from the class registry.
     * Pass the 'key' used to register the class.
     * @method jibo.face.ComponentCreator#unregisterClass
     * @param {String} [classType] The string used to identify the class, often this is defined by the class via DEFAULT_TYPE
     */
    public unregisterClass(classType:string):void {

        if(this._classRegistry.hasOwnProperty(classType)) {
            delete this._classRegistry[classType];
        }
        else {
            console.warn('ComponentCreator :: unregisterClass : there was no class registered for name: ' + classType);
        }
    }

    /**
     * Retrieve a class from the registry.
     * @method jibo.face.ComponentCreator#getClassFromRegistry
     * @param {String} className The name of the Class to retrieve.
     * @returns {any} Returns the requested Class if found in registry.
     * @internal
     */
    public getClassFromRegistry(className:string):any {

        if(this._classRegistry.hasOwnProperty(className)) {
            return this._classRegistry[className];
        }
        else {
            console.warn('ComponentCreator :: getClassFromRegistry : no class found in registry for class name: ' + className);
            return null;
        }
    }
}

export default ComponentCreator;
