const glslify  = require('glslify');
import DOFValues from '../../DOFValues';

/**
 * Apply a glow and halo effect to a Display Object.
 *
 * @class GlowFilter
 * @extends PIXI.Filter
 * @memberof jibo.face
 */
class GlowFilter extends PIXI.Filter {

    public uniforms: any;

    public padding: number;
    public blurXFilter: PIXI.filters.BlurXFilter;
    public blurYFilter: PIXI.filters.BlurYFilter;
    public defaultFilter: PIXI.filters.VoidFilter;
    public haloDistance: number;
    public haloSpeed:number;
    public haloMaxDistance: number;
    public target:PIXI.DisplayObject;
    public enabled:boolean = false;
    private _halo:number;
    private setWithDOFS:boolean;

    constructor() {
        super(glslify('./glow.vert'), glslify('./glow.frag'), "");

        this.padding = 200;
        this.blurXFilter = new PIXI.filters.BlurXFilter();
        this.blurYFilter = new PIXI.filters.BlurYFilter();

        /**
         * Render the glow over the displayObject.
         * Can use Add (recommended), or Screen.
         * @name jibo.face.GlowFilter#blendMode
         * @type {Number}
         */
        this.blendMode = PIXI.BLEND_MODES.ADD;
        this.defaultFilter = new PIXI.filters.VoidFilter("", "", "");
        this.uniforms.center.x = 0.1;
        this.uniforms.center.y = 0.1;
        this.uniforms.haloScale = 0.8;
        this.reset();

        /**
         * Target that the glow centers on.
         * @name jibo.face.GlowFilter#target
         * @type {DisplayObject}
         */
        this.target = null;
    }

    reset(): void {
        this.amount = 0;
        this.blur = 15;
        this.blurQuality = 4;
        this.haloSpeed = 0;
        this.halo = 0;
        this.haloMaxDistance = 80;
        this.color = 0x7df9ff;
    }

    apply(filterManager, input, output) {
        const target = this.target || filterManager.filterData.stack[filterManager.filterData.index].target;

        const renderTarget = filterManager.getRenderTarget(true);
        const renderTarget2 = filterManager.getRenderTarget(true);

        //TODO - copyTexSubImage2D could be used here?
        this.defaultFilter.apply(filterManager, input, output, true);
        this.defaultFilter.apply(filterManager, input, renderTarget, true);

        this.blurXFilter.apply(filterManager, renderTarget, renderTarget2, true);
        this.blurYFilter.apply(filterManager, renderTarget2, renderTarget, true);

        this.uniforms.center.x = target.position.x;
        this.uniforms.center.y = target.position.y;

        this.uniforms.uBlurSampler = renderTarget;

        const width = target.getBounds(true).width;
        this.uniforms.haloScale = 1/((width+this.haloDistance)/(width));

        filterManager.applyFilter(this, input, output, false);

        filterManager.returnRenderTarget(renderTarget);
        filterManager.returnRenderTarget(renderTarget2);
    }

    /**
     * Set the blur amount of the glow (increases size of glow).
     *
     * @name jibo.face.GlowFilter#blur
     * @type {Number}
     * @default 15
     */
    get blur() {
        return this.blurXFilter.blur;
    }

    set blur(value) {
        this.blurXFilter.blur = this.blurYFilter.blur = value;
    }

    /**
     * Set the quality of the blur. High quality (10) will degrade performance.
     * Low quality (1) will sacrifice quality for performance.
     *
     * @name jibo.face.GlowFilter#blurQuality
     * @type {Number}
     * @default 7
     */
    set blurQuality(value) {
        this.blurXFilter.quality = value;
        this.blurYFilter.quality = value;
    }

    get blurQuality() {
        return this.blurXFilter.quality;
    }

    /**
     * Speed (in pixels per frame) halo moves outward at each update.
     * Use negative values to animate in reverse.
     * @name jibo.face.GlowFilter#haloSpeed
     * @type {Number}
     * @default 0
     */

    /**
     * Maximum distance (in pixels) that the halo can be away from the edges.
     * @name jibo.face.GlowFilter#haloMaxDistance
     * @type {Number}
     * @default 80
     */


    /**
     * Set the distance of the halo from the glow from 0 to 1. 0 makes the halo touch the glow.
     * 1 puts the halo haloMaxDistance from the edge of the glow.
     * @name jibo.face.GlowFilter#halo
     * @type {Number}
     * @default 0
     */
    get halo() {
        return this._halo;
    }
    set halo(value) {
        this._halo = value;
        this.haloDistance = value * this.haloMaxDistance;
        this.uniforms.haloStrength = Math.sin(Math.PI * (1 - value));
    }

    /**
     * Filter amount from 0 to 1.
     * 0 to apply no lighting effect. 1 to make lighting effect fully visible.
     * @name jibo.face.GlowFilter#amount
     * @type {Number}
     * @default 1.0
     */
    get amount() {
        return this.uniforms.amount;
    }

    set amount(value) {
        this.enabled = value > 0;
        this.uniforms.amount = value;
    }

    /**
     * Color of the glow in hexadecimal.
     * eg 0xFF0000
     * @type {Hexadecimal}
     * @name jibo.face.GlowFilter#color
     */
    get color() {
        return PIXI.utils.rgb2hex(this.uniforms.glowColor);
    }

    set color(value) {
        this.uniforms.glowColor = this.hex2rgba(value);
    }

    /**
     * Conversion utility to convert hex into alpha
     * @method jibo.face.GlowFilter#hex2rgba
     */
    hex2rgba(value, alpha = 1) {
        const rgba = PIXI.utils.hex2rgb(value, this.uniforms.light);
        rgba[3] = alpha;
        return Array.prototype.slice.call(rgba);
    }

    /**
     * Update of DOFValues.
     * @method jibo.face.Eye#update
     * @param {Array<Number>} timestamp Timestamp when update is called.
     * @param {String} dofValues Update display according to these values.
     */
    update(timestamp:Array<number>, dofValues:DOFValues) {

        // No default values for glow in DOFs, we should check first
        if (dofValues.glow_amount !== undefined) {
            this.setWithDOFS = true;
            this.amount = dofValues.glow_amount;
            this.blur = dofValues.glow_blur;
            this.halo = dofValues.glow_halo;
            this.haloMaxDistance = dofValues.glow_haloMaxDistance;
            this.color = dofValues.glow_redChannel << 16 |
                dofValues.glow_greenChannel << 8 |
                dofValues.glow_blueChannel;
        }
        else if (this.setWithDOFS) {
            this.setWithDOFS = false;
            this.reset();
        }
    }

    /**
     * Update the halo animation.
     * @private
     * @method jibo.face.Eye#animate
     */
    animate():void {
        if (this.haloSpeed === 0) {
            return;
        }
        let value:number = this.halo + this.haloSpeed;
        if (value > 1) {
            value = 0;
        }
        else if (value < 0) {
            value = 1;
        }
        this.halo = value;
    }
}

export default GlowFilter;
