import Behavior from '../Behavior';
import TextToSpeech from './TextToSpeech';

/**
 * @class TextToSpeechJs
 * @extends jibo.bt.Behavior
 * @memberof jibo.bt.behaviors
 * @description Makes Jibo speak.
 * @param {Object} options See {@link jibo.bt.Behavior|Behavior} for all options.
 * @param {Function} options.getWords Function that returns a string of the words for Jibo to speak.
 * @param {Function} options.onWord Called each time a word is spoken. The word that is spoken is passed as an argument.
 */
export default class TextToSpeechJs extends Behavior {
    private behavior:TextToSpeech;
    
    constructor(options) {
        super(options);
        this.behavior = new TextToSpeech({
            emitter: this.emitter,
            blackboard: this.blackboard,
            onWord: this.options.onWord,
            assetPack: this.assetPack
        });
    }

    public start() {
        this.options.getWords((words) => {
            this.behavior.words = words;
            this.behavior._start();
        });
        return true;
    }

    public stop() {
        return this.behavior._stop();
    }

    public update() {
        return this.behavior._update();
    }

    public destroy() {
        super.destroy();
        if (this.behavior) {
            this.behavior.destroy();
            this.behavior = null;
        }
    }
}
