import {EventEmitter} from 'events';
import Runtime from "../Runtime";
import async = require('async');
import {NLUResponse, REQ_STATUS, Callback} from "./gl/DataTypes";

 /**
  * Callback for initializing service. Displayed as a global member.
  * @callback jibo.nlu~Callback
  * @param {Error} Error `null` if no error.
  * @param {String} Error.exception Brief description of type of error.
  * @param {any} Error.info Further information about the error.
  * @param {Object} result Data structure using the following format:
  * ```
  * {
  *    Input: "hello my name is Joe I work in a button factory"
  *    NLParse: {
  *       who: "Joe",
  *       what: "Button factory"
  *    }
  * }
  * ```
  */


/**
 * @description
 * Natural Language Understanding
 *
 * ```
 * var nlu = require("jibo").nlu;
 * ```
 * @namespace jibo.nlu
 */
class NLUService extends EventEmitter {
    public verbose:boolean;

    private httpInterface: string;
    private loggingEnabled: boolean;
    /**
     * Mapping of uris to fst filePaths.
     * @name jibo.gl#_handleToPath
     * @type {Map<string, string>}
     * @readOnly
     */
    private _handleToPath = new Map<string, string>();
    /**
     * Mapping of uris to rule text.
     * @name jibo.gl#_handleToRule
     * @type {Map<string, string>}
     * @readOnly
     */
    private _handleToRule = new Map<string, string>();

    constructor() {
        super();
    }

    init(service, cb) {
        this.httpInterface = "http://" + service.host + ":" + service.port;
        this.loggingEnabled = false;

        Runtime.instance.gl.events.socketReopen.on((service) => {
            if(service === 'nlu') {
                this.recompileCachedRules(() => {
                    console.warn('rules recompiled.');
                });
            }
        });

        cb();
    }


    /**
     * Precompile a rule from a string.
     * @param rule {String} Rule to compile.
     * @param callback {jibo.nlu~Callback} Callback for when the rule is compiled with generated handle.
     * @param [handle] {String} Enable dynamically generated rules to be accessible
     * within parser for all rule files in skill. Ex. 'crew'.
     * @method jibo.nlu~compile
     */
    compile(rule:string, callback:Callback, handle:string) {
        if(!rule) {
            callback('Cannot compile empty rule string');
            return;
        }
        let body:any = {
            "REQ_TYPE":"COMPILE",
            "REQ_CONTENT":{
                "RULE_STRING": rule
            }
        };
        if(handle) {
            if(!handle.startsWith("handle")) {
                handle = "handle:" + handle;
            }
            body.REQ_CONTENT.URI = handle;
        }

        this._sendRequest(body, (err, response: NLUResponse) => {
            if(err) {
                callback(err);
            }
            else if(response.Status === REQ_STATUS.OK) {
                const result = response.URI || handle;
                this._handleToRule.set(result, rule);
                callback(null, result);
            }
            // Error response
            else {
                callback(response.Message);
            }
        });
    }

    /**
     * Parse text using a rule.
     * @param rule {String} Rule to use when parsing text.
     * @param text {String} The text to parse.
     * @param callback {jibo.nlu~Callback} Callback for when the parse is complete.
     * @param messageId {String} Message ID to match ASR data to NLU parsing.
     * @method jibo.nlu#parseFromRule
     */
    parseFromRule(rule:string, rawText:string, callback:Callback, messageId:string) {
        if(!rule || typeof rawText !== "string") {
            callback(`ERROR: Must provide both rule and raw text, received ${rule} and ${rawText}`);
            return;
        }
        const body = {
            "REQ_TYPE":"PARSE_FROM_TEXT",
            "REQ_CONTENT":{
                "RULE_STRING": rule,
                "TXT_STRING": rawText.toLowerCase()
            },
            "MESSAGE_ID": messageId
        };

        this._sendRequest(body, (err, response: NLUResponse) => {
            if(err) {
                callback(err);
            }
            else if(response.Status === REQ_STATUS.OK) {
                let result = response.Result.length > 0 ? response.Result[0] : {Input: rawText};
                result.Input = rawText; //use properly cased Input
                callback(null, result);
            }
            // Error response
            else {
                callback(response.Message);
            }
        });
    }

    /**
     * Parse text using a rule file.
     * @param ruleHandle {String} URI handle for precompiled rule file.
     * @param text {String} The text to parse.
     * @param callback {jibo.nlu~Callback} Callback for when the parse is complete.
     * @param messageId {String} Message ID to match ASR data to NLU parsing.
     * @method jibo.nlu#parseFromURI
     */
    parseFromURI(ruleHandle:string, rawText:string, callback:Callback, messageId:string=null) {
        if(!ruleHandle || typeof rawText !== "string") {
            callback(`ERROR: Must provide both ruleHandle and raw text, received ${ruleHandle} and ${rawText}`);
            return;
        }
        const body = {
            "REQ_TYPE":"PARSE_FROM_URI",
            "REQ_CONTENT":{
                "URI": ruleHandle,
                "TXT_STRING": rawText.toLowerCase()
            },
            "MESSAGE_ID": messageId
        };

        this._sendRequest(body, (err, response: NLUResponse) => {
            if(err) {
                callback(err);
            }
            else if(response.Status === REQ_STATUS.OK) {
                let result = response.Result.length > 0 ? response.Result[0] : {Input: rawText};
                result.Input = rawText; //use properly cased Input
                callback(null, result);
            }
            // Error response
            else {
                callback(response.Message);
            }
        });
    }

    /**
     * Unionize many uris into one uri.
     * @param uris {Array<String>} Array of URIs to unionize.
     * @param callback {jibo.nlu~Callback} Callback for when the parse is complete.
     * @param ruleHandle {String} Message ID to match ASR data to NLU parsing.
     * @method jibo.nlu#union
     */
    union(uris:string[], callback:Callback, ruleHandle:string) {
        let body:any = {
            "REQ_TYPE":"UNION",
            "REQ_CONTENT":{
                "URIS": uris
            }
        };
        if(ruleHandle) {
            body.URI = ruleHandle;
        }

        this._sendRequest(body, (err, response: NLUResponse) => {
            if(err) {
                callback(err);
            }
            else if(response.Status === REQ_STATUS.OK) {
                const result = response.URI || ruleHandle;
                callback(null, result);
            }
            // Error response
            else {
                callback(response.Message);
            }
        });
    }

    setLogging(loggingEnabled:boolean) {
        this.loggingEnabled = loggingEnabled;
    }

    /**
     * Parse text using fst file.
     * @param ruleHandle {String} URI handle for precompiled fst file.
     * @param text {String} The text to parse.
     * @param callback {jibo.nlu~Callback} Callback for when the parse is complete.
     * @param messageId {String} Message ID to match ASR data to NLU parsing.
     * @method jibo.nlu#parseFromFile
     */
    parseFromFile(fstUri:string, rawText:string, callback:Callback, messageId:string) {
        if(!fstUri || typeof rawText !== "string") {
            callback(`ERROR: Must provide valid fst URI and raw text, received ${fstUri} and ${rawText}`);
            return;
        }
        let body = {
            "REQ_TYPE":"PARSE_FROM_FILE",
            "REQ_CONTENT":{
                "URI": fstUri,
                "TXT_STRING": rawText.toLowerCase()
            },
            "MESSAGE_ID": messageId
        };

        this._sendRequest(body, (err, response: NLUResponse) => {
            if(err) {
                callback(err);
            }
            else if(response.Status === REQ_STATUS.OK) {
                let result = response.Result.length > 0 ? response.Result[0] : {Input: rawText};
                result.Input = rawText; //use properly cased Input
                callback(null, result);
            }
            // Error response
            else {
                callback(response.Message);
            }
        });
    }

    /**
     * Precompile a rule from fst file.
     * @param fstFilePath {String} Absolute path to fst file to compile.
     * @param callback {jibo.nlu~Callback} Callback for when the rule is compiled with generated handle.
     * @param [handle] {String} Enable dynamically generated rules to be accessible
     * within parser for all rule files in skill. Ex. 'crew'.
     * @method jibo.nlu#compileFromFst
     */
    compileFromFst(fstFilePath:string, callback:Callback, handle:string) {
        if(!fstFilePath) {
            callback(`ERROR: Must provide fst filepath, received ${fstFilePath}`);
            return;
        }
        if(this.verbose) {
            console.log("fst path", fstFilePath);
        }
        let body: any = {
            "REQ_TYPE": "COMPILE",
            "REQ_CONTENT": {
                "BINARYFST_PATH": fstFilePath,
            }
        };
        if (handle) {
            if (!handle.startsWith("handle")) {
                handle = "handle:" + handle;
            }
            body.REQ_CONTENT.URI = handle;
        }
        this._sendRequest(body, (err, response: NLUResponse) => {
            if (err) {
                callback(err);
            }
            else if (response.Status === REQ_STATUS.OK) {
                const result = response.URI || handle;
                // save fst path to recompile.
                this._handleToPath.set(result, fstFilePath);
                callback(null, result);
            }
            // Error response
            else {
                callback(response.Message);
            }
        });
    }

    /**
     * Remove a rule from NLU rule cache via handle URI.
     * @param uri {String} URI of rule to remove.
     * @param callback {jibo.nlu~Callback} Callback for when the rule is removed.
     * @method jibo.nlu#removeFromMemory
     */
    removeFromMemory(uri:string, callback:Callback) {
        const body = {
            "REQ_TYPE":"REMOVE_FROM_MEM",
            "REQ_CONTENT":{
                "URI": uri
            }
        };

        this._sendRequest(body, (err, response: NLUResponse) => {
            if(err) {
                callback(err);
            }
            else if(response.Status === REQ_STATUS.OK) {
                const result = response.URI || uri;

                // remove it from memory if it's cached.
                if(this._handleToPath.has(uri)) {
                    this._handleToPath.delete(uri);
                }
                else if(this._handleToRule.has(uri)) {
                    this._handleToRule.delete(uri);
                }
                callback(null, result);
            }
            // Error response
            else {
                callback(response.Message);
            }
        });
    }

    /**
     * Save an FST to a particular file to cache on disk.
     * @param uri {String} URI of rule to save
     * @param filepath {String} Path to where fst should be saved.
     * @param callback {jibo.nlu~Callback} Callback for when the rule is saved.
     * @method jibo.nlu#saveFstOnDisk
     */
    saveFstOnDisk(uri:string, filePath:string, callback:Callback) {
        const body = {
            "REQ_TYPE":"SAVE_FST_IN_DISK",
            "REQ_CONTENT":{
                "URI": uri,
                "BINARYFST_PATH": filePath
            }
        };
        this._sendRequest(body, callback);
    }

    /**
     * Reset all NLU memory -- destroys all saved and compiled rules.
     * @param callback {jibo.nlu~Callback} Callback for when memory is cleared.
     * @method jibo.nlu#resetMemory
     */
    resetMemory(callback:Callback) {
        const body = {
            "REQ_TYPE":"RESET_MEMORY",
        };
        this._sendRequest(body, (err, result) => {
            // Clear our URI cache.
            this._handleToPath = new Map<string, string>();
            this._handleToRule = new Map<string, string>();
            callback(err, result);
        });
    }

    /**
     * Clear a rule from the NLU Service.
     * @method jibo.nlu#clearCache
     * @param {String} [uri] URI to remove from cached memory -- does not remove from NLU memory.
     * If none is provided, clear all.
     */
    public clearCache(uri?:string):void {
        if (uri) {
            // remove it from memory if it's cached.
            if(this._handleToPath.has(uri)) {
                this._handleToPath.delete(uri);
            }
            else if(this._handleToRule.has(uri)) {
                this._handleToRule.delete(uri);
            }
        }
        else {
            this._handleToPath = new Map<string, string>();
        }
    }

    /**
     * Recompile all the rules we've saved so far.
     * @param callback {jibo.nlu~Callback} Callback for when rules have been recompiled.
     * @method jibo.nlu#recompileCachedRules
     */
    public recompileCachedRules(callback:Callback) {
        let tasks = [];
        // recompile each cached rule.
        this._handleToPath.forEach((fstPath, fstHandle) => {
            tasks.push( (done) => {
                this.compileFromFst(fstPath, done, fstHandle);
            });
        });
        this._handleToRule.forEach((rule, ruleHandle) => {
            tasks.push( (done) => {
                this.compile(rule, done, ruleHandle);
            });
        });
        async.parallel(tasks, callback);
    }

    /**
     * Send a request to the NLU Service
     * @param body {any} Raw object data to send as request to NLU service
     * @param callback {jibo.nlu~Callback} Callback for when memory is cleared.
     * @method jibo.nlu#_sendRequest
     * @private
     */
    private _sendRequest(body:any, callback:Callback) {
        const request = new XMLHttpRequest();
        const bodyString = JSON.stringify(body);

        request.open("POST", this.httpInterface + '/nlu_interface', true);
        request.onreadystatechange = () => {
            if(request.readyState === 4 && request.status === 200) {
                const response: NLUResponse = JSON.parse(request.response);
                if(this.loggingEnabled) {
                    console.log('request.response');
                    console.log(request.response);
                }
                if(response.Status === REQ_STATUS.OK) {
                    callback(null, response);
                }
                else if(response.Status === REQ_STATUS.ERROR) {
                    callback(response.Message);
                }

            }
            else if(request.readyState === 4 && request.status === 0) {
                callback("NLU Service is unavailable");
            }
            else if(request.readyState === 4 && request.status === 400) {
                let response = JSON.parse(request.response);
                callback(response.Message);
            }
        };
        if(this.loggingEnabled) {
            console.log("body");
            console.log(body);
        }
        request.send(bodyString);
    }
}

export default NLUService;
