import ActivityImplementation from './ActivityImplementation';
import FlowExecutor from './FlowExecutor';
import Environment from './Environment';
import Procedure from "./core/Procedure";

/**
 * A Notepad object stores each procedure's "local" variables.
 * @class Notepad
 * @memberof jibo.flow
 * @param {jibo.flow.Context} context The context that is referencing the notepad.
 * @param {any} params The input parameters to the procedure, available as 'notepad.params' in the procedure.
 * @param {jibo.flow.Environment} environment The global environment of the executing flow.
 */

class Notepad {
    public context:Context; // TODO: think about whether  we really want to expose the context to the user.
    public params:any;
    // TODO: Place the FlowEnv in the procedureConstructor so that it's global to the whole Flow
    public FlowEnv:Environment;

    /**
     * A hook so that non-Flow activities (i.e. Behaviors) can set the activity's output transition.
     * Available as 'notepad.setTransition'.
     * @param {string} transition
     */
    setTransition(transition:string):void {
        this.context.current_activity.result = transition;
    }

    constructor(context:Context, params:any, environment:Environment) {
        this.context = context;
        this.params = params;
        this.FlowEnv = environment;
    }
}

/**
 * A Result object is provided during procedure execution to
 * hold any outputs the procedure needs to return to the caller.
 * It can be filled in as needed by the procedure (e.g. "result.foo = 42").
 * The Result object is made available to the caller throw the invoking Flow.Subflow activity
 * (via the "subflow_result_object" parameter of the "getTransition" parameter).
 * A procedure's Flow.End activity will always set result.transition.
 * @class Result
 * @memberof jibo.flow
 */

class Result {
    public transition:string;

    constructor() {
        this.transition = "";
    }
}

/**
 * A Context can be thought of as the stack frame in which a Flow procedure is executing.
 * It holds the current activity pointer (the "PC") and notepad (the "local variables") for
 * an executing procedure. Whenever a procedure invokes another procedure, the
 * existing Context is pushed on the stack and a new Context is created in which the invoked procedure will execute.
 * @class Context
 * @memberof jibo.flow
 * @param {jibo.flow.FlowExecutor} flowExecutor The FlowExecutor making the procedure call.
 * @param {jibo.flow.Context} parent The context from within which the sub-procedure call is being made.
 * @param {jibo.flow.Procedure} current_procedure The procedure to be invoked.
 * @param {Object} params The parameters being passed to the new procedure.
 * @internal
 */


class Context {
    public current_activity:ActivityImplementation;
    public notepad:Notepad;
    public result:Result;
    public code:{ [key:string]:any };
    public asyncFlows:Array<FlowExecutor> = [];

    constructor(public flowExecutor:FlowExecutor,
                public parent:Context,
                public current_procedure:Procedure,
                params:any) {
        this.notepad = new Notepad(this, params, flowExecutor.environment);
        this.result = new Result();
        this.code = current_procedure.procedureConstructor(this.flowExecutor.blackboard, this.notepad, this.result, this.flowExecutor.emitter);
    }

    getActivityOptions(activityId:string, optionCodeThis:any) {
        if (!(activityId in this.code)) {
            throw new Error(`FlowExecutor: Cannot find activity ID ${activityId} in procedure ${this.current_procedure.name}`);
        }
        let codeBehind = this.code[activityId];
        let options;
        if (typeof codeBehind === 'function') {
            // Bind and evaluate the function produced for this activity by behaviorify.
            options = codeBehind.bind(optionCodeThis)().options;
        } else {
            // Copy the options if they're not being generated afresh by a function.
            options = Object.assign({}, codeBehind.options || {});
        }
        return options;
    }
}

/**
 * A snapshot of all the relevant info in an exception. This is available as `notepad.FlowEnv.lastException` after an exception occurs.
 * @class FlowExceptionInfo
 * @property {string} name - The name of the exception, e.g. "~InteractionError.noMatch"
 * @property {jibo.flow.ActivityImplementation} activity - The activity in which the exception occurred. Equivalent to `stackTrace[0].activity`.
 * @property {jibo.flow.Procedure} procedure - The procedure in which the exception occurred. Equivalent to `stackTrace[0].procedure`.
 * @property {Array} stackTrace - An array of objects corresponding to the stack at the time the exception occurred, each having a procedure and activity property. The first element in the array is the inner most frame (ie. where the exception occurred).
 * @property {any} payload - An object containing further information about the exception. This may be provided by a `Flow.Throw` activity, or in the case of JS exceptions, is the information passed via the parameter to a JS `catch()` statement.
 * @memberof jibo.flow
 */

export class FlowExceptionInfo {
    public name:string;
    public activity:ActivityImplementation;
    public procedure:Procedure;
    public stackTrace:any[];
    public payload:any;
}

export default Context;
