import {EventEmitter} from 'events';
import * as path from "path";
import Runtime from '../Runtime';
import PathUtils from "../utils/PathUtils";
import { WSClient } from 'jibo-client-framework';


/**
 * The various event types that system manager's notification system emits.
 * @alias jibo.systemManager#NotificationEvents
 * @enum {String}
 */
const NotificationEvents = {
    SHUTDOWN: 'shutdown'
    // @TODO - add any others here
};


/**
 * @class SystemManager
 * @memberof jibo.services
 * @private
 */
class SystemManager extends EventEmitter {

    constructor() {
        super();
        this.notifications = {
            type: "",           // Arbitrary string identifying the type of data associated with this notification
            channel: "",        // Notification channel name. One of: "GENERAL", "NETWORK", "POWER_MANAGEMENT", "HARDWARE_FAULT"
            ts: [0, 0],         // chronometer timestamp associated with this notification
            data: { }           // type-specific notification data
        };

        // Provide external access to these enums
        this.NotificationEvents = NotificationEvents;
    }

    static get NotificationEvents() {
        return NotificationEvents;
    }

    init(service, cb) {
        this.httpInterface = "http://" + service.host + ":" + service.port;
        this.socketUrl = "ws:" + service.host + ":" + service.port;

        this.loggingEnabled = false;

        this.getVersion( (error, currentVersion) => {
            if (error) {
                // couldn't retrieve version? hmm...
                cb(error);
                return;
            }

            const versions = Runtime.instance.versions;
            if (!versions.supported(currentVersion)) {
                cb(`Platform version check failed! Skill allows version ${versions.requiresPlatform} but your current version is ${currentVersion}.`);
            }
            else {
                // create out notification socket
                this._createNotificationSocket(cb)
            }
        });
    }

    setLogging(logging) {
        this.loggingEnabled = logging;
    }


    _createNotificationSocket(cb) {
        this.NotificationSocket = new WSClient(this.socketUrl + "/system_notifications");
        this.NotificationSocket.on('error', () => {
            console.error(`Error opening system notifications socket at ${this.socketUrl}/system_notifications`);
        });
        // Jibo WS Client sends straight data, not events.
        this.NotificationSocket.on('message', (data) => {
            try {
                this.notifications = data;
                // @TODO - check for shutdown type here
                this.emit(NotificationEvents.SHUTDOWN, this.notifications);
            }
            catch(e) {
                console.error('System notification event data is not JSON format. ', e);
            }
        });
        cb();
    }


    /**
     * getVersion - Gets current version of platform build if connected to robot (raw numbers xx.xx.xx).
     * @function jibo.systemManager#getVersion
     *
     * @param {function} cb Callback that notifies the caller that the
     *                      version was retrieved; If successful, returns version; otherwise, error string.
     **/
    getVersion(callback) {

        this.getDisplayVersion( (error, version) => {
            // parse out number
            if (version) {
                let verMatch = version.trim().match('(0|[1-9]\\d*)\\.(0|[1-9]\\d*)\\.(0|[1-9]\\d*)');
                callback(null, verMatch[0]);
            }
            else {
                callback("Could not retrieve platform version from " + version, null);
            }
        });
   }

    /**
     * getDisplayVersion - Gets current display-friendly version of platform build if connected to robot.
     * @function jibo.systemManager#getDisplayVersion
     *
     * @param {function} cb Callback that notifies the caller that the
     *                      version was retrieved; If successful, returns version; otherwise, error string.
     **/
    getDisplayVersion(callback) {
        this._handleGET("/version", "version", callback);
    }

    /**
     * getCredentials - Gets the robot's current credentials
     * @function jibo.systemManager#getCredentials
     * @param {function} callback Callback that notifies caller of the robot's current credentials (can be empty).
     *
     * @private
     **/
    getCredentials(callback) {
        this._handleGET("/credentials", undefined, callback);
    }

    /**
     * setCredentials - Sets the robot's current credentials
     * @function jibo.systemManager#setCredentials
     * @param {Object} creds Credentials JSON object.
     * @param {function} callback Callback when completed.
     *
     * @private
     **/
    setCredentials(creds, callback) {
        if(!creds) {
            callback("No credentials given");
            return;
        }

        let request = new XMLHttpRequest();
        let body = "";
        try {
            body = JSON.stringify(creds);
        }
        catch(e) {
            callback("Credentials are not valid JSON");
            return;
        }

        request.open("POST", this.httpInterface + "/credentials", true);
        request.onreadystatechange = () => {
            if(request.readyState == 4) {
                if (request.status == 204) {
                    callback(); // success!
                }
                else {
                    // failure if anything else
                    let msg = 'System Manager is unavailable';
                    if (request.statusText !== undefined && request.statusText !== "") {
                        msg = request.statusText;
                    }

                    callback(msg);
                }
            }
        };
        if(this.loggingEnabled) {
            console.log("credentials requested");
            console.log(body);
        }
        request.send(body);
    }


    /**
     * getMode - Gets the robot's current mode (identified, oobe, int-developer, developer, normal)
     * @function jibo.systemManager#getMode
     * @param {function} callback Callback that notifies caller of the current mode.
     *
     * @private
     **/
    getMode(callback) {
        this._handleGET("/mode", "mode", callback);
    }

    /**
     * setMode - Sets the robot's current mode (requires reboot to take effect). !!! Use this with extreme caution !!!
     * @function jibo.systemManager#setMode
     * @param  {String} _mode Value that represents desired mode: identified, oobe, int-developer, developer, normal
     * @param {function} callback Callback when completed.
     *
     * @private
     **/
    setMode(_mode, callback) {
        if(!_mode) {
            callback("No mode given");
            return;
        }

        let request = new XMLHttpRequest();
        let body = "";
        try {
            body = JSON.stringify(
                {
                    mode: _mode
                });
        }
        catch(e) {
            callback("Mode request is not valid JSON");
            return;
        }

        request.open("POST", this.httpInterface + "/mode", true);
        request.onreadystatechange = () => {
            if(request.readyState == 4) {
                if (request.status == 204) {
                    callback(); // success!
                }
                else {
                    // failure if anything else
                    let msg = 'System Manager is unavailable';
                    if (request.statusText !== undefined && request.statusText !== "") {
                        msg = request.statusText;
                    }

                    callback(msg);
                }
            }
        };
        if(this.loggingEnabled) {
            console.log("mode requested");
            console.log(body);
        }
        request.send(body);
    }

    /**
     * getCurrentTime - Get the current time of the robot.
     * @function jibo.systemManager#getCurrentTime
     *
     * @param {function} callback Callback when completed.
     *
     * @private
     **/
    getCurrentTime(callback) {
        this._handleGET("/time/current", "time", callback);
    }

    /**
     * syncTime - Force a synchronization of the robot's time with an NTP server.
     * @function jibo.systemManager#syncTime
     *
     * @param {function} callback Callback when completed.
     *
     * @private
     **/
    syncTime(callback) {

        let request = new XMLHttpRequest();
        request.open("POST", this.httpInterface + "/time/synchronize", true);
        request.onreadystatechange = () => {
            if(request.readyState == 4) {
                if (request.status == 204) {
                    callback(); // success!
                }
                else {
                    // failure if anything else
                    let msg = 'System Manager is unavailable';
                    if (request.statusText !== undefined && request.statusText !== "") {
                        msg = request.statusText;
                    }

                    callback(msg);
                }
            }
        };
        if(this.loggingEnabled) {
            console.log("sync time requested");
        }
        request.send();
    }

    /**
     * getTimeZone - Gets current timezone of robot.
     * @function jibo.systemManager#getTimeZone
     *
     * @param {function} callback Callback that notifies the caller what the current timezone of the robot is.
     *
     * @private
     **/
    getTimeZone(callback) {
        this._handleGET("/time/zone", "timezone", callback);
    }

    /**
     * setTimeZone - Sets current timezone of robot.
     * @function jibo.systemManager#setTimeZone
     * @param {String} zone Timezone to set the robot to (e.g. "Etc/UTC, America/New_York")
     * @param {function} callback Callback that notifies the caller that setting the timezone succeeded or failed.
     *
     * @private
     **/
    setTimeZone(zone, callback) {

        if(!zone) {
            callback("No zone given");
            return;
        }

        let request = new XMLHttpRequest();
        let body = "";
        try {
            body = JSON.stringify(
                {
                    timezone: zone
                });
        }
        catch(e) {
            callback("Timezone request is not valid JSON");
            return;
        }

        request.open("POST", this.httpInterface + "/time/zone", true);
        request.onreadystatechange = () => {
            if(request.readyState == 4) {
                if (request.status == 204) {
                    callback(); // success!
                }
                else {
                    // failure if anything else
                    let msg = 'System Manager is unavailable';
                    if (request.statusText !== undefined && request.statusText !== "") {
                        msg = request.statusText;
                    }

                    callback(msg);
                }
            }
        };
        if(this.loggingEnabled) {
            console.log("timezone requested");
            console.log(body);
        }
        request.send(body);
    }


    /**
     * checkForUpdates - Returns a current list of available platform updates.
     * @function jibo.systemManager#checkForUpdates
     *
     * @param {function} cb Callback that notifies the caller of any updates; If successful,
     *                      returns the metadata associated with each update (if any exist); otherwise, error string.
     *
     * @private
     **/
    checkForUpdates(callback) {
        this._handleGET("/update", "updates", callback);
    }


    /**
     * @private
     **/
    downloadUpdates(data, callback) {
        if (!data || !data.hasOwnProperty('ids') || data.ids.length === 0) {
            callback('No IDs given.');
            return;
        }

        let request = new XMLHttpRequest();
        request.open("PUT", this.httpInterface + "/update" , true); // true == async

        // the download callback will be a stream of update statuses (we may change this to websocket later)
        // so we have to keep track of the previous statuses that we want to parse out of the newer stream
        request.previousText = "";

        request.onreadystatechange = () => {
            if(request.readyState > 2) {
                if(request.status === 200) {

                    if (request.responseText) {

                        // strip off the last bit from the previous bit
                        let newResponse = request.responseText.substring(request.previousText.length);

                        // now make sure we have the last '{}' entry (some can be cut off at the end so some ugly
                        // parsing is necessary here)
                        let lastIdx = newResponse.lastIndexOf('}');

                        if (lastIdx !== -1) {
                            lastIdx += 1; // need the closing curly bracket
                            let firstIdx = newResponse.lastIndexOf('{', lastIdx);
                            if(firstIdx !== -1) {
                                newResponse = newResponse.substring(firstIdx, lastIdx);
                                //console.log("new response = " + newResponse);
                                let cbData = JSON.parse(newResponse);
                                //if (cbData.status === "finished") {
                                //    console.log("responseText");
                                //    console.log(request.responseText);
                                //    console.log("previousText");
                                //    console.log(request.previousText);
                                //    console.log(cbData);
                                //}
                                callback(null, cbData);

                                // save off for next time
                                request.previousText = request.responseText.substring(0, request.responseText.lastIndexOf('}') + 1);
                            }
                        }
                    }
                    else {
                        callback('No data received from OTA service', null);
                    }
                }
                else {
                    // failure if anything else
                    let msg = 'System Manager is unavailable';
                    if(request.statusText !== undefined && request.statusText !== "") {
                        msg = request.statusText;
                    }

                    callback(msg, null);
                }
            }
        };

        this.getVersion((error, version) => {
            if (error) {
                callback("Cannot retrieve platform version to check compatibility. Download aborted.", null);
            }
            else {

                let body = {};
                if (version === "0.12.1") {

                    // for build 0.12.1, we could only send one update at a time
                    body = {
                        "id": data.ids[0]
                    };
                }
                else {
                    body = {
                        "ids": data.ids
                    };
                }
                request.send(JSON.stringify(body));
            }
        });
    }

    /**
     * Installs specified update IDs on robot.
     * @method jibo.systemManager#installUpdates
     * @private
     * @param  {Object} data The update IDs to install.
     * @param {function} callback The callback when installation request has been made.
     */
    installUpdates(data, callback) {
        if (!data || !data.hasOwnProperty('ids') || data.ids.length === 0) {
            callback('No IDs given.');
            return;
        }

        let request = new XMLHttpRequest();

        request.open("POST", this.httpInterface + "/update", true);
        request.onreadystatechange = () => {
            if(request.readyState == 4) {
                if (request.status == 200) {
                    if (request.response && request.response.length > 0) {
                        // failure if response is empty or non-existent
                        let response = {};
                        try {
                            response = JSON.parse(request.response);
                        }
                        catch (e) {
                            callback(e);
                        }

                        callback(response.error);
                    }
                    else {
                        callback(); // success!
                    }
                }
            }
        };

        let body = {
            "ids": data.ids
        };

        if(this.loggingEnabled) {
            console.log("install requested");
            console.log(body);
        }

        request.send(JSON.stringify(body));
    }

    //
    // private http GET helper; assumes return status code is 200 (OK)
    _handleGET(url, property, callback) {
        let request = new XMLHttpRequest();
        request.open("GET", this.httpInterface + url, true);

        request.onreadystatechange = () => {
            if(request.readyState == 4) {
                if (request.status == 200) {
                    let response = JSON.parse(request.response);
                    let data = (property ? response[property] : response);
                    if (this.loggingEnabled) {
                        console.log(property);
                        console.log(data);
                    }
                    callback(null, data);
                }
                else {
                    // failure if anything else
                    let msg = 'System Manager is unavailable';
                    if (request.statusText !== undefined && request.statusText !== "") {
                        msg = request.statusText;
                    }

                    callback(msg, null);
                }
            }
        };

        request.send();
    }

    /**
     * getIdentity - Gets the identity of the robot if connected.
     * @function jibo.systemManager#getIdentity (object containing name, WiFi MAC address and serial number)
     *
     * @param {function} cb Callback that notifies the caller that the
     *                      identity was retrieved; If successful, returns object containing name, MAC
     *                      address and serial number; otherwise, error string.
     **/
    getIdentity(callback) {

        this._handleGET("/identity", undefined, (error, response) => {
            if (error) {
                callback("Could not retrieve identity from Jibo", null);
            }
            else {
                callback(null, {
                    "name": response.name,
                    "wifi_mac": response.wifi_mac,
                    "serial_number": response.serial_number
                });
            }
        });
    }
}

export default SystemManager;
