import TweenManager from '../../tween/TweenManager';
import FaceRenderer from '../../FaceRenderer';
import ViewManager from '../ViewManager';

/**
 * @interface PauseOptions
 * @name jibo.face.PauseOverlay#PauseOptions
 * @description Interface for pause options.
 * @prop {number} [alpha] - Alpha value for overlay when opened.  Supports values between `0` and `1`.
 * @prop {number} [duration] - Duration in milliseconds of tween, if `0` no tween is used.
 * @prop {String} [type] - Type of tween applied to alpha transition when opening and closing.
 */
export interface PauseOptions {
    alpha?: number;
    duration?: number;
    type?: string;
};

/**
 * Creates and manages overlay that displays over paused views {@link jibo.face.View}
 * @class PauseOverlay
 * @memberof jibo.face
 * @param {jibo.face.PauseOverlay#PauseOptions} [options] - Options for pause.
 * @param {number} [options.alpha] - Level of opacity for overlay.
 * @param {number} [options.duration] - Duration in milliseconds of tween.
 * @param {String} [options.type] - Type of tween applied to alpha transition.
 * @internal
 */
class PauseOverlay
{
    /**
     * Level of opacity for overlay.
     * Supports values between `0` and `1`.
     * @name jibo.face.PauseOverlay#alpha
     * @default .7
     * @type {number}
     */
    public alpha:number = .7;

    /**
     * Duration in milliseconds of tween.
     * If `0` no tween is used.
     * @name jibo.face.PauseOverlay#duration
     * @default 550
     * @type {number}
     */
    public duration:number = ViewManager.TRANS_TIME;

    /**
     * Type of tween applied to alpha transition when opening and closing.
     * @name jibo.face.PauseOverlay#type
     * @default 'sineOut'
     * @type {string}
     */
    public type:string = 'sineOut';

    /**
     * Graphic for display overlay.
     * @name jibo.face.PauseOverlay#_overlay
     * @type {PIXI.Graphics}
     * @private
     */
    private _overlay:PIXI.Graphics;

    /**
     * Flag set to `true` after open is called, reset to `false` on close.
     * @name jibo.face.PauseOverlay#_isOpen
     * @type {boolean}
     * @private
     */
    private _isOpen:boolean = false;

    constructor(options?:PauseOptions) {

        if(options){
            this.applyOptions(options);
        }
        else {
            this.applyDefaults();
        }
    }

    /**
     * Apply values from options.
     * @method jibo.face.PauseOverlay#applyOptions
     * @example
     * {
     *   "alpha": ".7",
     *   "duration": 550,
     *   "type": "sineOut",
     * }
     * @param {jibo.face.PauseOverlay#PauseOptions} options - Options for pause.
     * @param {number} [options.alpha] - Level of opacity for overlay.
     * @param {number} [options.duration] - Duration in milliseconds of tween.
     * @param {String} [options.type] - Type of tween applied to alpha transition.
     */
    public applyOptions(options:PauseOptions):void {
        if(options.hasOwnProperty('alpha')){
            this.alpha = options.alpha;
        }
        if(options.hasOwnProperty('duration')){
            this.duration = options.duration;
        }
        if(options.hasOwnProperty('type')){
            this.type = options.type;
        }
    }

    /**
     * Apply default values.
     * @method jibo.face.PauseOverlay#applyDefaults
     */
    public applyDefaults():void{
        this.alpha = .7;
        this.duration = ViewManager.TRANS_TIME;
        this.type = 'sineOut';
    }

    /**
     * Open the overlay.
     * Creates PIXI.Graphic and adds to stage.
     * @method jibo.face.PauseOverlay#open
     * @param {PIXI.Container} container - Container for the overlay, should be View's stage.
     */
    public open(container:PIXI.Container):void{

        if(!this._isOpen){
            this._isOpen = true;

            if(!this._overlay){
                this._overlay = new PIXI.Graphics();
                this._overlay.beginFill(0x000000);
                this._overlay.drawRect(0,0,FaceRenderer.WIDTH, FaceRenderer.HEIGHT);
            }
            container.addChild(this._overlay);

            if(this.duration > 0 && this.alpha > 0){
                TweenManager.stop(this._overlay);
                this._overlay.alpha = 0;
                TweenManager.play(this._overlay,
                    {
                        to: { alpha: this.alpha },
                        duration: this.duration,
                        ease: this.type
                    }
                );
            }
            else{
                this._overlay.alpha = this.alpha;
            }
        }
    }

    /**
     * Close the overlay, once closed remove overlay from display.
     * @method jibo.face.PauseOverlay#close
     */
    public close():void{

        if(this._isOpen){
            this._isOpen = false;
            if(this.duration > 0 && this._overlay.alpha !== 0){
                TweenManager.stop(this._overlay);
                TweenManager.play(this._overlay,
                    {
                        to: { alpha: 0 },
                        duration: this.duration,
                        ease: this.type
                    },
                    () => {
                        this._overlay.parent.removeChild(this._overlay);
                    }
                );
            }
            else{
                this._overlay.parent.removeChild(this._overlay);
            }
        }
    }

    /**
     * Destroy
     * @method jibo.face.PauseOverlay#destroy
     */
    public destroy():void{

        if(this._overlay){
            TweenManager.stop(this._overlay);
            if(this._overlay.parent){
                this._overlay.parent.removeChild(this._overlay);
            }
            this._overlay = null;
        }
    }
}

export default PauseOverlay;
