type BUTTON = typeof BUTTON_BASE & { colors?:string[]|string };

// shorthand to see if a value is not an Object or Array, and thus directly copyable
function isValue(value):boolean {
    if (!value) {
        return true;
    }
    const valType = typeof value;
    if (valType === 'number' || valType === 'function' || valType === 'boolean' ||
        valType === 'string') {
        return true;
    }
    return false;
}
// Does a deep merge of a generic object/array, making deep copies of any array or object properties
export function mergeDeep(target:any, source:any) {
    for (const key in source) {
        if (isValue(source[key])) {
            target[key] = source[key];
        } else {
            if (Array.isArray(source[key])) {
                target[key] = [];
            } else {
                target[key] = {};
            }
            mergeDeep(target[key], source[key]);
        }
    }
    return target;
}

// TODO: Document this - will probably refactor while building general list stuff
// - is private to MIM code
// - Generates a view config from a list of sample utterances, with some changing of button
//   graphics if utterances are specific values
export default function(sampleUtterances:string): typeof CONFIG_BASE {
    if (sampleUtterances.charAt(0) === '{') {
        return JSON.parse(sampleUtterances);
    } else {
        const utterances = sampleUtterances.split(',');
        const config:typeof CONFIG_BASE = mergeDeep({}, CONFIG_BASE);
        for (let i = 0; i < utterances.length; ++i) {
            let button:BUTTON = mergeDeep({}, BUTTON_BASE);
            button.id = button.label = button.actions[0].data.utterance = utterances[i];
            // set up some defaults for all of the yes/no responses we are using, so that
            // they look better - later this can be removed when we can have these settings in .mims
            let name = button.label.toLowerCase();
            if (name === 'yes') {
                button.colors = 'confirm';
                button.iconSrc = 'core://resources/actionIcons/ok.png';
            } else if (name === 'no') {
                button.colors = 'cancel';
                button.iconSrc = 'core://resources/actionIcons/cancel.png';
            }
            //add button to list
            config.viewConfig.list.push(button);
        }
        return config;
    }
};