/**
 * @class ListenBundle
 * @memberof jibo.mim
 * @description Internal bundle of listen specific data.
 * @private
 */
class ListenBundle {
    /**
     * Timeout duration in milliseconds. If NaN, do not timeout.
     * @name jibo.mim.ListenBundle#timeout
     * @type {Number}
     */
    public timeout: number = NaN;
    /**
     * Beginning of timeout in epoch time. Timeout is triggered when the difference between this
     * time and current time is greater than timeout.
     * @name jibo.mim.ListenBundle#startTime
     * @type {Number}
     */
    public startTime: number = NaN;
    /**
     * Listener from jibo.mim#listenDelegate.
     * @name jibo.mim.ListenBundle#listener
     * @type {any}
     */
    public listener: Listener;
}

/**
 * @class ListFeedbackAudio
 * @memberof jibo.mim
 * @description Internal manager of list feedback audio - SFX/Mim played when page changes or is at end of list.
 * @param {Object} data SFX/Mim data.
 * @param {String} data.type Either 'sfx' or 'mim'.
 * @param {String} data.data If type is 'sfx', the audio alias to play with jibo.sound. If type is 'mim', the path to the .mim file to play.
 * @param {String} assetPack Asset pack to assign to mim files.
 * @param {Function} complete Callback when SFX or Mim completes playback
 * @private
 */
class ListFeedbackAudio {
    private sound: SoundInstance;
    private announcement: Mim;
    private complete: ()=>void;

    constructor(data:{type:string, data:string}, assetPack: string, complete: ()=>void) {
        if (data.type === 'sfx') {
            this.sound = Runtime.instance.sound.play(data.data, () => {
                this.complete();
                this.destroy();
            });
        } else if (data.type === 'mim') {
            this.announcement = new Mim({
                mimPath: data.data,
                assetPack: assetPack,
                ignoreEvents: true
            });
            this.announcement.start();
            this.update = this.update.bind(this);
            Runtime.instance.timer.on('update', this.update);
        }
        this.complete = complete;
    }

    /**
     * Immediately stop playback and perform cleanup.
     * @method jibo.bt.Mim.ListFeedbackAudio#stop
     * @private
     */
    public stop() {
        if (this.sound) {
            this.sound.stop();
        }
        if (this.announcement) {
            this.announcement.stop();
            Runtime.instance.timer.removeListener('update', this.update);
        }
        this.destroy();
    }

    private update() {
        if (this.announcement) {
            const done = this.announcement.update() !== Status.IN_PROGRESS;
            if (done) {
                Runtime.instance.timer.removeListener('update', this.update);
                this.complete();
                this.destroy();
            }
        }
    }

    private destroy() {
        if (this.sound) {
            this.sound.destroy();
            this.sound = null;
        }
        if (this.announcement) {
            this.announcement.destroy();
            this.announcement = null;
        }
        this.complete = null;
    }
}

/**
 * @class MimStates
 * @memberof jibo.mim
 * @description Bundle all the Mim's state machine states, with strong typing. Each
 *              property of MimStates is a State from jibo-state-machine. All actions are performed
 *              by functions of the Mim class.
 * @private
 */
class MimStates {
    public loadConfig: State;
    public loadRule: State;
    public choosePrompt: State;
    public speak: State;
    public listen: State;
    public restartListen: State;
    public analyzeMimGlobal: State;
    public analyzeMenuGlobal: State;
    public parseSpoof: State;
    public analyzeResults: State;
    public reportResults: State;
    public handleException: State;

    constructor(sm:StateMachine) {
        this.loadConfig = new State(sm, 'Load MIM Config');
        this.loadRule = new State(sm, 'Load Rule');
        this.choosePrompt = new State(sm, 'Choose Prompt');
        this.speak = new State(sm, 'Speak');
        this.listen = new State(sm, 'Listen');
        this.restartListen = new State(sm, 'Restart Listen');
        this.analyzeMimGlobal = new State(sm, 'Analyze Mim Global');
        this.analyzeMenuGlobal = new State(sm, 'Analyze Menu Global');
        this.analyzeResults = new State(sm, 'Analyze Results');
        this.parseSpoof = new State(sm, 'Parse Spoofed Utterance');
        this.reportResults = new State(sm, 'Report Results');
        this.handleException = new State(sm, 'Handle Exception');

        this.loadConfig.addTransition(new InternalTransition('Config loaded', this.loadRule));
        this.loadConfig.addTransition(new InternalTransition('AN mim', this.choosePrompt));
        this.loadRule.addTransition(new InternalTransition('Rule loading', this.choosePrompt));
        this.loadRule.addTransition(new InternalTransition('Spoofed utterance during config', this.parseSpoof));
        this.choosePrompt.addTransition(new InternalTransition('Has prompt', this.speak));
        this.choosePrompt.addTransition(new InternalTransition('No prompt', this.listen));
        this.speak.addTransition(new InternalTransition('AN speak done', this.reportResults));
        this.speak.addTransition(new InternalTransition('OR/Q speak done', this.listen));
        this.speak.addTransition(new InternalTransition('Spoofed utterance', this.parseSpoof));
        this.listen.addTransition(new InternalTransition('Listen complete', this.analyzeResults));
        this.listen.addTransition(new InternalTransition('Mim Global', this.analyzeMimGlobal));
        this.listen.addTransition(new InternalTransition('List Global', this.analyzeMenuGlobal));
        this.listen.addTransition(new InternalTransition('Premature Timeout', this.restartListen));
        this.listen.addTransition(new InternalTransition('Spoofed utterance', this.parseSpoof));
        this.restartListen.addTransition(new TimeoutTransition('5 ms', this.listen, 5));
        this.analyzeMimGlobal.addTransition(new InternalTransition('Quick Global', this.listen));
        this.analyzeMimGlobal.addTransition(new InternalTransition('Repeat', this.choosePrompt));
        this.analyzeMimGlobal.addTransition(new InternalTransition('Irrelevant global', this.analyzeResults));
        this.analyzeMenuGlobal.addTransition(new InternalTransition('Quick Global', this.listen));
        this.analyzeMenuGlobal.addTransition(new InternalTransition('Irrelevant global', this.analyzeResults));
        this.analyzeMenuGlobal.addTransition(new InternalTransition('Spoofed utterance', this.parseSpoof));
        this.parseSpoof.addTransition(new InternalTransition('Utterance parsed', this.analyzeResults));
        this.analyzeResults.addTransition(new InternalTransition('MIM success', this.reportResults));
        this.analyzeResults.addTransition(new InternalTransition('Another try', this.choosePrompt));
        this.analyzeResults.addTransition(new InternalTransition('Ignore NM', this.listen));
        this.reportResults.addTransition(new InternalTransition('NM/NI exception', this.handleException));
        this.handleException.addTransition(new InternalTransition('Exception solved', this.choosePrompt));
    }
}

export type MimResults = {
    asrResults: AsrResult;
    state: MimState;
};

/**
 * Return prompt data for MIM. Properties are used as variables
 * for MIM condition evaluation and prompt text insertion.
 * @callback jibo.bt.behaviors.Mim~GetPromptData
 * @returns {any}
 */
type GetPromptData = () => any;

/**
 * Called on incremental listen updates during  Optional Response or Question.
 * @callback jibo.bt.behaviors.Mim~OnStatus
 * @param {any} results Bundles data from MIM.
 * @param {jibo.mim.AsrResult} results.asrResults Data from  NLU service.
 * @param {jibo.mim.SpeakerIds} results.speakerIds If available, the ID of the speaker.
 * @param {jibo.mim.MimState} results.state Current state of the MIM.
 */
type OnStatus = (results:MimResults) => void;

/**
 * Called when an Optional Response or Question MIM completes successfully.
 * Optional Response MIMs always complete;
 * check `options.state.lastResultState` to see if  user responded.
 * @callback jibo.bt.behaviors.Mim~OnSuccess
 * @param {any} results Bundles data from MIM.
 * @param {jibo.mim.AsrResult} results.asrResults Data from NLU service.
 * @param {jibo.mim.SpeakerIds} results.speakerIds If available, the ID of the speaker.
 * @param {jibo.mim.MimState} results.state Current state of the MIM.
 * @param {String} results.firstGrammarTag (Flow use only) The value of the first rule slot (results.asrResults.NLParse[results.asrResults.slotActions[0]]). The default transition from a MIM. If a listen has multiple potential slots, this value should not be considered reliable.
 */
type OnSuccess = (results:MimResults & {firstGrammarTag?:string}) => void;

/**
 * (Flow use only) Called when a Question MIM fails entirely. Either the user did not
 * respond to Jibo or Jibo could not understand the user and has run out of error prompts.
 * Return value finds an error handler within the flow. Unhandled
 * errors use Jibo's standard MIM exception handling.
 * @callback jibo.bt.behaviors.Mim~OnFailure
 * @param {any} results Bundles data from MIM.
 * @param {jibo.mim.AsrResult} results.asrResults Data from  NLU service.
 * @param {jibo.mim.SpeakerIds} results.speakerIds If available, the ID of the speaker.
 * @param {jibo.mim.MimState} results.state Current state of the MIM.
 * @param {String} results.exception Exception for this failure; either `~InteractionError.noMatch` or `~InteractionError.noInput`.
 */
type OnFailure = (results:MimResults & {exception?:string}) => boolean;

/**
 * (Internal to Menu behavior only) Called to confirm that a positional selection makes sense, allowing custom handling to select certain types of items, if desired.
 * @callback jibo.bt.behaviors.Mim~OnPositionalSelect
 * @param {jibo.mim.AsrResult} commandASR Data from  NLU service.
 * @param {Number} intendedIndex Index that the menu plans to use for selection.
 * @param {jibo.face.MenuView} menu Created menu. Use to read button data, if you didn't keep track of it yourself.
 * @returns {number} Return an item index to change what will be selected, or null to select nothing. Returning undefined will use the default behavior (selecting intendedIndex).
 * @private
 */
type OnPositionalSelect = (commandASR:AsrResult, intendedIndex:number, menu:MenuView) => number;
// endregion support classes

const MIM_RULE_NAME = 'mimglobals';
const MIM_RULE_HANDLE = 'handle:mimglobals';

/**
 * @class Mim
 * @extends jibo.bt.Behavior
 * @memberof jibo.bt.behaviors
 * @description Perform a dialogue interaction. Can be an announcement, an
 *              announcement with optional user response, or a
 *              question and attempt to get answer from the user.
 * @param {Object} options See {@link jibo.bt.Behavior|Behavior} for all options.
 * @param {String} options.mimPath Path to the MIM file to use.
 * @param {jibo.bt.behaviors.Mim~GetPromptData} options.getPromptData Returns the prompt variable data.
 * @param {jibo.bt.behaviors.Mim~OnStatus} options.onStatus Called and passed data about what the Mim is hearing when it receives incremental updates from the listener. Optional Response and Question MIMs only.
 * @param {jibo.bt.behaviors.Mim~OnSuccess} options.onSuccess Called and passed data about what the Mim heard when it completes. Optional Response and Question MIMs only.
 * @param {jibo.bt.behaviors.Mim~OnFailure} options.onFailure Called and passed data about what the Mim heard or did not hear when it completes. Question MIMs only.
 */
export default class Mim extends Behavior {
    private static globalRulePromise:Promise<string>;
    //active view - could be GUI or noMatch exception display
    //is public so that Menu can make use of it
    public activeView:View;
    //promise to destroy active view - sometimes we need to make sure it is gone before we continue
    //is public so that Menu can make use of it, because view cleanup is asynchronous and
    //complicated
    public destroyViewPromise:Promise<any>;
    //How the view should be transitioned out
    public viewTransition:'leave'|ChangeOptions;
    //path to mim - behavior argument
    private mimPath: string;
    //prompt data for conditon eval and string replacement - returned by behavior argument func
    private promptData: any;
    //incremental update callback - behavior argument
    private onStatus: OnStatus;
    //question exception callback - behavior argument
    private onFailure: OnFailure;
    //OR/Q success callback - behavior argument
    private onSuccess: OnSuccess;
    //menu only callback - behavior argument
    private onPositionalSelect: OnPositionalSelect;
    //tracks overall state of mim, passed to callbacks
    private mimState: MimState;
    //prompt that played on first entrance of mim - used when repeating
    private entryPrompt: string;
    //number of times user has requested Jibo repeat himself
    private repeatCount: number;
    //config (.mim file)
    private mimConfig: MimConfig;
    //rule filename/path from mim config
    private ruleFileName: string;
    //behavior status
    private status: Status;
    //promise to compile the mim specific rule
    private rulePromise: Promise<string>;
    //handle of mim specific rule from ruleFileName
    private ruleHandle: string;
    //promise to combine ruleHandle and mim global rule
    private combinedRulePromise: Promise<string[]>;
    //handle of combined rule - this will actually be used for the listen
    private combinedRuleHandle: string;
    //most recent asr results - passed to callbacks
    private asrResults: AsrResult;
    //flow used for global exceptions, if the containing flow did not handle it
    private exceptionFlow:FlowExecutor;
    private mimMachine: StateMachine;
    private states: MimStates;
    private queuedState: {state:State, data?:any};
    // The bundle of variables used for managing a listen
    private listen: ListenBundle;
    //SFX or Mim played as list feedback
    private listAudio: ListFeedbackAudio;
    //If the Mim GUI should be retained as long as possible before removal
    private retainView:Boolean = false;
    //taking the place of a disposable pattern
    private viewEvents:{[event:string]:Function};
    //for attaching metadata to ASR logs
    private asrMetadata:any;

    constructor(options) {
        super(options);
        //ensure that default list audio is available and Repeat mims are available
        MimManager.instance.loadMimAssets();

        this.retainView = !!options.retainView;
        this.viewTransition = {
            remove: true,
            transitionClose: ViewManager.TRANS_DOWN
        };
        this.mimPath = options.mimPath;
        this.promptData = options.getPromptData ? options.getPromptData() : null;
        //secret internal capability - dynamically generate a mim config and pass it in
        if (options.mimConfig) {
            this.mimConfig = new MimConfig();
            this.mimConfig.initWithJSON(options.mimConfig);
        }
        this.asrMetadata = options.asrMetadata;
        //with current usage, only the Menu behavior will pass mim configs in directly
        if (this.mimConfig) {
            if (!this.asrMetadata) {
                this.asrMetadata = {};
            }
            //set up some basic information about the menu
            this.asrMetadata.mimType = 'menu';
            this.asrMetadata.mimId = 'menu:' + this.mimConfig.guiConfig.viewConfig.id;
        }

        this.onStatus = options.onStatus;
        this.onFailure = options.onFailure;
        this.onSuccess = options.onSuccess || options.onResults;
        this.onPositionalSelect = options.onPositionalSelect;
        this.status = Status.INVALID;

        this.mimState = new MimState();
        this.entryPrompt = null;
        this.repeatCount = 0;
        //initialize the state machine
        this.mimMachine = new StateMachine();
        const states = this.states = new MimStates(this.mimMachine);

        states.loadConfig.onEntry = this.loadMim.bind(this);
        states.loadRule.onEntry = this.loadRule.bind(this);
        states.choosePrompt.onEntry = this.choosePrompt.bind(this);
        states.speak.onEntry = this.speak.bind(this);
        states.speak.onStop = this.stopSpeaking.bind(this);
        states.listen.onEntry = this.startListen.bind(this);
        states.listen.onUpdate = this.updateListen.bind(this);
        states.listen.onStop = this.stopListen.bind(this);
        states.listen.onExit = this.listenExit.bind(this);
        states.analyzeMimGlobal.onEntry = this.analyzeMimGlobal.bind(this);
        states.analyzeMenuGlobal.onEntry = this.analyzeMenuGlobal.bind(this);
        states.analyzeResults.onEntry = this.analyzeResults.bind(this);
        states.parseSpoof.onEntry = this.parseSpoofedUtterance.bind(this);
        states.reportResults.onEntry = this.reportResults.bind(this);
        states.handleException.onEntry = this.handleException.bind(this);
        states.handleException.onUpdate = this.updateException.bind(this);
        states.handleException.onStop = this.stopException.bind(this);

        this.resetTimeout = this.resetTimeout.bind(this);

        //ensure that the global rules are loaded
        if (!Mim.globalRulePromise) {
            Mim.globalRulePromise = new Promise((resolve, reject) => {
                const fstPath = PathUtils.getAssetUri('core://rules/mimGlobal.fst');
                Runtime.instance.nlu.compileFromFst(fstPath, (err, handle:string) => {
                    if (err) {
                        console.error(err);
                        reject(err);
                        return;
                    }
                    resolve(handle);
                }, MIM_RULE_NAME);
            });
        }
        Runtime.instance.logger.info("Mim Variable Assignments: " + JSON.stringify(this.promptData));
        
        this.onEndEvent = this.onEndEvent.bind(this);
        this.onSpeechEvent = this.onSpeechEvent.bind(this);
        this.onOpenGUIEvent = this.onOpenGUIEvent.bind(this);
    }

    public start():boolean {
        this.status = Status.IN_PROGRESS;
        this.mimMachine.start();
        //only AN MIMs used for list end audio should ignore events
        if (!this.options.ignoreEvents) {
            MimManager.instance.openGUI.on(this.onOpenGUIEvent);
            MimManager.instance.handleSpeech.on(this.onSpeechEvent);
            MimManager.instance.end.on(this.onEndEvent);
        }
        return true;
    }

    public stop():Promise<void> {
        this.cleanUpEvents();
        // be really sure that if we have a view active, it gets removed
        this.removeView();
        this.mimMachine.stop();
        //clear the current state to prevent any future calls to .stop() from messing with
        //the states -PR to JSM to do this in stop itself
        this.mimMachine.current = null;
        this.unloadRules();
        this.status = Status.INVALID;
        //make sure that we haven't orphaned a listen mode
        const listenDelegate = MimManager.instance.listenDelegate;
        listenDelegate.setMode(MimManager.instance.ListenMode.NORMAL);
        
        return this.destroyViewPromise || Promise.resolve();
    }

    public update():Status {
        if (this.status !== Status.IN_PROGRESS) {
            return this.status;
        }

        this.mimMachine.update();
        return this.status;
    }

    public destroy() {
        //a destroyed behavior's status is super duper invalid
        this.status = Status.INVALID;
        super.destroy();
        // unload the rules we loaded, to be good manager of memory
        this.unloadRules();
        this.cleanUpEvents();
        // be really sure that if we have a view active, it gets removed
        this.removeView();
        this.mimMachine.stop();
        // null some reference variables
        this.mimMachine = null;
        this.mimState = null;
        this.onStatus = null;
        this.onFailure = null;
        this.onSuccess = null;
        this.destroyViewPromise = null;
    }

    // region cleanup
    /**
     * If this Mim has an active view, pops the top view from the list and destroys this Mim's
     * active view.
     * @method jibo.bt.Mim#removeView
     * @private
     * @param {string} intent Reason for removing the view - 'success', 'failure', or null if view should never be left blank.
     */
    public removeView() {
        if (this.activeView) {
            const activeView = this.activeView;
            const views = Runtime.instance.face.views;
            if (views.currentView === activeView) {
                if (this.viewEvents) {
                    for (const evType in this.viewEvents) {
                        activeView.removeListener(evType, this.viewEvents[evType]);
                    }
                }
                if (this.viewTransition === 'remain') {
                    //leave the active view in place
                    activeView.inputLocked = true;
                    this.activeView = null;
                    return;
                } else {
                    this.destroyViewPromise = new Promise((resolve, reject) => {
                        Runtime.instance.face.views.changeView(
                            this.viewTransition,
                            () => {
                            //removeView destroys view
                            resolve();
                            this.destroyViewPromise = null;
                        });
                    });
                }
            }
            this.activeView = null;
        }
    }

    /**
     * Remove combinedRuleHandle and ruleHandle from NLU memory.
     * @method jibo.bt.Mim#unloadRules
     * @private
     */
    private unloadRules() {
        if (this.combinedRuleHandle && this.combinedRuleHandle !== MIM_RULE_HANDLE) {
            Runtime.instance.nlu.removeFromMemory(this.combinedRuleHandle, ()=>{/*noop*/});
        }
        this.combinedRuleHandle = null;
        if (this.ruleHandle && /^handle:\d+$/.test(this.ruleHandle)) {
            Runtime.instance.nlu.removeFromMemory(this.ruleHandle, ()=>{/*noop*/});
            this.ruleHandle = null;
        }
        this.combinedRulePromise = null;
    }
    
    /**
     * Cleans up global event listeners that the MIM added.
     * @method jibo.bt.Mim#cleanUpEvents
     * @private
     */
    private cleanUpEvents() {
        MimManager.instance.openGUI.removeListener(this.onOpenGUIEvent);
        MimManager.instance.handleSpeech.removeListener(this.onSpeechEvent);
        MimManager.instance.end.removeListener(this.onEndEvent);
    }
    // endregion cleanup
    
    /**
     * Opens the MIM's GUI if it is not already open.
     * @method jibo.bt.Mim#openGUI
     * @private
     */
    private openGUI() {
        if (this.activeView) {
            return;
        }
        const mimConfig = this.mimConfig;
        const views = Runtime.instance.face.views;
        let config:typeof CONFIG_BASE;
        if (mimConfig.guiConfig) {
            config = mimConfig.guiConfig;
        } else {
            config = GenerateListConfig(mimConfig.sampleUtterances);
            //if parent is eye view, remove it, otherwise pause parent view
            if (views.currentView && views.currentView.type !== EyeView.DEFAULT_TYPE) {
                config.viewConfig.pauseParent = true;
            }
        }

        //if the current view is the view we want, then it will be wierd to make it go away
        //and immediately make it come back
        //TODO: Figure out if we can modify this - potentially a pain
        if (views.currentView && views.currentView.id === config.viewConfig.id) {
            this.activeView = views.currentView;
        } else {
            this.activeView = views.createView(config.viewConfig.type || 'MenuView', config);
            if (this.activeView){
              this.activeView.once("screenTap", ()=>{
                Runtime.instance.logger.info("Screen Tapped ListenTries: " + this.mimState.tries +  " LastResultState: " + this.mimState.lastResultState);
              });
            }
            //if the view already existed in the stack, then kill it
            const open:any = config.open || {};
            if (views.hasView(this.activeView.id)) {
                open.removeToInclude = this.activeView.id;
            }
            open.addView = this.activeView;
            views.changeView(open, () => {
                //view opened, no op
            }, () => {
                //view failed to open, we should stop
                this.stop();
                this.status = Status.FAILED;
            });
        }
        //listeners for SFX/other feedback
        if (config.events) {
            this.viewEvents = {};
            for (const evType in config.events) {
                this.viewEvents[evType] = this.onListEvent.bind(this, config.events[evType]);
                this.activeView.on(evType, this.viewEvents[evType]);
            }
        }
    }
    
    /**
     * Callback for events from `jibo.mim.openGUI`. Opens the GUI, if it is not already open.
     * @method jibo.bt.Mim#onOpenGUIEvent
     * @private
     */
    private onOpenGUIEvent() {
        if (this.status !== Status.IN_PROGRESS) {
            return;
        }
        const current = this.mimMachine.current;
        const states = this.states;
        //don't open the GUI if we haven't loaded the mim config file yet - we don't know what the
        //gui is
        if (current !== states.loadConfig) {
            this.openGUI();
        }
    }
    
    /**
     * Callback for events from `jibo.mim.handleSpeech`. Stops active speech or listen to parse a
     * spoofed utterance.
     * @method jibo.bt.Mim#onSpeechEvent
     * @param {string} utterance The spoofed utterance in need of parsing.
     * @private
     */
    private onSpeechEvent(utterance:string) {
        if (this.status !== Status.IN_PROGRESS) {
            return;
        }
        const current = this.mimMachine.current;
        const states = this.states;
        //only allow this event during asynchronous states, as we have to
        //make transitions for all of them
        if (current === states.speak || current === states.listen ||
            current === states.analyzeMenuGlobal) {
            //do a standard NL parse of data
            current.transitionTo(states.parseSpoof, utterance);
        } else if (current === states.loadConfig) {
            //if we are loading the config, then queue up parsing as soon as we have started loading
            //the rule
            this.queuedState = {state:states.parseSpoof, data:utterance};
        }
    }
    
    /**
     * Callback for events from `jibo.mim.end`. Ends the MIM immediately.
     * @method jibo.bt.Mim#onEndEvent
     * @param {any} data Not currently used. In the future, data about how the MIM should end.
     * @private
     */
    private onEndEvent(data:any) {
        if (this.status !== Status.IN_PROGRESS) {
            return;
        }
        const current = this.mimMachine.current;
        const states = this.states;
        //only allow this event during asynchronous states, as we have to
        //make transitions for all of them
        if (current === states.speak || current === states.listen ||
            current === states.loadConfig || current === states.analyzeMenuGlobal) {
            if (!data) {
                //just say that we succeeded
                //in flows, this should cause the flow transition to be nothing, so only a
                //default transition will catch it
                this.stop();
                this.status = Status.SUCCEEDED;
            } else {
                //TODO: Consider handing this in some other way,
                //perhaps using the data to handle a success
            }
        }
    }

    // region file management
    /**
     * State entry for states.loadConfig. Load .mim file(s) and then go to states.loadRule for OR/Q
     * mims or states.choosePrompt for AN mims.
     * @method jibo.bt.Mim#loadMim
     * @private
     */
    private loadMim(transition:Transition, result:any): void {
        if (this.mimConfig) {
            if (this.mimConfig.mimType === MimTypes.ANNOUNCEMENT) {
                this.states.loadConfig.transitionTo(this.states.choosePrompt);
            } else {
                this.states.loadConfig.transitionTo(this.states.loadRule);
            }
            return;
        }
        const assetPack = this.assetPack;
        MimConfig.load(PathUtils.getAssetUri(this.mimPath, assetPack))
            .then((result:MimConfig) => {
                //after async, bail if behavior is stopped or destroyed
                if (this.status !== Status.IN_PROGRESS) {
                    return;
                }
                //check for errors
                if (!(result instanceof MimConfig)) {
                    console.error(`Error: Cannot load Mim File for ${this.mimPath}!`);
                    console.error(result);
                    this.status = Status.FAILED;
                    return;
                }
                this.mimConfig = result;
                //set up mim specific metadata
                if (!this.asrMetadata) {
                    this.asrMetadata = {};
                }
                this.asrMetadata.mimType = this.mimConfig.mimType;
                this.asrMetadata.mimId = this.mimConfig.mimId;
                if (this.mimConfig.mimType === MimTypes.ANNOUNCEMENT) {
                    this.states.loadConfig.transitionTo(this.states.choosePrompt);
                } else {
                    this.states.loadConfig.transitionTo(this.states.loadRule);
                }
            },
            reason => {
                console.error('Failure to load mim config: ', reason);
                this.status = Status.FAILED;
            });
    }

    /**
     * State entry for states.loadRule. Load .mim file(s) and then go to states.loadRule for OR/Q
     * mims or states.choosePrompt for AN mims. Sets up loading of rule for mim and unionizing it
     * with mim global rule as a Promise. Immediately go to states.choosePrompt.
     * @method jibo.bt.Mim#loadRule
     * @private
     */
    private loadRule(transition:Transition, result:any): void {
        const mimConfig = this.mimConfig;
        const ruleName = mimConfig.ruleName;
        // Allow for no mim rule - just use mim global
        if (!ruleName) {
            this.states.loadRule.transitionTo(this.states.choosePrompt);
            return;
        }
        if (FactoryRules[ruleName]) {
            this.rulePromise = new Promise((resolve, reject) => {
                Runtime.instance.nlu.compile(FactoryRules[ruleName], (err, handle:string) => {
                    if (err) {
                        console.error(err);
                        reject(err);
                        return;
                    }
                    this.ruleHandle = handle;
                    resolve(handle);
                }, undefined);
            });
        } else {
            //load rule
            this.ruleFileName = PathUtils.getAssetUri(mimConfig.ruleName, this.assetPack);
            //start preloading the rule with a promise - we'll wait for the promise when we actually
            //need to listen, but we can let it load while speaking goes on
            const ext = path.extname(this.ruleFileName);
            if (ext === '.fst') {
                this.rulePromise = new Promise((resolve, reject) => {
                    Runtime.instance.nlu.compileFromFst(this.ruleFileName, (err, handle:string) => {
                        if (err) {
                            console.error(err);
                            reject(err);
                            return;
                        }
                        this.ruleHandle = handle;
                        resolve(handle);
                    }, undefined);
                });
            } else if (ext === '.rule') {
                this.rulePromise = new Promise((resolve, reject) => {
                    fs.readFile(this.ruleFileName, undefined, (err, text:string) => {
                        if (err || !text) {
                            reject(err || `No rule file content for ${this.ruleFileName}`);
                            return;
                        }
                        Runtime.instance.nlu.compile(text, (err, handle:string) => {
                            if (err) {
                                console.error(err);
                                reject(err);
                                return;
                            }
                            this.ruleHandle = handle;
                            resolve(handle);
                        }, undefined);
                    });
                });
            } else {
                this.rulePromise = <any>Promise.reject(`Invalid rule path: ${this.ruleFileName}`);
            }
        }
        this.combinedRulePromise = Promise.all([Mim.globalRulePromise, this.rulePromise])
            .then((results) => {
                return new Promise((resolve, reject) => {
                    Runtime.instance.nlu.union(results, (err, handle:string) => {
                        if (err) {
                            //console.error(err);
                            reject(err);
                            return;
                        }
                        this.combinedRuleHandle = handle;
                        //if MIM has been stopped, unload rules and leave the promise hanging
                        if (this.status !== Status.IN_PROGRESS) {
                            this.unloadRules();
                            return;
                        }
                        resolve(handle);
                    }, undefined);
                });
            });
        //if we got an event during the config loading, then we handle the queued state here
        if (this.queuedState) {
            this.states.loadRule.transitionTo(this.queuedState.state, this.queuedState.data);
        } else {
            //transition on to prompt speaking
            this.states.loadRule.transitionTo(this.states.choosePrompt);
        }
    }
    // endregion file management

    /**
     * State entry for states.choosePrompt. Choose prompt text to be played. Go to states.listen
     * if no prompt or silent prompt chosen. Go to states.speak to speak the prompt.
     * @method jibo.bt.Mim#choosePrompt
     * @private
     */
    private choosePrompt(transition:Transition, result:any): void {
        const mimState = this.mimState;
        const mimConfig = this.mimConfig;
        //show the GUI if appropriate - this state gets hit even if no prompt is actually played
        //so this will always show the GUI as early as possible
        if (mimConfig.hasGui && mimState.noMatchCount >= mimConfig.numTriesForGUI) {
            this.openGUI();
        }
        
        let promptText = '';
        const lastResultState = mimState.lastResultState;
        if (lastResultState === 'repeat') {
            const repeat = MimManager.instance.repeat.getRepeat(mimConfig.mimType, this.repeatCount);
            if (repeat.prompt) {
                promptText = repeat.prompt;
            }
            if (repeat.action === 'verbose' && mimConfig.hasVerbosePrompt()) {
                mimState.lastResultState = 'verbose';
                promptText += mimConfig.getPromptText(mimState, this.promptData);
            } else if (repeat.action !== 'exit') {
                promptText += this.entryPrompt;
            }
            this.mimState.promptText = promptText.trim();
        } else {
            promptText = mimConfig.getPromptText(mimState, this.promptData);
            this.mimState.promptText = promptText = promptText.trim();
            //save the prompt we enter with in case user requests Jibo repeat what he said
            if (lastResultState === 'entry' && this.entryPrompt === null) {
                this.entryPrompt = this.mimState.promptText;
            }
        }
        if (promptText) {
            this.states.choosePrompt.transitionTo(this.states.speak);
        } else {
            if (this.mimConfig.mimType === MimTypes.ANNOUNCEMENT) {
                this.states.speak.transitionTo(this.states.reportResults);
            } else {
                this.states.choosePrompt.transitionTo(this.states.listen, true);
            }
        }
    }

    // region speaking
    /**
     * State entry for states.speak. Speaks the chosen prompt through the TTS system. When finished,
     * goes to states.reportResults for an AN mim or states.listen for an OR/Q mim.
     * @method jibo.bt.Mim#speak
     * @private
     */
    private speak(transition:Transition, result:any) {
        const text = this.mimState.promptText;
        const options = {
            text: text,
            disableAutoRules: !this.mimConfig.esAutoTagging,
            followedByListen: this.mimConfig.mimType !== MimTypes.ANNOUNCEMENT
        };
        const mimStart = Date.now();
        Runtime.instance.logger.info("Starting Mim [" + this.mimConfig.mimType + "]" + this.mimConfig.mimId + " Prompt: \"" + text + "\"");
        MimManager.instance.speakDelegate.speak(options)
            .then(() => {
                //after async, bail if behavior is stopped or destroyed
                if (this.status !== Status.IN_PROGRESS) {
                    return;
                }
                const mimDuration = Date.now() - mimStart;
                Runtime.instance.logger.info("Ending Mim [" + this.mimConfig.mimType + "]" + this.mimConfig.mimId + " Duration: " + mimDuration + "ms");
                //if we hit the maximum number of repeats, then just quit
                if (this.repeatCount >= MimManager.instance.repeat.maxRepeat) {
                    Runtime.instance.lifecycle.finished();
                    return;
                }
                //otherwise, go on to the appropriate state
                if (this.mimConfig.mimType === MimTypes.ANNOUNCEMENT) {
                    this.states.speak.transitionTo(this.states.reportResults);
                } else {
                    this.states.speak.transitionTo(this.states.listen, true);
                }
            })
            .catch(e => {
                console.warn('Error when speaking:', e);
                //after async, bail if behavior is stopped or destroyed
                if (this.status !== Status.IN_PROGRESS) {
                    return;
                }
                if (this.mimMachine.current === this.states.speak) {
                    if (this.mimConfig.mimType === MimTypes.ANNOUNCEMENT) {
                        this.states.speak.transitionTo(this.states.reportResults);
                    } else {
                        this.states.speak.transitionTo(this.states.listen, true);
                    }
                }
            });
    }

    /**
     * State interuption for states.speak. Stops jibo.mim#speakDelegate playback.
     * @method jibo.bt.Mim#stopSpeaking
     * @private
     */
    private stopSpeaking() {
        MimManager.instance.speakDelegate.stop();
    }
    // endregion speaking

    // region listening
    /**
     * State entry for states.listen. Starts a listener from jibo.mim#listenDelegate.
     * If appropriate, starts timeout. If appropriate, displays the mim GUI. When listen completes,
     * transitions to states.analyzeResults for mim results or states.analyzeMimGlobal for mim
     * global commands.
     * @method jibo.bt.Mim#startListen
     * @private
     */
    private startListen(transition:Transition, resetTimeout:boolean) {
        //if this is somehow called after the behavior is destroyed, just bail out
        if (this.status !== Status.IN_PROGRESS) {
            return;
        }
        //ensure that combined rule is loaded
        //if combined rule was never started, mim did not provide a rule
        //so just use the global, which we will assume was loaded
        if (!this.combinedRuleHandle && this.combinedRulePromise) {
            //otherwise, make sure that global and mim rules get combined
            //then use that combined rule
            this.combinedRulePromise.then(() => {
                //if MIM was destroyed before rule loaded, clean up the rules
                //and don't continue
                if (this.status !== Status.IN_PROGRESS) {
                    this.unloadRules();
                    return;
                }
                this.startListen(transition, resetTimeout);
            }).catch((err) => {
                if (this.status !== Status.IN_PROGRESS) {
                    this.unloadRules();
                    return;
                }
                console.error('Unable to get combined rule!', err);
                this.combinedRuleHandle = this.ruleHandle || MIM_RULE_HANDLE;
                this.startListen(transition, resetTimeout);
            });
            return;
        }
        let listen = this.listen;
        if (resetTimeout || !listen) {
            listen = this.listen = new ListenBundle();
            listen.startTime = Date.now();
        }
        const mimConfig = this.mimConfig;
        //timeouts don't run in the simulator unless you tell them to
        const ignoreSimulator = mimConfig.mimType === MimTypes.OPTIONAL_RESPONSE || MimManager.instance.timeoutIgnoresSimulator;
        const jibo = Runtime.instance;
        const onRobot:boolean = jibo.runMode === jibo.RunMode.ON_ROBOT || jibo.runMode === jibo.RunMode.REMOTELY || jibo.runMode === jibo.RunMode.UNIT_TESTS;
        if (mimConfig.timeout > 0 && (onRobot || ignoreSimulator)) {
            listen.timeout = mimConfig.timeout * 1000;
        }

        //listeners for interaction to cancel timeout
        window.addEventListener('touchstart', this.resetTimeout);
        window.addEventListener('touchmove', this.resetTimeout);
        window.addEventListener('mousedown', this.resetTimeout);
        window.addEventListener('mousemove', this.resetTimeout);

        const listenDelegate = MimManager.instance.listenDelegate;
        const currentView = this.activeView || jibo.face.views.currentView;
        if (currentView && currentView.category === jibo.face.views.CATEGORY_GUI) {
            listenDelegate.setMode(MimManager.instance.ListenMode.UI);
        } else {
            switch(mimConfig.listenMode) {
                case ListenModes.OR:
                    listenDelegate.setMode(MimManager.instance.ListenMode.OPTIONAL_RESPONSE);
                    break;
                case ListenModes.UI:
                    listenDelegate.setMode(MimManager.instance.ListenMode.UI);
                    break;
                case ListenModes.NO_BODY:
                    listenDelegate.setMode(MimManager.instance.ListenMode.NO_BODY);
                    break;
                default:
                    listenDelegate.setMode(MimManager.instance.ListenMode.NORMAL);
                    break;
            }

        }

        // region listener setup
        const handle = this.combinedRuleHandle || MIM_RULE_HANDLE;
        //attach metadata to asr logs before we make our listener
        Runtime.instance.gl.setMetadata(this.asrMetadata);
        listen.listener = listenDelegate.create({incremental: true}, {rule:handle, type:'handle'});

        listen.listener.on(ListenEvent.FINISHED, () => {
            //after async, bail if behavior is stopped or destroyed
            if (this.status !== Status.IN_PROGRESS) {
                return;
            }
            listen.listener = null;
            if (this.mimMachine.current === this.states.listen) {
                if ((!this.asrResults || this.asrResults.state === 'noInput') && Date.now() - listen.startTime < listen.timeout) {
                    this.states.listen.transitionTo(this.states.restartListen);
                } else if (this.asrResults && this.asrResults.NLParse.domain === 'mim_global') {
                    this.states.listen.transitionTo(this.states.analyzeMimGlobal);
                } else if(this.asrResults && (this.asrResults.NLParse.domain === 'gui_command' ||
                    this.asrResults.NLParse.domain === 'menu_global')) {
                    //menu_global domain is deprecated, want to allow GUI commands beyond just
                    //menus, from local (specific mim) rules
                    this.states.listen.transitionTo(this.states.analyzeMenuGlobal);
                } else {
                    this.states.listen.transitionTo(this.states.analyzeResults);
                }
            }
        });

        listen.listener.on(ListenEvent.INCREMENTAL, (data:IncrementalResults, stopFunction:Function) => {
            //if doing a timeout, cancel the timeout on the first word said
            listen.timeout = NaN;
            //keep track of the asr results that we have
            this.asrResults = new AsrResult(data.result);
            //incremental updates don't actually supply this yet, but just in case
            // if (data.speakerId) {
            //     this.speakerIds = new SpeakerIds(data.speakerId);
            // }
            //supply incremental updates outside the mim
            if (this.onStatus) {
                this.onStatus({
                    state: this.mimState,
                    asrResults: this.asrResults
                });
            }
        });

        listen.listener.on(ListenEvent.CLOUD, (asrResultsData:ParseResults) => {
            this.asrResults = new AsrResult(asrResultsData);
        });
        // endregion listener setup
    }

    /**
     * Callback for screen interaction. Resets timeouts during listen.
     * @method jibo.bt.Mim#resetTimeout
     * @private
     */
    private resetTimeout() {
        if (this.listen) {
            this.listen.startTime = Date.now();
        }
    }

    /**
     * Callback for list event ('paged', 'at_front', 'at_back') from mim GUI. Plays SFX or MIM
     * as specified by the list configuration.
     * @method jibo.bt.Mim#onListEvent
     * @param {any} eventData List event object.
     * @param {string} eventData.type Type of action to take - 'sfx' to play sfx, or 'mim' to play an announcement Mim.
     * @param {string} eventData.data Data to act on
     * @private
     */
    private onListEvent(eventData:{type:string, data:string}) {
        if (!this.listAudio) {
            this.listAudio = new ListFeedbackAudio(eventData, this.assetPack, () => {
                this.listAudio = null;
            });
        }
    }

    /**
     * State interuption for states.listen. Stops listener and removes mim GUI if present.
     * @method jibo.bt.Mim#stopListen
     * @private
     */
    private stopListen() {
        this.listenExit();
    }

    /**
     * State exit for states.listen. Stops listener and removes screen touch listeners.
     * @method jibo.bt.Mim#listenExit
     * @private
     */
    private listenExit() {
        //clear metadata to make sure it isn't attached to any later listeners
        Runtime.instance.gl.setMetadata(null);
        if (this.listen && this.listen.listener) {
            //listener cleans up all event listeners attached to it in its stop() function.
            this.listen.listener.stop();
            this.listen.listener = null;
        }

        if (this.listAudio) {
            this.listAudio.stop();
            this.listAudio = null;
        }

        window.removeEventListener('touchstart', this.resetTimeout);
        window.removeEventListener('touchmove', this.resetTimeout);
        window.removeEventListener('mousedown', this.resetTimeout);
        window.removeEventListener('mousemove', this.resetTimeout);
    }

    /**
     * State update for states.listen. Tracks timeout. If timeout triggered, change state to
     * states.analyzeResults.
     * @method jibo.bt.Mim#updateListen
     * @private
     */
    private updateListen() {
        const listen = this.listen;
        //very simple check to see if we have timed out
        if (listen && listen.timeout && Date.now() - listen.startTime >= listen.timeout) {
            listen.listener.stop();
            listen.listener = null;
            this.states.listen.transitionTo(this.states.analyzeResults, true);
        }
    }
    // endregion listening

    // region parsing
    /**
     * State entry for states.analyzeMimGlobal. If global command is 'repeat', go to
     * states.choosePrompt. Otherwise, redirect to states.analyzeResults.
     * @method jibo.bt.Mim#analyzeMimGlobal
     * @private
     */
    private analyzeMimGlobal(transition:Transition, result:any) {
        const intent:string = this.asrResults.NLParse.intent;
        if (intent === 'repeat' && this.entryPrompt) {
            this.mimState.lastResultState = 'repeat';
            this.repeatCount++;
            this.states.analyzeMimGlobal.transitionTo(this.states.choosePrompt);
            return;
        }

        //go to analyzeResults, after parsing input with just the Mim's rule to see if it meant
        //anything to that rule
        if (this.ruleHandle) {
            Runtime.instance.nlu.parseFromURI(this.ruleHandle, this.asrResults.Input, (err, result) => {
                //after async, bail if behavior is stopped or destroyed
                if (this.status !== Status.IN_PROGRESS) {
                    return;
                }
                this.asrResults = new AsrResult(result);
                this.states.analyzeMimGlobal.transitionTo(this.states.analyzeResults);
            }, undefined);
        } else {
            //if no Mim rule provided, it should be considered a no match
            this.asrResults.slotIds.length = 0;
            this.states.analyzeMimGlobal.transitionTo(this.states.analyzeResults);
        }
    }

    /**
     * State entry for states.analyzeMenuGlobal. If global command is 'left' or right' and GUI is
     * active, scroll list and return to states.listen. Otherwise, redirect to
     * states.analyzeResults.
     * @method jibo.bt.Mim#analyzeMenuGlobal
     * @private
     */
    private analyzeMenuGlobal(transition:Transition, result:any) {
        const handled = Runtime.instance.face.views.actionEnactor(new ActionData(ActionData.VERBAL_COMMAND, this.asrResults.NLParse));
        //if the action was handled, then we can go back to listening
        //otherwise, we fall back to treating it as a no match
        if (handled) {
            //allow for the possibility that we an action from the GUI command kicks us into
            //a different state
            if (this.mimMachine.current === this.states.analyzeMenuGlobal) {
                this.states.analyzeMenuGlobal.transitionTo(this.states.listen, true);
            }
            return;
        }
        //go to analyzeResults, after parsing input with just the Mim's rule to see if it meant
        //anything to that rule
        if (this.ruleHandle) {
            Runtime.instance.nlu.parseFromURI(this.ruleHandle, this.asrResults.Input, (err, result) => {
                //after async, bail if behavior is stopped or destroyed
                if (this.status !== Status.IN_PROGRESS) {
                    return;
                }
                this.asrResults = new AsrResult(result);
                this.states.analyzeMenuGlobal.transitionTo(this.states.analyzeResults);
            }, undefined);
        } else {
            //if no Mim rule provided, it should be considered a no match
            this.asrResults.slotIds.length = 0;
            this.states.analyzeMenuGlobal.transitionTo(this.states.analyzeResults);
        }
    }
    
    /**
     * State entry for states.parseSpoof. Perform NLU parse on utterance text from GUI, followed * by going to states.reportResults.
     * @method jibo.bt.Mim#parseSpoofedUtterance
     * @private
     */
    private parseSpoofedUtterance(transition:Transition, utterance:string) {
        const listenDelegate = MimManager.instance.listenDelegate;
        //as we are done, reset the listen mode
        listenDelegate.setMode(MimManager.instance.ListenMode.NORMAL);
        //wait for rule to be loaded if it hasn't been already
        if (!this.ruleHandle) {
            this.rulePromise.then(() => {
                this.parseSpoofedUtterance(transition, utterance);
            });
            return;
        }
        Runtime.instance.nlu.parseFromURI(this.ruleHandle, utterance, (err, result) => {
            //after async, bail if behavior is stopped or destroyed
            if (this.status !== Status.IN_PROGRESS) {
                return;
            }
            this.asrResults = new AsrResult(result);
            this.states.parseSpoof.transitionTo(this.states.analyzeResults);
        }, undefined);
    }

    /**
     * State entry for states.analyzeResults. Analyze results to determine if result of listen is
     * 'noMatch', 'noInput', or 'match'. If result is 'match' or mim has run out of error prompts,
     * go to states.reportResults. Otherwise, go to states.choosePrompt.
     * @method jibo.bt.Mim#analyzeResults
     * @private
     */
    private analyzeResults(transition:Transition, timedOut:boolean) {
        const mimState = this.mimState;
        const mimConfig = this.mimConfig;
        if (!this.asrResults) {
            if (!timedOut) {
                console.error('No asr result!');
            }
        } else {
            mimState.lastResultState = this.asrResults.state;
            Runtime.instance.logger.info(`[${mimConfig.mimType}]${mimConfig.mimId} ASR Results: [${this.asrResults.Input}]`);
        }

        if (timedOut) {
            mimState.lastResultState = 'noInput';
        }

        const listenDelegate = MimManager.instance.listenDelegate;
        //optional responses don't have no-input or no-match errors,
        //so should always succeed on either a timeout or match
        if(mimConfig.mimType === MimTypes.OPTIONAL_RESPONSE) {
            if (mimConfig.ignoreNoMatch && mimState.lastResultState === 'noMatch') {
                this.states.analyzeResults.transitionTo(this.states.listen, false);
            } else {
                mimState.success = true;
                //as we are done, reset the listen mode
                listenDelegate.setMode(MimManager.instance.ListenMode.NORMAL);
                this.states.analyzeResults.transitionTo(this.states.reportResults);
            }
            return;
        }
        //as we are done, reset the listen mode
        listenDelegate.setMode(MimManager.instance.ListenMode.NORMAL);

        switch (mimState.lastResultState) {
            case 'match':
                mimState.success = true;
                break;
            case 'noMatch':
                mimState.incrementNoMatchCount();
                Runtime.instance.logger.info("[" + mimConfig.mimType + "]" + mimConfig.mimId + " No Match Count[" + mimState.noMatchCount + "]");
                if (!mimConfig.hasErrorPrompt('noMatch', mimState.noMatchCount)) {
                    mimState.failure = true;
                }
                break;
            case 'noInput':
                mimState.incrementNoInputCount();
                Runtime.instance.logger.info("[" + mimConfig.mimType + "]" + mimConfig.mimId + " No Input Count[" + mimState.noInputCount + "]");
                if (!mimConfig.hasErrorPrompt('noInput', mimState.noInputCount)) {
                    mimState.failure = true;
                }
                break;
        }

        if (mimState.done) {
            this.states.analyzeResults.transitionTo(this.states.reportResults);
        } else {
            this.states.analyzeResults.transitionTo(this.states.choosePrompt);
        }
    }
    // endregion parsing

    /**
     * State entry for states.reportResults. If mim has failed due to noInput or noMatch errors,
     * call onFailure to allow flow to handle exception. If exception not handled, go to
     * states.handleException. If mim successful, call onSuccess and end Mim behavior.
     * @method jibo.bt.Mim#reportResults
     * @private
     */
    private reportResults(transition:Transition, result:any) {
        this.cleanUpEvents();
        
        if (this.mimState.failure) {
            let result = false;
            this.viewTransition = {
                remove: true,
                transitionClose: ViewManager.TRANS_DOWN
            };
            if (this.onFailure) {
                result = this.onFailure({
                    state: this.mimState,
                    asrResults: this.asrResults
                });
            }
            // if result was not handled by flow, or we are not
            // in a flow, then do the global exception
            if (!result) {
                const exceptionData = {
                    state: this.mimState.lastResultState,
                    input: this.asrResults ? this.asrResults.Input : ''
                };
                this.states.reportResults.transitionTo(this.states.handleException, exceptionData);
                return;
            }
        } else {
            this.viewTransition = {
                remove: true,
                transitionClose: ViewManager.TRANS_DOWN
            };
            if (this.onSuccess) {
                this.onSuccess({
                    state: this.mimState,
                    asrResults: this.asrResults
                });
            }
        }
        this.unloadRules();
        this.removeView();
        if (this.destroyViewPromise) {
            this.destroyViewPromise.then(() => {
                //after async, bail if behavior is stopped or destroyed
                if (this.status !== Status.IN_PROGRESS) {
                    return;
                }
                this.status = Status.SUCCEEDED;
            });
        } else {
            this.status = Status.SUCCEEDED;
        }
    }

    // region internal flows
    /**
     * State entry for states.handleException. Begins global mim exception flow for either 'noInput'
     * or 'noMatch' failures.
     * @method jibo.bt.Mim#handleException
     * @private
     */
    private handleException(transition:Transition, result:any) {
        const state:string = result.state;
        if (state === 'noInput') {
            this.exceptionFlow = Runtime.instance.flow.create(NoInputException,
                {
                    assetPack:'core://',
                    blackboard: {
                        speechDelegate: MimManager.instance.speakDelegate
                    }
                });
        } else if (state === 'noMatch') {
            this.exceptionFlow = Runtime.instance.flow.create(NoMatchException,
                {
                    assetPack:'core://',
                    blackboard: {
                        showInputText: this.showInputText.bind(this, result.input),
                        hideInputText: this.hideInputText.bind(this),
                        speechDelegate: MimManager.instance.speakDelegate
                    }
                });
        }
    }

    /**
     * State update for states.handleException. Update exception flow. If flow is complete act upon
     * flow result. If flow result is 'exit', exit skill and return to be/idle. If flow result is
     * 'restart', go to states.choosePrompt.
     * @method jibo.bt.Mim#updateException
     * @private
     */
    private updateException():void {
        //run exception flow until it exits
        if (this.exceptionFlow && this.exceptionFlow.update()) {
            //check flow result to see if we should exit skill or restart the mim
            const result = this.exceptionFlow.result.transition;
            //destroy flow first
            this.exceptionFlow.destroy();
            this.exceptionFlow = null;
            //then handle the result of the flow
            if (result === 'exit') {
                //exit current skill
                Runtime.instance.lifecycle.finished();
            } else if (result === 'restart') {
                //restart current mim
                this.mimState.reset();
                this.mimState.lastResultState = 'holdReturn';
                this.states.handleException.transitionTo(this.states.choosePrompt);
            }
        }
    }

    /**
     * State interuption for states.handleException. Stop and clean up exception flow. Remove any
     * flow created view.
     * @method jibo.bt.Mim#stopException
     * @private
     */
    private stopException():void {
        if (this.exceptionFlow) {
            this.exceptionFlow.destroy();
            this.exceptionFlow = null;
        }
        this.hideInputText();
    }

    /**
     * Display text that mim rules could not match. Provided to noMatch exception flow as a
     * callback.
     * @method jibo.bt.Mim#showInputText
     * @param {string} notMatchedText Text from speech to text that NLU could not match.
     * @private
     */
    private showInputText(notMatchedText:string):void {
        const viewConfig = {
            viewConfig: {
                type: "View",
                id: "mim_not_matched_text"
            },
            componentConfigs: [
                {
                    id: "title",
                    type: "Label",
                    text: notMatchedText,
                    style: {
                        fontSize: "100",
                        fontFamily: "Proxima Nova Soft",
                        fontStyle: "bold",
                        fill: "#FFFFFF",
                        wordWrap: true,
                        wordWrapWidth: 1240,
                        align: 'center'
                    },
                    position: {
                        x: FaceRenderer.WIDTH / 2,
                        y: FaceRenderer.HEIGHT / 2
                    },
                    targetAnchor: {
                        x: 0.5,
                        y: 0.5
                    }
                }
            ]
        };
        if (this.destroyViewPromise) {
            this.destroyViewPromise.then(() => {
                //after async, bail if behavior is stopped or destroyed
                if (this.status !== Status.IN_PROGRESS) {
                    return;
                }
                this.activeView = Runtime.instance.face.views.createView("View", viewConfig, true);
            });
        } else {
            this.activeView = Runtime.instance.face.views.createView("View", viewConfig, true);
        }
        this.viewTransition = {
            remove: true,
            transitionClose: ViewManager.TRANS_DOWN
        };
    }

    /**
     * Remove text display created during noMatch exception flow.
     * @method jibo.bt.Mim#hideInputText
     * @private
     */
    private hideInputText():void {
        this.removeView();
    }
    // endregion internal flows
}
