import State from './State';
import ActivityImplementationFactory from './ActivityImplementationFactory';
import FlowRoot from './core/FlowRoot';
import Transition from './core/Transition';
import Activity from './core/Activity';
import Context from './Context';
import {FlowExceptionInfo} from './Context';
import Status from "../bt/Status";
import Blackboard from "../bt/Blackboard";
import {EventEmitter} from 'events';
import Environment from './Environment';
import Runtime from '../Runtime';

/**
 * Class representing a FlowExecutor.
 * The FlowExecutor runs a FlowRoot.
 * @class FlowExecutor
 * @memberof jibo.flow
 */

class FlowExecutor extends EventEmitter {
    public static InstanceCount = 0;

    public state:State;
    public flowRoot:FlowRoot;
    public context:Context = null;
    public blackboard:Blackboard;
    public emitter:EventEmitter;
    public assetPack:string;
    public environment:Environment;
    public primary:FlowExecutor = null; // In parallel threads, this is the thread they're associated with.
    public params:any; // These are the parameters passed in externally from JS to our starting procedure.
    public result:any; // Set when the flow exits, contains the "result" object from e.g. main.flow.
    public enableLogging:boolean; // Turns on FlowExecutor activity execution tracing.

    // We use name and id for logging.
    public name:string;
    public nextClonePid:number = 0;

    // External methods for use by consumers of FlowExecutor.

    /**
     * Create a FlowExecutor.
     * @param {FlowRoot} flowRoot - The flowRoot to be executed.
     * @param {any} overrides - provides options and alternatives to the default objects normally made during construction.
     * @internal
     */
    constructor(flowRoot?:FlowRoot, overrides?:any) {
        super();

        overrides = overrides || {};
        this.blackboard = overrides.blackboard || Runtime.instance.bt.getBlackboard();
        this.emitter = overrides.emitter || new EventEmitter();
        this.assetPack = overrides.assetPack || "";
        this.params = overrides.params || {};
        this.enableLogging = overrides.enableLogging || false;

        // The Environment is an object global to the entire Flow.
        // We place it temporarily on the notepad, until it is moved into Behaviorify.
        this.environment = overrides.environment || new Environment(this.assetPack);

        this.setupName(overrides);

        this.state = State.READY;

        if (flowRoot) {
            this.flowRoot = flowRoot;
            this.emit('constructing-flow-executor', {
                timestamp: Date.now(),
                thread: this.name,
                uri: flowRoot.startUri
            });
            this.enterProcedure(flowRoot.startProcedureOrName, flowRoot.startUri, this.params);
        }
    }

    /**
     * Keep track of PIDs for logging and unit tests.
     * @method jibo.flow.FlowExecutor#setupName
     * @param {any} overrides Object of properties that can be set/overridden externally: blackboard, emitter, assetPack, params, enableLogging
     * @internal
     */
    setupName(overrides:any) {
        FlowExecutor.InstanceCount++; // for Unit tests
        let pid = 0;
        if (overrides.getNextPid) {
            pid = overrides.getNextPid();
        }
        this.name = (overrides.name || '') + `${pid}-`;
    }

    getNextPid() {
        return this.nextClonePid++;
    }


    /**
     * Step the primary flow and all parallel flows.
     * @method jibo.flow.FlowExecutor#update
     * @returns {boolean}
     */
    update():boolean {
        this.updateAsyncs(this.context);
        return this.updatePrimary();
    }

    /**
     * Step the primary flow.
     * This is the FlowExecutor's central state machine.
     * @method jibo.flow.FlowExecutor#updatePrimary
     * @returns {boolean}
     * @internal
     */
    updatePrimary() {
        if (this.state === State.READY) {
            let success = false;
            let current_activity = this.context.current_activity;
            try {
                success = current_activity.start(this.context);
            } catch (e) {
                current_activity.exceptionPayload = e;
                current_activity.result = current_activity.formOrThrowException(e);
            }
            this.state = (!success) ? State.DONE : State.IN_PROGRESS;
        }

        if (this.state === State.IN_PROGRESS) {
            let current_activity = this.context.current_activity;
            let status;
            try {
                status = current_activity.update(this.context);
            } catch (e) {
                current_activity.exceptionPayload = e;
                current_activity.result = current_activity.formOrThrowException(e);
                this.state = State.DONE;
            }
            if (this.state !== State.IN_PROGRESS) {
                // If we're not IN_PROGRESS after the update then the Activity itself
                // has transitioned us (e.g. Flow.End) and we leave our state alone.
            } else if (status === Status.SUCCEEDED || status === Status.FAILED) {
                this.state = State.DONE;
                // For activities that return Status.FAILED (essentially only wrapped Behaviors),
                // if the activity has not set the result, set it to 'fail'.
                if (status === Status.FAILED && this.context.current_activity.result === null) {
                    this.context.current_activity.result = 'fail';
                }
            }
        }

        // Perform the transition only if current_activity.update() has not already done so (see e.g. System.End).
        if (this.state === State.DONE) {
            this.selectAndFollowTransition();
            this.state = State.READY;
        }

        return this.state === State.EXITED;
    }

    /**
     * Step all the parallel flows referenced by this FlowExecutor.
     * @method jibo.flow.FlowExecutor#updateAsyncs
     * @param {jibo.flow.Context} context the stack frame of the async tasks to be updated.
     * @internal
     */
    updateAsyncs(context:Context) {
        // Do our parent's updates before ours.
        if (context) {
            this.updateAsyncs(context.parent);
            for (let i = 0; i < context.asyncFlows.length; i++) {
                let flow = context.asyncFlows[i];
                if (flow.update()) {
                    // Remove flows that have run to completion.
                    context.asyncFlows.splice(i);
                }
            }
        }
    }


    /**
     * Start the Flow Executor.
     * This is effectively a nop since all the work is done through update().
     * @method jibo.flow.FlowExecutor#start
     */
    start():void {
        /**
         * When FlowExecutor starts
         * @event jibo.flow.FlowExecutor#start
         */
        this.emit('start');
    }

    /**
     * Stop the Flow Executor.
     *
     * 1) Stop the current activity.
     * 2) Emit `stop` to stop update ticks.
     * @method jibo.flow.FlowExecutor#stop
     * @return {Promise<void>} A promise that resolves after any asynchronous cleanup has been performed.
     */
    stop():Promise<void> {
        /**
         * When FlowExecutor stops.
         * @event jibo.flow.FlowExecutor#stop
         */
        this.log('Stopped');
        this.state = State.PAUSED;
        const rtn = this.stopCurrentActivity();
        this.emit('stop');
        this.emit('stopping-flow-executor', {
            timestamp: Date.now(),
            thread: this.name,
            uri: this.context.current_procedure.relativeUri
        });
        return rtn;
    }

    /**
     * Send `stop` to the current activity of the Flow Executor in the primary thread.
     * @method jibo.flow.FlowExecutor#stopCurrentActivity
     */
    stopCurrentActivity(): Promise<void> {
        return this.stopCurrentActivityInContext(this.context);
    }

    /**
     * Send `stop` to the current activity of the Flow Executor in the primary thread of the given context.
     * @method jibo.flow.FlowExecutor#stopCurrentActivityInContext
     */
    stopCurrentActivityInContext(context): Promise<void> {
        const current_activity = context.current_activity;
        context.flowExecutor.emit('stopping-activity', {
            timestamp: Date.now(),
            thread: this.name,
            uri: this.context.current_procedure.relativeUri,
            id: current_activity.activity.id,
            name: current_activity.name,
            type: current_activity.class,
            result: current_activity.getResultAsString()
        });
        
        const rtn = current_activity.stop(context);
        rtn.then(() => {
            current_activity.destroy();
        });
        return rtn;
    }

    /**
     * Destroy the FlowExecutor.
     * Stop the primary thread and destroy all parallel flows within its scope.
     * The flow is no longer runnable.
     * @method jibo.flow.FlowExecutor#destroy
     */
    destroy() {
        this.log('Destroyed');
        FlowExecutor.InstanceCount--;
        this.stopCurrentActivity();
        this.emit('destroy');
        let context = this.context;
        while (context !== null) {
            this.destroyAsyncFlows([context]);
            context = context.parent;
        }
        this.flowRoot = null;
    }

    /**
     * Stop all the parallel flows.
     * @method jibo.flow.FlowExecutor#destroyAsyncFlows
     * @param {array} contexts the list of stack frames containing async flows to be destroyed
     */
    destroyAsyncFlows(contexts:Array<Context>) {
        for (let context of contexts) {
            for (let flow of context.asyncFlows) {
                flow.stop().then(() => {
                    flow.destroy();
                });
            }
            context.asyncFlows = [];
        }
    }

    // Internal methods for use by ActivityImplementations.

    /**
     * Do the work of starting execution of a .flow file:
     * Push a frame on the stack, load the procedure, start execution
     * at its Flow.Begin and Flow.Parallel-Begin activities.
     * @method jibo.flow.FlowExecutor#enterProcedure
     * @param procedureObjectOrName
     * @param currentUri
     * @param params
     * @internal
     */

    enterProcedure(procedureObjectOrName:any, currentUri?:string, params?:any):void {
        if (currentUri === undefined) {
            currentUri = this.context.current_procedure.uri;
        }
        let currentProcedure = this.flowRoot.loadProcedure(currentUri, procedureObjectOrName);
        this.emit('entering-procedure', {
            timestamp: Date.now(),
            thread: this.name,
            uri: currentProcedure.relativeUri
        });
        params = params || {};
        this.context = new Context(this, this.context, currentProcedure, params); // Push a frame onto the call stack.
        let beginActivity = currentProcedure.getBeginActivity();
        this.context.current_activity = ActivityImplementationFactory.getImplementationOfActivity(beginActivity, this);
        this.loadAsyncBegins();
    }

    /**
     * Create flowexecutors for all the async begins and add them to the context.
     * @method jibo.flow.FlowExecutor#loadAsyncBegins
     * @internal
     */
    loadAsyncBegins() {
        let asyncBegins = this.context.current_procedure.getAsyncBeginActivities();
        for (let asyncBegin of asyncBegins) {
            this.context.asyncFlows.push(this.clone(asyncBegin));
        }
    }

    /**
     * Make a new FlowExecutor (borrowing heavily from this one) that will begin at the given activity.
     * We specifically share our notepad with the clone.
     * @method jibo.flow.FlowExecutor#clone
     * @param activity
     * @returns {FlowExecutor}
     * @internal
     */
    clone(activity:Activity):FlowExecutor {
        let flow = new FlowExecutor(undefined, this);
        flow.primary = this;
        flow.flowRoot = this.flowRoot;
        flow.context = new Context(flow, null, this.context.current_procedure, {});
        flow.context.notepad = this.context.notepad;
        flow.context.current_activity = ActivityImplementationFactory.getImplementationOfActivity(activity, flow);
        return flow;
    }

    /**
     * Do the work of ending execution of a .flow file and returning to the calling file.
     * If we are the last item on the call stack, this terminates the FlowExecutor.
     * @method jibo.flow.FlowExecutor#returnFromProcedure
     * @param transition
     * @internal
     */
    returnFromProcedure(transition):void {
        this.emit('returning-from-procedure', {
            timestamp: Date.now(),
            thread: this.name,
            uri: this.context.current_procedure.relativeUri,
            result: transition});
        // Wipe out anything asynchronous running in the context we're leaving.
        this.destroyAsyncFlows([this.context]);

        let result = this.context.result;
        result.transition = transition;

        if (this.context.parent === null) {
            this.state = State.EXITED;
            this.result = result;
        } else {
            // Pop the call stack.
            this.context = this.context.parent;
            if (this.context.current_activity.class !== "Flow.Subflow") {
                throw new Error("Returned from a subflow (to something besides a Flow.Subflow activity");
            }
            this.context.current_activity.result = this.context.current_activity.options.getTransition(result);
        }
    }

    /**
     * Find the next activity to be executed and transition to it.
     * @method jibo.flow.FlowExecutor#selectAndFollowTransition
     * @internal
     */
    selectAndFollowTransition():void {
        let dfault:Transition = null;
        let selected:Transition = null;
        let activityResult = this.context.current_activity.getResultAsString();

        if (activityResult.startsWith('~')) {
            this.throwException(activityResult);
            return;
        }

        this.log('jfe-Transition: ' + activityResult);

        for (let transition of this.context.current_activity.transitions) {
            if (transition.value === '') {
                dfault = transition;
            }
            if (activityResult === transition.value) {
                selected = transition;
                break;
            }
        }

        if (selected === null) {
            if (dfault === null) {
                let activity_type = this.context.current_activity.activity.class;
                let procedure = this.context.current_procedure.name;
                throw new Error(`Activity named "${this.context.current_activity.name}" of type ${activity_type}
                in procedure "${procedure}" with result: "${activityResult}" found no matching transition.`);
            }
            selected = dfault;
        }
        this.transitionTo(selected.to);
    }

    /**
     * Cause the primary thread to take an exception.
     * @method jibo.flow.FlowExecutor#injectExceptionInPrimary
     * @param exception
     * @internal
     */
    injectExceptionInPrimary(exception) {
        this.primary.stopCurrentActivity();
        this.primary.state = State.DONE;
        this.primary.context.current_activity.result = exception;
    }


    /**
     * Search for a handler for the given exception.
     * Returns undefined if no handler can be found.
     * @method jibo.flow.FlowExecutor#searchException
     * @param exception
     * @returns {{context: Context, activity: any, abandonedContexts: Array<Context>}}
     * @internal
     */
    searchException(exception:string) {
        let context = this.context;
        let foundActivity;
        let abandonedContexts:Array<Context> = [];

        outer: do {
            // Search for a suitable outbound on the current activity, longest exception name first.
            let exceptions = context.current_activity.exceptions
                .sort((a,b)=>b.value.length - a.value.length);
            for (let transition of exceptions) {
                if (this.isExceptionMatch(exception, transition.value)) {
                    foundActivity = context.current_procedure.activities[transition.to];
                    break outer;
                }
            }
            // Search all System.Catch activities on the current page, longest activity name first.
            let catches = Object.keys(context.current_procedure.activities)
                .map((a)=>context.current_procedure.activities[a])
                .filter((a)=>a.class === 'Flow.Catch')
                .sort((a,b)=>b.name.length - a.name.length);
            for (let activity of catches) {
                if (this.isExceptionMatch(exception, activity.name)) {
                    foundActivity = activity;
                    break outer;
                }
            }
            // Found nothing on this page, go up a level.
            abandonedContexts.push(context);
            context = context.parent;
        } while (context !== null);

        if (context !== null) {
            return {
                context: context,
                activity: foundActivity,
                abandonedContexts: abandonedContexts
            };
        }
    }

    getCurrentStackTrace() {
        let trace = [];
        let context = this.context;
        while (context !== null) {
            trace.push({activity: context.current_activity, procedure: context.current_procedure});
            context = context.parent;
        }
        return trace;
    }

    getFlowExceptionInfo(exception:string) {
        let flowException = new FlowExceptionInfo();
        flowException.name = exception;
        flowException.activity = this.context.current_activity;
        flowException.procedure = this.context.current_procedure;
        flowException.stackTrace = this.getCurrentStackTrace();
        flowException.payload = this.context.current_activity.exceptionPayload;
        return flowException;
    }

    /**
     * Cause the FlowExecutor to transition to a suitable handler for the given exception.
     * @method jibo.flow.FlowExecutor#throwException
     * @param exception
     * @internal
     */
    throwException(exception:string) {
        this.log('jfe-Exception: ' + exception);
        //prevent flow from updating during async stop(), or if we can't find a handler and throw
        //an actual error (don't want to keep throwing that error every tick)
        this.state = State.PAUSED;

        let found = this.searchException(exception);

        if (!found) {
            throw new Error(`Failed to find exception handler for ${exception}`);
        }

        let exceptionInfo = this.getFlowExceptionInfo(exception);
        this.environment.lastException = exceptionInfo;

        this.context = found.context;

        //destroy the previous activity
        this.context.current_activity.stop(this.context).then(() => {
            this.context.current_activity.destroy();

            this.context.current_activity = ActivityImplementationFactory.getImplementationOfActivity(found.activity, this, {"in": exceptionInfo});

            // We have already transitioned, so tell update not to.
            this.state = State.READY;
        });

        // Wipe out anything running in the contexts we're abandoning.
        this.destroyAsyncFlows(found.abandonedContexts);
        for (let context of found.abandonedContexts) {
            this.stopCurrentActivityInContext(context);
        }
    }

    /**
     * Implement the FlowExecutor's exception matching logic: the actual_exception and candidate_catch are
     * of the form ~[a[.b[.c]]] -- we repeatedly truncate the actual_exception and attempt to match it against
     * the candidate_catch.
     * @method jibo.flow.FlowExecutor#isExceptionMatch
     * @param actual_exception
     * @param candidate_catch
     * @returns {boolean}
     * @internal
     */
    isExceptionMatch(actual_exception:string, candidate_catch:string):boolean {
        // Non-conforming candidates or exceptions can never match.
        if (!candidate_catch || !candidate_catch.startsWith('~') ||
            !actual_exception || !actual_exception.startsWith('~')) {
            return false;
        }
        // normalize both to ~.[a[.b[.c]]
        let trycatch = candidate_catch.replace('~', '~.').replace(/\.$/, '');
        let exception = actual_exception.replace('~', '~.').replace(/\.$/, '');
        if (!exception.startsWith('~')) {
            return false;
        }
        while (true) {
            if (exception === trycatch) {
                return true;
            }
            if (exception === '~') {
                break;
            }
            exception = exception.replace(/\.[^.]+$/, '');
        }
        return false;
    }

    /**
     * Move the FlowExecutor's program counter to the given activity.
     * @method jibo.flow.FlowExecutor#transitionTo
     * @param {string} to - UUID of activity being transition to.
     * @internal
     */
    transitionTo(to:string):void {
        // All code in the next activity's options has access to "this." We create that here.
        let nextActivityThis = {
            'in': this.context.current_activity.optionCodeThis.out,
            'inResult': this.context.current_activity.result,
            'inTransition': String(this.context.current_activity.result)
        };
        //destroy the previous activity
        this.stopCurrentActivity();
        //get the new activity
        this.context.current_activity =
            ActivityImplementationFactory.getImplementationOfActivity(
                this.context.current_procedure.activities[to],
                this,
                nextActivityThis
            );
    }

    /**
     * Print lovely log messages.
     * @method jibo.flow.FlowExecutor#log
     * @param {string} msg - message to be logged to the console
     * @internal
     */
    log(msg:string):void {
        if (this.enableLogging) {
            console.log(this.name + msg);
        }
    }
}


export default FlowExecutor;
