import Task from '../../loader/tasks/Task';
import AssetManager from '../../loader/AssetManager';
import Callback from '../../loader/LoaderCallback';
import PathUtils from '../../utils/PathUtils';
import Sound from '../../sound/Sound';
import Timeline from '../animation/Timeline';
import Runtime from '../../Runtime';
import path = require('path');
import KeysAnimation from '../animation/KeysAnimation';
import async = require('async');

const jiboKeyframes = require('jibo-keyframes');

/**
 * Dummy class representing in-memory version of a .keys file.
 */
class Keyframes {
    public layers:[any];
    public duration:Number;
}

/**
 * Loads an animation timeline with PixiAnimate.
 * @class KeysTask
 * @memberof jibo.loader
 * @private
 * @param {String} asset.type Must be set to "keys".
 * @param {String} [asset.src] The keys file path.
 * @param {String} [asset.data] The keys file object.
 * @param {String} [assets.root] The root directory of stored keys file.
 * @param {Boolean} [asset.cache=false] `true` to cache the result.
 * @param {String} [asset.id] The ID of the task.
 * @param {Function} [asset.complete] The callback to call when the load is completed.
 */

class KeysTask extends Task
{
    static priority:number;
    public src:string;
    public data:any;
    public root:string;
    public upload:boolean;

    /**
     * Tests if an asset should be loaded.
     * @method jibo.loader.KeysTask.test
     * @static
     * @param {Object} asset The asset to test.
     * @return {Boolean} `true` if the asset qualifies for this task.
     */
    static test(asset:any): boolean
    {
        return asset.type === "keys" && !!asset.root &&
          ((!!asset.src && /\.keys$/i.test(asset.src)) || !!asset.data);
    }

    constructor(manager:AssetManager, asset:any)
    {
        super(manager, asset, asset.src);

        /**
         * The timeline source path.
         * @name jibo.loader.KeysTask#src
         * @type {String}
         */
        this.src = this.prepare(asset.src);

        /**
         * The timeline object.
         * @name jibo.loader.KeysTask#data
         * @type {String}
         */
        this.data = asset.data;

        /**
         * The root for the project.
         * @name jibo.loader.KeysTask#root
         * @type {String}
         */
        this.root = asset.root;

        /**
         * Load texture immediate to the GPU.
         * @name jibo.loader.KeysTask#upload
         * @type {Boolean}
         */
        this.upload = asset.upload === undefined ? true : asset.upload;
    }

    /**
     * Starts the load.
     * @method jibo.loader.KeysTask#start
     * @param {jibo.loader.Task~completeCallback} callback Callback to call when the load is done
     */
    start(callback:Callback):void
    {
        // Create the new animation
        const animation = new KeysAnimation(path.basename(this.src));
        animation.root = this.root;

        async.waterfall([
            (done) =>
            {
                // Get the current project root and name
                let root = PathUtils.findRoot();
                let projectName = PathUtils.getProjectName(root);

                // Get the assetPack from base directory of the source file
                const parent:string = PathUtils.findRoot(path.resolve(this.src));
                const assetPack:string = PathUtils.getProjectName(parent);

                // Get the assetpack
                animation.assetPack = assetPack === projectName ? '': assetPack;
                // If the keys data is already provided, we skip loading
                if (this.data) {
                    done(null, this.data);
                }
                else {
                    // Load the JSON keys file
                    this.nestedLoad(this.src, done);
                }
            },
            (data, done) =>
            {
                // Needed in case simpleLoad loaded the data
                this.data = data;
                // Get the assets definitions from keys
                animation.data = data;
                const assets = this.getAssetsFromKeys(animation);
                if (!assets.length)
                {
                    return done(null, {});
                }
                // Load the timeline and sound objects
                this.load(assets, done);
            },
            (results, done) =>
            {
                // Register the timeline and sounds
                // with the animation object
                for (let id in results)
                {
                    if (results[id] instanceof Timeline)
                    {
                        animation.addTimeline(id, results[id]);
                    }
                    else if (results[id] instanceof Sound)
                    {
                        animation.addSound(id, results[id]);
                    }
                }

                // Create the builder
                animation.builder = this.createBuilder();

                done(null);
            }
        ],
        (err, results) =>
        {
            if (err)
            {
                animation.destroy();
                callback(err);
                return;
            }
            callback(null, animation);
        });
    }

    private getAssetsFromKeys(animation:KeysAnimation): Array<any>
    {
        const assets:Array<any> = [];
        animation.data.layers.forEach((layer:any) =>
        {
            layer.keyframes.forEach((keyframe:any) =>
            {
                const AudioEvent = keyframe.value.AudioEvent;
                const Pixi = keyframe.value.Pixi;
                if (AudioEvent)
                {
                    assets.push({
                        id: AudioEvent.file,
                        type: 'sound',
                        src: PathUtils.getAudioUri(AudioEvent.file, animation.assetPack, animation.root)
                    });
                }
                else if (Pixi)
                {
                    assets.push({
                        id: Pixi,
                        type: 'timeline',
                        upload: this.upload,
                        src: PathUtils.getTimelineUri(Pixi, animation.assetPack, animation.root)
                    });
                }
            });
        });
        return assets;
    }

    /**
     * Creates the builder from the keys animation object.
     * @method jibo.loader.KeysTask#createBuilder
     * @private
     */
    private createBuilder():void
    {
        let baseName = path.basename(this.src);
        let animData = (<any>jiboKeyframes).keysObjToAnimObject(this.data, baseName);

        const animUtils = Runtime.instance.animate;
        return animUtils.createAnimationBuilderFromData(animData, this.root);
    }

    /**
     * Nested Keys File Loading.
     *
     * Given a keys file url, load the file recursively.
     * Returns the result of the compositing operation with all the HOLD_SAFE's in reference layers removed.
     * @memberof jibo.loader
     * @param {String} url path nanme of the keys file to be loaded
     * @param {Callback} complete callback to call when the load is completed.
     * @private
     */

    private nestedLoad(url:string, complete:Callback):void {
        this.innerNestedLoad(url, (err, keyframes) => {
            if (err) {
                return complete(err);
            }
            this.removeHoldSafesInReferences(keyframes);
            complete(null, keyframes);
        });
    }

    /**
     * Nested Keys File Loading.
     *
     * Given a keys file url, load the file and then recursively
     * composite into it any keys files it points to (somewhat like macro expansion).
     * Returns the result of the compositing operation with all reference layers removed.
     * @memberof jibo.loader
     * @param {String} url path nanme of the keys file to be loaded
     * @param {Callback} complete callback to call when the load is completed.
     * @param {String} [parentId] the layer ID of the referencing frame.
     * @private
     */

    private innerNestedLoad(url:string, complete:Callback, parentId?:string)
    {
        this.simpleLoad(url, (err, keyframes) => {
            if (err) {
                return complete(err);
            }

            if (parentId !== undefined) {
                this.fixLayerIds(keyframes, parentId);
            }
            const fileRefs = this.getKeyFileReferences(keyframes, url);
            async.each(fileRefs, (ref, callback) => {
                this.innerNestedLoad(ref.url, (err, newkeyframes) => {
                    if (err) {
                        return callback(err);
                    }

                    ref.frames = newkeyframes;
                    const validUpto = ref.holdFinalPose ? ref.nextRefStart : ref.timeOffset + ref.frames.duration;
                    this.timeshift(ref.frames, ref.timeOffset, validUpto, ref.containerDuration - 1);
                    callback();
                }, ref.parentId);
            }, (err) => {
                if (err) {
                    return complete(err);
                }

                for (let ref of fileRefs) {
                    this.composite(ref.layerNumber, keyframes, ref.frames);
                }

                this.removeReferenceLayers(keyframes);
                complete(null, keyframes);
            });

        });
    }

    /**
     * Find all references in a keys file, returning them in reverse-order.
     * @memberof jibo.loader
     * @param {Keyframes} frames a keyframes structure containing reference layers.
     * @param {String} referencingUri  the filename from whence the given keyframes were loaded.
     * @returns {Array} an array of objects describing references to other keys files,
     * each object has these properties:
     * `url`: the url of the file being referenced,
     * `parentId`: the layerID of the parent,
     * `holdFinalPose`: whether the final frame of the referenced layer is held until the next reference (or end),
     * `containerDuration`: the duration of the file that contains this reference.
     * `layerNumber`: the ordinal layer number of the reference,
     * `atEnd`: a boolean that is true if this is the last reference in the layer.
     * `nextRefStart`: where the next reference frame is, or Infinity if there are no further references.
     * `timeOffset`: the timepoint at which it is to be inserted in the referencing layer.
     * @private
     */

    private getKeyFileReferences(frames:Keyframes, referencingUri:string) {
        const fileRefs = [];
        const dirpath = path.dirname(referencingUri);
        for (let i = 0; i < frames.layers.length; i++) {
            const layer = frames.layers[i];
            if (layer.type === 'Reference' && layer.visible) {
                for (let keyi = 0; keyi < layer.keyframes.length; keyi++) {
                    const keyframe = layer.keyframes[keyi];
                    const atEnd = layer.keyframes.length === keyi + 1;
                    const nextRefStart = atEnd ? Infinity : layer.keyframes[keyi + 1].time;
                    fileRefs.push({
                        url: path.join(dirpath, keyframe.value.KeysFileReference.file),
                        parentId: layer.id,
                        holdFinalPose: keyframe.value.HoldFinalPose,
                        containerDuration: frames.duration,
                        layerNumber: i,
                        atEnd,
                        nextRefStart,
                        timeOffset: keyframe.time
                    });
                }
            }
        }
        fileRefs.reverse();
        return fileRefs;
    }

    /**
     * Find any "HOLD_SAFE" events in referenced layers and remove them (by renaming them).
     * @memberof jibo.loader
     * @param {Keyframes} frames keyframes to be cleaned.
     * @private
     */
    private removeHoldSafesInReferences(frames) {
        for (let layer of frames.layers) {
            if (layer.type === 'Event' && this.isReferencedLayer(layer)) {
                for (let keyframe of layer.keyframes) {
                    if (keyframe.value.Event.name === 'HOLD_SAFE') {
                        keyframe.value.Event.name = 'REFERENCED_HOLD_SAFE';
                    }
                }
            }
        }
    }

    /**
     * Strip out any reference-type layers from the keyframes.
     * @memberof jibo.loader
     * @param {Keyframes} keyframes keyframes structure containing reference layers.
     * @private
     */

    private removeReferenceLayers(keyframes:Keyframes) {
        for (let i = keyframes.layers.length-1; i >= 0; i--) {
            const layer = keyframes.layers[i];
            if (layer.type === 'Reference') {
                keyframes.layers.splice(i, 1);
            }
        }
    }

    /**
     * Shift the timepoint of all the keyframes within each of the given layers by the given timeOffset.
     * validFrom and validUpto are in "referencing" layer coordinates.
     * @memberof jibo.loader
     * @param {Keyframes} frames the layers containing the keyframes to be shifted.
     * @param {number} startTime the beginning of the valid region.
     * @param {number} validUpto the ending of valid region, or Infinity for unlimited.
     * @private
     */
    private timeshift(frames:Keyframes, validFrom:Number, validUpto:Number, holdAfter:Number) {
        for (let layer of frames.layers) {
            if (layer.validFrom === undefined) {
                // Initialize all not-yet-bounded layers.
                layer.validFrom = validFrom;
                layer.validUpto = validUpto;
                layer.holdAfter = holdAfter;

            } else {
                // Shift the valid region of previously bounded layers.
                layer.validFrom += validFrom;
                layer.validUpto += validFrom;
                layer.holdAfter += validFrom;
            }
            // Limit a layer's end time if it exceeds the requested end time.
            if (layer.validUpto > validUpto) {
                layer.validUpto = validUpto;
            }
            // Limit a layer's hold after point if it exceeds the requested one.
            if (layer.holdAfter > holdAfter) {
                layer.holdAfter = holdAfter;
            }
            // Shift the individual keyframes over by the new start point.
            for (let keyframe of layer.keyframes) {
                keyframe.time += validFrom;
            }
        }
    }

    /**
     * Insert all the layers of toBeInsertedKeyframes into existingKeyframes at the given layer number.
     * Insert them last-first in order to preserve their original ordering at the designated layer.
     * @memberof jibo.loader
     * @param {Number} layerNumber the layer number in which the keyframes are to be inserted.
     * @param {Keyframes} existingKeyframes the existing keyframes into which the layers will be inserted.
     * @param {Keyframes} toBeInsertedKeyframes the source of the keyframes to be inserted.
     * @private
     */
    private composite(layerNumber:number, existingKeyframes:Keyframes, toBeInsertedKeyframes:Keyframes) {
        for (let i = toBeInsertedKeyframes.layers.length - 1; i >= 0; i--) {
            existingKeyframes.layers.splice(layerNumber, 0, toBeInsertedKeyframes.layers[i]);
        }
    }

    /**
     * Modifies the layer ids to prefixed by the referencing layer's id (delimited by "-")
     * and suffixed with the layer number (delimited by '.').
     * @memberof jibo.loader
     * @param {Keyframes} frames the set of layers to be modified.
     * @param {string} prefix the string with which to prefix each layer id.
     * @private
     */
    private fixLayerIds(frames:Keyframes, prefix:string) {
        let i = 0;
        for (let layer of frames.layers) {
            layer.id = `${prefix}-${layer.id}.${i}`;
            i++;
        }
    }

    /**
     * Was this layer produced from a keyframes reference?
     * @memberof jibo.loader
     * @param {any} layer the layer to be checked
     * @returns {boolean}
     * @private
     */
    private isReferencedLayer(layer) {
        return layer.id.indexOf('-') >= 0;
    }

    // TODO: we will likely need this in the runtime as well, so leaving it here for now.
    // /**
    //  * Return true if frame being referenced already exists in hierarchy.
    //  * @param frames
    //  * @param prefix
    //  */
    //  private hasCircularReference(frames:Keyframes, prefix:string) {
    //      for (let layer of frames.layers) {
    //          if (prefix.indexOf(layer.id) >= 0) {
    //              return true;
    //          }
    //      }
    //      return false;
    //  }
}

export default KeysTask;
