import { Event, EventContainer, EmitterMode } from 'jibo-typed-events';
import { ListenResults, ParseResults, SpeakerId } from './DataTypes';


/**
 * @class GlobalEvents
 * @description Typed global events for gl module (`jibo.gl.global`)
 * only emits event to LAST subscriber.
 * ```
 * jibo.gl.global.help.subscribe();
 * jibo.gl.global.help.on((data) => {
 *    // data is of type asrResult
 *    // the ASR service has finished listening a cloud result
 *    // and all subscribed listeners will be removed
 * });
 * // When finished with event listening
 * jibo.gl.global.help.removeLastListener();
 * ```
 * @memberof jibo.gl
 */
export class GlobalEvents extends EventContainer {
  public stop: Event<ListenResults>;
  public repeat: Event<ListenResults>;
  public help: Event<ListenResults>;
  public cancel: Event<ListenResults>;

  constructor() {
        super();
        /**
         * Global stop command received
         * @name jibo.gl.GlobalEvents#stop
         * @type {Event}
         */
        this.stop = new Event<ListenResults>('Received global stop command');
        this.stop.setMode(EmitterMode.LAST_HANDLER);

        /**
         * Received global repeat command
         * @name jibo.gl.GlobalEvents#repeat
         * @type {Event}
         */
        this.repeat = new Event<ListenResults>('Received global repeat command');
        this.repeat.setMode(EmitterMode.LAST_HANDLER);

        /**
         * Received global help command
         * @name jibo.gl.GlobalEvents#help
         * @type {Event}
         */
        this.help = new Event<ListenResults>('Received global help command');
        this.help.setMode(EmitterMode.LAST_HANDLER);

        /**
         * Received global cancel command
         * @name jibo.gl.GlobalEvents#cancel
         * @type {Event}
         */
        this.cancel = new Event<ListenResults>('Received global cancel command');
        this.cancel.setMode(EmitterMode.LAST_HANDLER);
    }
}


/**
 * @class StateEvents
 * @description Typed Events for global listen module (`jibo.gl.events`)
 * ```
 * jibo.gl.events.cloudReceived.on((data) => {
 *    // data is of type asrResult
 *    // the ASR service has finished listening a cloud result
 *    // and all subscribed listeners will be removed
 * });
 * ```
 * @memberof jibo.gl
 */
export default class StateEvents extends EventContainer {
  public cloudReceived: Event<ListenResults>;
  public hjOnly: Event<ListenResults>;
  public listenFinished: Event<any>;
  public incremental: Event<ParseResults>;
  public hjHeard: Event<ListenResults>;
  public speakerId: Event<SpeakerId>;
  public eos: Event<any>;
  public sos: Event<any>;
  public startHjListen: Event<any>;
  public noGlobalMatch: Event<any>;
  public startNonHjListen: Event<any>;
  public skillRelaunch: Event<any>;
  public glStopped: Event<any>;
  public glStarted: Event<any>;
  public enrollment: Event<any>;
  public global: Event<any>;
  public socketClose: Event<string>;
  public socketReopen: Event<string>;

  constructor() {
    super();
    /**
     * Received Cloud results.
     * @name jibo.gl.StateEvents#cloudReceived
     * @type {Event}
     */
    this.cloudReceived = new Event<ListenResults>('Received Cloud results');
    /**
     * Received only a `hey jibo`
     * @name jibo.gl.StateEvents#hjOnly
     * @type {Event}
     */
    this.hjOnly = new Event<ListenResults>('Received only a "hey jibo"');
    /**
     * SDK listener finished.
     * @name jibo.gl.StateEvents#listenFinished
     * @type {Event}
     */
    this.listenFinished = new Event<any>('SDK listener finished');
    /**
     * Incremental speech results.
     * @name jibo.gl.StateEvents#incremental
     * @type {Event}
     */
    this.incremental = new Event<ParseResults>('Incremental speech results');
    /**
     * Heard `hey jibo`.
     * @name jibo.gl.StateEvents#hjHeard
     * @type {Event}
     */
    this.hjHeard = new Event<ListenResults>('Heard Hey Jibo');
    /**
     * Speaker was identified.
     * @name jibo.gl.StateEvents#speakerId
     * @type {Event}
     */
    this.speakerId = new Event<SpeakerId>('Got Speaker ID');
    /**
     * End of Speech signal received.
     * @name jibo.gl.StateEvents#eos
     * @type {Event}
     */
    this.eos = new Event<any>('End of Speech signal received');
    /**
     * Start of Speech signal received.
     * @name jibo.gl.StateEvents#sos
     * @type {Event}
     */
    this.sos = new Event<any>('Start of Speech signal received');
    /**
     * Starting `hey jibo` listening
     * @name jibo.gl.StateEvents#startHjListen
     * @type {Event}
     */
    this.startHjListen = new Event<any>('Starting HJ listening');
    /**
     * Parsed against global grammar and no result.
     * @name jibo.gl.StateEvents#noGlobalMatch
     * @type {Event}
     */
    this.noGlobalMatch = new Event<any>('Parsed against global grammar and no result');
    /**
     * Starting a non `hey jibo` listen.
     * @name jibo.gl.StateEvents#startNonHjListen
     * @type {Event}
     */
    this.startNonHjListen = new Event<any>('Starting a non Hey Jibo listen');
    /**
     * Launch grammar evoked for currently running skill
     * @name jibo.gl.StateEvents#skillRelaunch
     * @type {Event}
     */
    this.skillRelaunch = new Event<any>('Launch grammar evoked for currently running skill');
    /**
     * Global Listening is paused.
     * @name jibo.gl.StateEvents#glStopped
     * @type {Event}
     */
    this.glStopped = new Event<any>('GL Listening is paused');
    /**
     * Global Listening is restarted.
     * @name jibo.gl.StateEvents#glStarted
     * @type {Event}
     */
    this.glStarted = new Event<any>('GL Listening is restarted');
    /**
     * Global listen enrollment.
     * @name jibo.gl.StateEvents#enrollment
     * @type {Event}
     */
    this.enrollment = new Event<any>('GL enrollment');
    /**
     * A global command was heard
     * @name jibo.gl.StateEvents#global
     * @type {Event}
     */
    this.global = new Event<any>('GL global command parsed');
    /**
     * A Socket was closed. Likely due to a crash. Data will be string name of socket ('nlu' or 'asr').
     * @name jibo.gl.StateEvents#socketClose
     * @type {Event}
     */
    this.socketClose = new Event<string>('ASR or NLU Socket closed');
    /**
     * A Socket was reopened. Data will be string name of socket ('nlu' or 'asr').
     * @name jibo.gl.StateEvents#socketReopen
     * @type {Event}
     */
    this.socketReopen = new Event<string>('ASR or NLU Socket reopened after close');
  }
}
