import MenuButton from './MenuButton';
import Timeline from "../../animation/Timeline";

/**
 * Information about album displayed on the button.
 * @class AlbumInfo
 * @memberof jibo.face.ContentButton
 */
type AlbumInfo = {
    /**
     * Album title.
     * @name jibo.face.ContentButton.AlbumInfo#title
     * @type {String}
     */
    title: string,
    /**
     * Number of items in the album.
     * @name jibo.face.ContentButton.AlbumInfo#length
     * @type {Number}
     */
    length: number
};

/**
 * Content button, extends MenuButton to handle specifics required for displaying photo, video, or
 * album thumbnails.
 * @class ContentButton
 * @extends jibo.face.MenuButton
 * @memberof jibo.face
 */
class ContentButton extends MenuButton
{
    /**
     * The default class identifier.
     * Generally used to register the class.
     * @name jibo.face.ContentButton#DEFAULT_TYPE
     * @type {String}
     * @private
     * @readOnly
     */
    public static get DEFAULT_TYPE():string {return 'ContentButton';}

    /**
     * The Class type variant.
     * The MenuButton allows for type variants within it.
     * @name jibo.face.ContentButton#_type
     * @type {String}
     * @protected
     */
    protected _type:string = ContentButton.DEFAULT_TYPE;

    /**
     * `true` if button represents video content. `false` if button represents photo content.
     * @name jibo.face.ContentButton#_isVideo
     * @type {Boolean}
     * @default false
     * @protected
     */
    protected _isVideo:boolean;

    /**
     * Information about the album this button represents.
     * @name jibo.face.ContentButton#_albumInfo
     * @type {String}
     * @protected
     */
    protected _albumInfo:AlbumInfo;

    /**
     * Create a ContentButton from a configuration Object derived from JSON.
     * @method jibo.face.ContentButton#createFromConfig
     * @param {Object} configData Object derived from JSON, must be a specific format refer to examples.
     * @returns {jibo.face.ContentButton} ContentButton created from the given configuration.
     */
    public static createFromConfig(configData:any):ContentButton {
        let btn:ContentButton = new ContentButton();
        btn.assignConfig(configData);
        return btn;
    }

    constructor() {
        super();
        this._buttonDatas[ContentButton.DEFAULT_TYPE] = {
            assetPath: 'core://resources/buttons/contentButton.js',
            dimensions: new PIXI.Point(330, 330)
        };
    }

    public assignConfig(configData:any):void {
        super.assignConfig(configData);

        this._isVideo = !!configData.isVideo;
        this._albumInfo = configData.albumInfo;
    }

    /**
     * Destroy.
     * @method jibo.face.ContentButton#destroy
     */
    public destroy():void {
        super.destroy();
    }

    /**
     * Set up the timeline asset associated with the button.
     * @method jibo.face.ContentButton#setupTimeline
     * @protected
     */
    protected setupTimeline(assets:any):void {

        if(assets.hasOwnProperty(this.timelineId)) {
            const stageInstance:any = new (assets[this.timelineId] as Timeline).library.stage();

            const sprite:PIXI.Sprite = new PIXI.Sprite();
            sprite.texture = assets[this.iconId];
            const content = this._content = stageInstance.content;
            content.target.addChild(sprite);
            //if it's a video or video album, show the video icon
            content.videoIcon.visible = this._isVideo;
            //do album stuff if an album
            if (this._albumInfo) {
                //have to manually enable word wrap on the album title
                const style = (<PIXI.Text>content.albumTitle).style;
                style.wordWrap = true;
                style.wordWrapWidth = 300;//width of text element in contentButton.xfl

                content.albumTitle.text = this._albumInfo.title;
                content.albumLength.text = this._albumInfo.length;
                const bwFilter = new PIXI.filters.ColorMatrixFilter();
                bwFilter.blackAndWhite();
                content.target.filters = [bwFilter];
            } else {
                //hide album specific stuff
                content.albumTitle.visible = false;
                content.albumLength.visible = false;
                content.overlay.visible = false;
                content.underlay.visible = false;
            }
            this.display.addChild(stageInstance);
        }
        else {
            console.warn('WARNING :: ContentButton :: createDisplay : timeline not found in assets');
        }
    }
}

export default ContentButton;
