/**
 * The object returned by the SpritesheetTask.
 * @class Spritesheet
 * @memberof jibo.rendering.animation
 * @param {PIXI.BaseTexture} baseTexture
 * @param {Object} frames The frames map
 */
class Spritesheet
{
    /**
     * The collection of textures by name.
     * @name jibo.rendering.animation.Spritesheet#frames
     * @type {Object}
     */
    public frames:{[id:string]: PIXI.Texture};

    constructor(baseTexture:PIXI.BaseTexture, frames:{[id:string]: any})
    {
        this.frames = {};
        for(let name in frames)
        {
            let frame = frames[name];
            let rect = frame.frame;
            let trim = null;
            let size = new PIXI.Rectangle(rect.x, rect.y, rect.w, rect.h);

            // If the frame is rotated
            if (frame.rotated)
            {
                size.width = rect.h;
                size.height = rect.w;
            }

            //  Check to see if the sprite is trimmed
            if (frame.trimmed)
            {
                trim = new PIXI.Rectangle(
                    frame.spriteSourceSize.x, // / resolution,
                    frame.spriteSourceSize.y, // / resolution,
                    frame.sourceSize.w, // / resolution,
                    frame.sourceSize.h // / resolution
                );
            }
            this.frames[name] = new PIXI.Texture(
                baseTexture,
                size,
                size.clone(), 
                trim,
                frame.rotate
            );
        }
    }

    /**
     * Destroys all the textures/frames of spritesheet.
     * @method jibo.rendering.animation.Spritesheet#destroy
     */
    destroy()
    {
        for (let name in this.frames)
        {
            this.frames[name].destroy(true);
        }
        this.frames = null;
    }
}

export default Spritesheet;
