
/**
 * ViewState serves as a data representation of a {@link jibo.face.View} and its current state.
 * ViewState is used to recreate View objects within the {@link jibo.face.ViewManager}.
 * @class ViewState
 * @memberof jibo.face
 * @internal
 */
class ViewState
{
    /**
     * Identifier, same as id of View that ViewState represents.
     * @name jibo.face.ViewState#id
     * @type {String}
     */
    public id:string = '';

    /**
     * URI to the configuration JSON file for the corresponding view.
     * @name jibo.face.ViewState#configPath
     * @type {String}
     */
    public configPath:string = '';

    /**
     * Class name of the corresponding view.
     * @name jibo.face.ViewState#viewClassName
     * @type {String}
     */
    public viewClassName:string = '';

    /**
     * Configuration Objects, generally derived from JSON,
     * that defines corresponding view.
     * @name jibo.face.ViewState#viewConfig
     */
    public viewConfig:any = null;

    /**
     * Array of configuration Objects, generally derived from JSON,
     * that define corresponding view's components.
     * @name jibo.face.ViewState#componentConfigs
     * @type {Object[]}
     */
    public componentConfigs:any[];

    /**
     * Flag to determine whether, when corresponding view is opened,
     * it should pause the view below it.
     * @name jibo.face.ViewState#pauseParent
     * @type {boolean}
     * @default false
     */
    public pauseParent:boolean = false;

    /**
     * Flag to determine if corresponding view should enact close on swipe down.
     * @name jibo.face.ViewState#ignoreSwipeDown
     * @type {boolean}
     * @default false
     */
    public ignoreSwipeDown:boolean = false;

    /**
     * Can pass in the name of the corresponding ViewState class and config if available at construction.
     * @param {String} [viewClassName = 'View'] - Class name of View the ViewState represents.
     * @param {Object} [config] - Configuration Object for the corresponding View, generally derived from JSON.
     *              Contains both view and components configurations.
     */
    constructor(viewClassName:string = 'View', config?:any) {
        if(viewClassName) {
            this.viewClassName = viewClassName;
        }

        if(config) {
            this.applyConfig(config);
        }
    }

    /**
     * Derives separate references to view configuration, component configurations,
     * and View type from the given configuration.
     * @method jibo.face.ViewState#applyConfig
     * @param {Object} config Configuration Object for the corresponding View, generally derived from JSON.
     *              Contains both view and components configurations.
     */
    public applyConfig(config:any):void {
        if (config) {
            if (config.hasOwnProperty('viewConfig')) {
                this.viewConfig = config.viewConfig;
                // assigning type now if defined, needed to know which class to use when creating view from ViewState
                if(this.viewConfig.hasOwnProperty('type')) {
                    this.viewClassName = this.viewConfig.type;
                }
                if(this.viewConfig.hasOwnProperty('id')) {
                    this.id = this.viewConfig.id;
                }
            }
            if (config.hasOwnProperty('componentConfigs')) {
                this.componentConfigs = config.componentConfigs;
            }
        }
    }
}

export default ViewState;
