import {TimelineBuilder, RobotInfo, JiboConfig, animate, visualize, THREE, AuxOutput} from 'animation-utilities';
import Runtime from '../Runtime';


//keep these around
let robotInfo;
let timeline;
let renderer;

/**
 * we want to wrap the loading of animations into our own runtime file resolution
 * and format conversion
 * @private
 */
function wrapAnimationUtilities(animUtils) {

    /**
     * provided for backwards compatibility
     * @deprecated
     * @private
     */
    animate.createAnimationUtilities = () => {
        console.warn("Warning: createAnimationUtilities() is deprecated. Access anim utils via jibo.animate.");
        return animUtils;
    };

    /**
     * Creates an animation builder from a .keys file.
     * @function jibo.animate#createAnimationBuilderFromKeysPath
     * @param {String} uri Path to the .keys file.
     * @param {String} root Base path from which texture files are located.
     * @param {jibo.animate~AnimationBuilderCreatedCallback} cb Callback function that takes an {@link AnimationBuilder} as an argument.
     * @deprecated since 3.1.0
     * @see jibo.loader.KeysTask
     */
    animUtils.createAnimationBuilderFromKeysPath = (uri, root, cb) => {
        console.warn("Warning: createAnimationBuilderFromKeysPath() is deprecated. Use the 'keys' load task instead.");
        Runtime.instance.loader.load({
            src: uri,
            root: root,
            type: 'keys',
            complete: function(err, animation) {
                cb(animation.builder);
            }
        });
    };

    /**
     * provided for backwards compatibility
     * @deprecated
     * @private
     */
    animUtils.createAnimationUtilities = () => {
        return animUtils;
    };

    // pass module types through to the singleton instance
    animUtils.MODALITY_NAME = animate.MODALITY_NAME;
    animUtils.trajectory = animate.trajectory;
    animUtils.AnimationEventType = animate.AnimationEventType;
    animUtils.LookatEventType = animate.LookatEventType;

    // plus the shared three.js module
    /**
     * Shared three.js module reference.
     * @member jibo.animate.THREE
     */
    animUtils.THREE = THREE;
}


/**
 * Wrapping this call because we already have a reference to robot info
 * and the timeline.
 * @private
 */
function wrapVisualize(headless) {
    visualize.robotInfo = robotInfo;
    visualize.timeline = timeline;

    if(!headless) {
        /**
         * Creates a face renderer bound to the given DOM element.
         * @function jibo.visualize#createFaceRenderer
         * @param {HTMLElement} element The element to draw the eye to.
         * @returns {FaceRenderer}
         */
        visualize.createFaceRenderer = (element) => {
            if (renderer) {
                return renderer;
            }
            renderer = Runtime.instance.face;
            renderer.init(element);
            timeline.addOutput(new AuxOutput(robotInfo, renderer.eye));
            return renderer;
        };
    }

    let createRobotRenderer = visualize.createRobotRenderer;
    visualize.createRobotRenderer = (element, type, callback) => {
        createRobotRenderer(robotInfo, element, type, (renderer) => {
            if (renderer !== null) {
                TimelineBuilder.connectRenderer(timeline, renderer);
                if(callback) {
                    callback(null, renderer);
                }
            }
            else {
                if(callback) {
                    callback("Renderer creation failed");
                }
            }
        });
    };
}

function init(animUtils, done, headless) {
    let config = new JiboConfig();
    RobotInfo.createInfo(config,  (ri) => {
        TimelineBuilder.createTimeline(ri, (tl) => {
            robotInfo = ri;
            timeline = tl;
            animUtils.init(timeline, robotInfo);
            wrapAnimationUtilities(animUtils);
            wrapVisualize(headless);
            done();
        });
    });
}

export default {
    init
};