import Task from '../../loader/tasks/Task';
import AssetManager from '../../loader/AssetManager';
import Callback from '../../loader/LoaderCallback';
import Timeline from '../animation/Timeline';
import PathUtils from '../../utils/PathUtils';
import path = require('path');
import Runtime from '../../Runtime';

/**
 * Loads an animation timeline with PixiAnimate.
 * @class TimelineTask
 * @memberof jibo.loader
 * @private
 * @param {String} asset.type Must be "texture" to signify that this asset should be parsed
 *                            specifically for Pixi.js.
 * @param {String} [asset.src] The texture image path.
 * @param {Boolean} [asset.upload=false] Upload the GPU immediate after loading.
 * @param {String} [asset.alpha] The alpha image path, if not using image property.
 * @param {Boolean} [asset.cache=false] `true` to cache the result.
 * @param {String} [asset.id] The ID of the task.
 * @param {Function} [asset.complete] The callback to call when the load is completed.
 */

class TimelineTask extends Task
{
    static priority:number;
    public src:string;
    public upload:boolean;
    public instance:boolean;

    /**
     * Tests if an asset should be loaded.
     * @method jibo.loader.TimelineTask.test
     * @static
     * @param {Object} asset The asset to test.
     * @return {Boolean} `true` if the asset qualifies for this task.
     */
    static test(asset:any): boolean
    {
        return asset.type === "timeline" && !!asset.src && /\.js$/i.test(asset.src);
    }

    constructor(manager:AssetManager, asset:any)
    {
        super(manager, asset, asset.src);

        /**
         * The timeline source path.
         * @name jibo.loader.TimelineTask#src
         * @type {String}
         */
        this.src = this.prepare(asset.src);

        /**
         * Texture are uploaded to the GPU immediately.
         * @name jibo.loader.TimelineTask#upload
         * @type {Boolean}
         */
        this.upload = !!asset.upload;

        /**
         * Cause timeline to add an instance on load.
         * @name jibo.loader.TimelineTask#instance
         * @type {Boolean}
         */
        this.instance = asset.instance !== undefined ? !!asset.instance : true;
    }

    /**
     * Starts the load.
     * @method jibo.loader.TimelineTask#start
     * @param {jibo.loader.Task~completeCallback} callback Callback to call when the load is done
     */
    start(callback:Callback):void
    {
        const timeline = new Timeline();

        this.simpleLoad(this.src, (err, results) =>
        {
            if (err)
            {
                return callback(err);
            }
            // Save the library for later
            timeline.library = results;
            const assets = this.getAssets(timeline);
            if(assets.length){
                this.load(assets, (err, results) =>
                {
                    if (err)
                    {
                        return callback(err);
                    }

                    // Add instance to Timeline
                    if(this.instance)
                    {
                        timeline.addInstance();
                    }


                    // Upload to the renderer immediately
                    if (this.upload && Runtime.instance.face)
                    {
                        timeline.upload(Runtime.instance.face, () =>
                        {
                            callback(null, timeline);
                        });
                    }
                    else
                    {
                        // Callback
                        callback(null, timeline);
                    }
                });
            }
            else{
                callback(null, timeline);
            }
        });
    }

    getAssets(timeline:Timeline): Array<any>
    {
        let basePath = this.src;
        //need to handle asset packs here so that the base path for sub-assets aren't
        //messed up - path.join() normalizes the "//" to "/" in "asset-pack://"
        //also, only do it if there is a asset pack - we don't want to make relative paths
        //absolute just yet
        if (PathUtils.getAssetPack(basePath)) {
            basePath = PathUtils.getAssetUri(basePath);
        }
        basePath = path.dirname(basePath);
        const results = [];
        const assets = timeline.library.stage.assets;

        for(let id in assets) {
            let src = assets[id];
            // Load a texture
            if (src.search(/\.shapes\.(txt|json)$/i) > -1) {
                results.push({
                    id: id,
                    src: path.join(basePath, src),
                    type: 'shapes',
                    complete: (err, result) => {
                        if (err) {
                            return;
                        }
                        timeline.addShapes(result);
                    }
                });
            }
            else if (src.search(/\.(png|jpg|gif)$/i) > -1) {
                results.push({
                    id: id,
                    src: path.join(basePath, src),
                    type: 'texture',
                    complete: (err, result) => {
                        if (err) {
                            return;
                        }
                        timeline.addTexture(result, id);
                    }
                });
            }
            else if (src.search(/\.json$/i) > -1) {
                results.push({
                    id: id,
                    src: path.join(basePath, src),
                    type: 'spritesheet',
                    complete: (err, result) => {
                        if (err) {
                            return;
                        }
                        timeline.addSpritesheet(result);
                    }
                });
            }
        }
        return results;
    }
}

export default TimelineTask;
