import FlowExecutor from './FlowExecutor';
import Activity from './core/Activity';
import {FlowBehavior} from './ActivityImplementation';
import ActivityImplementation from './ActivityImplementation';
import Runtime from '../Runtime';
import {BehaviorConstructor} from '../bt/Factory';
/**
 * Create the runtime implementation of shapes on the Flow editor's diagram.
 * @class ActivityImplementationFactory
 * @memberof jibo.flow
 * @internal
 */
class ActivityImplementationFactory {

    /**
     * Given a Flow activity and the current Flow Executor, create the runtime implementation of the activity.
     * @method jibo.flow.ActivityImplementationFactory#getImplementationOfActivity
     * @param {jibo.flow.Activity} activity - The activity we wish to get the implementation of.
     * @param {jibo.flow.FlowExecutor} flowExecutor - The current FlowExecutor.
     * @param {any} optionCodeThis - object containing only an '.in' property, whose value is the 'this.out' from the previous activity executed.
     * @returns {jibo.flow.ActivityImplementation} an ActivityImplementation for the given activity.
     */
    public static getImplementationOfActivity(activity:Activity, flowExecutor:FlowExecutor, optionCodeThis?:any):ActivityImplementation {
        let implementation:ActivityImplementation;

        optionCodeThis = optionCodeThis || {};

        let result = this.getActivityOrBehaviorConstructor(activity);
        if (result.isActivity) {
            implementation = this.getActivityClassInstance(result.constructor, activity, flowExecutor, optionCodeThis);
        } else {
            implementation = this.getBehaviorClassInstance(result.constructor, activity, flowExecutor, optionCodeThis);
        }

        // Since the execution of every activity comes through here, it's a
        // convenient place for logging and updating the environment.
        this.log(activity, flowExecutor);
        let environment = flowExecutor.context.notepad.FlowEnv;
        environment.currentActivity = implementation;
        environment.currentProcedure = flowExecutor.context.current_procedure;
        environment.currentFile = flowExecutor.context.current_procedure.uri;
        flowExecutor.emit('constructing-activity', {
            timestamp: Date.now(),
            thread: flowExecutor.name,
            uri: flowExecutor.context.current_procedure.relativeUri,
            id: implementation.activity.id,
            name: implementation.name,
            type: implementation.class
        });
        return implementation;
    }

    /**
     * Given a Flow activity, return either a Flow-Activity or Behavior constructor for it.
     * @method jibo.flow.ActivityImplementationFactory#getActivityOrBehaviorConstructor
     * @param {jibo.flow.Activity} activity - The activity to find the constructor for.
     * @returns {any} Object with an ActivityImplementation constructor or a Behavior constructor.
     */
    static getActivityOrBehaviorConstructor(activity:Activity):any {
        let className = this.getActivityImplementationClassName(activity);
        let isActivity = true;
        let constructor;

        constructor = Runtime.instance.flow.getActivityConstructor(className, activity.assetPack);
        if (!constructor) {
            constructor = Runtime.instance.bt.getBehaviorConstructor(className, activity.assetPack);
            if (constructor) {
                isActivity = false;
            }
        }
        if (!constructor) {
            throw new Error(`No implementation found for activity type: "${activity.class}" in namespace "${activity.assetPack}"`);
        }

        return {isActivity: isActivity, constructor: constructor};
    }

    /**
     * Return the JS Class name for the given activity. This is simply a permutation of the activity's Flow Type.
     * (e.g. it converts Flow.Eval-Async to FlowEvalAsync)
     * @param {jibo.flow.Activity} activity - The activity to find the constructor for.
     * @returns {string} - The JS Class name of the activity's implementation.
     */
    static getActivityImplementationClassName(activity:Activity) {
        return activity.class.replace(/[.-]/g, '');
    }

    /**
     * Given a BehaviorConstructor, return the Flow implementation of a Behavior (really a Flow Class instance that wraps a Behavior Class instance).
     * @method jibo.flow.ActivityImplementationFactory#getBehaviorClassInstance
     * @param {jibo.bt.BehaviorConstructor} behaviorConstructor - The Behavior constructor for the Behavior or Decorator being wrapped by this Flow Activity.
     * @param {jibo.flow.Activity} activity - The current Behavior-type Flow activity.
     * @param {jibo.flow.FlowExecutor} flowExecutor - The current FlowExecutor.
     * @param {any} optionCodeThis - The object being used for the "this" object in the option code.
     * @returns {jibo.flow.FlowBehavior} - a FlowBehavior instance that wraps the instantiated Behavior.
     */
    static getBehaviorClassInstance(behaviorConstructor:BehaviorConstructor, activity:Activity, flowExecutor:FlowExecutor, optionCodeThis:any):FlowBehavior {
        let behaviorOptions = Object.assign({
            name: activity.name,
            emitter: flowExecutor.emitter,
            blackboard: flowExecutor.blackboard,
            assetPack: flowExecutor.assetPack,
        },
            // Form the Behavior's options (arguments).
            flowExecutor.context.getActivityOptions(activity.id, optionCodeThis)
        );

        // optionCodeThis is needed in two places for FlowBehaviors:
        // 1) It is bound as "this" to the functions within options (done with getActivityOptions() above)
        // 2) It is passed along to the FlowBehavior constructor (below) so that the FlowExecutor has access to this.out

        let behavior = new behaviorConstructor(behaviorOptions);
        return new FlowBehavior(activity, flowExecutor, behavior, optionCodeThis);
    }

    /**
     * Given an activity constructor, return the constructed activity.
     * @param {any} activityConstructor - The ActivityImplementation constructor.
     * @param {jibo.flow.Activity} activity - The current Flow activity.
     * @param {jibo.flow.FlowExecutor} flowExecutor - The current FlowExecutor.
     * @param {any} optionCodeThis - The object being used for the "this" object in the option code.
     * @returns {jibo.flow.ActivityImplementation} an ActivityImplementation for the given activity.
     */
    static getActivityClassInstance(activityConstructor, activity:Activity, flowExecutor:FlowExecutor, optionCodeThis:any):ActivityImplementation {
        return new activityConstructor(activity, flowExecutor, optionCodeThis);
    }

    /**
     * Log the start of execution of every activity.
     * @method jibo.flow.ActivityImplementationFactory#log
     * @param {jibo.flow.Activity} activity - The Activity to log a record of.
     * @param {jibo.flow.FlowExecutor} flowExecutor - The current FlowExecutor.
     */
    static log(activity:Activity, flowExecutor:FlowExecutor):void {
        let name = activity.name ? `("${activity.name}") ` : ''; // for quieter output on un-named activities.
        flowExecutor.log(`jfe-Executing: ${activity.class} ${name}in ${flowExecutor.context.current_procedure.name}`);
    }

}

export default ActivityImplementationFactory;
