import View from './View';
import Label from "../components/Label";
import MenuButton from "../components/MenuButton";
import List from '../components/List';
import ActionData from '../actions/ActionData';
import FaceRenderer from '../../FaceRenderer';
import Component from "../Component";

/**
 * View designed to display standard list menus.
 *
 *
 * Takes a simplified JSON configuration.
 * @example
 * <caption>JSON format</caption>
 *  {
 *      "viewConfig": {
 *          "type": "MenuView",
 *          "id": "my_menu",
 *          "title": "Menu Title",
 *          "listDefault": {
 *              "menuButtonType": "SkillButton"
 *          }
 *          "list": [
 *              {
 *                  "id": "mySkill",
 *                  "label": "My SKill",
 *                  "colors": ["0xff892f", "0xaf4123"],
 *                  "iconSrc": "resources/icons/mySkill.png",
 *                  "action": {
 *                      "type": "event",
 *                      "data": {
 *                          "event": "openSkill"
 *                          "skill": "mySkill"
 *                      }
 *                  }
 *              }
 *          ]
 *      }
 *  }
 * @class MenuView
 * @extends jibo.face.View
 * @memberof jibo.face
 */
class MenuView extends View
{
    /**
     * The default class identifier.
     * Generally used to register the class.
     * @name jibo.face.MenuView.DEFAULT_TYPE
     * @type {String}
     * @readOnly
     * @internal
     */
    public static get DEFAULT_TYPE():string {return 'MenuView';}

    /**
     * @name jibo.face.MenuView#_type
     * @type {String}
     * @private
     */
    protected _type:string = MenuView.DEFAULT_TYPE;

    /**
     * Title for MenuView, not required.
     * @name jibo.face.MenuView#_title
     * @type {jibo.face.Label}
     * @protected
     * @internal
     */
    protected _title:Label = null;

    /**
     * List for the MenuView.
     * @name jibo.face.MenuView#_list
     * @type {jibo.face.List}
     * @protected
     * @internal
     */
    protected _list:List = null;

    /**
     * Array of Labels for the MenuView.
     * The number of labels created is equal to number of list elements per page.
     * @name jibo.face.MenuView#_buttonLabels
     * @type {jibo.face.Label[]}
     * @protected
     * @internal
     */
    protected _buttonLabels:Label[] = null;

    //////////////////////// CONSTRUCTION ////////////////////////

    /**
     * Apply data to define and create required Components.
     * The MenuView does not require a component configurations as it manually
     * creates its Components based on data provided within the view configuration.
     * See the class description for an example of the view configuration schema.
     * @method jibo.face.MenuView#applyData
     * @internal
     */
    public applyData():void {
        super.assignConfig(this._viewConfig);

        //create List
        this._list = new List();
        this.addComponent(this._list);

        // create components for list
        this.createListComponents(this._list);
        const menuButton:MenuButton= <MenuButton>this._list.getComponentByIndex(0);

        // create config for List
        const listConfig:any = {
            id: 'list',
            elementsPerPage: 3,
            elementDimensions: menuButton.dimensions
        };

        // extract and act on view config data
        if (this._viewConfig) {
            // create Title, if one was specified in view config
            if (this._viewConfig.hasOwnProperty('title')) {
                // TODO :: this implements a unique JSON config format, would be good to test ViewConfig against an interface
                this._title = new Label();
                this._title.id = 'title';
                this._title.text = this._viewConfig.title;
                this._title.style = Label.createFontStyle(100, 'Proxima Nova Soft', '#FFFFFF', 'bold');
                this.addComponent(this._title); // need to center in createDisplay
            }
            //assign data that pay apply to list config
            if (this._viewConfig.hasOwnProperty('dynamic')) {
                listConfig['dynamic'] = this._viewConfig['dynamic'];
            }
            if (this._viewConfig.hasOwnProperty('noPan')) {
                listConfig['noPan'] = this._viewConfig['noPan'];
            }
            if (this._viewConfig.hasOwnProperty('pageIndex')) {
                listConfig['pageIndex'] = parseInt(this._viewConfig['pageIndex'] );
            }
            if (this._viewConfig.hasOwnProperty('elementsPerPage')) {
                listConfig['elementsPerPage'] = parseInt(this._viewConfig['elementsPerPage']);
            }
            if (this._viewConfig.hasOwnProperty('elementBuffer')) {
                listConfig['elementBuffer'] = parseInt(this._viewConfig['elementBuffer']);
            }
        }

        // apply view config
        this._list.assignConfig(listConfig);

        // create menu button labels, if menu buttons specify labels
        if (menuButton && menuButton.hasOwnProperty('label')) {
            this._buttonLabels = [];
            let buttonLabel:Label;
            for (let i:number = 0; i < this._list.elementsPerPage; i++) {
                buttonLabel = new Label();
                buttonLabel.id = 'buttonLabel' + i;
                buttonLabel.style = Label.createFontStyle(50,'Proxima Nova Light','#FFFFFF','');    // TODO :: should this be overridable?
                this.addComponent(buttonLabel);
                this._buttonLabels.push(buttonLabel);
            }
        }
    }

    /**
     * Create and add components for List.
     * @method jibo.face.MenuView#createListComponents
     * @param {jibo.face.List} list The List components components will be added to.
     * @protected
     * @internal
     */
    protected createListComponents(list:List):void {

        // look for default values for list components
        if(this._viewConfig) {
            // define default element configuration, this configuration is merge into all list elements
            const defaultElementData = this._viewConfig.listDefault || {};
            //view configs should switch to using 'type' instead of 'menuButtonType', but we allow
            //for old view configs
            const componentType:string = defaultElementData.menuButtonType || MenuButton.ACTION;
            if (!defaultElementData.type) {
                defaultElementData.type = componentType;
            }

            // use List to merge configs and create elements
            list.createComponentsFromConfigs(this._viewConfig.list, defaultElementData);
        }
        else {
            console.warn('MenuView :: createListComponents : the viewConfig is not defined, but is required.');
        }
    }

    /**
     * List for the MenuView.
     * @name jibo.face.MenuView#list
     * @public
     * @readOnly
     * @type {jibo.face.List}
     */
    public get list():List {
        return this._list;
    }

    /**
     * Loaded
     * - position elements in relation to each other.
     * - setup list labels to update in response to current list elements in view.
     * @method jibo.face.MenuView#loaded
     * @protected
     * @internal
     */
    protected loaded() {
        // TODO :: on loaded can we actually determine the size of the menu button base from the animation? This will save us from having to hard code the dimensions

        // set positions for components prior to creating displays
        this.positionComponents();

        super.createDisplay(this._stage, this._assets);

        //TODO :: listen for when List changes its page
        this.updateButtonLabels(false);

        this.ready();
    }

    /**
     * Destroy.
     * @method jibo.face.MenuView#destroy
     * @internal
     */
    public destroy():void {
        this._title = null;
        this._list = null;
        this._buttonLabels = null;
        super.destroy();
    }

    /**
     * Method to bubble actions up from Components.
     * MenuView overrides so that it can catch the page change actions triggered by its list
     * @method jibo.face.MenuView#actionHandler
     * @param {jibo.face.ActionData} action The action called. Contains string for type of action and data Object
     *                                      with any pertinent data dependent on action type.
     * @param {jibo.face.Component} fromComponent The component that triggered the action (if applicable).
     * @internal
     */
    public actionHandler(action:ActionData, fromComponent?:Component):void {

        if(!this._inputLocked) {
            if(action.type === List.PAGED) {
                this.updateButtonLabels();
                return;
            }
            else if(action.type === List.PAN) {
                this.fadeOutButtonLabels();
                return;
            }
            super.actionHandler(action, fromComponent);
        }
    }

    /**
     * Update configuration Object to reflect the current configuration state.
     * This ensures that when the Component is recreated from its configuration it reflects its last state.
     * @method jibo.face.MenuView#updateConfig
     * @param {Object} configObject
     * @returns {any} - Returns the given configuration Object with any required values updates applied.
     * @internal
     */
    public updateConfig(configObject?:any):any
    {
        /**
         * Apply List config update values (pageIndex, indexOfAction) directly to view config.
         * This occurs because MenuView does not use a standard component configuration,
         * instead storing List related data directly to its viewConfig.
         */
        if(this._list.stateChanged) {
            configObject = this._list.updateConfig(configObject);
        }
        return super.updateConfig(configObject);
    }

    /**
     * Determine y positions for the menu elements, as they are relative to each other.
     * @method jibo.face.MenuView#positionComponents
     * @param {number} [overrideTitleHeight] Override the calculated title height (or if there is no title but you want more spacing).
     */
    protected positionComponents(overrideTitleHeight?:number):void {

        let titleTotalHeight:number = 0;
        const titleBuffer:number = 100;     // TODO :: 100 is a hard constant specified by design, probably want to make define it as such
        if (overrideTitleHeight) {
            titleTotalHeight = overrideTitleHeight + titleBuffer;
        } else if(this._title) {
            titleTotalHeight = +this._title.getTextDimensions('Flat').y + titleBuffer;
        }

        let menuLabelTotalHeight:number = 0;
        const menuLabelBuffer:number = 40;  // TODO :: 10 is a hard constant specified by design, probably want to make define it as such
        if(this._buttonLabels) {
            menuLabelTotalHeight = +this._buttonLabels[0].getTextDimensions('Flat').y + menuLabelBuffer;
        }

        const groupBuffer:number = (FaceRenderer.HEIGHT - (+titleTotalHeight + +this._list.elementDimensions.y + +menuLabelTotalHeight))/2;

        if(this._title) {
            this._title.setTargetPosition(FaceRenderer.WIDTH/2, groupBuffer);
            this._title.setTargetAnchor(.5,0);
        }

        this._list.axisPosition = +groupBuffer + +titleTotalHeight + (this._list.elementDimensions.y/2);    // TODO :: am I centering the list, have the buttons already been positioned

        // position button labels, their x determined by the list
        if(this._buttonLabels) {

            const buttonLabelY:number = +groupBuffer + +titleTotalHeight + +this._list.elementDimensions.y + +menuLabelBuffer;
            let buttonLabel:Label;
            for (let i:number = 0; i < this._buttonLabels.length; i++) {
                buttonLabel = this._buttonLabels[i];
                buttonLabel.text = 'Sample Text';
                buttonLabel.setTargetPosition(+this._list.listStartPosition.x + (i * this._list.elementSpacing) + this._list.elementDimensions.x/2, buttonLabelY);
                buttonLabel.setTargetAnchor(.5,0);
            }
        }
    }

    /**
     * Calls the close transition on all of the button labels.
     * @method jibo.face.MenuView#fadeOutButtonLabels
     * @private
     */
    private fadeOutButtonLabels():void {

        // check currently visible buttons
        const buttonComponents:Array<Component> = this._list.getElementsByPage();
        const length:number = buttonComponents.length;
        for( let i:number = 0; i < length; i++) {
            let buttonLabel:Label = this._buttonLabels[i];
            buttonLabel.close(null, null, 100, 'sineInOut');
        }
    }

    /**
     * Update the button labels to match the list elements.
     * Enacts the Label close and open transitions by default.
     * @method jibo.face.MenuView#updateButtonLabels
     * @param {Boolean} [playTransition = true] Flag determining if close and open transitions will be used,
     *      if false updates the text without any transitions.
     * @private
     */
    private updateButtonLabels(playTransition:boolean = true):void {

        // check currently visible buttons
        const buttonComponents:Array<Component> = this._list.getElementsByPage();
        const length:number = buttonComponents.length;
        if(playTransition) {
            for( let i:number = 0; i < length; i++) {
                let menuBtn:MenuButton = <MenuButton>buttonComponents[i];
                let buttonLabel:Label = this._buttonLabels[i];
                if (buttonLabel.text !== menuBtn.label) {
                    // transition button
                    if(buttonLabel.display.alpha === 1) {
                        buttonLabel.close(() => {
                            buttonLabel.text = menuBtn.label;
                            buttonLabel.open(null, null, 200);
                        }, null, 200);
                    }
                    else{
                        buttonLabel.text = menuBtn.label;
                        buttonLabel.open(null, null, 200);
                    }
                }
                else if(buttonLabel.display.alpha < 1) {
                    buttonLabel.open(null, null, 200);
                }
            }
        }
        else{
            for( let i:number = 0; i < length; i++) {
                this._buttonLabels[i].text = (<MenuButton>buttonComponents[i]).label;
            }
        }
    }
}

export function isMenuView(view:View):view is MenuView {
    return view instanceof MenuView;
}

export default MenuView;
