function warn(msg:string) {
    let stack = new Error().stack;
    stack = stack.split('\n').splice(3).join('\n');
    if ((console as any).groupCollapsed) {
        (console as any).groupCollapsed("%cDeprecation Warning: %c%s", "color:#614108;background:#fffbe6", "font-weight:normal;color:#614108;background:#fffbe6", msg);
        console.warn(stack);
        console.groupEnd();
    }
    else {
        console.warn("Deprecation Warning:", msg);
        console.warn(stack);
    }
}

