    // Dynamically create a new behavior class from config object
    function newBehavior(config) {

        config = Object.assign({
            constructor: function(){ /* do nothing */ },
            start: function(){return true;},
            update: function(){return this.currentStatus;},
            stop: function(){ /* do nothing */ }
        }, config);

        class NewElement extends Behavior
        {
            constructor(options) {
                super(options);
                for(let method in config) {
                    if (method === "constructor") {
                       continue;
                    }
                    if (typeof config[method] === "function") {
                        this[method] = config[method];
                    }
                }
                config.constructor.call(this, options);
            }

            update() {
                return config.update.call(this);
            }
        }
        return NewElement;
    }

    // Dynamically create a new Decorator class from config object
    function newDecorator(config) {

        config = Object.assign({
            constructor: function(){ /* do nothing */ },
            start: function(){return true;},
            update: function(status){return status;},
            stop: function(){ /* do nothing */ }
        }, config);

        class NewElement extends Decorator
        {
            constructor(options) {
                super(options);
                for(let method in config) {
                    if (method === "constructor") {
                        continue;
                    }
                    if (method === "name") {
                        continue;
                    }
                    if (method === "namespace") {
                        continue;
                    }
                    this[method] = config[method];
                }
                config.constructor.call(this, options);
            }

            update(result) {
                return config.update.call(this, result);
            }
        }
        return NewElement;
    }

