import Runtime from '../Runtime';
import {Plugin, PluginCallback} from '../Plugin';

/**
 * Fetch the list of services from the registry
 */
class ServiceRecordsPlugin implements Plugin {
    init(done:PluginCallback): void {

        const jibo:Runtime = Runtime.instance;

        // Ignore services if runing in 
        if (jibo.runMode === jibo.RunMode.UNIT_TESTS) {
            return done();
        }

        const asset = {
            src: jibo.registryHost,
            format: 'json',
            timeout: 3000
        };

        jibo.loader.load(asset, (err, services) => {
            if (err) {
                return done(new Error(`Could not find registry service at ${jibo.registryHost}`));
            }

            if (services.records) {
                jibo.records = services.records;

                // sort them so service-manager is at the top
                jibo.records.sort( (a, b) => {
                    if (a.name === "system-manager") {
                        return -1;
                    }
                    if (b.name === "system-manager") {
                        return 1;
                    }
                    return -1;
                });
            }
            else {
                jibo.records = services;
            }
            done();
        }); 
    }
}

Runtime.registerPlugin(ServiceRecordsPlugin, 'service-records', {
    depends: ['loader', 'registry']
});

export default ServiceRecordsPlugin; 