/*
 * Events dispatched by all MIM listeners.
 */
const ListenEvent = {
    /*
     * Dispatched on incremented updates from the listening service.
     */
    INCREMENTAL: 'INCREMENTAL',
    //EOS: 'EOS',
    /*
     * Dispatched when the cloud result has been received - final event handling has not yet occurred.
     */
    CLOUD: 'CLOUD',
    /*
     * Dispatched when the listen is complete, even if it was interrupted.
     */
    FINISHED: 'FINISHED',
    /*
     * Dispatched when the listen rule has been compiled.
     */
    RULE_COMPILED: 'RULE_COMPILED'
};

export default ListenEvent;
