import Behavior from '../Behavior';
import Status from '../Status';
import Runtime from '../../Runtime';

import Mim, {MimResults} from './Mim';
import AsrResult from '../mim/AsrResult';
import {mergeDeep} from '../mim/GenerateListConfig';

import {ChangeOptions} from '../../rendering/gui/ViewManager';
import View from '../../rendering/gui/views/View';
import MenuView from '../../rendering/gui/views/MenuView';
import ActionData from '../../rendering/gui/actions/ActionData';

/**
 * Load or generate the menu configuration data. For the menu to function, the button actions must
 * be an 'utterance' or 'press' event - no other button actions will be responded to.
 * @callback jibo.bt.behaviors.Menu~GetConfig
 * @param {Function} callback When config has been loaded or generated, pass it to this callback.
 */
type GetConfig = (callback:(config:any)=>void)=>void;
/**
 * Called when a Menu times out or closes. Return value finds an exception handler within the flow. *Unhandled exceptions use the default behavior of returning to Jibo's idle state.
 * @callback jibo.bt.behaviors.Menu~OnMenuClosed
 * @param {boolean} timedOut `true` if the menu timed out, `false` if it was closed by the user.
 * @param {jibo.face.MenuView} menu Created menu. Use to read menu position or any other information before the menu closes.
 * @param {Function} overrideMenuTransition Override the transition out of the menu. Pass a [ChangeOptions]{@link jibo.face.ViewManager#ChangeOptions} to control the transition, or `remain` in order to leave the menu in place.
 * @param {String} results.exception (Flow Only) Exception for the closed menu; either `~InteractionError.MenuTimeout` or `~InteractionError.MenuClosed`.
 */
type OnMenuClosed = (timedOut:boolean, menu:MenuView, overrideMenuTransition:(trans:'remain'|ChangeOptions)=>void)=>boolean;
/**
 * Called when an item has been chosen.
 * @callback jibo.bt.behaviors.Menu~OnItemChosen
 * @param {any} results Either the listen results or the button press event, depending on how the menu is configured.
 * @param {jibo.face.MenuView} menu Created menu. Use to read menu position or any other information before the menu closes.
 * @param {Function} overrideMenuTransition Call to override the transition out of the menu. Pass a [ChangeOptions]{@link jibo.face.ViewManager#ChangeOptions} to control the transition, or `remain` in order to leave the menu in place.
 */
type OnItemChosen = (result:any, menu:MenuView, overrideMenuTransition:(trans:'remain'|ChangeOptions)=>void)=>void;

/**
 * Called to confirm that a positional selection makes sense, allowing custom handling to select certain types of items, if desired. This is called when a user says something like 'open the one on the right', and is called before the onItemChosen callback.
 * @callback jibo.bt.behaviors.Menu~OnPositionalSelect
 * @param {jibo.mim.AsrResult} commandASR Data from  NLU service.
 * @param {Number} intendedIndex Index that the menu plans to use for selection.
 * @param {jibo.face.MenuView} menu Created menu. Use to read button data, if you didn't keep track of it yourself.
 * @returns {number} An item index to change what will be selected, or NaN to select nothing. Returning undefined will use the default behavior (selecting intendedIndex).
 */
type OnPositionalSelect = (commandASR:AsrResult, intendedIndex:number, menu:MenuView) => number;

//'.mim' file data to use for each menu. Some values are overridden
const MENU_MIM_CONFIG = {
    mim_id: "Menu_AutoGenerated",
    mim_type: "optional-response",
    rule_name: null,
    gui_config: null,
    timeout: 10,
    barge_in: false,
    prompts: [
        {
            prompt_category: "Entry-Core",
            prompt_sub_category: "AN",
            index: 1,
            condition: "",
            prompt: "",
            media: "silence",
            prompt_id: ""
        }
    ],
    num_tries_for_gui: 0,
    es_auto_tagging: true,
    ignore_no_match: true
};

export const BLANK_VIEW_MODE = {
    ANY: 'any',
    SUCCESS: 'success',
    CANCEL: 'cancel',
    NONE: 'none'
};

/**
 * @class Menu
 * @extends jibo.bt.Behavior
 * @memberof jibo.bt.behaviors
 * @description A single stage menu.
 * @param {Object} options See {@link jibo.bt.Behavior|Behavior} for all options.
 * @param {jibo.bt.behaviors.Menu~GetConfig} options.getConfig Load or generate the menu config data.
 * @param {jibo.bt.behaviors.Menu~OnMenuClosed} options.onMenuClosed Called if the menu times out or is closed.
 * @param {jibo.bt.behaviors.Menu~OnItemChosen} options.onItemChosen Called when the user picks an item from the list.
 * @param {jibo.bt.behaviors.Menu~OnPositionalSelect} options.onPositionalSelect Called when the user uses a positional selection voice command
 */
export default class Menu extends Behavior {
    //behavior status
    private status: Status;
    private mim: Mim;
    private getConfig: GetConfig;
    private onMenuClosed: OnMenuClosed;
    private onItemChosen: OnItemChosen;
    private onPositionalSelect: OnPositionalSelect;
    //if the menu has been created yet - that way we only react to it once
    private createdMenu: boolean = false;
    //if we are quitting, instead of finishing the behavior
    private isQuitting: boolean = false;
    //if we got a chosen menu item - ensure that we only have one callback
    private gotPick: boolean = false;
    //the loaded menu config object
    private config: any;

    constructor(options) {
        super(options);
        this.getConfig = options.getConfig;
        this.onMenuClosed = options.onMenuClosed;
        this.onItemChosen = options.onItemChosen;
        this.onPositionalSelect = options.onPositionalSelect;
        this.onListClosed = this.onListClosed.bind(this);
        this.onPressEvent = this.onPressEvent.bind(this);
    }

    public start():boolean {
        this.status = Status.IN_PROGRESS;
        const configLoaded = (config:any) => {
            if (!config) {
                this.status = Status.FAILED;
                return;
            }
            if (typeof config === 'string') {
                const path = Runtime.instance.utils.PathUtils.getAssetUri(config, this.assetPack);
                Runtime.instance.loader.load(path, (err, data) => {
                    if (err) {
                        throw err;
                    }
                    configLoaded(data);
                });
                return;
            }
            this.config = config;
            //make a copy of the default config
            let mimConfig:typeof MENU_MIM_CONFIG = mergeDeep({}, MENU_MIM_CONFIG);
            //attach the gui config that was provided to us
            mimConfig.gui_config = config;
            //if timeout in the mim config is a valid number, then use it as the timeout
            //otherwise, we have a default of 10 seconds
            if (config.timeout > 1) {
                mimConfig.timeout = config.timeout;
            }
            //if the config specified a rule, use that
            mimConfig.rule_name = config.rule;
            //make the behavior options
            let mimOptions:any = {
                retainView: true,
                assetPack: this.assetPack,
                //insert our success callback
                onSuccess: this.onMimEnd.bind(this),
                onPositionalSelect: this.onPositionalSelect,
                mimConfig: mimConfig,
                asrMetadata: {
                    skill: this.assetPack
                }
            };
            this.mim = new Mim(mimOptions);
            this.mim.start();
        };
        this.getConfig(configLoaded);
        return true;
    }

    public stop():Promise<void> {
        this.status = Status.INVALID;
        if (this.mim) {
            return this.mim.stop();
        }
        return Promise.resolve();
    }

    public update():Status {
        if (this.isQuitting) {
            return Status.IN_PROGRESS;
        }
        if (this.status !== Status.IN_PROGRESS) {
            return this.status;
        }
        if (this.mim) {
            this.status = this.mim.update();
            if (this.isQuitting) {
                //don't accidentally return the Mim's success if we are going to stay running
                //unitl the skill quits - this could happen on a timeout
                this.status = Status.IN_PROGRESS;
            }
            //see if the menu just got created
            const activeView = this.mim.activeView;
            if (!this.createdMenu && activeView &&
                (activeView.state === View.LOADED || activeView.state === View.OPENED)) {

                //attach listeners to our brand new menu
                activeView.once(View.BACK, this.onListClosed);
                activeView.once('press', this.onPressEvent);
                //adding this listener in case the view is closed externally, so that
                //the behavior can properly end early
                activeView.once(View.CLOSED, this.onListClosed);
                this.createdMenu = true;
                //ensure that the view does not have a CLOSE_VIEW action attached to the
                //swipe down stuff - we want to do that ourselves
                const swipeDownActions = activeView.swipeDownActions;
                if (swipeDownActions) {
                    for (let i = swipeDownActions.length - 1; i >= 0; --i) {
                        if (swipeDownActions[i].type === ActionData.CLOSE_VIEW) {
                            swipeDownActions.splice(i, 1);
                        }
                    }
                }
            }
        }
        return this.status;
    }

    public destroy() {
        super.destroy();
        if (this.mim) {
            this.mim.destroy();
            this.mim = null;
        }
    }

    /**
     * Callback for button 'press' events from the menu.
     * @method jibo.bt.Menu#onPressEvent
     * @param {any} event Whatever the press event from the menu was, as defined in the view config.
     * @private
     */
    private onPressEvent(event) {
        //ensure that we only have one ending callback
        if (this.gotPick || !this.mim) {
            return;
        }
        this.gotPick = true;
        let transition:'remain'|ChangeOptions = this.config.defaultSelect;
        //pass along the chosen button data, in whatever form it was supplied
        this.onItemChosen(event, <MenuView>this.mim.activeView, (trans) => {
            transition = trans;
        });
        if (!this.mim) {
            console.error('Menu was destroyed during onItemChosen() - please wait until the behavior returns Status.SUCCEEDED or Status.FAILED from update() to consider it completed');
            return;
        }
        this.mim.viewTransition = transition;

        if (this.mim.activeView) {
            const activeView = this.mim.activeView;
            activeView.removeListener(View.BACK, this.onListClosed);
            activeView.removeListener('press', this.onPressEvent);
            activeView.removeListener(View.CLOSED, this.onListClosed);
        }
        //stop mim
        this.mim.stop();
        //wait for view to go away before continuing
        if (this.mim.destroyViewPromise) {
            this.mim.destroyViewPromise.then(() => {
                this.status = Status.SUCCEEDED;
            });
        } else {
            this.status = Status.SUCCEEDED;
        }
    }

    /**
     * Callback for when the list is closed for any reason.
     * @method jibo.bt.Menu#onListClosed
     * @private
     */
    private onListClosed() {
        //ensure that we only have one ending callback - list is closed on success as well
        if (this.gotPick || !this.mim) {
            return;
        }
        this.gotPick = true;
        let transition:'remain'|ChangeOptions = this.config.defaultClose;
        //inform containing BT/flow of the closing
        let handled:boolean = false;
        if (this.onMenuClosed) {
            handled = this.onMenuClosed(false, <MenuView>this.mim.activeView, (trans) => {
                transition = trans;
            });
        }
        if (!this.mim) {
            console.error('Menu was destroyed during onMenuClosed() - please wait until the behavior returns Status.SUCCEEDED or Status.FAILED from update() to consider it completed');
            return;
        }
        this.mim.viewTransition = transition;
        if (this.mim.activeView) {
            const activeView = this.mim.activeView;
            activeView.removeListener(View.BACK, this.onListClosed);
            activeView.removeListener('press', this.onPressEvent);
            activeView.removeListener(View.CLOSED, this.onListClosed);
        }

        //if not handled in the flow, quit skill
        if (!handled) {
            this.isQuitting = true;
            this.mim.activeView.inputLocked = true;
            Runtime.instance.lifecycle.finished();
        } else {
            //stop mim
            this.mim.stop();
            //wait for view to go away before continuing
            if (this.mim.destroyViewPromise) {
                this.mim.destroyViewPromise.then(() => {
                    this.status = Status.SUCCEEDED;
                });
            } else {
                this.status = Status.SUCCEEDED;
            }
        }
    }

    private onMimEnd(results:MimResults) {
        //ensure that we only have one ending callback
        if (this.gotPick || !this.mim) {
            return;
        }
        this.gotPick = true;
        let transition:'remain'|ChangeOptions = this.config.defaultClose;
        //if the ending state was 'noInput', then the list timed out
        if (results.state.lastResultState === 'noInput') {
            //inform containing BT/flow of the timeout
            let handled:boolean = false;
            if (this.onMenuClosed) {
                handled = this.onMenuClosed(true, <MenuView>this.mim.activeView, (trans) => {
                    transition = trans;
                });
                if (!this.mim) {
                    console.error('Menu was destroyed during onMenuClosed() - please wait until the behavior returns Status.SUCCEEDED or Status.FAILED from update() to consider it completed');
                    return;
                }
            }
            //if not handled in the flow, quit skill
            if (!handled) {
                this.isQuitting = true;
                Runtime.instance.lifecycle.finished();
            }
        } else {
            transition = this.config.defaultSelect;
            //otherwise, the state would be 'match' - the mim config we created tells it to
            //ignore no match errors and continue to timeout or match.
            //since the list succeeded with a voice command, then we pass the ASR result along as
            //the chosen list item
            this.onItemChosen(results.asrResults, <MenuView>this.mim.activeView, (trans) => {
                transition = trans;
            });
            if (!this.mim) {
                console.error('Menu was destroyed during onItemChosen() - please wait until the behavior returns Status.SUCCEEDED or Status.FAILED from update() to consider it completed');
                return;
            }
        }
        this.mim.viewTransition = transition;
        if (this.mim.activeView) {
            const activeView = this.mim.activeView;
            activeView.removeListener(View.BACK, this.onListClosed);
            activeView.removeListener('press', this.onPressEvent);
            activeView.removeListener(View.CLOSED, this.onListClosed);
        }
    }
}
