import MimPrompt from './MimPrompt';
import MimState from './MimState';
import {CONFIG_BASE} from './GenerateListConfig';
import fs = require('fs');
import vm = require('vm');
import path = require('path');
import {constant} from '../../utils/decorators';

type PromptCategory = 'Entry-Core' | 'Errors';
const PROMPT_CATEGORY_ENTRY:'Entry-Core' = 'Entry-Core';
const PROMPT_CATEGORY_ERROR:'Errors' = 'Errors';

type PromptSubCategory = 'Q' | 'AN' | 'NM' | 'NI' | 'HoldReturn' | 'Verbose' | 'Truncated';
const PROMPT_SUB_CATEGORY_QUESTION:'Q' = 'Q';
const PROMPT_SUB_CATEGORY_ANNOUNCEMENT:'AN' = 'AN';
const PROMPT_SUB_CATEGORY_NO_MATCH:'NM' = 'NM';
const PROMPT_SUB_CATEGORY_NO_INPUT:'NI' = 'NI';
const PROMPT_SUB_CATEGORY_HOLD_RETURN:'HoldReturn' = 'HoldReturn';
const PROMPT_SUB_CATEGORY_VERBOSE:'Verbose' = 'Verbose';
const PROMPT_SUB_CATEGORY_TRUNCATED:'Truncated' = 'Truncated';

const TYPE_AN = 'announcement';
const TYPE_OR = 'optional-response';
const TYPE_Q = 'question';
export class MimTypes {
    @constant
    public static ANNOUNCEMENT = TYPE_AN;
    @constant
    public static OPTIONAL_RESPONSE = TYPE_OR;
    @constant
    public static QUESTION = TYPE_Q;
};

export class ListenModes {
    @constant
    public static NORMAL = 'NORMAL';
    @constant
    public static OR = 'OR';
    @constant
    public static UI = 'UI';
    @constant
    public static NO_BODY = 'NO_BODY';
};

/**
 * MIM configuration data generated from the .mim files.
 * @class MimConfig
 * @memberof jibo.mim
 * @private
 */
export default class MimConfig {
    public mimId:string;
    public mimType:string;
    public ruleName:string;
    public sampleUtterances:string;
    public guiConfig:typeof CONFIG_BASE;
    public timeout:number;
    public numTriesForGUI:number;
    public bargeIn:boolean;
    public esAutoTagging:boolean;
    public ignoreNoMatch:boolean;
    public prompts:MimPrompt[];
    public listenMode:string;

    /**
     * Promised loading of a single .mim file.
     * @method jibo.mim.MimConfig~load
     * @param {string} filePath Path to the .mim file.
     * @returns {Promise<MimConfig>} Promise to load a new MimConfig instance.
     * @static
     */
    public static load(filePath:string):Promise<MimConfig> {
        return new Promise((resolve, reject) => {
            fs.readFile(filePath, 'utf8', (error, result) => {
                if (error) {
                    reject(error);
                } else {
                    let mim = new MimConfig();
                    mim.mimId = path.basename(filePath, path.extname(filePath));
                    mim.initWithJSON(JSON.parse(result));
                    resolve(mim);
                }
            });
        });
    }

    constructor() {
        this.mimId = '';
        this.mimType = '';
        this.ruleName = '';
        this.sampleUtterances = '';
        this.timeout = 0;
        // the default behavior here is to display the gui the second time the mim is displayed
        this.numTriesForGUI = 2;
        this.bargeIn = true;
        this.esAutoTagging = true;
        this.ignoreNoMatch = false;
        this.listenMode = ListenModes.NORMAL;

        this.prompts = [];
    }
    
    /**
     * If the Mim has a gui available, either as sampleUtterances or guiConfig.
     * @name jibo.mim.MimConfig~hasGui
     * @type {Boolean}
     * @readOnly
     */
    public get hasGui() {
        return !!this.sampleUtterances || !!this.guiConfig;
    }

    /**
     * Pick a prompt and get the text for it.
     * @method jibo.mim.MimConfig~getPromptText
     * @param {MimState} mimState State of the active MIM.
     * @param {any} promptData Dictionary of variables to use for condition evaluation and text replacement.
     * @return {String} Prompt text.
     */
    public getPromptText(mimState:MimState, promptData:any):string {
        let entryPromptSubCategory:PromptSubCategory;
        switch (this.mimType) {
            case TYPE_Q:
                entryPromptSubCategory = PROMPT_SUB_CATEGORY_QUESTION;
                break;
            case TYPE_AN:
                entryPromptSubCategory = PROMPT_SUB_CATEGORY_ANNOUNCEMENT;
                break;
            case TYPE_OR:
                entryPromptSubCategory = PROMPT_SUB_CATEGORY_ANNOUNCEMENT;
                break;
            default:
                console.error(`In MiM ${this.mimId}, incorrect mimType of ${this.mimType}`);
                break;
        }
        //internal usage of not supplying any information to just get a quick entry prompt
        if (!mimState) {
            const prompt = this.getPromptWithCategoryAndSubCategory(PROMPT_CATEGORY_ENTRY,
                                                            entryPromptSubCategory,
                                                            null);
            return prompt.getPromptText().trim();
        }
        //make a sandbox for prompt condition evaluation and prompt value replacement
        let promptDataSandbox:vm.Context;
        if (promptData) {
            promptDataSandbox = vm.createContext(promptData);
        }
        let prompt:MimPrompt = null;
        switch (mimState.lastResultState) {
            case 'entry':
                prompt = this.getPromptWithCategoryAndSubCategory(PROMPT_CATEGORY_ENTRY,
                                                                entryPromptSubCategory,
                                                                promptDataSandbox);
                break;
            case 'verbose':
                prompt = this.getPromptWithCategoryAndSubCategory(PROMPT_CATEGORY_ENTRY,
                                                                PROMPT_SUB_CATEGORY_VERBOSE,
                                                                promptDataSandbox);
                if (!prompt) {
                    prompt = this.getPromptWithCategoryAndSubCategory(PROMPT_CATEGORY_ENTRY,
                                                                entryPromptSubCategory,
                                                                promptDataSandbox);
                }
                break;
            case 'truncated':
                prompt = this.getPromptWithCategoryAndSubCategory(PROMPT_CATEGORY_ENTRY,
                                                                PROMPT_SUB_CATEGORY_TRUNCATED,
                                                                promptDataSandbox);
                if (!prompt) {
                    prompt = this.getPromptWithCategoryAndSubCategory(PROMPT_CATEGORY_ENTRY,
                                                                entryPromptSubCategory,
                                                                promptDataSandbox);
                }
                break;
            case 'holdReturn':
                prompt = this.getPromptWithCategoryAndSubCategory(PROMPT_CATEGORY_ENTRY,
                                                                PROMPT_SUB_CATEGORY_HOLD_RETURN,
                                                                promptDataSandbox);
                if (!prompt) {
                    prompt = this.getPromptWithCategoryAndSubCategory(PROMPT_CATEGORY_ENTRY,
                                                                    entryPromptSubCategory,
                                                                    promptDataSandbox);
                }
                break;
            case 'noMatch':
                prompt = this.getErrorNoMatchPrompt(promptDataSandbox, mimState.noMatchCount);
                break;
            case 'noInput':
                prompt = this.getErrorNoInputPrompt(promptDataSandbox, mimState.noInputCount);
                break;
            default:
                console.error(`Invalid lastResultState: ${mimState.lastResultState}`);
                break;
        }
        if (!prompt) {
            console.error(`Unable to find a valid prompt for mim ${this.mimId} - last result state: ${mimState.lastResultState}`);
            return '';
        }
        //if we aren't doing a TTS, then don't say anything
        if (prompt.media !== 'TTS') {
            return '';
        }

        //On Tuesday, it will be: ${conditions} ${inLocale} With a high in the: ${highTemp} And a low in the: ${lowTemp}
        let promptText = '';
        if (promptDataSandbox) {
            let script_text = '`' + prompt.getPromptText() + '`';
            try {
                promptText = vm.runInContext(script_text, promptDataSandbox);
            } catch (e) {
                console.error(`Error parsing prompt text: ${prompt.getPromptText()} - error: ${e.message}`);
            }
        } else {
            promptText = prompt.getPromptText();
        }
        return promptText;
    }
    
    /**
     * See if MimConfig has error prompts of the corresponding type and index.
     * @method jibo.mim.MimConfig~hasErrorPrompt
     * @param {String} error The error type
     * @param {Number} index The prompt index
     * @return {Boolean}
     */
    public hasErrorPrompt(error:string, index:number):boolean {
        let errorCategory:string;
        if (error === 'noInput') {
            errorCategory = PROMPT_SUB_CATEGORY_NO_INPUT;
        } else if (error === 'noMatch') {
            errorCategory = PROMPT_SUB_CATEGORY_NO_MATCH;
        } else {
            return false;
        }
        for (let prompt of this.prompts) {
            if (prompt.promptCategory === PROMPT_CATEGORY_ERROR &&
                prompt.promptSubCategory === errorCategory && prompt.index === index) {
                return true;
            }
        }
        return false;
    }
    
    /**
     * See if MimConfig has at least one verbose prompt.
     * @method jibo.mim.MimConfig~hasVerbosePrompt
     * @return {Boolean}
     */
    public hasVerbosePrompt():boolean {
        for (let prompt of this.prompts) {
            if (prompt.promptCategory === PROMPT_CATEGORY_ENTRY &&
                prompt.promptSubCategory === PROMPT_SUB_CATEGORY_VERBOSE) {
                return true;
            }
        }
        return false;
    }
    
    /**
     * See if MimConfig has at least one truncated prompt.
     * @method jibo.mim.MimConfig~hasTruncatedPrompt
     * @return {Boolean}
     */
    public hasTruncatedPrompt():boolean {
        for (let prompt of this.prompts) {
            if (prompt.promptCategory === PROMPT_CATEGORY_ENTRY &&
                prompt.promptSubCategory === PROMPT_SUB_CATEGORY_TRUNCATED) {
                return true;
            }
        }
        return false;
    }

    public initWithJSON(data):void {
        this.mimType = data.mim_type;
        //'announce' was changed to 'announcement' in our database of MIM files, but we potentially
        //have a bunch of mims that have not been updated
        if (this.mimType === 'announce') {
            this.mimType = TYPE_AN;
        }
        this.ruleName = data.rule_name;
        if (data.gui_config) {
            this.guiConfig = data.gui_config;
        } else {
            this.sampleUtterances = data.sample_utterances;
        }
        //convert string to number
        this.timeout = parseFloat(data.timeout);
        // timeout must be greater than 0 (although values < 1 are probably not useful)
        if (this.mimType !== TYPE_AN && !(this.timeout > 0)) {
            console.error(`Timeout is an invalid value (${this.timeout}) in mim ${this.mimId}`);
            //default to avoid immediately breaking things
            this.timeout = 6;
        }
        this.numTriesForGUI = parseInt(data.num_tries_for_gui);
        //ensure that numTriesForGUI has an integer value of at least 0
        if (!(this.numTriesForGUI >= 0)) {
            this.numTriesForGUI = 2;
        }
        //bargeIn and esAutoTagging both default to true
        this.bargeIn = data.barge_in !== false;
        this.esAutoTagging = data.es_auto_tagging !== false;
        //only Optional Response mims are allowed to ignore no match errors
        if (this.mimType === TYPE_OR) {
            this.ignoreNoMatch = data.ignore_no_match === true;
            this.listenMode = ListenModes.OR;
        }
        //NOTE: might not use this feature, but adding it here just in case
        if (data.listenMode) {
            switch(data.listenMode) {
                case 'OR':
                    this.listenMode = ListenModes.OR;
                    break;
                case 'UI':
                    this.listenMode = ListenModes.UI;
                    break;
                case 'NO_BODY':
                    this.listenMode = ListenModes.NO_BODY;
                    break;
            }
        }

        if (data.prompts) {
            for(let prompt_data of data.prompts) {
                this.addPromptWithJSON(prompt_data);
            }
        }
    }

    private getPromptWithCategoryAndSubCategory(category:PromptCategory,
                                                sub_category:PromptSubCategory,
                                                promptData:any):MimPrompt {
        let prompts = [];
        let result = null;
        let totalWeight = 0;

        for (let prompt of this.prompts) {
            if (prompt.promptCategory === category &&
                prompt.promptSubCategory === sub_category &&
                this.promptMeetsCondition(prompt, promptData)) {

                prompts.push(prompt);
                totalWeight += prompt.weight;
            }
        }
        const rand = Math.random() * totalWeight;
        let ongoingWeight = 0;
        for (let i = 0; i < prompts.length; ++i) {
            ongoingWeight += prompts[i].weight;
            if (rand <= ongoingWeight) {
                result = prompts[i];
                break;
            }
        }
        return result;
    }

    private getErrorNoMatchPrompt(promptData:any, index:number):MimPrompt {
        let prompts = [];
        let result = null;
        let totalWeight = 0;
        for (let prompt of this.prompts) {
            if (prompt.promptCategory === PROMPT_CATEGORY_ERROR &&
                prompt.promptSubCategory === PROMPT_SUB_CATEGORY_NO_MATCH &&
                prompt.index === index && this.promptMeetsCondition(prompt, promptData)) {

                prompts.push(prompt);
                totalWeight += prompt.weight;
            }
        }

        const rand = Math.random() * totalWeight;
        let ongoingWeight = 0;
        for (let i = 0; i < prompts.length; ++i) {
            ongoingWeight += prompts[i].weight;
            if (rand <= ongoingWeight) {
                result = prompts[i];
                break;
            }
        }
        return result;
    }

    private getErrorNoInputPrompt(promptData:any, index:number):MimPrompt {
        let prompts = [];
        let result = null;
        let totalWeight = 0;
        for (let prompt of this.prompts) {
            if (prompt.promptCategory === PROMPT_CATEGORY_ERROR &&
              prompt.promptSubCategory === PROMPT_SUB_CATEGORY_NO_INPUT &&
              prompt.index === index && this.promptMeetsCondition(prompt, promptData)) {

                prompts.push(prompt);
                totalWeight += prompt.weight;
            }
        }

        const rand = Math.random() * totalWeight;
        let ongoingWeight = 0;
        for (let i = 0; i < prompts.length; ++i) {
            ongoingWeight += prompts[i].weight;
            if (rand <= ongoingWeight) {
                result = prompts[i];
                break;
            }
        }
        return result;
    }

    private promptMeetsCondition(prompt:MimPrompt, promptData:vm.Context | any):boolean {
        if (!promptData || !prompt.condition) {
            return true;
        }

        //zero or negative weights should be interpreted as 'never pick this prompt'
        if (promptData.weight && promptData.weight <= 0) {
            return false;
        }

        //remove the leading '${' and trailing '}' from the condition string, because
        //we don't want those - older mims may have been created with them present
        let condition = prompt.condition.replace(/^\$\{/, "").replace(/\}$/, "");
        //do a safe eval on the condition
        try {
            let isTrue = false;
            if (vm.isContext(promptData)) {
                isTrue = vm.runInContext(condition, promptData);
            } else {
                isTrue = vm.runInNewContext(condition, promptData);
            }
            return isTrue;
        } catch (e) {
            console.error(`error evaluating prompt condition: ${prompt.condition} - error: ${e.message}`);
            return false;
        }
    }

    private addPromptWithJSON(data):void {
        this.prompts.push(new MimPrompt(data));
    }
}
