import {EventEmitter} from 'events';
import Runtime from '../Runtime';
import {HTTPClient} from 'jibo-client-framework';

interface StorePhotoResult {
    id:string;
    thumbnails:{[key:string]:string};
}

/**
 * @description
 * Media Service
 * ```
 * jibo.lps.takePhoto(
 *    jibo.lps.PhotoRes.LARGE,
 *    true,
 *    jibo.lps.CameraID.LEFT,
 *    jibo.lps.PhotoType.FULL,
 *    (error, imageUrl) => {
 *       jibo.loader.load({src: imageUrl, format: 'binary'}, (error, buffer) => {
 *          jibo.media.storePhoto(
 *             buffer,
 *             {
 *                "80x80": [80, 80],
 *                "330x330": [330, 330]
 *             },
 *             (error, result) => {
 *                jibo.media.getPhoto(result.thumbnails['330x330'], (err, pixiTexture) => {
 *                   const s = new PIXI.Sprite();
 *                   s.texture = pixiTexture;
 *                   jibo.face.stage.addChild(s);
 *                })
 *             }
 *          );
 *       });
 *    }
 * );
 *
 * ```
 * @namespace jibo.media
 * @extends {EventEmitter}
 */
class MediaService extends EventEmitter {

    private mediaServiceUrl:string;
    private http:HTTPClient;
    private isInitialized:boolean = false;
    private _recording:boolean = false;

    constructor() {
        super();
        this.isInitialized = false;
    }

    init(service, cb) {
        if (!service.host || typeof service.host !== 'string') {
            throw new Error(`Missing required service.host`);
        }
        this.mediaServiceUrl = "http://" + service.host + ":" + service.port;
        this.isInitialized = true;

        this.http = new HTTPClient(service.host, service.port);
        cb();
    }


    /**
     * Callback for {@link jibo.media#storePhoto}.
     * @callback jibo.media.OnStorePhoto
     * @param {Error} error `null` if there is no error.
     * @param {Object} result   The object's keys correspond to the thumbnail keys provided in the `thumbnails`
     *                          argument of `storePhoto`.
     *                          Values are the photo id as assigned by the media service. Use `getPhoto` to retrieve the
     *                          PIXI.Texture that corresponds to this photo, or `getUrlById` to get the url as served
     *                          by the media service.
     */

    /**
     * Store a photo and thumbnails to disk and return the UUID of each saved image.
     * @param {Buffer} buffer The image buffer to save to disk,
     * @param {object} thumbnails Keys are id to associate with that thumbnail. Values are two element Arrays, where the
     *                            first element is the width of the thumbnail, and the second if the height in pixels.
     * @param {jibo.media.OnStorePhoto} callback Called when photos are stored.
     * @method jibo.media#storePhoto
     */
    storePhoto(buffer:Buffer, thumbnails:{[key:string]:[number, number]}, callback:(err:Error, result:StorePhotoResult) => void):void {
        const request = new XMLHttpRequest();
        request.open("POST", this.mediaServiceUrl + '/media/photo/store', true);
        request.onreadystatechange = () => {
            if(request.readyState === 4 && request.status === 200) {
                let response:StorePhotoResult = JSON.parse(request.response);
                callback(null, response);
            }
            else if(request.readyState === 4) {
                callback(new Error('Error ' + request.status), null);
            }
        };
        request.send(JSON.stringify({
            buffer: buffer.toString('base64'),
            thumbnails
        }));
    }

    /**
     * @description Retrieve the PIXI.Texture that corresponds to the specified photo.
     * @param {string} id The photo ID to retrieve the texture for.
     * @param callback {Function} Node style callback that returns a `PIXI.Texture`.
     * @method jibo.media#getPhoto
     */
    getPhoto(id:string, callback:(err:Error, image:any) => void):void {
        Runtime.instance.loader.load({
            format: 'image',
            src: this.getUrlById(id),
            type: 'texture'
        }, callback);
    }

    /**
     * Get a URL given a photo ID.
     * @param {string} id ID of the photo.
     * @returns {string} URL to the photo.
     * @method jibo.media#getUrlById
     */
    getUrlById(id:string):string {
        return this.mediaServiceUrl + `/media/photo/get?id=${id}`;
    }

    /**
     * Start recording audio and/or video.
     *
     * **Example**
     * ```
     * jibo.media.startRecording({
     *      audio: {},
     *      video: { width: 1280, height: 720 }
     * }, (err, recordingInfo) => {
     *     if(err){
     *         // Handle error
     *         return;
     *     }
     *
     *     // Save the id for playback later
     *     const recordingId = recordingInfo.id
     * });
     * ```
     *
     * @param {Object} options Options to configure the recording.
     * @param {Object} [options.audio] If provided, audio will be recorded.
     * @param {Object} [options.video] If provided, video will be recorded.
     * @param {Object} [options.video.width=640] The width the recorded video should be.
     * @param {Object} [options.video.height=360] The height the recorded video should be.
     * @param {Function} callback   Return an error or information about the started recording in the form {id: <recordingId> }.
     * @method jibo.media#startRecording
     */
    startRecording( options, callback ) {
        if( this._recording === true ) {
            throw new Error("jibo.media.startRecording() was called twice. Call jibo.media.stopRecording() before calling it again.");
        }

        let payload:any = {
                "meta": {}
            };

        if( options.audio ) {
            payload.audioRec = {
                volume: 1,
                source: "ASRIn.monitor"
            };
        }

        if( options.video ) {
            payload.videoRec = {
                width: options.video.width || 640,
                height: options.video.height || 360
            };
        }

        this._recording = true;
        this._stopRecording( (err) => {
            if ( err ) {
                callback(err);
                return;
            }

            this.http.postJSON("/media/recording/start", payload, (err, response) => {
                if(err){
                    callback(err);
                    return;
                }
                callback(null, {
                    id: response.id
                });
            });
        });
    }

    /**
     * @description
     * `true` if a recording is in progress.
     *
     * **Example**
     * ```
     * // Don't start a recording while one is progress
     * if( jibo.media.recording === false ){
     *     // Disable record button
     * }
     * ```
     * @name jibo.media.recording
     * @type {boolean}
     * @readOnly
     */
    get recording(){
        return this._recording;
    }

    /**
     * Stop an in-progress recording.
     *
     * **Example**
     * ```
     * jibo.media.stopRecording( (err, recordingInfo) => {
     *     if(err){
     *         // Handle error
     *         return;
     *     }
     *     // Optionally play back the recording now using `jibo.media.playRecording(...)`
     * });
     * ```
     * @param {Function} callback   Provide notification when recording stops
     *                              or an error if something went wrong.
     * @method jibo.media#stopRecording
     */
    stopRecording( callback ) {
        if( this._recording === false ) {
            throw new Error("jibo.media.stopRecording() was called when there was no recording in progress.");
        }

        this._stopRecording( (err) => {
            this._recording = false;

            if ( err ) {
                callback(err);
                return;
            }

            callback(null);
        });
    }

    /*
     * Internal implementation of stopRecording. This one is difference than the main
     * implementation in that it doesn't throw errors when developers call it when
     * no recording was in progress. This is used by startRecording(), which calls
     * the robot media service to stop any rogue recording that might have been left running.
     * TODO: The robot media service should auto timeout or support auto stopping when
     * recording/start is called. Jira ticket here:
     * https://jira.jibo.com/browse/PLATSVCS-758
     */
    _stopRecording( callback ) {
        let payload = {
                id: 0,
                cmd:"stop"
            };

        this.http.postJSON("/media/recording/control", payload, (err) => {
            if ( err ) {
                callback(err);
                return;
            }

            callback(null);
        });
    }

    /**
     * @description
     * Play back a previous recording.
     *
     * **Example**
     * ```
     * jibo.media.playRecording( { id: "<recordingId>" }, (err) => {
     *     if(err){
     *         // Handle error
     *         return;
     *     }
     *
     *     // Re-enable the playback button
     * });
     * ```
     *
     * @param {Object} options Options to configure the playback.
     * @param {Object} options.id ID of a known recording. See {@link jibo.media#startRecording} for how to get an ID.
     * @param {Function} callback   Return when the playback is successfully started or an error
     *                              if something went wrong. Note: There are no playback controls, such as stop/pause/unpause. Coming soon.
     * @method jibo.media#playRecording
     */
    playRecording( options, callback ) {
        let payload = {
                source : options.id,
                audio : {
                    volume : 1
                }
            };

        this.http.postJSON("/media/recording/play", payload, (err, response) => {
            if(err){
                callback(err);
                return;
            }
            callback(null);
        });

    }
}

export default MediaService;
