import Procedure from '../Procedure';

/**
 * Loader for Behaviorify-processed .flow files.
 * @class TreeLoader
 * @memberof jibo.flow.core.loaders
 * @internal
 */

class TreeLoader {
    public static getStartProcedureOrName(data:any):Procedure {
        return data;
    }

    public static getUri(data:any):string {
        return data().meta.uri;
    }

    public static loadProcedureRelative(uri:any, procedureObject:any):Procedure {
        let procedure = new Procedure();
        procedure.loadPropertiesFromTreeFunction(procedureObject);
        return procedure;
    }
}

export default TreeLoader;