import FlowExecutor from './FlowExecutor';
import Context from './Context';
import Activity from './core/Activity';
import Transition from './core/Transition';
import Status from '../bt/Status';
import Behavior from '../bt/Behavior';
import Decorator from '../bt/Decorator';
import Subtree from "../bt/behaviors/Subtree";
import Mim from '../bt/behaviors/Mim';
import {MimResult} from '../bt/mim/MimResult';
import Menu from '../bt/behaviors/Menu';
import * as path from 'path';


/**
 * ActivityImplementations encapsulate the runtime logic for
 * each of the [built-in] Activity types. An ActivityImplementation instance is
 * created anew by the Flow Executor every time a Flow Activity is to be executed.
 * @class ActivityImplementation
 * @memberof jibo.flow
 * @param {jibo.flow.Activity} activity Flow Activity to instantiate
 * @param {jibo.flow.FlowExecutor} flowExecutor The Flow Executor that will execute it
 * @internal
 */

class ActivityImplementation {
    public name:string;
    public class:string;
    // "Result" is the activity's result (which may be an arbitrary object) that will be
    // converted into a string when selecting the activity's output transition.
    public result:any;
    public optionCodeThis:any;  // All user code supplied in Options has access to a 'this.' which is stored here.
    public exceptionPayload:any; // if result starts with a ~, this is (potentially) the payload accompanying it.
    public options:any;//{ [key:string]:any };
    public transitions:Transition[];
    public exceptions:Transition[];

    /**
     * Perform whatever pre-update setup is required.
     * Return true for success, false for failure.
     * If a failure, update will not be called.
     * @method jibo.flow.ActivityImplementation#start
     * @param {jibo.flow.Context} context The executor's context
     * @returns {boolean}
     */
    public start(context:Context): boolean {return true;};

    /**
     * Perform the activity's normal update action. This will continue to be
     * called on every update tick until it returns SUCCEEDED or FAILED.
     * @method jibo.flow.ActivityImplementation#update
     * @param {jibo.flow.Context} context The executor's context
     * @returns {jibo.bt.Status}
     */
    public update(context:Context): Status {return Status.SUCCEEDED;};
    
    /**
     * Stop any ongoing activity (called during the processing of Flow.Interrupt and general exceptions).
     * This is provided so that an asynchronous activity can be stopped and its resources released.
     * @method jibo.flow.ActivityImplementation#stop
     * @param {jibo.flow.Context} context The executor's context
     * @return {Promise<void>} A promise that resolves after any asynchronous cleanup has been performed.
     */
    public stop(context:Context):Promise<void> {
        return Promise.resolve();
    };
    
    /**
     * Destroy the activity, doing a full cleanup of any resources that need releasing.
     * @method jibo.flow.ActivityImplementation#destroy
     */
    public destroy():void { /* */ };

    constructor(public activity:Activity, public flowExecutor:FlowExecutor, optionCodeThis:any) {
        this.name = activity.name;
        this.class = activity.class;
        this.optionCodeThis = optionCodeThis;
        this.options = flowExecutor.context.getActivityOptions(activity.id, this.optionCodeThis);
        this.transitions = activity.transitions;
        this.exceptions = activity.exceptions;
        this.result = null;
        this.exceptionPayload = null;
    }

    /**
     * If the Flow has a transition or Flow.Catch in scope capable of handling the given JS exception, turn it into
     * a Flow ~Exception.* and process it internally, otherwise stop Flow execution and throw the JS exception.
     * @method jibo.flow.ActivityImplementation#formOrThrowException
     * @param jsexception {Exception} Javascript Exception object to throw as a JS exception or convert to a Flow exception
     * @returns {string} the name of the Flow Exception to be thrown
     */
    public formOrThrowException(jsexception:any) {
        let exception =  '~Exception.' + jsexception.name;
        if (!this.flowExecutor.searchException(exception)) {
            throw jsexception;
        }
        return exception;
    }

    public getResultAsString() {
        let activityResult = this.result;

        if (activityResult === undefined) {
            activityResult = '';
        }
        return String(activityResult);
    }
}

/**
 * Mark the beginning of execution in a flow procedure.
 * @class FlowBegin
 * @memberof jibo.flow
 * @internal
 */
class FlowBegin extends ActivityImplementation {}

/**
 * Do nothing.
 * @class FlowNop
 * @memberof jibo.flow
 * @internal
 */
class FlowNop extends ActivityImplementation {}

/**
 * Mark the beginning of a parallel thread of execution in a flow procedure.
 * @class FlowBeginParallel
 * @memberof jibo.flow
 * @internal
 */
class FlowBeginParallel extends ActivityImplementation {}

/**
 * Wait the user-provided number of milliseconds.
 * @class FlowWait
 * @memberof jibo.flow
 * @internal
 */
class FlowWait extends ActivityImplementation {
    startTime:number;
    ms_to_pause:number;

    start() {
        this.startTime = Date.now();
        this.ms_to_pause = parseFloat(this.options.ms_to_pause);
        return true;
    }
    update() {
        let success = Date.now() - this.startTime >= this.ms_to_pause;
        return success ? Status.SUCCEEDED : Status.IN_PROGRESS;
    }
}

/**
 * Call another Flow procedure.
 * @class FlowSubflow
 * @memberof jibo.flow
 * @internal
 */
class FlowSubflow extends ActivityImplementation {
    update() {
        // Handle the case where we're passed a function that does a 'require' of the flow code.
        let subflow
            = typeof this.options.subflowId === typeof ''
            ? this.options.subflowId
            : this.options.subflowId();
        this.flowExecutor.enterProcedure(subflow, undefined, this.options.inputParameters());
        return Status.SUCCEEDED;
    }
}

/**
 * End the execution of the current Flow procedure and possible the entire flow.
 * FlowEnd uses the update hook (instead of the start hook)
 * because of the effect it has on the FlowExecutor's state.
 * @class FlowEnd
 * @memberof jibo.flow
 * @internal
 */
class FlowEnd extends ActivityImplementation {
    update() {
        let transition = this.options.getTransition();
        if (transition === undefined) {
            transition = this.name || '';
        }
        this.flowExecutor.returnFromProcedure(transition);
        return Status.SUCCEEDED;
    }
}

/**
 * Catch Flow exceptions.
 * @class FlowCatch
 * @memberof jibo.flow
 * @internal
 */
class FlowCatch extends ActivityImplementation {
    update() {
        // Backward compatability with old flows without this parameter:
        if (typeof(this.options.getTransition) === 'function') {
            // Although the ExceptionInfo is available to the Activity as this.in, we provide
            // it as well via arguments on the getTransition method.
            this.result = this.options.getTransition(this.optionCodeThis.in.name, this.optionCodeThis.in.payload);
        }
        return Status.SUCCEEDED;
    }
}

/**
 * Throw Flow exceptions.
 * @class FlowThrow
 * @memberof jibo.flow
 * @internal
 */
class FlowThrow extends ActivityImplementation {
    update() {
        this.result = this.name;
        this.exceptionPayload = this.options.getPayload && this.options.getPayload();
        return Status.SUCCEEDED;
    }
}

/**
 * Cause an exception in the primary thread of a Flow (used by parallel threads).
 * @class FlowInterrupt
 * @memberof jibo.flow
 * @internal
 */
class FlowInterrupt extends ActivityImplementation {
    update() {
        this.flowExecutor.injectExceptionInPrimary(this.name);
        this.result = '';
        return Status.SUCCEEDED;
    }
}

/**
 * Evaluate an arbitrary bit of JS code.
 * @class FlowEval
 * @memberof jibo.flow
 * @internal
 */
class FlowEval extends ActivityImplementation {
    update() {
        this.result = this.options.Script();
        return Status.SUCCEEDED;
    }
}

/**
 * Call the given behavior (used to wrap a Behavior in a Flow Activity).
 * @class FlowBehavior
 * @memberof jibo.flow
 * @internal
 */
export class FlowBehavior extends ActivityImplementation {
    constructor(activity:Activity, flowExecutor:FlowExecutor, public behavior:Behavior|Decorator, optionCodeThis:any) {
        super(activity, flowExecutor, optionCodeThis);
    }
    start() {
        return <boolean>this.behavior.start();
    }
    update() {
        return this.behavior.update(Status.IN_PROGRESS);
    }
    stop() {
        return this.behavior ? this.behavior.stop() : Promise.resolve();
    }
    destroy() {
        if (this.behavior) {
            this.behavior.destroy();
            this.behavior = null;
        }
    }
}

type MimSuccessResult = MimResult & {firstGrammarTag:string, grammarResults:any};
type MimFailureResult = MimResult & {exception:string};

/**
 * Execute a Mim behavior.
 * @class FlowMim
 * @memberof jibo.flow
 * @internal
 */
export class FlowMim extends ActivityImplementation {
    private mim:Mim;
    private transition:string;
    private activityClass:string;

    constructor(activity:Activity, flowExecutor:FlowExecutor, optionCodeThis:any) {
        super(activity, flowExecutor, optionCodeThis);
        let options = this.options;
        this.activityClass = activity.class;

        // allow for deprecated mim pathing
        if (options.mimId && !options.mimPath) {
            let env = flowExecutor.environment;
            options.mimPath = path.join('mims', env.language, options.mimId);
            if (!options.mimPath.endsWith('.mim')) {
                options.mimPath += '.mim';
            }
            if (!options.config) {
                options.config = {};
            }
            //supply default rule path in case of old mim
            options.config.rulesPath = path.join('rules', env.language);
        }
        if (typeof options.getMimPath === 'function') {
            options.mimPath = options.getMimPath();
        }

        //wrap success callback
        if (!options.innerOnSuccess) {
            options.innerOnSuccess = options.onSuccess || options.onResults;
        }
        let onSuccess =
            // Mim.Announcements have no success or failure methods.
            this.activityClass === 'Mim.Announcement'
                ? ()=> {/* */}
                : (result:MimSuccessResult) => {
                let firstGrammarTag = '';
                if (result.asrResults && result.asrResults.NLParse) {
                    let firstSlot = result.asrResults.slotIds[0];
                    firstGrammarTag = result.firstGrammarTag = result.asrResults.NLParse[firstSlot];
                    result.grammarResults = result.asrResults.NLParse;
                }
                let transition = options.innerOnSuccess(result);
                if (transition === undefined) {
                    transition = firstGrammarTag;
                }
                this.transition = transition;
            };
        options.onSuccess = onSuccess;

        //wrap failure callback
        if (!options.innerOnFailure) {
            options.innerOnFailure = options.onFailure;
        }
        let onFailure =
            // Only Mim.Questions have onFailure methods.
            this.activityClass !== 'Mim.Question'
                ? ()=> {/* */}
                : (result:MimFailureResult) => {
                let exception = "~InteractionError." + result.state.lastResultState;
                result.exception = exception;
                let transition = options.innerOnFailure(result);
                if (transition === undefined) {
                    transition = exception;
                }
                this.transition = transition;
                // Return to the Mim an indication of whether the
                // exception from the Mim failure can be handled by the flow.
                return flowExecutor.searchException(transition) !== undefined;
            };

        options.onFailure = onFailure;
        options.assetPack = flowExecutor.assetPack;
        options.blackboard = flowExecutor.blackboard;
        options.emitter = flowExecutor.emitter;
        options.asrMetadata = {
            skill: flowExecutor.assetPack,
            flowFile: flowExecutor.environment.currentFile,
            activityName: activity.name,
            activityId: activity.id
        };

        //make our Mim
        this.mim = new Mim(options);
    }

    start() {
        return this.mim.start();
    }

    update():Status {
        let status:Status = this.mim.update();
        if(status !== Status.IN_PROGRESS) {
            this.result = this.transition;
        }
        return status;
    }
    stop() {
        return this.mim ? this.mim.stop() : Promise.resolve();
    }
    destroy() {
        if (this.mim) {
            this.mim.destroy();
            this.mim = null;
        }
    }
}

/**
 * Execute a Behavior Tree.
 * @class FlowSubtree
 * @memberof jibo.flow
 * @internal
 */
export class FlowSubtree extends ActivityImplementation {

    private subtree:Subtree;
    private transition:string;

    constructor(activity:Activity, flowExecutor:FlowExecutor, optionCodeThis:any) {
        super(activity, flowExecutor, optionCodeThis);
        if(!this.options.onInnerResult) {
            this.options.onInnerResult = this.options.onResult;
        }

        let onResult = (result) => {
            this.transition = this.options.onInnerResult(result);
        };
        this.options.onResult = onResult;
        this.options.assetPack = flowExecutor.assetPack;
        this.options.blackboard = flowExecutor.blackboard;
        this.options.emitter = flowExecutor.emitter;
        this.subtree = new Subtree(this.options);
    }

    start() {
        return this.subtree.start();
    }

    update():Status {
        let status:Status = this.subtree.update();
        if(status !== Status.IN_PROGRESS) {
            this.result = this.transition;
        }
        return status;
    }
    
    stop() {
        return this.subtree ? this.subtree.stop() : Promise.resolve();
    }
    
    destroy() {
        if (this.subtree) {
            this.subtree.destroy();
            this.subtree = null;
        }
    }
}

/**
 * Evaluate an arbitrary bit of JS code.
 * Flow execution continues to the next activity when the given JS code invokes the provided callback.
 * @class FlowEvalAsync
 * @memberof jibo.flow
 * @internal
 */
export class FlowEvalAsync extends ActivityImplementation {
    private isDone:boolean;

    start() {
        this.isDone = false;
        try {
            this.options.exec((transition:string):void => {
                if (!this.isDone) {
                    this.isDone = true;
                    this.result = transition;
                }
            });
        } catch (e) {
            if (!this.isDone) {
                this.isDone = true;
                this.exceptionPayload = e;
                this.result = this.formOrThrowException(e);
            }
        }
        return true;
    }

    update():Status {
        if(this.isDone) {
            return Status.SUCCEEDED;
        }
        return Status.IN_PROGRESS;
    }

    stop():Promise<void> {
        if (this.options.onStop) {
            //allow onStop() to return a promise - currently not documented anywhere
            return this.options.onStop() || Promise.resolve();
        }
        return Promise.resolve();
    }
}

/**
 * Offer the user a multiple choice menu.
 * @class FlowMenu
 * @memberof jibo.flow
 * @internal
 */
export class FlowMenu extends ActivityImplementation {
    private menu:Menu;
    private transition:string;

    constructor(activity:Activity, flowExecutor:FlowExecutor, optionCodeThis:any) {
        super(activity, flowExecutor, optionCodeThis);
        let options = this.options;

        //wrap success callback
        if (!options.innerOnItemChosen) {
            options.innerOnItemChosen = options.onItemChosen;
            //warn about API change
            if (options.innerOnItemChosen.length === 2) {
                console.warn('Menu::onItemChosen signature has changed from (result, menu) => string to (result, menu, overrideMenuTransition) => string');
            }
        }
        let onItemChosen = (result:any, menu:any, overrideMenuTransition:Function) => {
            let firstGrammarTag = '';
            //result might be an AsrResult - it also might not, depending on the menu setup
            if (result && result.NLParse && result.slotIds) {
                let firstSlot = result.slotIds[0];
                firstGrammarTag = result.NLParse[firstSlot];
            }
            let transition = options.innerOnItemChosen(result, menu, overrideMenuTransition);
            if (transition === undefined) {
                transition = firstGrammarTag;
            }
            this.transition = transition;
        };
        options.onItemChosen = onItemChosen;

        //wrap failure callback
        if (!options.innerOnMenuClosed) {
            options.innerOnMenuClosed = options.onMenuClosed;
            //warn about API change
            if (options.innerOnMenuClosed.length === 3) {
                console.warn('Menu::onMenuClosed signature has changed from (wasTimeout, menu, exception) => string to (wasTimeout, menu, overrideMenuTransition, exception) => string');
            }
        }
        let onMenuClosed = (timedOut:boolean, menu:any, overrideMenuTransition:Function) => {
            let exception = "~InteractionError." + (timedOut ? 'MenuTimeout' : 'MenuClosed');
            let transition = options.innerOnMenuClosed(timedOut, menu, overrideMenuTransition, exception);
            if (transition === undefined) {
                transition = exception;
            }
            this.transition = transition;
            // Return to the Mim an indication of whether the
            // exception from the Mim failure can be handled by the flow.
            return flowExecutor.searchException(transition) !== undefined;
        };

        options.onMenuClosed = onMenuClosed;
        options.assetPack = flowExecutor.assetPack;
        options.blackboard = flowExecutor.blackboard;
        options.emitter = flowExecutor.emitter;

        //make our Menu
        this.menu = new Menu(options);
    }

    start() {
        return this.menu.start();
    }

    update():Status {
        let status:Status = this.menu.update();
        if(status !== Status.IN_PROGRESS) {
            this.result = this.transition;
            //if the menu failed, throw an error, otherwise the result will be ''
            if (status === Status.FAILED) {
                this.result = this.transition = '~MenuFailed';
            }
        }
        return status;
    }
    stop() {
        return this.menu ? this.menu.stop() : Promise.resolve();
    }
    destroy() {
        if (this.menu) {
            this.menu.destroy();
            this.menu = null;
        }
    }
}

export let FlowClasses = {
    FlowBegin,
    FlowBeginParallel,
    FlowInterrupt,
    FlowCatch,
    FlowEvalAsync,
    FlowNop,
    FlowWait,
    FlowSubflow,
    FlowSubtree,
    FlowEnd,
    FlowThrow,
    FlowEval,
    Mim: FlowMim,
    MimAnnouncement: FlowMim,
    MimOptionalResponse: FlowMim,
    MimQuestion: FlowMim,
    Menu: FlowMenu
};

export default ActivityImplementation;
