import { ParseResults } from '../../services/gl/DataTypes';

/**
 * Wrapper for ASR results. Returned by Mim callbacks.
 * @class AsrResult
 * @memberof jibo.mim
 */
export default class AsrResult {
    /**
     * Original parse result data.
     * @name jibo.mim.AsrResult~data
     * @type {jibo.gl.ParseResults}
     */
    public data: ParseResults;
    /**
     * Raw text input to NLParse
     * @name jibo.mim.AsrResult~Input
     * @type {String}
     */
    public Input: string;
    /**
     * NLParse according to given parse rule
     * @name jibo.mim.AsrResult~NLParse
     * @type {any}
     */
    public NLParse: any;
    /**
     * Score for how well the text input parsed against the rule.
     * @name jibo.mim.AsrResult~heuristic_score
     * @type {Number}
     */
    public heuristic_score: number;
    /**
     * List of slot names on the NLParse object.
     * @name jibo.mim.AsrResult~slotIds
     * @type {String[]}
     */
    public slotIds: string[];

    constructor(data:ParseResults) {
        this.data = data;
        this.Input = null;
        this.NLParse = null;
        this.heuristic_score = 0;
        this.slotIds = null;

        if (data) {
            this.Input = data.Input;
            this.NLParse = data.NLParse || {};
            this.heuristic_score = data.heuristic_score;

            this.slotIds = [];
            if (this.NLParse) {
                let id:string;
                for (id in this.NLParse) {
                    //NLParse may have a 'union_original_fst_name' property that is not a slot
                    //it used to have a 'status' property, but doesn't seem to anymore
                    if (id !== 'union_original_fst_name' && this.NLParse.hasOwnProperty(id)) {
                        this.slotIds.push(id);
                    }
                }
            }
        }
    }

    //property deprecation
    /*
     * Getter for Input, so code written for old MIMs still functions.
     * @deprecated
     */
    public get input():string {
        return this.Input;
    }
    /*
     * Getter for NLParse, so that code written for old MIMs still functions.
     * @deprecated
     */
    public get nlParse():any {
        return this.NLParse;
    }

    /**
     * The type of MIM response this result represents.
     * Can be 'noInput', 'noMatch', or 'match'.
     * @name jibo.mim.AsrResult~state
     * @type {String}
     * @readOnly
     */
    public get state():'noInput'|'noMatch'|'match' {
        if (!this.Input) {
            return 'noInput';
        } else if (!this.slotIds || this.slotIds.length === 0) {
            return 'noMatch';
        } else if (this.Input && (this.slotIds && this.slotIds.length > 0)) {
            return 'match';
        }
        //should never reach this point, unless someone is improperly using AsrResult.
        //but just for safety, return a value
        return 'noInput';
    }
}
