import EyeMesh from './EyeMesh';
import DOFValues from "./DOFValues";
import path = require('path');
import Runtime from '../../Runtime';

/**
 * Abstract class for eye overlay and eye classes.
 * @class AbstractEye
 * @extends PIXI.Container
 * @memberof jibo.face
 * @param {Boolean} cache `true` to cache textures.
 */
abstract class AbstractEye extends PIXI.Container {

    /**
     * The eye mesh.
     * @name jibo.face.AbstractEye#eyeMesh
     * @type {jibo.face.EyeMesh}
     */
    public eyeMesh:EyeMesh;

    /**
     * Tint filter.
     * @name jibo.face.AbstractEye#filter
     * @type {PIXI.filters.ColorMatrixFilter}
     */
    public filter:PIXI.filters.ColorMatrixFilter;

    /**
     * Previous texture path.
     * @name jibo.face.AbstractEye#texturePrev
     * @type {String}
     */
    public texturePrev:string;

    /**
     * If should update according to DOFValues.
     * @name jibo.face.AbstractEye#connected
     * @type {String}
     */
    public connected:boolean;

    private _emptyTexture:PIXI.Texture;
    private _texture:PIXI.Texture;
    private _textureId:string;
    private _destroyed:boolean;

    constructor(public cache:boolean) {

        super();

        // Create an empty canvas texture because
        // Texture.EMPTY renders as a black square
        let canvas:HTMLCanvasElement = document.createElement('canvas');
        canvas.width = 1;
        canvas.height = 1;
        this._emptyTexture = PIXI.Texture.fromCanvas(canvas);

        this.filter = new PIXI.filters.ColorMatrixFilter();
        this.filter.reset();
        this.cache = cache;

        this.filters = [this.filter];
        this.x = 0;
        this.y = 0;

        this.eyeMesh = new EyeMesh(this._emptyTexture);
        this.addChild(this.eyeMesh);

        this.visible = true;
        this.connected = true;
        this._destroyed = false;
    }

    /**
     * Path to the texture to load.
     * @name jibo.face.AbstractEye#texture
     * @type {String}
     */
    set texture(value:string) {

        if (this._textureId && !this.cache) {
            Runtime.instance.loader.unload(this._textureId);
        }
        if(path.extname(value).length === 0) {
            this.visible = false;
            return;
        }

        // Trying to reload the texture that's already set
        // or it's being loaded currently, chill for a sec
        if (this._textureId === value) {
            return;
        }

        // Update the texture id and check for cached texture
        this._textureId = value;
        const cachedTexture = Runtime.instance.loader.cached(value);

        // If the texture is already cached, let's use that!
        if (cachedTexture) {
            this._texture =
            this.eyeMesh.texture = cachedTexture;
        }
        else {
            // Load the eye texture to render
            Runtime.instance.loader.load({
                id: value,
                src: value,
                type: 'texture',
                cache: this.cache,
                complete: (err, texture) => {
                    this._texture = this.eyeMesh.texture = texture;
                    this.visible = true;
                }
            });
        }
    }

    /**
     * Red value to tint.
     * @name jibo.face.AbstractEye#red
     * @type {Number}
     */
    set red(value:number) {
        this.filter.matrix[0] = value;
    }

    /**
     * Green value to tint.
     * @name jibo.face.AbstractEye#green
     * @type {Number}
     */
    set green(value:number) {
        this.filter.matrix[6] = value;
    }

    /**
     * Blue value to tint.
     * @name jibo.face.AbstractEye#blue
     * @type {Number}
     */
    set blue(value:number) {
        this.filter.matrix[12] = value;
    }

    /**
     * Destroy and don't use after this.
     * @method jibo.face.AbstractEye#destroy
     */
    destroy(): void {
        if (this._destroyed) {
            return;
        }
        this._destroyed = true;
        this.filter = null;
        this.eyeMesh = null;
        this._texture = null;
        this._emptyTexture.destroy(true);
        this._emptyTexture = null;
        if (this._textureId) {
            Runtime.instance.loader.unload(this._textureId);
        }
        super.destroy(true);
    }

    abstract update(timestamp:Array<number>, dofValues:DOFValues);
}
export default AbstractEye;
