import Task from '../../loader/tasks/Task';
import AssetManager from '../../loader/AssetManager';
import Runtime from '../../Runtime';
import Callback from '../../loader/LoaderCallback';
import PathUtils from '../../utils/PathUtils';
import Sound from '../Sound';
import SoundPlugin from '../SoundPlugin';
import path = require('path');

/**
 * Internal class for dealing with async load assets through Loader.
 * @class SoundTask
 * @extends jibo.loader.Task
 * @memberof jibo.loader
 * @constructor
 * @private
 * @param {Object} asset The data properties.
 * @param {String} asset.src The source.
 * @param {Boolean} [asset.cache=false] true to cache the result.
 * @param {String} [asset.id] ID of asset.
 */
class SoundTask extends Task
{
    static priority:number;
    public src:string;
    public block:boolean;
    public volume:number;
    public panning:number;
    public loop:boolean;
    public autoPlay:boolean;
    public useXHR:boolean;

    /**
     * Tests if tasks should be run.
     * @method jibo.loader.SoundTask.test
     * @static
     * @param {Object} asset The asset to check.
     * @return {Boolean} true if the asset is compatible with this asset.
     */
    static test(asset:any):boolean
    {
        return !!asset.src && /\.(mp3|m4a|wav|ogg|oga|aif)$/i.test(asset.src);
    }

    constructor(manager:AssetManager, asset:any)
    {
        super(manager, asset, asset.src);

        /**
         * The source URL to load.
         * @type {String}
         * @name jibo.loader.SoundTask#src
         */
        this.src = this.prepare(asset.src);

        /**
         * true to block the audio from being played more than once at a time.
         * @type {Boolean}
         * @name jibo.loader.SoundTask#block
         */
        this.block = !!asset.block;

        /**
         * The initial volume of the sound (0 to 1).
         * @type {Number}
         * @name jibo.loader.SoundTask#volume
         */
        this.volume = asset.volume || 1;

        /**
         * The panning from -1 (left) to 1 (right). Default is 0 (center).
         * @type {Number}
         * @name jibo.loader.SoundTask#panning
         */
        this.panning = asset.panning || 0;

        /**
         * true if the sound should play.
         * @type {Boolean}
         * @name jibo.loader.SoundTask#loop
         */
        this.loop = !!asset.loop;

        /**
         * true to start playing the sound immediately after loading.
         * @type {Boolean}
         * @name jibo.loader.SoundTask#autoPlay
         */
        this.autoPlay = !!asset.autoPlay;

        /**
         * true to use XMLHttpRequest to download file.
         * @type {Boolean}
         * @name jibo.loader.SoundTask#useXHR
         */
        this.useXHR = asset.remote === true || PathUtils.isURL(this.src);
    }

    /**
     * Starts the task.
     * @method  jibo.loader.SoundTask#start
     * @param  {jibo.loader.Task~completeCallback} callback Callback when finished.
     */
    start(callback:Callback): void
    {  
        const alias:string = this.id || path.parse(this.src).name;
        const soundPlugin:SoundPlugin = Runtime.instance.sound;

        // Check for sound with the same alias
        if (soundPlugin.exists(alias))
        {
            const sound:Sound = soundPlugin.sound(alias);

            // Same alias, same sound
            if (sound.src === this.src)
            {
                return callback(null, sound);
            }
            else
            {
                console.info(`Overwriting existing sound (alias: ${alias})`);
                soundPlugin.remove(alias);
            }
        }

        const sound = soundPlugin.add(alias, {
            src: this.src,
            preload: true,
            block: this.block,
            loop: this.loop,
            volume: this.volume,
            panning: this.panning,
            autoPlay: this.autoPlay,
            useXHR: this.useXHR,
            loaded: callback
        });

        // When the sound is destroyed, remove from the
        // the soundmanager plugin
        (<any>sound).__baseDestroy = sound.destroy;
        sound.destroy = function() {
            if (this.__destroyed)
            {
               return;
            }
            this.__destroyed = true;
            soundPlugin.remove(alias);

            //destroy the base texture as well
            (<any>this).__baseDestroy(true);
        };
    }
}

export default SoundTask;
