import { Event, EventContainer } from 'jibo-typed-events';
import { ListenOptions, ListenResults, ParseResults, SpeakerId, Callback } from './DataTypes';
import Runtime from "../../Runtime";

import path = require('path');

let UUID = require('uuid');



export class IncrementalResults {
  constructor(public result: ParseResults,
              private _listener: ClientDialogListener) {}

  stop() {
    this._listener.events.interrupted.emit();
    Runtime.instance.gl.unsubscribe(this._listener);
  }
}

/**
 * @class ListenerEvents
 * @description Typed events for ClientDialogListener (`jibo.gl.events`).
 * ```
 * var listener = jibo.gl.createDialogListener(options, ruleText);
 * listener.events.on.cloudReceived((asrResult) => {
 *    // data is of type ListenResults
 *    // After this event, listener will emit
 *    // unsubscribed.
 *    // Listener is always guaranteed to end with 'unsubscribed' event.
 *    // This will happen automatically after hjOnly, cloudReceived or interrupted,
 *    // but will also happen if you manually call unsubscribe.
 * });
 * ```
 * @memberof jibo.gl
 */
export class ListenerEvents extends EventContainer {
  public cloudReceived: Event<ListenResults>;
  public hjOnly: Event<ListenResults>;
  public interrupted: Event<any>;
  public incremental: Event<IncrementalResults>;
  public eos: Event<any>;
  public sos: Event<any>;
  public hj: Event<any>;
  public speakerId: Event<SpeakerId>;
  public ruleCompiled: Event<string>;
  public unsubscribed: Event<string>;

  constructor() {
    super();
    /**
     * Emit {@link jibo.gl.ListenResults} when cloud results are received.
     * @name jibo.gl.ListenerEvents#cloudReceived
     * @type {Event}
     */
    this.cloudReceived = new Event<ListenResults>('Cloud results');
    /**
     * Emit event when an interrupt is requested.
     * @name jibo.gl.ListenerEvents#interrupted
     * @type {Event}
     */
    this.interrupted = new Event<any>('Interrupt request');
    /**
     * Emit {@link jibo.gl.ListenResults} when incremental results are received.
     * @name jibo.gl.ListenerEvents#incremental
     * @type {Event}
     */
    this.incremental = new Event<IncrementalResults>('Incremental results');
    /**
     * Emit event when end of speech is detected.
     * @name jibo.gl.ListenerEvents#eos
     * @type {Event}
     */
    this.eos = new Event<any>('End of speech');
    /**
     * Emit event when start of speech is detected.
     * @name jibo.gl.ListenerEvents#sos
     * @type {Event}
     */
    this.sos = new Event<any>('Start of speech');
    /**
     * Emit {@link jibo.gl.ListenResults} when "Hey Jibo" is heard.
     * @name jibo.gl.ListenerEvents#hj
     * @type {Event}
     */
    this.hj = new Event<any>('Hey Jibo');
    /**
     * Emit {@link jibo.gl.ListenResults} when only "Hey Jibo" is heard.
     * @name jibo.gl.ListenerEvents#hjOnly
     * @type {Event}
     */
    this.hjOnly = new Event<any>('Hey Jibo Only -- no other speech detected');
    /**
     * Emit {@link jibo.gl.SpeakerId} when Speaker is identified.
     * @name jibo.gl.ListenerEvents#speakerId
     * @return {Event}
     */
    this.speakerId = new Event<SpeakerId>('Speaker Id recognized.');
    /**
     * Emit a string when the rule is compiled.
     * @name jibo.gl.ListenerEvents#ruleCompiled
     * @type {Event}
     */
    this.ruleCompiled = new Event<string>('Rule compiled');
    /**
     * Emit a string when ClientDialogListener has been unsubscribed.
     * @name jibo.gl.ListenerEvents#unsubscribed
     * @type {Event}
     */
    this.unsubscribed = new Event<string>('ClientDialogListener has been unsubscribed');
  }
}

export const RuleTypes = {
    TEXT: 'text',
    FST: 'fst',
    HANDLE: 'handle'
};


/**
 * @class ClientDialogListener
 * @description Dialog listener for listening subscription management.
 * Listens for emitting typed events until `unsubscribed`, at which point the listener
 * is unsubscribed from the listening service. You can also manually call `listener.unsubscribe()`
 * to unsubscribe. In this case, the `unsubscribed` event will fire as well.
 * ```
 * var listener = jibo.gl.createDialogListener(options, ruletext)
 * listener.events.cloudReceived.on((listenData) => {
 *     var parse = data.NLParse // event emits a ListenResults object.
 *     foo(parse);
 * }
 * ```
 * @param {jibo.gl.ListenOptions} options Options for listening
 * @param {Object} ruleData Information about the parsing rule.
 * @param {string} ruleData.rule The parsing rule. Must be sytnactically valid .rule file content OR path to .fst file OR a rule handle.
 * @param {string} ruleData.type Rule type (`text` for .rule file text, `fst` for .fst file path, or `handle` for rule handle).
 * @memberof jibo.gl
 */
export class ClientDialogListener {
  public events: ListenerEvents;
  public _listenerId: string;
  public options: ListenOptions;
  public rule: string;
  public ruleType: string;

  constructor(options: ListenOptions, rule: string|{rule:string, type:string}) {
    /**
     * Typed events of ClientDialogListener module.
     * @name jibo.gl.ClientDialogListener#events
     * @type {jibo.gl.ListenerEvents}
     */
    this.events = new ListenerEvents();
    /**
     * Options for listening.
     * @name jibo.gl.ClientDialogListener#options
     * @type {jibo.gl.ListenOptions}
     */
    this.options = options;
    /**
     * Text of the rule to be used for parsing. Must be sytnactically valid OR path to .fst file.
     * @name jibo.gl.ClientDialogListener#ruleText
     * @type {String}
     */
    if (typeof rule === 'string') {
        this.rule = rule;
        this.ruleType = path.extname(rule) === '.fst' ? RuleTypes.FST : RuleTypes.TEXT;
    } else {
        this.rule = rule.rule;
        this.ruleType = rule.type;
    }
    /**
     * Typed events of ClientDialogListener module.
     * @name jibo.gl.ClientDialogListener#_listenerId
     * @type {String}
     * @readOnly
     */
    this._listenerId = UUID.v1();
  }


/**
 * Convenience to wrap jibo.gl.subscribe.
 * @method jibo.gl.ClientDialogListener#start
 * @param [options] {jibo.gl.ListenOptions} Options for listening.
 * @param callback {Function} Callback with Global Listen response.
 * @public
 */
  public start(options?:any, callback?:Callback):void {
    if(typeof options === "function" && !callback) {
      callback = options;
    }
    Runtime.instance.gl.subscribe(this, callback);
  }

  /**
   * Restart listening task after unsubscribe.
   * @method jibo.gl.ClientDialogListener#restart
   * @param callback {Function} Callback with Global Listen response.
   * @public
   */
  public restart(callback:Callback):void {
    this.start(callback);
  }

  /**
   * Convenience to wrap jibo.gl.unsubscribe
   * Do not need to call if the listener.events has emitted cloudReceived.
   * @method jibo.gl.ClientDialogListener#unsubscribe
   * @param callback {Function} Callback with Global Listen response.
   * @public
   */
  public unsubscribe(callback:Callback):void {
    Runtime.instance.gl.unsubscribe(this, callback);
  }


}
export default ClientDialogListener;