import path = require('path');
import callsite = require('callsite');
import Runtime from '../Runtime';
import BehaviorEmitter from './BehaviorEmitter';
import Blackboard from './Blackboard';
import BehaviorTree from './BehaviorTree';
import Status from './Status';
import BaseElement from "./BaseElement";
import Behavior from "./Behavior";
import ParentBehavior from "./ParentBehavior";
import Decorator from "./Decorator";
import behaviors from "./behaviors";
import decorators from "./decorators";

/**
 * @class BehaviorConstructor
 * @memberof jibo.bt
 * @description Abstract type alias (needed by the Factory function) for the constructors of the behavior and decorator classes.
 */
export type BehaviorConstructor = new (options:any)=>Behavior|Decorator;

/**
 * Utility methods for registering behaviors and creating behaviors trees.
 * @namespace jibo.bt
 */
class Factory {

    _behaviors:{[key:string]:{[key:string]:BehaviorConstructor}};
    blackboard:any;
    emitter:BehaviorEmitter;
    //mixed in properties
    behaviors:typeof behaviors;
    decorators:typeof decorators;
    Status:typeof Status;
    BaseElement: typeof BaseElement;
    Behavior: typeof Behavior;
    BehaviorEmitter: typeof BehaviorEmitter;
    BehaviorTree: typeof BehaviorTree;
    Blackboard: any;
    Decorator: typeof Decorator;
    ParentBehavior: typeof ParentBehavior;

    constructor(bt) {

        /**
         * Map of behaviors
         * @name jibo.bt#_behaviors
         * @type {Object}
         * @private
         */
        this._behaviors = {};

        this.Status = Status;

        /**
         * The default blackboard
         * @name jibo.bt#blackboard
         * @type {jibo.bt.Blackboard}
         * @private
         */
        this.blackboard = new Blackboard();
        this.emitter = new BehaviorEmitter();

        // Mixin the classes
        Object.assign(this, bt);

        // Register core behaviors and decorators
        this.registerCore();
    }

    /**
     * Register a behavior or decorator globally
     * @name jibo.bt#register
     * @method
     * @param {String} name The PascalCased name for the behavior
     * @param {String} namespace This behavior's namespace. Pass in a globally unique name for this namesapce.
     * @param {Module} classRef Class reference for the behavior or decorator
     */
    register(name:string, namespace:string, classRef) {
        let ns = this._behaviors[namespace];
        if (!ns) {
            ns = this._behaviors[namespace] = {};
        }
        ns[name] = classRef;
    }

    /**
     * Add all behaviors
     * @method jibo.bt#registerCore
     * @private
     */
    registerCore() {
        const namespace = 'core';
        const all = Object.assign({}, this.behaviors, this.decorators);

        // Add the core behaviors/decorators
        for (let name in all) {
            this.register(name, namespace, all[name]);
        }
    }

    // Allows the Flow Executor to access the Behavior constructors.

    getBehaviorConstructor(behavior:string, namespace:string):BehaviorConstructor {
        let ns = this._behaviors[namespace || 'core'];
        if (ns) {
            return ns[behavior];
        }
    }

    // Provides Flow Executor access to the blackboard and emitter.

    getBlackboard() {
        return this.blackboard;
    }

    getEmitter() {
        return this.emitter;
    }

    /**
     * Creates a runnable behavior tree from a bt file import.
     * @method jibo.bt#create
     * @param {String|Function} uri Relative or absolute path to a `.bt` file or module export of behavior tree.
     * @param {Object} [overrides] Options for populating behavior tree globals.
     * @param {jibo.bt.Blackboard} [overrides.blackboard] Override the default blackboard object for this behavior tree.
     * @param {Object} [overrides.notepad] Provide your own notepad object instead of the default one.
     * @param {String} [overrides.assetPack] The asset pack name to use for loading assets in this tree.
     * @returns {jibo.bt.BehaviorTree}
     */
    create(uri:string|Function, overrides:any = {}) {
        let createTree:Function;
        if(typeof uri === 'string') {
            let calleeDirname:string = callsite()[1].getFileName();
            let treePath:string = this.getFilePathFromCallee(calleeDirname, uri);
            try {
                createTree = require(treePath);
            }
            catch(e) {
                console.error(e);
                throw new Error(uri + ' is not a valid behavior tree');
            }
        }
        else {
            createTree = uri;
        }


        let blackboard = overrides.blackboard || this.blackboard;
        let notepad = overrides.notepad || {};
        let result = {};

        let tree = createTree(blackboard, notepad, result, this.emitter);
        let map = {};
        let i, j, node, id;
        let ids = Object.keys(tree);
        let namespace = "", ns;

        // Support new behaviorify style that requires late binding of "this" in options.
        for(i = 0; i < ids.length; i++) {
            id = ids[i];
            if(id === 'meta') {
                continue;
            }
            node = tree[id];
            if (typeof node === 'function') {
                tree[id] = node.bind({})({});
            }
        }


        for(i = 0; i < ids.length; i++) {
            id = ids[i];
            if(id === 'meta') {
                continue;
            }
            node = tree[id];
            namespace = node['asset-pack'] || "core";
            if (namespace === "project" && overrides.assetPack) {
                namespace = overrides.assetPack;
            }
            ns = this._behaviors[namespace];

            if (!ns) {
                throw new Error("Namespace '" + namespace + "' is not registered with the behavior factory");
            }
            else if(!ns[node.class]) {
                throw new Error("Behavior '" + node.class + "' in namespace '" + namespace + "' is not registered with the behavior factory");
            }
            else if (Array.isArray(node.args)) {
                throw new Error("Behavior '" + node.class + "' options are invalid, re-run behaviorify");
            }

            let Constructor = ns[node.class];
            // let args = node.args ? [node.name].concat(node.args) : [node.name];
            // map[id] = Constructor.apply(null, args);
            let options = Object.assign({
                name: node.name,
                emitter: this.emitter,
                blackboard: blackboard,
                assetPack: overrides.assetPack || ""
            }, node.options || {});
            map[id] = new Constructor(options);
        }

        let possibleRoots = {};
        for(i = 0; i < ids.length; i++) {
            id = ids[i];
            if(id === 'meta') {
                continue;
            }
            node = tree[id];
            if(!node.parent) {
                possibleRoots[node.id] = true;
            }
            if(node.skipped) {
                delete possibleRoots[node.id];
                continue;
            }
            let behavior = map[node.id];
            if(node.children) {
                let children = [];
                for(j = 0; j < node.children.length; j++) {
                    let childId = node.children[j];
                    let child = map[childId];
                    if(!tree[childId].skipped){
                        children.push(child);
                    }
                }
                behavior.children = children;
            }
            if (node.decorators) {
                let decorators = [];
                for(j = 0; j < node.decorators.length; j++) {
                    let decorator = map[node.decorators[j]];
                    delete possibleRoots[node.decorators[j]];
                    if (!tree[node.decorators[j]].skipped){
                        decorators.push(decorator);
                    }
                }
                if(decorators.length > 0) {
                    behavior.decorators = decorators;
                }
            }
        }
        let root = map[Object.keys(possibleRoots)[0]];
        return new BehaviorTree(root, this.blackboard, notepad, result, this.emitter);
    }

    /**
     * Creates and runs a runnable behavior tree from a bt file import.
     * ```
     * const jibo = require('jibo');
     * jibo.init('face', (err) => {
     *   jibo.bt.run('./behaviors/main', function(status){});
     * });
     *
     * // Other supported APIs
     * jibo.bt.run('./behaviors/main');
     * jibo.bt.run('./behaviors/main', (status) => {});
     * const overrides = {};
     * jibo.bt.run('./behaviors/main', overrides);
     * jibo.bt.run('./behaviors/main', overrides, (status) => {});
     * ```
     *
     * @method jibo.bt#run
     * @param {String|Function} uri Relative or absolute path to a `.bt` file or module export of behavior tree.
     * @param {Object} [overrides] Options for populating behavior tree globals.
     * @param {jibo.bt.Blackboard} [overrides.blackboard] Override the default blackboard object for this behavior tree.
     * @param {Object} [overrides.notepad] Provide your own notepad object instead of the default one.
     * @param {String} [overrides.assetPack] The asset pack name to use for loading assets in this tree.
     * @param {Function} onFinishedCallback The callback which gets called when the behavior tree has reached a status of FAILED, SUCCEEDED, or INTERRUPTED.
     * @param {Status} status The status which the behavior tree finished with.
     * @returns {jibo.bt.BehaviorTree}
     */
    run(uri:string|Function, overrides:any={}, onFinishedCallback:(status:Status)=>void=null):BehaviorTree {
        if(typeof(overrides) === "function") {
            onFinishedCallback = overrides;
            overrides = {};
        }
        if(typeof uri === 'string') {
            let calleeDirname:string = callsite()[1].getFileName();
            //the 'typeof' type guard fails because we are assigning to uri, even though everything
            //should be strings right here :(
            uri = this.getFilePathFromCallee(calleeDirname, <string>uri);
        }

        const behaviorTree = this.create(uri, overrides);

        function doUpdate(elapsed) {
            // If the tree is in progress, keep updating
            if (behaviorTree.currentStatus === Status.IN_PROGRESS) {
                behaviorTree.update();
            } else if ( behaviorTree.currentStatus === Status.FAILED ||
                       behaviorTree.currentStatus === Status.SUCCEEDED ||
                       behaviorTree.currentStatus === Status.INTERRUPTED ) {
                stopUpdate();
            }
        }

        function clearTimer() {
            Runtime.instance.timer.removeListener('update', doUpdate);
        }

        function stopUpdate() {
            clearTimer();
            if (onFinishedCallback) {
                let callback = onFinishedCallback;
                onFinishedCallback = null;
                callback(behaviorTree.currentStatus);
            }
        }

        function startUpdate() {
            clearTimer();
            Runtime.instance.timer.on('update', doUpdate);
        }

        behaviorTree.on('start', startUpdate);
        behaviorTree.on('stop', stopUpdate);
        behaviorTree.on('destroy', clearTimer);

        behaviorTree.start();
        return behaviorTree;
    }

    /**
     * Resolves the path in relation to a calleeDirname directory. If the supplied uri is an absolute path, the uri is
     * returned unmodified
     * @param {String}  calleeDirname The directory name where the uri is relative to
     * @param {String}  uri The relative or absolute uri to a file in relation to the calleeDirname
     * @returns {String} The result absolute path
     *
     */
    private getFilePathFromCallee(calleeDirname:string, uri:string):string {
        let filePath:string;
        uri = uri.substr(0, uri.lastIndexOf(path.parse(uri).ext));
        if(!path.isAbsolute(uri)) {
            if(calleeDirname.indexOf('file://') === 0) {
                calleeDirname = calleeDirname.substr(7);
            }
            filePath = path.join(calleeDirname, '..', uri);
        }
        else {
            filePath = uri;
        }

        return filePath;
    }
}

export default Factory;
