import Runtime from '../Runtime';
import {Plugin, PluginCallback} from '../Plugin';
import SerialTimer from '../utils/perf/SerialTimer';

/**
 * Fetch the registry host from the IPC host
 */
class RegistryPlugin implements Plugin {
    init(done:PluginCallback): void {

        const jibo:Runtime = Runtime.instance;

        // Ignore services if runing in unit tests
        if (jibo.runMode === jibo.RunMode.UNIT_TESTS) {
            return done();
        }

        const timer = new SerialTimer('getRegistryHost', jibo.initTimer);

        // Ignore if not running Electron
        if (!Runtime.electron) {
            timer.stop();
            return done();
        }

        if (jibo.options.registryHost) {
            jibo.registryHost = jibo.options.registryHost;
            timer.stop();
            return done();
        }

        Runtime.ipcRenderer.on('set-context', (sender, initData) => {
            if(typeof initData === 'string' || initData instanceof String) {
                jibo.registryHost = <string>initData;
            }
            else {
                jibo.registryHost = initData.registryHost;
                if (initData.token) {
                    jibo.session.token = initData.token;
                }
                if (initData.context) {
                    jibo.context = initData.context;
                }
            }
            timer.stop();
            done();
        });
    }
}

Runtime.registerPlugin(RegistryPlugin, 'registry');

export default RegistryPlugin;