import Behavior from '../Behavior';
import Status from '../Status';
import Runtime from '../../Runtime';

/**
 * Callback for when Jibo takes a photo.
 * ```
 * let behavior = TakePhoto(2, 2, (url) => {
 *    let img = new Imgage();
 *    img.src = url;
 * });
 * ```
 * @callback jibo.bt.behaviors.TakePhoto~OnPhoto
 * @param {String} url The image URL.
 */

/**
 * @class TakePhoto
 * @extends jibo.bt.Behavior
 * @memberof jibo.bt.behaviors
 * @description Makes Jibo take a photo and will return a URL to get the contents of that photo.
 * @param {Object} options Options
 * @param {number} options.resolution `1` for a 672x380 photo. `2` for 1280x720 photo. `3` for 1920x1080 photo. `4` for 2688x1520 photo.
 * @param {jibo.bt.behaviors.TakePhoto~OnPhoto} options.onPhoto Called after Jibo takes a picture. The image URL is passed to this function.
 * @param {boolean} [options.noDistortion=true] Removes camera distortion from photo.
 */
export default class TakePhoto extends Behavior {
    private status:Status;

    constructor(options) {
        super(options, {
            noDistortion: true
        });
        this.status = Status.INVALID;
    }

    public start() {
        this.status = Status.IN_PROGRESS;
        Runtime.instance.lps.takePhoto(
            this.options.resolution,
            this.options.noDistortion,
            Runtime.instance.lps.CameraID.LEFT,        // always LEFT camera for now
            Runtime.instance.lps.PhotoType.FULL,       // always FULL type for now
            (error, imageUrl) => {
                //if status is not in progress, then behavior was stopped or destroyed
                if (this.status !== Status.IN_PROGRESS) {
                    return;
                }
                if (error) {
                    this.onPhoto(error, null);
                    this.status = Status.SUCCEEDED;
                    return;
                }
                else {
                    this.onPhoto(null, imageUrl);
                }
            }
        );
        return true;
    }
    public update() {
        return this.status;
    }
    public destroy() {
        super.destroy();
        this.status = null;
    }
    
    private onPhoto(error, imageUrl:string) {
        this.options.onPhoto(error, imageUrl);
        this.status = Status.SUCCEEDED;
    }
}
