import request = require('request');
import querystring = require('querystring');

import {promisify} from './decorators';
import Model from './Model';
import KnowledgeDatabase from './KnowledgeDatabase';
import Node from './Node';
import UserNode from './User';
import Asset from './Asset';
import LoopModel from './LoopModel';
import DatabaseManager from './DatabaseManager';
import Log = require('jibo-log');
const log = new Log('KnowledgeBase');

export type ErrCallback = (err:Error)=>void;
export type CreateCallback = (err:Error, created?:boolean)=>void;
export type ExistsCallback = (err:Error, exists?:boolean)=>void;
export type NodeConstructor = new (...args:any[])=>Node;
export type ModelConstructor = new (kbNames:string|string[], httpUrl:string)=>Model;
export type ServiceObject = {host:string, port:string|number};
/**
 * @description KnowledgeBase Class.
 *
 * @deprecated since version 3.0.0
 * @class KnowledgeBase
 * @memberof jibo.kb
 */

/** The Knowledge Base API.
 *
 * Can be accessed via `jibo.kb` (or `import {kb} from 'jibo'`).
 *
 * @namespace jibo.kb
 *
 * @example
 * let model = jibo.kb.createModel('/skillname');
 *
 */
class KnowledgeBase {

    public httpUrl:string;

    public Asset:typeof Asset;
    public KnowledgeDatabase:typeof KnowledgeDatabase;
    public Model:typeof Model;
    public Node:typeof Node;
    public UserNode:typeof UserNode;

    public databaseManager:DatabaseManager;
    /**
     * Loop model information.
     * @name jibo.kb#loop
     * @type {jibo.kb.LoopModel}
     */
    public loop:LoopModel;

    public config:any;

    //usage: registry[kbName][nodeType] = classConstructor;
    private nodeClassRegistry:{[kbName:string]:{[nodeType:string]:NodeConstructor}};
    //usage: registry[key] = classConstructor;
    private modelClassRegistry:{[kbNames:string]:ModelConstructor};


    constructor() {
        this.Asset = Asset;
        this.KnowledgeDatabase = KnowledgeDatabase;
        this.Model = Model;
        this.Node = Node;
        this.databaseManager = new DatabaseManager();

        this.nodeClassRegistry = {};
        this.modelClassRegistry = {};

        this.registerModelClass('jibo/loop', LoopModel);
        this.registerNodeClass('user', UserNode, 'jibo/loop');
    }


    /** Initialize the kb API singleton object.
     *
     * @method jibo.kb#init
     * @param {Object} service Service object with host and port of the KB service.
     * @param {Function} callback Called when done.
     * @internal
     */
    public init(service:ServiceObject, callback?:ErrCallback) {  // initalize as web client
        this.httpUrl = 'http://' + service.host + ':' + service.port;
        setImmediate(callback);
    }


    /** Optionally attach a loop model as `kb.loop`.
     * Call this only after init() has been called.
     *
     * @method jibo.kb#initLoop
     * @internal
     */
    public initLoop() {  // init .loop
        let loop = <LoopModel>this.createModel('/jibo/loop');
        this.loop = loop;
    }


    /** Create a KB slice. KB slices must be created before they are
     * used the first time. This method creates the KB slice, or does
     * nothing if it has already been created. The callback is
     * supplied with a boolen indicating if the slice needed to be
     * created. If callback is omitted a promise is returned instead.
     *
     * @method jibo.kb#createSlice
     * @param {string} sliceName Name of KB slice to create.
     * KB name must start with a `/`, followed by the skill name.
     * @param {string} [httpUrl] Base URL of KB service. Defaults to
     * URL generated from the service object given to `init()`.
     * @param {Function} [callback] Called with `(err, created)`
     * arguments. `created` is `false` if the KB slice already
     * existed. If callback is omitted a promise that returns
     * `created` is returned instead.
     * @returns {Promise} A promise that resolves with the value of
     * `created` if the callback is omitted.
     */
    public createSlice(sliceName:string, callback:CreateCallback);
    public createSlice(sliceName:string, httpUrl:string, callback:CreateCallback);
    public createSlice(sliceName:string, httpUrl?:string):Promise<boolean>;
    @promisify
    public createSlice(sliceName:string, httpUrl:string|CreateCallback, callback?:CreateCallback):void|Promise<boolean> {
        // check if a httpUrl was given and adjust args
        if (typeof httpUrl === 'function' && !callback) {
            callback = <CreateCallback>httpUrl;
            httpUrl = null;
        }
        httpUrl = httpUrl || this.httpUrl;

        let escapedName = querystring.escape(sliceName);
        let url = `${this.httpUrl}/v1/kb/${escapedName}/create`;
        request.post(url, {json: true}, (err, res, body) => {
            err = this._checkStatusCode(err, res, body);
            log.iferr(err, 'request.post', url);
            let created = body && body.created;
            if (callback) {
                callback(err, created);
            }
        });
    }


    /** Check if a KB slice exists. The callback is supplied with a
     * boolen indicating if the slice exists. If callback is omitted a
     * promise is returned instead.
     *
     * @method jibo.kb#existsSlice
     * @param {string} sliceName Name of KB slice to check.
     * KB name must start with a `/`, followed by the skill name.
     * @param {string} [httpUrl] Base URL of KB service. Defaults to
     * URL generated from the service object given to `init()`.
     * @param {Function} [callback] Called with `(err, exists)`
     * arguments. `exists` is `true` if the KB slice exists. If
     * callback is omitted a promise that returns `exists` is returned
     * instead.
     * @returns {Promise} A promise that resolves with the value of
     * `exists` if the callback is omitted.
     */
    public existsSlice(sliceName:string, callback:ExistsCallback):void;
    public existsSlice(sliceName:string, httpUrl:string, callback:ExistsCallback):void;
    public existsSlice(sliceName:string, httpUrl?:string):Promise<boolean>;
    @promisify
    public existsSlice(sliceName:string, httpUrl:string|ExistsCallback, callback?:ExistsCallback):void|Promise<boolean> {
        // check if a httpUrl was given and adjust args
        if (typeof httpUrl === 'function' && !callback) {
            callback = <ExistsCallback>httpUrl;
            httpUrl = null;
        }
        httpUrl = httpUrl || this.httpUrl;

        let escapedName = querystring.escape(sliceName);
        let url = `${this.httpUrl}/v1/kb/${escapedName}/exists`;
        request.get(url, {json: true}, (err, res, body) => {
            err = this._checkStatusCode(err, res, body);
            log.iferr(err, 'request.get', url);
            let exists = body && body.exists;
            if (callback) {
                callback(err, exists);
            }
        });
    }


    /** Create a new Model object. Models are the primary interface
     * to the knowledge base.
     *
     * @method jibo.kb#createModel
     * @param {string|string[]} kbNames Array of knowledge base slice
     * names to include in model, in order of precedence. A single
     * KB name can be given as a string instead of an array of strings.
     * KB names must start with a `/`, followed by the skill name.
     * @param {string} [httpUrl] Base URL of KB.
     * service. Defaults to URL generated from the service object
     * given to `init()`.
     * @param {string} [httpUrl] Base URL of KB service. Defaults to
     * URL generated from the service object given to `init()`.
     * @returns {jibo.kb.Model} New Model object.
     */
    public createModel(kbNames:string|string[], httpUrl?:string):Model {
        kbNames = this._toArray(kbNames);
        httpUrl = httpUrl || this.httpUrl;
        if (!httpUrl) {
            throw new Error('Knowledge Base has not been inited');
        }
        let newKBNames:string[] = [];
        // strip off '/'s in kb names
        //TODO: typecasting won't be needed when TypeScript 2.0 is released
        (<string[]>kbNames).forEach( (kbName) => {
            if (!kbName.startsWith('/')) {
                throw new Error('kb#createModel: kb names must be rooted (must start with /)');
            } else {
                kbName = kbName.substr(1);
            }
            newKBNames.push(kbName);
        });

        let ModelClass = this.findModelClass(newKBNames);
        return new ModelClass(newKBNames, httpUrl);
    }


    /** Register a Node subclass to be instantiated when a node of a
     * given type is loaded or created.
     *
     * @method jibo.kb#registerNodeClass
     * @param {string|string[]} nodeType Node type to use this
     * subclass for.
     * @param {Function} classConstruction The constructor function
     * for the subclass.
     * @param {string} [kbName] Name of KB to limit the use
     * of this subclass to. Defaults to all KBs.
     */
    public registerNodeClass(nodeType:string, classConstructor:NodeConstructor, kbName:string='*') {
        let registry = this.nodeClassRegistry;
        if (registry[kbName] && registry[kbName][nodeType]) {
            log.warn('registerNodeClass: overwriting previous class registered for type', nodeType);
        }
        if (!registry[kbName]) {
            registry[kbName] = {};
        }
        registry[kbName][nodeType] = classConstructor;
    }


    /** Register a Model subclass to be instantiated for a given KB name
     * list.
     *
     * @method jibo.kb#registerModelClass
     * @param {string|string[]} kbNames KB name or name list use this
     * subclass for.
     * @param {Function} classConstructor The constructor function for
     * the subclass.
     */
    public registerModelClass(kbNames:string|string[], classConstructor:ModelConstructor) {
        kbNames = this._toArray(kbNames);
        let key = (<string[]>kbNames).join(';');
        let registry = this.modelClassRegistry;
        if (registry[key]) {
            log.warn('registerModelClass: overwriting previous class registered for ', key);
        }
        registry[key] = classConstructor;
    }


    /** Use the node type to find a Node subclass in the Node Class
     * registry. Default to the plain `Node` object if nothing
     * matches.
     *
     * @method jibo.kb#findNodeClass
     * @param {string} nodeType Type of node.
     * @param {string} kbName Name of KB slice.
     * @returns {Function} Node class constructor.
     */
    public findNodeClass(nodeType:string, kbName:string):NodeConstructor {
        let NodeClass = Node;  // unless we find a more specific subclass
        let registry = this.nodeClassRegistry;
        if (registry[kbName] && registry[kbName][nodeType]) {
            NodeClass = registry[kbName][nodeType];
        } else if (registry['*'] && registry['*'][nodeType]) {
            NodeClass = registry['*'][nodeType];
        }
        return NodeClass;
    }


    /** Use the given KB slice names to find a Model subclass in the
     * Model subclass registry. Defaults to the plain `Model` object
     * if nothing matches.
     *
     * @method jibo.kb#findModelClass
     * @param {string|string[]} kbNames Array of knowledge base slice
     * names.
     * @returns {Function} Model class constructor.
     */
    public findModelClass(kbNames:string|string[]):ModelConstructor {
        kbNames = this._toArray(kbNames);
        let key = (<string[]>kbNames).join(';');
        let ModelClass = Model;  // unless we find a more specific subclass
        let registry = this.modelClassRegistry;
        if (registry[key]) {
            ModelClass = registry[key];
        }
        return ModelClass;
    }


    /** Unload a given kb slice from the Skills Service Manager memory
     * and remove it from disk.  Also removes any sub-kbs inside this
     * slice. For example, if you remove `/jibo`, that would also
     * remove `/jibo/loop`, `/jibo/settings` and all other kb slices
     * under `/jibo`. If callback is omitted a promise is returned
     * instead.
     *
     * @method jibo.kb#removeSlice
     * @param {string} sliceName Name of kb slice to be removed,
     * including all of its sub-slices (if any).
     * @param {Function} [callback] Called when done, with `err`
     * parameter if there was an error. If callback is omitted a
     * promise is returned instead.
     * @returns {Promise} A promise if the callback is omitted.
     */
    public removeSlice(sliceName:string, callback:ErrCallback);
    public removeSlice(sliceName:string):Promise<any>;
    @promisify
    public removeSlice(sliceName:string, callback?:ErrCallback):void|Promise<any> {
        let escapedName = querystring.escape(sliceName);
        let url = `${this.httpUrl}/v1/kb/${escapedName}/remove/yesiamsure`;
        request.del(url, (err, res, body) => {
            err = this._checkStatusCode(err, res, body);
            log.iferr(err, 'request.del', url);
            if (callback) {
                callback(err);
            }
        });
    }


    /** Unload all kb slices from the Skills Service Manager memory,
     * stop the Loop Manager, and delete the ENTIRE KNOWLEDGEBASE!
     *
     * @method jibo.kb#removeAll
     * @param {Function} [callback] Called when done, with `err`
     * parameter if there was an error. If callback is omitted a
     * promise is returned instead.
     * @returns {Promise} A promise if the callback is omitted.
     * @internal
     */
    public removeAll(callback:ErrCallback);
    public removeAll():Promise<any>;
    @promisify
    public removeAll(callback?:ErrCallback):void|Promise<any> {
        let url = `${this.httpUrl}/v1/removeall/yesiamsure`;
        request.del(url, (err, res, body) => {
            err = this._checkStatusCode(err, res, body);
            log.iferr(err, 'request.del', url);
            if (callback) {
                callback(err);
            }
        });
    }


    /** Check http request result for null error object and 2xx result code and
     * generate an error object if not (or pass through non null error object).
     *
     * @method jibo.kb.WebClient#_checkStatusCode
     * @param {Error} err Error object returned from request.
     * @param {Object} res Http request result object.
     * @param {string} [message] Message to add to error object.
     * @returns {Error} Error object or null.
     * @private
     */
    private _checkStatusCode(err:Error, res, message:string=null):Error {
        if (!err) {  // game over if we already have an err
            if (res.statusCode < 200 || res.statusCode > 299) {
                let description = 'HTTP Error Code '+res.statusCode;
                if (message) {
                    description += message;
                }
                err = new Error(description);
            }
        }
        return err;
    }


    /** Convert a single item to an array for arguments that may be a
     * single thing or an array of things.
     *
     * @method jibo.kb#_toArray
     * @private
     */
    private _toArray<T>(items:T|T[]):T[] {
        if (!Array.isArray(items)) {
            return [items];  // separate returns makes typescript happy
        } else {
            return items;
        }
    }
}

export default KnowledgeBase;
