import Timer from '../utils/Timer';
import ViewManager from './gui/ViewManager';
import TweenManager from './tween/TweenManager';
import EyeContainer from './eye/EyeContainer';
import GestureManager from './input/GestureManager';

/**
 * @description
 * Controls the rendering of the eye, overlay, and background.
 * ```
 * let jibo = require('jibo');
 * jibo.init('face', () => {
 *    // Setup complete!
 * });
 * ```
 * @namespace jibo.face
 */
class FaceRenderer extends PIXI.WebGLRenderer {
    
    /**
     * Entire width of Jibo's face.
     * @name jibo.face.WIDTH
     * @type {int}
     * @default 1280
     * @readOnly
     */
    public static WIDTH:number = 1280;

    /**
     * Entire height of Jibo's face.
     * @name jibo.face.HEIGHT
     * @type {int}
     * @default 720
     * @readOnly
     */
    public static HEIGHT:number = 720;
   
    /**
     * Stage container for all PIXI display objects.
     * @name jibo.face#stage
     * @type {PIXI.Container}
     */
    public stage:PIXI.Container;

    /**
     * If the display is updating.
     * @name jibo.face#_paused
     * @type {Boolean}
     * @private
     */
    private _paused:boolean;

    /**
     * Instance of the update timer for handling events.
     * @name jibo.face#_timer
     * @type {jibo.timer}
     * @private
     */
    private _timer:Timer;

    /**
     * Instance to the GUI/View Manager.
     * @private
     * @name jibo.face#_views
     * @type {jibo.face.ViewManager}
     */
    private _views:ViewManager;


    /**
     * Instance to the GestureManager for input gestures.
     * @private
     * @name jibo.face#_gestures
     * @type {jibo.face.GestureManager}
     */
    private _gestures:GestureManager;

    /**
     * Instance to the Eye display.
     * @private
     * @name jibo.face#_eye
     * @type {jibo.face.EyeContainer}
     */
    private _eye:EyeContainer;

    /**
     * Creates the canvas for the renderer.
     * @private
     * @method jibo.face.createView
     */
    public static createView(): HTMLCanvasElement {
        // Create the canvas element
        const view:HTMLCanvasElement = document.createElement('canvas');
        view.style.width = '100%';
        view.style.height = '100%';
        return view;
    }

    constructor(timer:Timer, public cache:boolean=true) {

        super(
            FaceRenderer.WIDTH,
            FaceRenderer.HEIGHT, {
                view: FaceRenderer.createView(),
                antialias: true
            }
        );

        // Save the canvas
        this.stage = new PIXI.Container();
        this.update = this.update.bind(this);
        this._paused = true;
        this._timer = timer;


        // Create the eye view
        this._eye = new EyeContainer(cache);

        // Create the GUI manager and tween manager
        this._views = new ViewManager();

        // Create the Gesture Manager
        this._gestures = GestureManager.init(this);

        // Add the view manager to the render node
        this.stage.addChild(this._views.stage);

        // start the update loop
        this._timer.on('update', this.update);
    }

    /**
     * Adds a face animation to play.
     * @private
     * @method jibo.face#init
     * @param {HTMLElement} element HTML element which will contain the view
     */
    public init(element:HTMLElement) {
        element.appendChild(this.view);
        // initialize ViewManager, sets up jibo module dependent aspects
        this._views.init();
        
        this.paused = false;
    }

    /**
     * Manage the views on Jibo's face.
     * @name jibo.face#views
     * @type {jibo.face.ViewManager}
     */
    public get views():ViewManager{
        return this._views;
    }

    /**
     * Create and manage the input gestures.
     * @name jibo.face#gestures
     * @type {jibo.face.GestureManager}
     */
    public get gestures():GestureManager {
        return this._gestures;
    }

    /**
     * Tweens manager.
     * @name jibo.face#tween
     * @type {jibo.face.TweenManager}
     */
    public get tween():typeof TweenManager {
        return TweenManager;
    }

    /**
     * Representation of the eye itself.
     * @name jibo.face#eye
     * @type {jibo.face.EyeContainer}
     */
    public get eye():EyeContainer {
        return this._eye;
    }

    /**
     * Update/render the stage.
     * @method jibo.face#update
     * @private
     * @param {int} elapsed Time in milliseconds since the last update
     */
    public update(elapsed:number) {
        if (this._paused) {
            return;
        }
        // Update render
        TweenManager.update(elapsed);
        this._views.update(elapsed);
        this.render(this.stage);
    }

    /**
     * If `true`, pauses the face renderer completely.
     * @name jibo.face#paused
     * @type {boolean}
     */
    public set paused(value:boolean) {
        if(value !== this._paused) {
            this._paused = value;
        }
    }
    public get paused(): boolean {
        return this._paused;
    }

    /**
     * Cleans up the renderer.
     * @method jibo.face#destroy
     */
    public destroy():void {
        if (this._views) {
            this.stage.removeChild(this._views.stage);
            this._views.destroy();
        }
        if (this._timer) {
            this._timer.removeListener('update', this.update);
            this._timer = null;
        }
        this._paused = true;
        this.stage.destroy(true);
        this.stage = null;
        super.destroy(true);
    }
}

export default FaceRenderer;
