import GlobalPerfTimer from './utils/perf/GlobalPerfTimer';
import SerialTimer from './utils/perf/SerialTimer';
import services from './services';
import utils from './utils';
import plugins from './plugins';
import loader from './loader';
import Runtime from './Runtime';
import electron from './utils/electron';

// Import deprecated functionality
import deprecation from './deprecation';

const root:any = global;

// Create/start global performance timer
GlobalPerfTimer.init();

// Measure the time it takes to require the top level jibo module
const timer = new SerialTimer('jibo required', GlobalPerfTimer.get());

if (!root.jibo) {
    // Create the class definitions
    // and hang it on a global namespace
    // object called jibo
    const classes = {
        services,
        utils,
        loader,
        plugins,
        Runtime
    };

    // Include flows, bt, rendering and sound
    // if we are in Electron
    if (electron) {

        const rendering = require('./rendering');
        const sound = require('./sound');
        const bt = require('./bt');
        const flow = require('./flow');

        Object.assign(classes, {
            rendering,
            sound,
            bt,
            flow
        });
    }

    // Deprecate before create jibo
    deprecation(classes);

    // Export the jibo singleton
    root.jibo = new Runtime(classes);
}

timer.stop();

module.exports = root.jibo;