import Timeline from '../../animation/Timeline';
import MenuButton from './MenuButton';
import Label from './Label';
import ActionData from '../actions/ActionData';
import UserNode from '../../../services/kb/User';

/**
 * Contact button, extends MenuButton to handle specifics required for contacts
 *
 * @class ContactButton
 * @extends jibo.face.MenuButton
 * @memberof jibo.face
 */
class ContactButton extends MenuButton
{
    /**
     * The default class identifier.
     * MenuButton uses variants, so this should be defined specifically at
     * Generally used to register the class.
     * @name jibo.face.ContactButton.DEFAULT_TYPE
     * @type {String}
     * @readOnly
     */
    public static get DEFAULT_TYPE():string {return 'ContactButton';}

    /**
     * The Class type variant.
     * The MenuButton allows for type variants within it.
     * @name jibo.face.ContactButton#_type
     * @type {String}
     * @protected
     * @internal
     */
    protected _type:string = ContactButton.DEFAULT_TYPE;

    /**
     * Flag determining if the button should toggle on click
     * @name jibo.face.ContactButton#willToggle
     * @type {Boolean}
     * @default false
     */
    public willToggle:boolean = false;

    /**
     * Loop member associated with button.
     * @method jibo.face.ContactButton#looper
     * @type {jibo.kb.UserNode}
     * @readOnly
     */
    public get looper():UserNode { return this._looper; }

    /**
     * Flag determining if the button displays check mark.
     * @method jibo.face.ContactButton#isChecked
     * @type {Boolean}
     * @readOnly
     */
    public get isChecked():boolean { return this._isChecked; }

    /**
     * Flag determining if the button should display the check mark.
     * @name jibo.face.ContactButton#_isChecked
     * @type {Boolean}
     * @private
     */
    private _isChecked:boolean = false;

    /**
     * Looper member associated with button.
     * @name jibo.face.ContactButton#_looper
     * @type {jibo.kb.UserNode}
     * @private
     */
    private _looper:UserNode = null;

    /**
     * Create a ContactButton from a configuration Object derived from JSON.
     * @method jibo.face.ContactButton#createFromConfig
     * @param {Object} configData Object derived from JSON, must be a specific format refer to examples.
     * @returns {jibo.face.ContactButton} Returns the ContactButton created from the given configuration.
     */
    public static createFromConfig(configData:any):ContactButton {
        let btn:ContactButton = new ContactButton();
        btn.assignConfig(configData);
        return btn;
    }

    constructor() {
        super();

        // setup colors & data specific to ContactButton
        this.colors = [0xbac5c9, 0x434d55];
        this._buttonDatas[ContactButton.DEFAULT_TYPE] = {
            assetPath: 'core://resources/buttons/contactButton.js',
            dimensions: new PIXI.Point(330, 330)
        };
    }

    /**
     * Get flag determining if the button is has checkmark.
     * This flag is checked during createDisplay() at which point the check is made visible or not.
     * @method jibo.face.ContactButton#setChecked
     * @param {Boolean} bool Value to assign to check mark
     * @param {Boolean} [animate = false] `true` to animate check mark display.
     */
    public setChecked(bool:boolean, animate:boolean = true):void {
        this._isChecked = bool;
        this.displayCheck(animate);
    }

    /**
     * Create and add a button asset descriptor that corresponds with the type value.
     * If `type` is provided as a parameter, it is applied to the internal type variable.
     * Add an asset descriptor for the looper's photo, if defined.
     * @method jibo.face.ContactButton#applyButtonType
     * @param {String} [type] If definfed, applied to [MenuButton#_type]{@link jibo.face.MenuButton#_type},
     *          which is then used to determine which timeline assets to use for the button.
     * @internal
     */
    public applyButtonType(type?:string):void{
        super.applyButtonType(type);
        // add assetDescriptor for looper photo (if found)
        if(this._looper.data.photoUrl ) {
            super.addAssetDescriptor(this._looper.id, this._looper.data.photoUrl, 'texture');
        }
    }

    /**
     * Destroy.
     * @method jibo.face.ContactButton#destroy
     * @internal
     */
    public destroy():void {
        this._looper = null;
        super.destroy();
    }

    /**
     * Keep reference to looper Object and use to define variables.
     * @method jibo.face.ContactButton#assignLooper
     * @param {jibo.kb.UserNode} looper Reference to Looper.
     */
    public assignLooper(looper:UserNode):void {
        this._looper = looper;

        // get label from data
        this.label = looper.getWrittenName();
        this.id = looper.id;

        // create action to spoof utterance of name/nickname
        this.addAction(ActionData.UTTERANCE, {utterance:this.label});
    }

    /**
     * Set up the timeline asset associated with the button.
     * @method jibo.face.ContactButton#setupTimeline
     * @protected
     * @internal
     */
    protected setupTimeline(assets:any):void {

        if(assets.hasOwnProperty(this.timelineId)) {

            // TODO :: validation that assets are what we expect would be helpful
            let stageInstance:any = new (assets[this.timelineId] as Timeline).library.stage();
            this._content = stageInstance['content'];
            const imageContainer:PIXI.Container = this._content['icon'];

            // TODO :: We want to have photo loaded prior to this
            const photoTexture:PIXI.Texture = this._assets[this._looper.id];
            if(photoTexture){
                const photoSprite:PIXI.Sprite = new PIXI.Sprite(photoTexture);
                // scale sprite to button dimensions
                photoSprite.width = this._dimensions.x;
                photoSprite.height = this._dimensions.y;
                // center anchor
                photoSprite.anchor.x = photoSprite.anchor.y = .5;
                // add to button display
                photoSprite.setParent(imageContainer);
            }
            else{
                if (this.colors) {
                    this._content['background'].children[0].tint = this.colors[0];
                    this._content['gradient'].children[0].tint = this.colors[1];
                }
                // if no assets are defined default to creating initials
                const initialText:PIXI.Text = new PIXI.Text(this._looper.getInitials(), Label.createFontStyle(135,'Proxima Nova Soft','#FFFFFF','bold'));
                initialText.anchor.x = initialText.anchor.y = .5;
                imageContainer.addChild(initialText);
            }

            // setup check mark display
            this.displayCheck(false);

            this.display.addChild(stageInstance);
        }
        else {
            console.warn('WARNING :: ContactButton :: createDisplay : timeline not found in assets');
        }
    }

    /**
     * Handler for click touch input.
     * If `willToggle` is `true`, toggle the check mark on each click.
     * @method jibo.face.ContactButton#click
     * @protected
     * @internal
     */
    protected click() {
        if(this.willToggle) {
            this.setChecked( !this._isChecked, true);
        }
        super.click();
    }

    /**
     * Update the check mark display.
     * @method jibo.face.ContactButton#displayCheck
     * @param {Boolean} [animate = true] Flag determining if check mark should animate.
     * @private
     */
    private displayCheck(animate:boolean = true):void {
        if(this._content) {
            const checkClip:PIXI.animate.MovieClip = this._content['check'];
            if(checkClip) {
                let label:string = (this._isChecked) ? 'check_open' : 'check_close';
                if(animate) {
                    PIXI.animate.Animator.play(checkClip, label);
                }
                else {
                    checkClip.gotoAndStop(label + '_stop');
                }
            }
        }

    }
}

export default ContactButton;
