import ParentBehavior from '../ParentBehavior';
import Status from '../Status';

/**
 * @class Switch
 * @extends jibo.bt.ParentBehavior
 * @memberof jibo.bt.behaviors
 * @description Runs its child nodes in sequence until one succeeds. Fails if all of the children failed
 * and succeeds if one child succeeded.
 * @param {Object} options See {@link jibo.bt.Behavior|Behavior} for all options.
 * @param {Array<jibo.bt.Behavior>} [options.children=[]] - An array of the Switch's child behaviors.
 */
export default class Switch extends ParentBehavior {
    private current:number;
    
    constructor(options) {
        super(options);
        this.current = -1;
    }
    public start() {
        if(this.children.length === 0) {
            return false;
        }
        this.current = 0;
        return this.findStart();
    }
    public findStart() {
        let startOk = false;
        while(!startOk && this.current < this.children.length) {
            startOk = this.children[this.current]._start();
            if(!startOk) {
                this.current++;
            }
        }
        return true;
    }
    public stop():Promise<void> {
        let rtn:Promise<void>;
        if(this.current !== -1 && this.current < this.children.length) {
            rtn = this.children[this.current]._stop();
            this.current = -1;
        }
        return rtn || Promise.resolve();
    }
    public update() {
        if(this.current !== -1 && this.current < this.children.length) {
            const childStatus = this.children[this.current]._update();
            if(childStatus === Status.FAILED) {
                this.current++;
                if(this.current >= this.children.length || !this.findStart()) {
                    return Status.SUCCEEDED;
                }
                else {
                    return Status.IN_PROGRESS;
                }
            }
            else if(childStatus === Status.PAUSED) {
                return Status.IN_PROGRESS;
            }
            return childStatus;
        }
        return Status.SUCCEEDED;
    }
}
