import FlowExecutor from './FlowExecutor';
import FlowRootFactory from './core/FlowRootFactory';
import Runtime from '../Runtime';
import path = require('path');
import ActivityImplementation from './ActivityImplementation';

/**
 * Utility methods for registering activities and creating flows.
 * @class FlowExecutorFactory
 * @namespace jibo.flow
 */

class FlowExecutorFactory {
    ActivityImplementation: typeof ActivityImplementation;
    activities: any;
    _activities: any;

    static create(uri:any, overrides:any = {}):FlowExecutor {
        let flowRoot = FlowRootFactory.create(uri);
        return new FlowExecutor(flowRoot, overrides);
    }

    constructor(flow) {
        this._activities = {};
        Object.assign(this, flow);
        this.registerCore();
    }

    /**
     * Register an activity globally
     * @method jibo.flow#register
     * @param {String} name The PascalCased name for the behavior.
     * @param {String} namespace This behavior's namespace. Pass in a globally unique name for this namesapce.
     * @param {Module} classRef Class reference for the behavior or decorator.
     */
    register(name:string, namespace:string, classRef) {
        let ns = this._activities[namespace];
        if (!ns) {
            ns = this._activities[namespace] = {};
        }
        ns[name] = classRef;
    }

    /**
     * Add all activities
     * @method jibo.flow#registerCore
     * @private
     */
    registerCore() {
        for (let name in this.activities) {
            this.register(name, 'core', this.activities[name]);
        }
    }

    /**
     * Give the Flow Executor access to the Activity constructors.
     * @param {string} className - Final Class name (e.g. `FlowEvalAsync`)
     * @param {string} [namespace] - Namespace of activity -- `core` if unsupplied.
     * @returns {jibo.flow.ActivityImplementation} - Constructor of the activity or undefined if not found.
     */
    getActivityConstructor(className:string, namespace?:string):ActivityImplementation {
        let ns = this._activities[namespace || 'core'];
        if (ns) {
            return ns[className];
        }
    }

    /**
     * Create a runnable flow executor from a flow file import.
     * @method jibo.flow#create
     * @param {String|Function} uri Relative or absolute path to a `.flow` file or module export of flow.
     * @param {Object} [overrides] Options for populating flow globals.
     * @param {jibo.bt.Blackboard} [overrides.blackboard] Override the default blackboard object for this flow.
     * @param {Object} [overrides.notepad] Provide your own notepad object instead of the default one.
     * @param {Object} [overrides.blackboard] Provide your own blackboard object instead of the default one shared with behavior trees.
     * @param {Object} [overrides.emitter] Provide your own emitter object instead of the default one shared with behavior trees.
     * @param {String} [overrides.assetPack] The asset pack name to use for loading assets in this tree.
     * @returns {jibo.flow.FlowExecutor}
     */
    create(uri:string|Function, overrides:any = {}):FlowExecutor {
        let flowProcedure:any;

        if (typeof overrides.enableLogging === 'undefined' &&
            Runtime.instance.runMode !== Runtime.instance.RunMode.UNIT_TESTS) {
            console.log('FlowExecutor tracing is now normally disabled. Do "options.enableLogging = true;" in index.ts before calling e.g. jibo.flow.run(mainFlow, options, ...');
        }

        if(typeof uri === 'string') {
            let calleeDirname:string = callsite()[1].getFileName();
            flowProcedure = this.getFilePathFromCallee(calleeDirname, uri);
        }
        else {
            flowProcedure = uri;
        }

        let flowRoot = FlowRootFactory.create(flowProcedure);
        return new FlowExecutor(flowRoot, overrides);
    }

    /**
     * Create and run a runnable flow from a flow file import.
     * ```
     * const jibo = require('jibo');
     * jibo.init('face', (err) => {
     *   jibo.flow.run('./flows/main', function(status){});
     * });
     *
     * // Other supported APIs
     * jibo.flow.run('./flows/main');
     * jibo.flow.run('./flows/main', (status) => {});
     * const overrides = {};
     * jibo.flow.run('./flows/main', overrides);
     * jibo.flow.run('./flows/main', overrides, (status) => {});
     * ```
     *
     * @method jibo.flow#run
     * @param {String|Function} uri Relative or absolute path to a `.flow` file or module export of flow.
     * @param {Object} [overrides] Options for populating flow globals.
     * @param {jibo.bt.Blackboard} [overrides.blackboard] Override the default blackboard object for this flow.
     * @param {Object} [overrides.notepad] Provide your own notepad object instead of the default one.
     * @param {Object} [overrides.blackboard] Provide your own blackboard object instead of the default one shared with behavior trees.
     * @param {Object} [overrides.emitter] Provide your own emitter object instead of the default one shared with behavior trees.
     * @param {String} [overrides.assetPack] The asset pack name to use for loading assets in this tree.
     * @param {jibo.flow~onFinishedCallback} onFinishedCallback The callback which gets called when the flow has reached a status of FAILED, SUCCEEDED, or INTERRUPTED
     * @returns {jibo.flow.FlowExecutor}
     */
    run(uri:string|Function, overrides:any={}, onFinishedCallback:(err, status)=>void=null):FlowExecutor {
        if(typeof(overrides) === "function") {
            onFinishedCallback = overrides;
            overrides = {};
        }
        let flowExecutor:any;
        try {
            flowExecutor = this.create(uri, overrides);
        } catch (e) {
            console.error('Could not start flow: ' + e);
            return;
        }

        let isExited = flowExecutor.update();

        function doUpdate(elapsed:any) {
            if (!isExited) {
                try {
                    isExited = flowExecutor.update();
                } catch (e) {
                    console.log(`FlowExecutor caught exception: ${e}`);
                    if (onFinishedCallback !== null) {
                        clearTimer();
                        // Don't allow our stop listener to call the callback when we stop the flow.
                        flowExecutor.removeListener('stop', stopUpdate);
                        flowExecutor.stop();
                        flowExecutor.destroy();
                        let callback = onFinishedCallback;
                        onFinishedCallback = null;
                        callback(e, flowExecutor.status);
                    }
                }
            } else {
                flowExecutor.stop();
            }
        }

        function clearTimer() {
            Runtime.instance.timer.removeListener('update', doUpdate);
        }

        function stopUpdate() {
            clearTimer();
            if (onFinishedCallback) {
                let callback = onFinishedCallback;
                onFinishedCallback = null;
                callback(null, flowExecutor.status);
            }
        }

        function startUpdate() {
            clearTimer();
            Runtime.instance.timer.on('update', doUpdate);
        }

        flowExecutor.once('start', startUpdate);
        flowExecutor.once('stop', stopUpdate);
        flowExecutor.once('destroy', clearTimer);

        flowExecutor.start();
        return flowExecutor;
    }

    /**
     * Resolve the path in relation to a calleeDirname directory. If the supplied uri is an absolute path, the uri is
     * returned unmodified.
     * @param {String}  calleeDirname The directory name where the uri is relative to.
     * @param {String}  uri The relative or absolute uri to a file in relation to the calleeDirname.
     * @returns {String} The result absolute path.
     * @private
     */
    private getFilePathFromCallee(calleeDirname, uri) {
        let filePath:string;
        uri = uri.substr(0, uri.lastIndexOf(path.parse(uri).ext));
        if(!path.isAbsolute(uri)) {
            if(calleeDirname.indexOf('file://') === 0) {
                calleeDirname = calleeDirname.substr(7);
            }
            filePath = path.join(calleeDirname, '..', uri);
        }
        else {
            filePath = uri;
        }

        return filePath;
    }
}

export default FlowExecutorFactory;
