import PathUtils from '../utils/PathUtils';
import {FlowExceptionInfo} from './Context';
import ActivityImplementation from './ActivityImplementation';
import Procedure from "./core/Procedure";

/**
 * The Environment is available to Javascript code running in Flow Activities.
 * It is a collection of miscellaneous information related to the Flow and FlowExecutor.
 * @class Environment
 * @memberof jibo.flow
 * @param {string} assetPack The asset pack associated with the Flow (blank if unused).
 * @internal
 */
class Environment {
    public lastException:FlowExceptionInfo;
    public currentFile:string;
    public currentActivity:ActivityImplementation;
    public currentProcedure:Procedure;
    public language:string;
    public projectRoot:string;

    constructor(public assetPack:string) {
        this.assetPack = assetPack;
        this.lastException = null;
        this.language = "en-us";
        this.projectRoot = PathUtils.findRoot();
    }
}

export default Environment;
