import {EventEmitter} from 'events';
import { WSClient } from 'jibo-client-framework';

/**
 * Wifi interface for the robot.
 * @namespace jibo.wifi
 * @private
 */

/**
 * Class to interface to the wifi service in Skills Service Manager.
 * @class WifiService
 * @private
 * @memberof jibo.wifi
 */
class WifiService extends EventEmitter {

    private _httpInterface:string;
    private _wsInterface:string;
    private _initialized:boolean;


    constructor() {
        super();

        this._httpInterface = null;
        this._wsInterface = null;
        this._initialized = false;
    }

    /**
     * Initialize the wifi module for `jibo.init`.
     * @method jibo.wifi#init
     * @param service {Object} The service options
     * @param service.host {String} host name
     * @param service.port {String} port number
     * @param callback {Function} callback
     */
    public init(service:{host:string; port:string}, callback:ErrorMsgCallback):void {
        this._httpInterface = "http://" + service.host + ":" + service.port;
        this._wsInterface = "ws:" + service.host + ":" + service.port;
        this._initialized = true;

        // create out event socket
        this._createEventSocket(callback);
    }

    /**
     * Add a wifi network.
     * @method jibo.wifi#addNetwork
     * @param networkData {Object} The network data
     * @param minVerifyTime {Integer} The minimum amount of time in seconds to verify the connection before failing
     * @param callback {Function} callback
     * @private
     */
    public addNetwork(networkData:NetworkData, minVerifyTime:number, callback:ErrorMsgCallback):void {

        let data = {
            networkData: networkData,
            minVerifyTime: minVerifyTime
        };
        this._sendWifiCommand('/add_network', data, callback);
    }

    /**
     * Select (enable) a wifi network.
     * @method jibo.wifi#selectNetwork
     * @param ssid {String} The network name
     * @param callback {Function} callback
     * @private
     */
    public selectNetwork(_ssid:string, callback:ErrorMsgCallback):void {
        let data = {
            ssid: _ssid
        };
        this._sendWifiCommand('/select_network', data, callback);
    }

    /**
     * Remove a wifi network.
     * @method jibo.wifi#removeNetwork
     * @param ssid {String} The network name
     * @param callback {Function} callback
     * @private
     */
    public removeNetwork(_ssid:string, callback:ErrorMsgCallback):void {
        let data = {
            ssid: _ssid
        };
        this._sendWifiCommand('/remove_network', data, callback);
    }

    /**
     * Remove all wifi networks.
     * @method jibo.wifi#removeAllNetworks
     * @param callback {Function} callback
     * @private
     */
    public removeAllNetworks(callback:ErrorMsgCallback):void {
        this._sendWifiCommand('/remove_all', null, callback);
    }

    /**
     * Get current network stats.
     * @method jibo.wifi#getCurrentNetwork
     * @param callback {Function} callback
     * @private
     */
    public getCurrentNetwork(callback:(error:Error, stats?:NetworkStats) => void):void {
        this._getWifiData('/get_current_network', (error:Error, response?:any) => {
            if (error) {
                return callback(error);
            }

            callback(null, response.stats);
        });
    }

    /**
     * Get currently saved networks.
     * @method jibo.wifi#getSavedNetworks
     * @param callback {Function} callback
     * @private
     */
    public getSavedNetworks(callback:(error:Error, data?:Array<SavedNetworkEntry>) => void):void {
        this._getWifiData('/get_saved_networks', (error:Error, response?:any) => {
            if (error) {
                return callback(error);
            }

            callback(null, response.networks);
        });
    }

    /**
     * Verify the current network connection if network exists.
     * @method jibo.wifi#verifyConnection
     * @param callback {Function} callback
     * @private
     */
    public verifyConnection(callback:(error?:Error, errorCode?:number) => void):void {
        if(!this._initialized) {
            callback(new Error("Wifi service is unavailable"));
            return;
        }

        let request:XMLHttpRequest = new XMLHttpRequest();
        request.open("POST", this._httpInterface + '/verify_connection', true);

        request.onreadystatechange = () => {
            // console.log("request.readyState|status = " + request.readyState + " | " + request.status);

            // request is complete
            if(request.readyState === 4) {
                let response = JSON.parse(request.response);

                // "OK" status
                if(request.status === 200) {
                    callback(null);
                }
                else {
                    // failure if anything else
                    callback(response.error, response.code);
                }
            }
        };

        request.send();
    }


   private _sendWifiCommand(path:string, data:any, callback:ErrorMsgCallback) {
       if(!this._initialized) {
           callback(new Error("Wifi service is unavailable"));
           return;
       }

       let request:XMLHttpRequest = new XMLHttpRequest();
       request.open("POST", this._httpInterface + path, true);

       request.onreadystatechange = () => {
           // console.log("request.readyState|status = " + request.readyState + " | " + request.status);

           // request is complete
           if(request.readyState === 4) {
               // "OK" status
               if(request.status === 200) {
                   callback();
               }
               else {
                   // failure if anything else
                   let response = JSON.parse(request.response);
                   callback(new Error(response.error));
               }
           }
       };

       if(data) {
           request.send(JSON.stringify(data));
       }
       else {
           request.send();
       }
   }


   private _getWifiData(path:string, callback:(error:Error, response?:any)=> void):void {
       if(!this._initialized) {
           callback(new Error("Wifi service is unavailable"));
           return;
       }

       let request:XMLHttpRequest = new XMLHttpRequest();
       request.open("POST", this._httpInterface + path, true);

       request.onreadystatechange = () => {
           // console.log("request.readyState|status = " + request.readyState + " | " + request.status);

           // request is complete
           if(request.readyState === 4) {
               let response = JSON.parse(request.response);

               // "OK" status
               if(request.status === 200) {
                   callback(null, response);
               }
               else {
                   // failure if anything else
                   callback(new Error(response.error));
               }
           }
       };

       request.send();
   }


   private _createEventSocket(cb) {
       let socket = new WSClient(this._wsInterface + "/wifi_events");
       socket.on('error', () => {
           console.error(`Error opening system notifications socket at ${this._wsInterface}/wifi_events`);
       });
       socket.on('message', (data) => {
           let socketData;
           try {
               socketData = data;
               this._tryEmit(socketData.eventName, socketData.data);
           }
           catch(e) {
               console.error('Wifi event data is not JSON format.');
           }
       });
       cb();
   }

    private _tryEmit(eventName:string, data?:any) {
        try {
            this.emit(eventName, data);
        }
        catch(e) {
            console.log("Nothing listening for event [" + eventName + "]");
        }
    }

}


//
// Custom declarations, types and interfaces
//
declare type ErrorMsgCallback = (err?:Error) => void;

// @TODO - needs documentation
export enum NetworkType {
    DHCP,     // 0
    STATIC    // 1
}

export interface StaticNetworkSettings {
    staticIP:string;
    gateway:string;
    netmask:string;
    dns1?:string;
    dns2?:string;
}

export interface NetworkData {
    ssid:string;
    pswd:string;
    security:string;
    hidden:number;
    networkType:NetworkType;
    staticSettings:StaticNetworkSettings;
}

export interface NetworkStats {
    ssid: string;
    strength: number;
    speed: number;
    ip_address: string;
}

export interface SavedNetworkEntry {
    index: string;
    ssid: string;
    current: boolean;
}

export default WifiService;
