import ParentBehavior from '../ParentBehavior';
import Behavior from '../Behavior';
import Status from '../Status';

/**
 * @class Parallel
 * @extends jibo.bt.ParentBehavior
 * @memberof jibo.bt.behaviors
 * @description Runs its child nodes in parallel. Returns with `Status.FAILED` if one of the children failed
 * and `Status.SUCCEEDED` if all children succeeded.
 * @param {Object} options See {@link jibo.bt.Behavior} for all options.
 * @param {boolean} options.succeedOnOne If the Parallel should succeed when the first child succeeds.
 * @param {Array<jibo.bt.Behavior>} [options.children=[]] An array of the Parallel's child behaviors.
 */
export default class Parallel extends ParentBehavior {
    private runChildren:Behavior[];
    private activeChildren:number;
    private childStops:Promise<void>[];
    private stopping:boolean;

    constructor(options) {
        super(options);

        this.runChildren = null;
        this.activeChildren = 0;
        this.childStops = [];
        this.stopping = false;
    }
    public destroy() {
        super.destroy();
        this.runChildren = null;
        this.childStops = null;
    }
    public start() {
        if(this.children.length === 0) {
            return false;
        }
        let oneFailedToStart = false;
        this.runChildren = [];
        for(let i = 0; i < this.children.length; i++) {
            const child = this.children[i];
            if(child._start()) {
                this.runChildren.push(child);
            }
            else {
                oneFailedToStart = true;
            }
        }
        this.activeChildren = this.runChildren.length;
        if(oneFailedToStart) {
            for(let i = 0; i < this.runChildren.length; i++) {
                this.runChildren[i]._stop();
            }
            return false;
        }
        return true;
    }
    public stop():Promise<void> {
        for(let i = 0; i < this.runChildren.length; i++) {
            if (!this.runChildren[i]) {
                continue;
            }
            this.childStops.push(this.runChildren[i]._stop());
        }
        if (this.childStops.length === 0) {
            return Promise.resolve();
        }
        return <any>Promise.all(this.childStops);
    }
    public update() {
        if (this.stopping) {
            return Status.IN_PROGRESS;
        }
        let oneFailed = false;
        for(let i = 0; i < this.runChildren.length; i++) {
            if (!this.runChildren[i]) {
                continue;
            }

            const child = this.runChildren[i];
            const status = child._update();

            if(status === Status.SUCCEEDED) {
                if(this.options.succeedOnOne) {
                    // Stop all children
                    this.stopping = true;
                    this._stop().then(() => {
                        //have to set the internal status because this is
                        //happening asynchronously
                        this._currentStatus = Status.SUCCEEDED;
                        this.stopping = false;
                    });
                    return Status.IN_PROGRESS;
                }
                else {
                    this.childStops.push(child._stop()); // Stop current child
                    this.runChildren[i] = null;
                    this.activeChildren--;
                }
            }
            else if(status === Status.FAILED) {
                oneFailed = true;
            }
            else if(status === Status.PAUSED) {
                return Status.IN_PROGRESS;
            }
        }

        if(oneFailed) {
            return Status.FAILED;
        }
        else if(this.activeChildren === 0) {
            return Status.SUCCEEDED;
        }
        else {
            return Status.IN_PROGRESS;
        }
    }
}
