/**
 * Created on 6/22/16.
 * @author carolynsaund
 *
 *
 * This is a sister class to ClientDialogListener
 * Has its own set of events, specifically for Pronunciation
 * Has the ability to directly POST to the ListenService, to tell it to pause GlobalListen and start a pronunciation listen.
 *  *
 */

import { Event } from 'jibo-typed-events';
import { ListenOptions } from './DataTypes';
import { ClientDialogListener, ListenerEvents } from './ClientDialogListener';
import Runtime from "../../Runtime";



let UUID = require('uuid');

/**
 * @class Pronunciation
 * @description Resposne object for heardPronunciation event.
 * @memberof jibo.gl
 */
export class Pronunciation {
    public pronunciation:string;
    public word:string;
    // public say_as: string;
    public success:boolean;

    constructor(options:Pronunciation) {
      /**
       * The phonetic pronunciation heard by the PronunciationListener.
       * @name jibo.gl.Pronunciation#pronunciation
       * @type {string}
       * @readOnly
       */
        this.pronunciation = options.pronunciation;
      /**
       * The spelling of the word which was pronounced.
       * @name jibo.gl.Pronunciation#word
       * @type {string}
       * @readOnly
       */
        this.word = options.word;
      /**
       * TO BE IMPLEMENTED: Another phonetic pronunciation of the word.
       * @name jibo.gl.Pronunciation#say_as
       * @type {string}
       * @readOnly
       */
        // this.say_as = options.say_as;
      /**
       * Determines whether NameListener was confident in acoustic pronunciation.
       * @name jibo.gl.Pronunciation#success
       * @type {boolean}
       * @readOnly
       */
        this.success = options.success;
    }
}


/**
 * @class Pronunciation Events
 * @description Typed Events for pronunciation (`{@link jibo.gl.PronunciationListener}.events`).
 * @extends jibo.gl.PronunciationEvents
 * @memberof jibo.gl
 */
export class PronunciationEvents extends ListenerEvents {
  public generatedPronunciations:Event<any>;
  public heardPronunciations:Event<Pronunciation>;
  public pronunciationError:Event<any>;

  constructor() {
    super();

    /**
     * generatedPronunciations Event
     * Pronunciations generated by the cloud model.
     * @name jibo.gl.PronunciationEvents#generatedPronunciations
     * @type {Event}
     * @readOnly
     */
     this.generatedPronunciations = new Event<any>('pronunciations from generated model');

    /**
     * heardPronunciations Event.
     * Pronunciations heard by acoustic example.
     * @name jibo.gl.PronunciationEvents#heardPronunciations
     * @type {Event}
     * @readOnly
     */
     this.heardPronunciations = new Event<any>('pronunciations heard by acoustic example');

    /**
     * pronunciationError Event.
     * An error occured generating the pronunciation model or hearing the acoustic example.
     * @name jibo.gl.PronunciationEvents#pronunciationError
     * @type {Event}
     * @readOnly
     */
     this.pronunciationError = new Event<any>('An error occured generating the pronunciation model or hearing the acoustic example.');
  }
}


/**
 * @class PronunciationOptions
 * @description Options to pronounce.
 * @param {String} [word] Word to be pronounced.
 * @memberof jibo.gl
 */
export class PronunciationOptions extends ListenOptions {
  word: string;
  action: string;
  listenerId: string;

  constructor(word?: string) {
    super();
    /**
     * Word to be pronounced.
     * @name jibo.gl.PronunciationOptions#word
     * @type {String}
     */
    this.word = word || "";
    /**
     * Action for listener to perform. Either `generateG2P` to generate
     * the model, or `collectExample` to collect acoustic example.
     * @default generateG2P
     * @name jibo.gl.PronunciationOptions#action
     * @type {String}
     */
    this.action = "generateG2P";
    /**
     * ID used to identify listener in GLService.
     * @name jibo.gl.PronunciationListener#_listenerId
     * @type {String}
     */
    this.listenerId = UUID.v1();
  }

}

/**
 * @class PronunciationListener
 * @description Listener for new pronunciations of words.
 * ```
 * () => {
 *   let pronounce = jibo.gl.createPronunciationListener({
 *     word: "Pronunciation"
 *   });
 *   pronounce.events.generatedPronunciations.on(function(data) {
 *     console.log("GENERATED PRONUN", data); // ["Pro nun see ay shun", "Proe nown see ae shun"]
 *     pronounce.collectExample();
 *   });
 *   pronounce.events.heardPronunciations.on(function(data) {
 *     console.log("HEARD PRONUN", data); // {jibo.gl.Pronunciation}
 *   });
 *   pronounce.events.pronunciationError.on(function(data) {
 *     console.log("ERROR IN PRONUN", data);
 *   });
 *   pronounce.start();
 * }
 * ```
 * @memberof jibo.gl
 * @extends jibo.gl.ClientDialogListener
 */
export class PronunciationListener extends ClientDialogListener {
    public events: PronunciationEvents;
    public options: PronunciationOptions;
    public _listenerId: string;


    constructor(options:PronunciationOptions) {
        super(new ListenOptions() ,"");
        /**
         * Events for pronunciation.
         * @name jibo.gl.PronunciationListener#events
         * @type {jibo.gl.PronunciationEvents}
         */
        this.events = new PronunciationEvents();
        /**
         * Options for pronunciation.
         * @name jibo.gl.PronunciationListener#options
         * @type {jibo.gl.PronunciationOptions}
         */
        this.options = options || new PronunciationOptions();

        this._listenerId = UUID.v1();
    }

   /**
    * Convenience to wrap `jibo.gl.pronounce(options, callback);`.
    * @param [word] {String} Word to pronounce
    * @param [callback] {Function} Callback with GL response.
    * @method jibo.gl.PronunciationListener#start
    * @public
    */
    public start(word?:string, callback?) {
        if(typeof word === "function") {
            callback = word;
        }
        else if(typeof word === "string") {
            this.options.word = word;
        }
        if(!callback) {
            callback = (err) => {
                if(err) { console.warn(err); }
            };
        }
        // TODO listener ID needs to live in OPTIONS or in here. only one
        this.options.listenerId = this._listenerId;
        this.options.action = "generateG2P";
        Runtime.instance.gl.pronounce(this.options, callback);
    }

   /**
    * Can be called after generated-pronun event is received.
    * Collect the acoustic example of the word to be pronounced.
    * @method jibo.gl.PronunciationListener#collectExample
    * @public
    */
    public collectExample() {
        this.options.action = "collectExample";
        Runtime.instance.gl.pronounce(this.options, () => {return;});
    }


   /**
    * Set options to PronunciationListener.
    * @param options {jibo.gl.PronunciationOptions} Options for PronunciationListener
    * @method jibo.gl.PronunciationListener#setOptions
    * @public
    */
    public setOptions(options:PronunciationOptions) {
        this.options = options;
    }

   /**
    * Stop PronunciationListener.
    * @param callback {Function} Callback with Global Listen response.
    * @method jibo.gl.PronunciationListener#stop
    * @public
    */
    public stop(callback?) {
        this.options.action = "stop";
        Runtime.instance.gl.pronounce(this.options, callback);
    }
}
