import electron from '../../utils/electron';
import {writable} from '../../utils/decorators';

let HammerJS;
if (electron) {
    HammerJS = require('hammerjs');
}

/**
 * @description
 * A wrapper around HammerJS to register gesture input events with the PIXI DOM Element.
 * @class GestureManager
 * @memberof jibo.face
 */
class GestureManager {
    /**
     * Pan gesture event string.
     * @type {string}
     * @name jibo.face.GestureManager.PAN
     * @readOnly
     */
    @writable(false)
    public static PAN:string = 'pan';
    /**
     * Panstart gesture event string.
     * @type {string}
     * @name jibo.face.GestureManager.PANSTART
     * @readOnly
     */
    @writable(false)
    public static PANSTART:string = 'panstart';
    /**
     * Panmove gesture event string.
     * @type {string}
     * @name jibo.face.GestureManager.PANMOVE
     * @readOnly
     */
    public static PANMOVE:string = 'panmove';
    /**
     * Panend gesture event string.
     * @type {string}
     * @name jibo.face.GestureManager.PANEND
     * @readOnly
     */
    @writable(false)
    public static PANEND:string = 'panend';
    /**
     * Pancancel gesture event string.
     * @type {string}
     * @name jibo.face.GestureManager.PANCANCEL
     * @readOnly
     */
    public static PANCANCEL:string = 'pancancel';
    /**
     * Panleft gesture event string.
     * @type {string}
     * @name jibo.face.GestureManager.PANLEFT
     * @readOnly
     */
    public static PANLEFT:string = 'panleft';
    /**
     * Panright gesture event string.
     * @type {string}
     * @name jibo.face.GestureManager.PANRIGHT
     * @readOnly
     */
    public static PANRIGHT:string = 'panright';
    /**
     * Panup gesture event string.
     * @type {string}
     * @name jibo.face.GestureManager.PANUP
     * @readOnly
     */
    public static PANUP:string = 'panup';
    /**
     * Pandown gesture event string.
     * @type {string}
     * @name jibo.face.GestureManager.PANDOWN
     * @readOnly
     */
    public static PANDOWN:string = 'pandown';


    /**
     * Swipe gesture event string.
     * @type {string}
     * @name jibo.face.GestureManager.SWIPE
     * @readOnly
     */
    public static SWIPE:string = 'swipe';
    /**
     * Swipeleft gesture event string.
     * @type {string}
     * @name jibo.face.GestureManager.SWIPELEFT
     * @readOnly
     */
    public static SWIPELEFT:string = 'swipeleft';
    /**
     * Swiperight gesture event string.
     * @type {string}
     * @name jibo.face.GestureManager.SWIPERIGHT
     * @readOnly
     */
    public static SWIPERIGHT:string = 'swiperight';
    /**
     * Swipeup gesture event string.
     * @type {string}
     * @name jibo.face.GestureManager.SWIPEUP
     * @readOnly
     */
    public static SWIPEUP:string = 'swipeup';
    /**
     * Swipedown gesture event string.
     * @type {string}
     * @name jibo.face.GestureManager.SWIPEDOWN
     * @readOnly
     */
    public static SWIPEDOWN:string = 'swipedown';

    /**
     * Pixi gesture.
     * @type {*}
     * @name jibo.face.GestureManager#_pixiGesture
     * @private
     */
    private _pixiGesture:any = null;

    /**
     * Pixi interaction manager reference.
     * @type {PIXI.interation.InteractionManager}
     * @name jibo.face.GestureManager#_interactionManager
     * @private
     */
    private _interactionManager:PIXI.interaction.InteractionManager = null;

    /**
     * Create the singleton instance of the GestureManager.
     * @method jibo.face.GestureManager.init
     * @return {GestureManager}
     */
    public static init(renderer:PIXI.WebGLRenderer): GestureManager {
        return new GestureManager(renderer);
    }

    /**
     * Instantiate a HammerJS Manager object with the PIXI renderer.
     * This should be called before a call to addStageGesture.
     * @method jibo.face.GestureManager#init
     * @param {PIXI.WebGLRenderer} renderer - The pixi renderer object.
     */
    constructor(renderer:PIXI.WebGLRenderer) {
        this._pixiGesture = new HammerJS.Manager(renderer.view);
        this._interactionManager = new PIXI.interaction.InteractionManager(renderer);
    }

    /**
     * Get a reference to HammerJS,
     * @method jibo.face.GestureManager#hammer
     * @return {Object} The HammerJS object. See http://hammerjs.github.io/getting-started/ for documentation on what objects are accessible through this module.
     */
    public get hammer() {
        return HammerJS;
    }

    /**
     * Add a gesture recognized by the PIXI renderer stage DOM element.
     * See documentation at: http://hammerjs.github.io/getting-started/ for specifics on gesture options and hammer api objects.
     * @method jibo.face.GestureManager#addStageGesture
     * @param {PIXI.DisplayObject} displayObject - The pixi display object which you want the gesture to be recognized on.
     * @param {Object} hammerType - This can be retrieved from the jibo.face.gestures.hammer reference. This is the hammer object type to be instantiated to create the gesture.
     *                          eg. ```jibo.face.gestures.hammer.Pan```
     * @param {Object} gestureOptions - This varies between each gesture. This must include an event field (which is of type string, some of which are specified as constants in this class).
     *                          eg. ```event { GestureManager.SWIPE }```
     * @param {Function(Object)} gestureCallback - Upon successful gesture recognition against the supplied displayobject, this callback will be triggered.
     *                          It will have the event parameter supplied from the HammerJS event callback.
     * @return {Object | null} - The hammer object which was successfully created, or null if it was not successfully created.
     * An example in calling this would be
     *   ```
     *    GestureManager.addStageGesture(pixiDisplayObject,
     *                                   jibo.face.gestures.hammer.Swipe,
     *                                   { event: blackboard.GestureManager.SWIPELEFT},
     *                                   function(gestureEvent){
     *                                      // Got event!
     *                                   });
     *  ```
     */
    public addStageGesture(displayObject:PIXI.DisplayObject, hammerType:any, gestureOptions:any, gestureCallback: (hammerEvent:{}) => void):any {
        if (!this._pixiGesture || !this._interactionManager) {
            throw new Error("The pixi HammerJS Manager or the pixi Interaction Manager is null.  Has init been called?");
        }

        if (!gestureOptions.event) {
            throw new Error("Invalid event string.");
        }

        const hammerResult = new hammerType(gestureOptions);
        this._pixiGesture.add(hammerResult);
        this._pixiGesture.on(gestureOptions.event, (event) => {
            if(event.pointers.length > 0) {
                const firstTouchPoint:PIXI.Point = new PIXI.Point(
                        event.pointers[0].clientX,
                        event.pointers[0].clientY
                );
                const hitFunction = (displayObject:PIXI.DisplayObject, hit:boolean):void => { /*no op*/ };
                const interactiveMgr = this._interactionManager;
                const wasHit = (interactiveMgr as any).processInteractive(firstTouchPoint, displayObject, hitFunction, true, true);
                if(wasHit) {
                  gestureCallback(event);
                }
            }
        });
        return hammerResult;
    }

    /**
     * Removes a gesture for PIXI.
     * @method jibo.face.GestureManager#removeStateGesture
     * @param {Object} gestureRecognizer The gesture to remove.
     */
    public removeStageGesture(gestureRecognizer) {
        this._pixiGesture.off(gestureRecognizer.options.event);
        this._pixiGesture.remove(gestureRecognizer);
    }

    // TODO :: Could we have a removeAll option?
}

export default GestureManager;
