import { Event, EventContainer   } from 'jibo-typed-events';
import View from './views/View';
import ViewProcess from './ViewProcess';

/**
 * @class ViewGlobalEvents
 * @description Typed global view events for ViewManager (`jibo.face.views.events`)
 * @example
 * jibo.face.views.events.process.on(onProcess);
 *
 * onProcess = (result:ViewProcessResult) => {
 *   // act accordingly
 * }
 *
 * // When finished with event listening
 * jibo.face.views.events.process.removeListener(onProcess);
 *
 * @memberof jibo.face
 */
export default class ViewGlobalEvents extends EventContainer {

    /**
     * Emits results from view change process.
     * @name jibo.face.ViewGlobalEvents#process
     * @type {Event<jibo.face.ViewProcessResult>}
     */
    public process: Event<ViewProcessResult>;

    /**
     * Emits results from View emitted events.
     * @name jibo.face.ViewGlobalEvents#view
     * @type {Event<jibo.face.ViewResult>}
     */
    public view: Event<ViewResult>;

    constructor() {
        super();

        this.process = new Event<ViewProcessResult>('View process status changed');

        this.view = new Event<ViewResult>('View emitted an event');
    }
}

/**
 * @class ViewProcessResult
 * @description Result from change in view change process.
 * @memberof jibo.face
 */
export class ViewProcessResult {

    /**
     * Current state of view process.
     * Refer to {@link jibo.face.ViewProcess} for status values.
     * @name jibo.face.ViewProcessResult#status
     * @type {String}
     * @readOnly
     */
    public status:string = '';

    /**
     * Id of current view in process.
     * @name jibo.face.ViewProcessResult#currentId
     * @type {String}
     * @readOnly
     */
    public currentId:string = '';

    /**
     * Id of closing view in process.
     * @name jibo.face.ViewProcessResult#closingId
     * @type {String}
     * @readOnly
     */
    public closingId:string = '';

    constructor(viewProcess:ViewProcess) {
        this.status = viewProcess.status;
        this.currentId = (viewProcess.currentView) ? viewProcess.currentView.id : '';
        this.closingId = (viewProcess.closingView) ? viewProcess.closingView.id : '';
    }
}

/**
 * @class ViewResult
 * @description Results from events emitted by View.
 * @memberof jibo.face
 */
export class ViewResult {

    /**
     * Event emitted from view.
     * @name jibo.face.ViewResult#event
     * @type {String}
     * @readOnly
     */
    public event:string = '';

    /**
     * Id of view emitting the event.
     * @name jibo.face.ViewResult#id
     * @type {String}
     * @readOnly
     */
    public id:string = '';

    /**
     * Type of view emitting the event.
     * @name jibo.face.ViewResult#type
     * @type {String}
     * @readOnly
     */
    public type:string = '';

    /**
     * Statis of view emitting the event.
     * Refer to {@link jibo.face.View} for status values.
     * @name jibo.face.ViewResult#status
     * @type {String}
     * @readOnly
     */
    public status:string = '';

    /**
     * Any additional data that may be passed with the event.
     * @name jibo.face.ViewResult#data
     * @type {any}
     * @readOnly
     */
    public data:any = null;

   /**
    * @internal
    * @param {jibo.face.View} view - View event is dispatched from.
    * @param {string} event - Event emitted from view.
    * @param {any} data - Any additional data that may be passed with the event.
    */
    constructor(view:View, event?:string, data?:any) {
        this.event = event;
        this.id = view.id;
        this.type = view.type;
        this.status = view.state;
        this.data = data;
    }
}
