import AssetManager from './AssetManager';
import AssetLoad from './AssetLoad';
import AssetUtils from './AssetUtils';
import Task from './tasks/Task';
import LoadTask from './tasks/LoadTask';
import ListTask from './tasks/ListTask';
import FunctionTask from './tasks/FunctionTask';
import LoaderError from './errors/LoaderError';
import AssetCache from './AssetCache';
import {Cache, Caches} from './AssetCache';
import Runtime from '../Runtime';
import {ITaskDefinition, Asset} from './AssetLoad';
import {Plugin, PluginCallback} from '../Plugin';

interface MultiOptions {
    complete?:Function;
    taskDone?:Function;
    progress?:Function;
    cacheAll?:boolean|string;
    startAll?:boolean;
    remoteAll?:boolean;
    timeoutAll?:number;
}

/**
 * Adds all assets to a skill,
 * including custom ones from your file system
 * that are not included in the template skill by default.
 * Assets can include images, sounds, code, data, and other files.
 * @namespace jibo.loader
 */
class LoaderPlugin implements Plugin
{
    public assetManager:AssetManager;
    public AssetUtils:typeof AssetUtils;
    public Task:typeof Task;
    public LoadTask:typeof LoadTask;
    public ListTask:typeof ListTask;
    public FunctionTask:typeof FunctionTask;
    public LoaderError:typeof LoaderError;

    constructor()
    {
        /**
         * Instance of the asset manager.
         * @name jibo.loader#assetManager
         * @type {jibo.loader.AssetManager}
         */
        this.assetManager = new AssetManager();

        // Expose public classes
        this.AssetUtils = AssetUtils;
        this.Task = Task;
        this.LoadTask = LoadTask;
        this.ListTask = ListTask;
        this.FunctionTask = FunctionTask;
        this.LoaderError = LoaderError;

        // Register tasks
        this.register(LoadTask, 0)
            .register(ListTask, 5)
            .register(FunctionTask, 10);
    }

    init(done:PluginCallback): void {
        done();
    }

    /**
     * Handles any errors coming from the manager.
     * @method jibo.loader#register
     * @param {Function} TaskDefinition The class definition for a loader task.
     * @param {int} [priority=0] The priority of the task. Higher priority tasks
     *        are run first and therefore should be more specific
     *        types of tasks. Lower priority tasks are more generalized.
     * @return {jibo.loader} The loader namespace for chaining.
     */
    register(TaskDefinition:ITaskDefinition, priority:number=0): LoaderPlugin
    {
        this.assetManager.register(TaskDefinition, priority);
        return this;
    }

    /**
     * Performs simple load of a single file.
     * @method jibo.loader#load
     * @param {String} source The file to load.
     * @param {jibo.loader.AssetManager~completeCallback} complete The completed callback with a single
     *      parameters result object.
     * @param {jibo.loader.AssetManager~progressCallback} [progress=null] Callback percentage updates.
     * @param {Boolean|String} [cache=false] `true` to save to the asset cache after load.
     * @param {Object} [data] Optional data to pass along
     * @param {Boolean} [remote=false] `true` to force remote download.
     * @param {Number} [timeout=0] Number of milliseconds to timeout remote load.
     * @param {String} [format] Force a format type, either:
     *        "image", "json", "xml", "css", "js", "svg", "text", or "html"
     */
    load(source:string, complete:Function, progress?:Function, cache?:boolean, data?:any, remote?:boolean, timeout?:number):AssetLoad;
    /**
     * Loads a single file with options.
     * @method jibo.loader#load
     * @param {Object} asset The file resource to load.
     * @param {String} asset.src The file to load.
     * @param {Boolean|String} [asset.cache=false] `true` if the result should be cached for later.
     *        If string, then the name of the cache to use.
     * @param {Boolean} [asset.remote=false] `true` if the src should be loaded of http(s), `false` to auto-determine.
     * @param {String} [asset.format] Force a format type, either:
     *        "image", "json", "xml", "css", "js", "svg", "text", or "html"
     * @param {Number} [asset.timeout=0] Number of milliseconds to timeout remote load.
     * @param {jibo.loader.AssetManager~completeCallback} [asset.complete=null] Callback when finished.
     * @param {jibo.loader.AssetManager~completeCallback} [complete] The completed callback with a single
     *      parameter which is a result object. Will
     *      only use if `asset.complete` is undefined.
     */
    load(asset:{src:string, complete?:Function, cache?:boolean}, complete?:Function):AssetLoad;
    /**
     * Loads a single custom asset with options.
     * @method jibo.loader#load
     * @param {Object} asset The single asset resource to load, properties
     *      will depend on the type of asset loading.
     * @param {jibo.loader.AssetManager~completeCallback} [asset.complete=null] Callback when finished.
     * @param {String} [asset.id=null] The ID to attach to this asset.
     * @param {Boolean|String} [asset.cache=false] `true` if the result should be cached for later.
     * @param {Boolean} [asset.remote=false] `true` if the src should be loaded of http(s), `false` to auto-determine.
     * @param {String} [asset.format] Force a format type, either:
     *        "image", "json", "xml", "css", "js", "svg", "text", or "html"
     * @param {Number} [asset.timeout=0] Number of milliseconds to timeout remote load.
     * @param {jibo.loader.AssetManager~completeCallback} [complete] The completed callback with a single
     *      parameters which is a result object. Will
     *      only use if `asset.complete` is undefined.
     */
    load(asset:{id:string, complete?:Function, cache?:boolean}, complete?:Function):AssetLoad;
    /**
     * Loads a map of multiple assets and return mapped result objects.
     * @method jibo.loader#load
     * @param {Object} assets Load a map of assets.
     * @param {jibo.loader.AssetManager~completeCallback|object} [options] Callback where the only parameter is the
     *      map of the results by ID, or the collection of load options.
     * @param {jibo.loader.AssetManager~completeCallback} [options.complete=null] The complete callback if using load options.
     * @param {jibo.loader.Task~completeCallback} [options.taskDone=null] The callback when a single item is finished.
     * @param {jibo.loader.AssetManager~progressCallback} [options.progress=null] Callback percentage updates.
     * @param {Boolean} [options.cacheAll=false] `true` if tasks should be cached.
     * @param {Boolean} [options.startAll=true] `true` if tasks should be run in parallel.
     * @param {Boolean} [options.remoteAll=false] `true` to force remote calls on all assets.
     * @param {Number} [options.timeoutAll=0] Number of milliseconds to timeout remote calls.
     */
    load(assets:any, options?:MultiOptions|Function):AssetLoad;
    /**
     * Loads a list of multiple assets and return array of result objects.
     * @method jibo.loader#load
     * @param {Array} assets The list of assets.
     *      If each object has a `id` the result will be a mapped object.
     * @param {function|object} [options] Callback where the only parameter is the
     *      collection or map of the results, or the collection of load options.
     * @param {jibo.loader.AssetManager~completeCallback} [options.complete=null] The complete callback if using load options.
     * @param {jibo.loader.Task~completeCallback} [options.taskDone=null] The callback when a single item is finished.
     * @param {jibo.loader.AssetManager~progressCallback} [options.progress=null] Callback percentage updates.
     * @param {Boolean} [options.cacheAll=false] `true` if tasks should be cached.
     * @param {Boolean} [options.startAll=true] `true` if tasks should be run in parallel.
     * @param {Boolean} [options.remoteAll=false] `true` to force remote calls on all assets.
     * @param {Number} [options.timeoutAll=0] Number of milliseconds to timeout remote calls.
     */
    load(list:any[], options?:MultiOptions|Function):AssetLoad;
    load(source:any, complete?:any, progress?:any, cache?:any, data?:any, remote:boolean=false, timeout:number=0, format?:string):AssetLoad
    {
        let options;
        // If the load arguments are setup like the Loader.load call
        // then we'll convert to an object that we can use
        if (typeof source === "string")
        {
            source = {
                src: source,
                progress: progress || null,
                complete: complete || null,
                cache: !!cache,
                remote: remote,
                timeout: timeout,
                format: format,
                data: data || null
            };
        }
        else
        {
            // Presume complete is an options object
            options = complete;

            // Second argument is callback
            if (typeof complete === "function")
            {
                options = {
                    complete: complete
                };
            }
        }
        return this.assetManager.load(source, options);
    }

    /**
     * Sets the base path to prepend to all loads.
     * @name jibo.loader#basePath
     * @type {String}
     */
    set basePath(basePath:string)
    {
        this.assetManager.localLoader.basePath = basePath;
    }
    get basePath(): string
    {
        return this.assetManager.localLoader.basePath;
    }

    /**
     * Sets the base URL to prepend to all remote loads.
     * @name jibo.loader#baseUrl
     * @type {String}
     */
    set baseUrl(baseUrl:string)
    {
        this.assetManager.remoteLoader.baseUrl = baseUrl;
    }
    get baseUrl(): string
    {
        return this.assetManager.remoteLoader.baseUrl;
    }

    /**
     * Unloads an asset or list of assets.
     * @method jibo.loader#unload
     * @param {Array|String} assets The collection of asset ids or
     *      single asset id. As an array, it can be a manifest
     *      with objects that contain an ID, or an array of multiple strings.
     * @return {jibo.loader} The loader namespace for chaining.
     */
    unload(assets:any): LoaderPlugin
    {
        if (typeof assets === "string")
        {
            assets = Array.prototype.slice.call(arguments);
        }

        for (let i = 0; i < assets.length; i++)
        {
            this.assetManager.cache.delete(assets[i]);
        }
        return this;
    }

    /**
     * Unloads an asset or list of assets from a specific cache.
     * @method jibo.loader#unloadFrom
     * @param {Array|String} assets The collection of asset ids or
     *      single asset id. As an array, it can be a manifest
     *      with objects that contain an ID, or an array of multiple strings.
     * @param {String} [cacheId] Target cache to unload from. Uses active cache if empty.
     * @return {jibo.loader} The loader namespace for chaining.
     */
    unloadFrom(assets:Asset|Asset[], cacheId?:string): LoaderPlugin
    {
        if (Array.isArray(assets)) {
            for (let i = 0; i < assets.length; i++)
            {
                this.assetManager.cache.delete(assets[i], cacheId);
            }
            return this;
        }
        this.assetManager.cache.delete(assets, cacheId);
        return this;
    }

    /**
     * Unloads all assets from the assets cache.
     * @method jibo.loader#unloadAll
     * @param {String} [cacheId] The specific cache to unload. Uses active cache if empty.
     * @return {jibo.loader} The loader namespace for chaining.
     */
    unloadAll(cacheId?:string): LoaderPlugin
    {
        this.assetManager.cache.empty(cacheId);
        return this;
    }

    /**
     * Cancels all the current loads.
     * @method jibo.loader#cancelAll
     * @return {jibo.loader} The loader namespace for chaining.
     */
    cancelAll(): LoaderPlugin
    {
        this.assetManager.cancelAll();
        return this;
    }

    /**
     * Adds a new custom cache. This "bucket" can be unloaded later.
     * @method jibo.loader#addCache
     * @param {String} cacheId The unique ID for cache.
     * @return {jibo.loader} The loader namespace for chaining.
     */
    addCache(cacheId:string): LoaderPlugin
    {
        this.assetManager.cache.addCache(cacheId);
        return this;
    }

    /**
     * Set or get the currently active cache.
     * @name jibo.loader#activeCache
     * @type {String}
     */
    set activeCache(cacheId:string)
    {
        this.assetManager.cache.activeCache = cacheId;
    }
    get activeCache(): string
    {
        return this.assetManager.cache.activeCache;
    }

    /**
     * Select the default cache.
     * @method jibo.loader#defaultCache
     * @return {jibo.loader} The loader namespace for chaining.
     */
    defaultCache(): LoaderPlugin
    {
        this.assetManager.cache.activeCache = AssetCache.DEFAULT_CACHE;
        return this;
    }

    /**
     * Unloads all assets from the assets cache.
     * @method jibo.loader#deleteCache
     * @return {jibo.loader} The loader namespace for chaining.
     */
    deleteCache(cacheId:string): LoaderPlugin
    {
        this.assetManager.cache.deleteCache(cacheId);
        return this;
    }

    /**
     * Get a cache by ID, useful for debugging.
     * @method jibo.loader#getCache
     * @internal
     * @param {String} [cacheId] Cache ID, uses active cache if non is specified.
     * @return {Object|null} The cache for corresponding ID, returns `null` if cache doesn't exist.
     */
    getCache(cacheId?:string): Cache
    {
        return this.assetManager.cache.getCache(cacheId) || null;
    }

    /**
     * Get all caches, useful for debugging.
     * @method jibo.loader#getCaches
     * @internal
     * @return {Object} The cache for corresponding ID.
     */
    getCaches(): Caches
    {
        return this.assetManager.cache.getCaches();
    }

    /**
     * Gets an asset from the cache by ID
     * @method jibo.loader#cached
     * @param {String} id The asset to fetch.
     * @param {String} [cacheId] The cache to grab asset from, uses the active cache if empty.
     * @return {*|null} The cached object or null if empty.
     */
    cached(id:string, cacheId?:string):any
    {
        return this.assetManager.cache.read(id, cacheId);
    }
}

Runtime.registerPlugin(LoaderPlugin, 'loader', {
    api: true
});

export default LoaderPlugin;
