import * as async from 'async';
import Runtime from '../Runtime';
import {EventEmitter} from 'events';
import { WSClient } from 'jibo-client-framework';

/**
 * @description
 * Non-motion-related robot body services (i.e. temperature, fan, battery, backlight, etc.).
 *
 * ```
 * var jibo = require("jibo");
 * jibo.system.getBatteryTemperature();
 * ```
 * @namespace jibo.system
 */
class SystemService extends EventEmitter {

    constructor() {
        super();

        this.bodyOutput = undefined;
        this.bs = {};

        this.bs.miscState = {
            ts : [],    // Chronometer timestamp
            main_board_temp : 0,   // Main board temperature sensor in degrees Celsius
            cpu_temp : 0,   // CPU die temperature in degrees Celsius
            intake_temp : 0, // Cooling air intake temperature in degrees Celsius
            exhaust_temp : 0, // Cooling air exhaust temperature in degrees Celsius
            neck_motor_temp : 0,   // Head motor temperature in degrees Celsius
            torso_motor_temp : 0,  // Torso motor temperature in degrees Celsius
            pelvis_motor_temp : 0  // Pelvis motor temperature in degrees Celsius
        };
        this.bs.touchState = {
            "ts" : [],  // Chronometer timestamp
            "touched" : false,  // True if any sensors touched.
            "pad_state" : [0, 0, 0, 0, 0, 0],   // Array with pad state (int) for each touch pad sensor, 0...N.
            "changed": [0, 0, 0, 0, 0, 0]       // Array with the indices of the pads that changed in this update, empty if none.
        };
        this.bs.powerState = {
            ts: [], // Chronometer timestamp
            source: "",                 // Are we on 'BATTERY' or 'EXTERNAL'
            vsys  : 0,                  // The current system voltage estimate
            battery :                       // Battery object, or undefined if no battery is present or detected.
                {
                    id : 0,           // Battery ID
                    cycles : 0,       // Number of battery cycles on this battery
                    capacity : 0,   // Current capacity of this battery in amphours
                    max_capacity : 0, // Maximum capacity of this battery in amp hours
                    charge_rate: 0,   // Charge rate of battery negative means draining, positive means charging.
                    temp : 0    // Battery temperature in Celsius
                }
        };
    }

    /**
     * Initialize the body service
     * @private
     * @method jibo.system#initBody
     */
    initBody(service, callback) {
        this.bodyHttpInterface = "http://" + service.host + ":" + service.port;
        this.socketUrl =  "ws:" + service.host + ":" + service.port;

        async.parallel(
            [
                this.createMiscSocket.bind(this),
                this.createTouchSocket.bind(this),
                this.createPowerSocket.bind(this)
            ],
            callback
        );
    }

    /**
     * Set the body output.
     * @name jibo.BodyService#output
     * @type {Object}
     * @private
     */
    set output(_output) {
        this.bodyOutput = _output;
    }

    /**
     * Get the robot's battery temperature.
     * @method  jibo.system#getBatteryTemperature
     * @return The temperature of the battery in degrees Celsius.
     */
    getBatteryTemperature() {
        return this.bs.powerState.battery.temp;
    }

    /** Get the robot's battery level.
     * @method jibo.system#getBatteryLevel
     * @return The current level of the battery as a percentage.
     */
    getBatteryLevel() {
        return (this.bs.powerState.battery.capacity/this.bs.powerState.battery.max_capacity) * 100;
    }

    /**
     * Get the robot's system voltage.
     * @method jibo.system#getSystemVoltage
     * @return The current system voltage estimate.
     */
    getSystemVoltage() {
        return this.bs.powerState.vsys;
    }

    /**
     * `true` if the robot is plugged in.
     * @name jibo.system#pluggedIn
     * @type {boolean}
     */
    get pluggedIn() {
        return (this.bs.powerState.source === 'EXTERNAL');
    }

    /**
     * `true` if the robot's battery is charging.
     * @name jibo.system#batteryCharging
     * @type {boolean}
     */
    // The units are mA and full charging is 2000mA. As Martin said charging at 0.02 (20mA) is impossible.
    get batteryCharging () {
        return (this.bs.powerState.battery.charge_rate >= 0.1);
    }

    /**
     * Get the robot's charging rate.
     * @name jibo.system#batteryChargeRate
     * @type {number}
     */
    get batteryChargeRate() {
        return this.bs.powerState.battery.charge_rate;
    }

    /**
     * Get the robot's main board temperature.
     * @method jibo.system#getMainBoardTemperature
     * @return The temperature of the main board in degrees Celsius.
     */
    getMainBoardTemperature() {
        return this.bs.miscState.main_board_temp;
    }

    /**
     * Get the robot's CPU temperature.
     * @method jibo.system#getCPUTemperature
     * @return The temperature of the CPU in degrees Celsius.
     */
    getCPUTemperature() {
        return this.bs.miscState.cpu_temp;
    }

    /**
     * @typedef jibo.system#touchState
     * @description The state of Jibo's head touchpads.
     * @type Object
     * @property changed {Array.<Number>}  The pads that have changed since last stream.
     * @property pad_state {Array.<Number>} The array of the 6 pads with `true` for on
     *                                      and `false` for off. 3 run verticaly down
     *                                      the left side of Jibo's head from top to bottom: `pad_state[0, 1, 2]`.
     *                                      3 run verticaly down the right of his head: `pad_state[3, 4, 5]`.
     * @property touch {Boolean} `true` if any of the pads have been touched.
     */

    /**
     * Get the touch state of pads in Jibo's head.
     * @method jibo.system#getTouchState
     * @returns {jibo.system#touchState} The state of Jibo's head touchpads.
     */
    getTouchState() {
        return this.bs.touchState;
    }

    /**
     * Get the robot's fan speed.
     * @method jibo.system#getFanSpeed
     * @param {Function} callback Notify the caller that the
     *                      system data was received or that an error was encountered.
     *                      If successful, return cooling fan speed as percentage of
     *                      maximum (range [0.0, 1.0]).
     *
     */
    getFanSpeed(callback) {
        this._getSystemSetting("fan_speed", callback);
    }

    /**
     * Get LCD backlight information.
     * @method jibo.system#getBacklight
     * @param {Function} callback Notify the caller that the
     *                      system data was received or that an error was encountered.
     *                      If successful, return the LCD backlight brightness
     *                      in percentage of maximum (range [0.0, 1.0]).
     */
    getBacklight(callback) {
        this._getSystemSetting("lcd_backlight", callback);
    }

    _getSystemSetting(setting, callback) {
        if (this.bodyHttpInterface === undefined) {
            return callback('Body Service is not available', null);
        }
        const request = new XMLHttpRequest();
        request.open("GET", this.bodyHttpInterface + '/settings', true);
        request.onreadystatechange = () => {
            if(request.readyState == 4) {
                if (request.status == 200) {
                    if (request.response) {
                        // success!
                        const response = JSON.parse(request.response);
                        callback(null, response[setting]);
                    }
                    else {
                        callback('No data received from body service', null);
                    }
                }
                else {
                    // failure if anything else
                    let message = 'Body service is unavailable';
                    if (request.statusText !== undefined && request.statusText !== "") {
                        message = request.statusText;
                    }

                    callback(message, null);
                }
            }
        };

        request.send();
    }

    /**
     * Set the LCD backlight brightness.
     * @method jibo.system#setBacklight
     * @param {Value} value Desired brightness of LCD backlight (range [0.0 - 1.0]).
     * @param {Function} callback Notify the caller that
     *                      system data was received or that an error was encountered.
     *                      If unsuccessful, return the error; otherwise, return `null`.
     */
    setBacklight(value, callback) {
        // ensure that value is between 0.0 and 1.0
        if ((value < 0.0) || (value > 1.0)) {
            return callback(`Backlight brightness value of ${value} is out of range [0.0 - 1.0].`);
        }
        // get fan speed so we can set current value in body (so we don't muck with it!)
        this.getFanSpeed((error, fan) => {
            if (error) {
                callback(error);
            }
            else {
                const body = {
                    "lcd_backlight" : value,
                    "fan_speed" : fan
                };
                const request = new XMLHttpRequest();
                const uri = this.bodyHttpInterface + '/settings';
                request.open("POST", uri, true);
                request.onreadystatechange = () => {
                    if(request.readyState == 4) {
                        if (request.status == 204) { // no content means success!
                            callback(null);
                        }
                        else {
                            // failure if anything else
                            let message = 'Body service is unavailable';
                            if (request.statusText !== undefined && request.statusText !== "") {
                                message = request.statusText;
                            }
                            callback(message, null);
                        }
                    }
                };

                request.send(JSON.stringify(body));
            }
        });
    }

    /**
     * Attempt to index the robot (can be re-indexing or happening for the first time).
     * @method jibo.system#index
     * @param {Function} callback Notify the caller that the robot was successfully indexed.
     *                      If unsuccessful, return the error; otherwise, return `null`.
     */
    index(callback) {

        // Consider the robot indexed immediately when in the simulator
        if (jibo.runMode === jibo.RunMode.SIMULATOR) {
            setImmediate( callback );
            return;
        }

        if (!this.bodyOutput) {
            callback("Do not have body output defined to index.");
            return;
        }

        // pause motion output
        //console.log("Robot will index now, pausing body output!");
        this.bodyOutput.setPaused(true);

        // get motion interface and current DOFs
        let motionInterface = this.bodyOutput.getMotionInterface();
        let dofs = motionInterface.getMotionDOFNames();

        // save off current index counter
        let prevDofs = [];
        for (let i=0; i<dofs.length; i++) {
            let dofState = motionInterface.getState(dofs[i]);
            if (dofState) {
                prevDofs.push(dofState.getIndexCount());
            }
         //   console.log("DOF[" + i + "] previous index count: " + dofState.getIndexCount());
        }

        let counter = 100;

        // run the loop every 100ms; timeout after some time?
        let interval = Runtime.instance.timer.setInterval(() =>{

            counter--;

            if (counter < 0) {
                interval.stop();
                this.bodyOutput.setPaused(false);
                callback("Robot indexing timed out");
                return;
            }

            // check if we're done now
            if (!motionInterface.isConnected())
            {
               // console.log("Waiting for connection to body service...");
                return;
            }

            // check to see if all the DOFs are already indexed
            let allIndexed = true;
            for (let i=0; i<dofs.length; i++)
            {
                let dofState = motionInterface.getState(dofs[i]);
                if (!dofState.isIndexed() || (prevDofs[i] === dofState.getIndexCount()))
                {
                    allIndexed = false;
                    break;
                }
            }
            if (allIndexed) {
                interval.stop();
                this.bodyOutput.setPaused(false);
                callback();
                return;
            }
            else if (motionInterface.hasLockout() || motionInterface.hasFault()) {
                interval.stop();
                this.bodyOutput.setPaused(false);
                callback("Robot has a motor error, cancelled indexing");
                return;
            }

            // set a command for each DOF
            for (let i=0; i<dofs.length; i++)
            {
                let dofState = motionInterface.getState(dofs[i]);
                if (dofState.isIndexed() && (prevDofs[i] !== dofState.getIndexCount()))
                {
                    // indexed, hold still
                    // setCommand(dofName, commandMode, commandValue, velocityLimit, accelerationLimit, currentLimit)
                    motionInterface.setCommand(dofs[i], 4, [0], null, 50, null);
                }
                else
                {
                    // not indexed, spin counter-clockwise
                    // setCommand(dofName, commandMode, commandValue, velocityLimit, accelerationLimit, currentLimit)
                    motionInterface.setCommand(dofs[i], 4, [-1], null, 50, null);
                }
            }

            // send the motion command to the body service
            motionInterface.sendCommand();
          // console.log("Indexing...");

        },100);
    }

    createMiscSocket(callback) {
        this.MiscSocket = new WSClient(this.socketUrl + "/misc");
        this.MiscSocket.on('error', () => {
            console.error(`Error opening misc state socket at ${this.socketUrl}/misc`);
        });
        this.MiscSocket.on('message', (data) => {
            this.bs.miscState = data;
        });
        callback();
    }

    createTouchSocket(callback) {
        this.TouchSocket = new WSClient(this.socketUrl + "/touch");
        this.TouchSocket.on('error', () => {
            console.error(`Error opening touch state socket at ${this.socketUrl}/touch`);
        });
        this.TouchSocket.on('message', (data) => {
            this.bs.touchState = data;
        });
        callback();
    }

    createPowerSocket(callback) {
        this.PowerSocket = new WSClient(this.socketUrl + "/power");
        this.PowerSocket.on('error', () => {
            console.error(`Error opening power state socket at ${this.socketUrl}/power`);
        });
        this.PowerSocket.on('message', (data) => {
            this.bs.powerState = data;
        });
        callback();
    }

    /**
     * Initializes the audio system.
     * @name jibo.system#initAudio
     * @private
     */
    initAudio(service, callback) {
        this.audioHttpInterface = "http://" + service.host + ":" + service.port;
        this._inputEnergy = {
            ts: [],         // Chronometer timestamp of this state
            db_rms: 0.0,    // Overall dB RMS of input waveform
            db_high: 0.0,   // ~1KHz dB RMS of input waveform
            db_mid: 0.0,    // ~500Hz dB RMS of input waveform
            db_low: 0.0     // ~200Hz dB RMS of input waveform
        };
        const audioSocketUrl = "ws:" + service.host + ":" + service.port;
        const energySocket = new WSClient(audioSocketUrl + "/input_energy");
        energySocket.on('error', () => {
            console.error(`Error opening audio input energy socket at ${audioSocketUrl}/input_energy`);
        });
        energySocket.on('message', (data) => {
            this._inputEnergy = data;
            /**
             * Emitted audio input energy changes.
             * @event jibo.system#input-energy
             * @param {Object} inputEnergy Object that represents input energy.
             * @param {Number[]} inputEnergy.ts Chronometer timestamp of this state
             * @param {Number} inputEnergy.db_rms Overall dB RMS of input waveform
             * @param {Number} inputEnergy.db_high ~1KHz dB RMS of input waveform
             * @param {Number} inputEnergy.db_mid ~500Hz dB RMS of input waveform
             * @param {Number} inputEnergy.db_low ~200Hz dB RMS of input waveform
             */
            this.emit('input-energy', this._inputEnergy);
        });
        callback();
    }

    /**
     * Energy statistics for input audio at 20Hz.
     * @name jibo.system#inputEnergy
     * @private
     */
    get inputEnergy() {
        return this._inputEnergy;
    }


    /**
     * Get current master volume.
     * @method jibo.system#getMasterVolume
     * @param {Function} callback Notify the caller that the
     *                      system data was received or that an error was encountered.
     *                      If successful, return the master volume (range [0.0, 1.0]).
     */
    getMasterVolume(callback) {
        this._getMixerSetting((error, settings) => {
            if (error) {
                callback(error);
            }
            else {
                callback(null, settings.master.playbackVolume);
            }
        });
    }

    /**
     * Set the master volume.
     * @method jibo.system#setMasterVolume
     * @param {Value} value Desired master volume (range [0.0 - 1.0]).
     * @param {Function} callback Notify the caller that
     *                      system data was received or that an error was encountered.
     *                      If unsuccessful, return the error; otherwise, return `null`.
     */
    setMasterVolume(value, cb) {
        if (isNaN(value)) {
            let error = value + ' is not a number. Please pick a value between [0.0 - 1.0].';
            cb(error);
            return;
        }

        // ensure that value is between 0.0 and 1.0
        if (value < 0.0 || value > 1.0) {
            let error = 'Master volume of ' + value + ' is out of range [0.0 - 1.0].';
            cb(error);
            return;
        }
        // get mixer settings so we can only alter the one property
        this._getMixerSetting((error, settings) => {
            if (error) {
                cb(error);
            }
            else {
                let request = new XMLHttpRequest();
                let uri = this.audioHttpInterface + '/mixer';

                request.open("POST", uri, true);

                request.onreadystatechange = () => {
                    if(request.readyState == 4) {
                        if (request.status == 204) { // no content means success!
                            cb(null);
                        }
                        else {
                            // failure if anything else
                            let msg = 'Audio Service is unavailable';
                            if (request.statusText !== undefined && request.statusText !== "") {
                                msg = request.statusText; // use "reason" if they gave it
                            }

                            cb(msg);
                        }
                    }
                };

                settings.master.playbackVolume = value;
                request.send(JSON.stringify(settings));
            }
        });
    }

    /**
     * Get mixer settings.
     * @method jibo.system#_getMixerSetting
     * @private
     * @param {Function} callback Callback when complete.
     */
    _getMixerSetting(cb) {
        if (!this.audioHttpInterface) {
            cb('Audio Service is not available', null);
            return;
        }

        let request = new XMLHttpRequest();

        request.open("GET", this.audioHttpInterface + '/mixer', true);

        request.onreadystatechange = () => {
            if(request.readyState == 4) {
                if (request.status == 200) {
                    if (request.response) {
                        // success!
                        let response = JSON.parse(request.response);
                        cb(null, response);
                    }
                    else {
                        cb('No data received from audio service', null);
                    }
                }
                else {
                    // failure if anything else
                    let msg = 'Audio service is unavailable';
                    if (request.statusText !== undefined && request.statusText !== "") {
                        msg = request.statusText;
                    }

                    cb(msg, null);
                }
            }
        };
        request.send();
    }
}

export default SystemService;
