/**
 * Enum of RunMode types.
 *
 * ```
 * jibo.RunMode.SIMULATOR
 * ```
 *
 * @alias jibo~RunMode
 * @enum {string}
 */
const RunMode = {
    /** Running in the simulator. */
    SIMULATOR: "SIMULATOR",
    /** Running in remote mode. */
    REMOTELY: "REMOTELY",
    /** Running on the robot. */
    ON_ROBOT: "ON_ROBOT",
    /** Running in dev mode, no SSM */
    UNIT_TESTS: "UNIT_TESTS"
};

/**
 * Internal object for an installed plugin
 */
interface InstalledPlugin {
    instance?:Plugin;
    pluginClass:PluginConstructor;
    depends:string[];
    api:boolean;
    id:string;
    name:string;
    initialized:boolean;
    installed:boolean;
    electron:boolean;
}

interface PluginOptions {
    api?:boolean;
    depends?:string[];
    name?:string;
    electron?:boolean;
}

