import Element from './Element';
import TweenManager from '../../tween/TweenManager';
import ViewManager from '../ViewManager';

interface FontStyle {
    fontSize:number|string;
    fontFamily:string;
    fill:string;
    fontStyle?:string;
}

/**
 * Wraps text label in Pixi.
 *
 * @class Label
 * @extends jibo.face.Element
 * @memberof jibo.face
 */
class Label extends Element
{
    /**
     * The Class name as a string.
     * @type {String}
     * @default = 'Label'
     * @protected
     * @internal
     */
    protected _type:string = Label.DEFAULT_TYPE;    // ATTENTION !! Every class must define _type to be equal to the Class name

    /**
     * The default class identifier.
     * Generally used to register the class.
     * @name jibo.face.Label.DEFAULT_TYPE
     * @type {String}
     * @readOnly
     * @internal
     */
    public static get DEFAULT_TYPE():string {return 'Label';}

    /**
     * Object describing the font specification used by PIXI.Text.
     * Example -
     *  fontSize: 100,
     *  fontFamily: 'Proxima Nova Soft',
     *  fill: '#FFFFFF',
     *  fontStyle: 'bold'
     *  @name jibo.face.Label#style
     *  @type {Object}
     */
    public style:FontStyle = null;

    /**
     * Reference to the PIXI.Text object.
     * @name jibo.face.Label#textDisplay
     * @type {PIXI.Text}
     */
    public textDisplay:PIXI.Text = null;

    /**
     * Anchor values for display, values range from 0 to 1
     * and represent a percentage of the total width or height.
     * If defined anchor values will be applied to display on its creation.
     * @name jibo.face.Label#_targetAnchor
     * @type {PIXI.Point}
     * @protected
     * @internal
     */
    protected _targetAnchor:PIXI.Point = null;

    /**
     * Anchor values for display, values range from 0 to 1
     * and represent a percentage of the total width or height.
     * If defined anchor values will be applied to display on its creation.
     * @name jibo.face.Label#targetAnchor
     * @type {PIXI.Point}
     * @readOnly
     * @internal
     */
    public get targetAnchor():PIXI.Point {
        if(!this._targetAnchor) {
            this._targetAnchor = new PIXI.Point();
        }
        return this._targetAnchor;
    }

    /**
     * Text message to display.
     * @name jibo.face.Label#_text
     * @returns {String}
     * @protected
     * @internal
     */
    protected _text:string = '';

    /**
     * Text to display.
     * @name jibo.face.Label#text
     * @type {String}
     */
    public get text():string { return this._text; }
    public set text(newText:string) {
        this._text = newText;
        if(this.textDisplay) {
            this.textDisplay.text = this._text;
        }
    }

    /**
     * Helper method to create font style Objects for use with `PIXI.Text`.
     * @method jibo.face.Label.createFontStyle
     * @param {Number|String} size The size of the font.
     * @param {String} family The font family/name.
     * @param {String} color The font color.
     * @param {String} [style] The font style (e.g. bold, italic)
     * @returns {{fontSize: number, fontFamily: string, fill: string, fontStyle: string}}
     *          Object in format required by Pixi to define text style.
     */
    public static createFontStyle(size:number|string, family:string, color:string, style?:string):FontStyle {
        let fontStyle = {
            fontSize: Number(size) || size,
            fontFamily: family,
            fill: color,
            fontStyle: style
        };
        return fontStyle;
    }

    /**
     * Create Label from config Object.
     * @method jibo.face.Label.createFromConfig
     * @returns {PIXI.Point}
     */
    public static createFromConfig(configData:any):Label {

        let label:Label = new Label();
        label.assignConfig(configData);
        return label;
    }

    /**
     * Applies data contained within the given configData Object (generally derived
     * from JSON) to the class. Specifically assigns 'text' and 'style' variables.
     * @method jibo.face.Label#assignConfig
     * @param {Object} configData The configuration Object for the Component.
     * @internal
     */
    public assignConfig(configData:any):void {

        super.assignConfig(configData);

        if(configData.hasOwnProperty("text")) {
            this.text = configData.text;
        }

        if(configData.hasOwnProperty("style")) {
            // have to cast fontSize to number
            this.style = <FontStyle>configData.style;
            if(this.style.fontSize){
                this.style.fontSize = Number(this.style.fontSize) || this.style.fontSize;
            }
        }

        if (configData.hasOwnProperty('targetAnchor')) {
            this._targetAnchor = new PIXI.Point(Number(configData.targetAnchor.x), Number(configData.targetAnchor.y));
        }
    }

    /**
     * Set up the display.
     * Assign assets, set timelines, etc.
     * @method jibo.face.Label#setupDisplay
     * @param {Object} [assets] Object passed back from loader namespace load method,
     *        refer to {@link jibo.loader} for detail
     */
    public setupDisplay(assets?:any):void {
        this.textDisplay = new PIXI.Text(this.text, this.style);
        this.display.addChild(this.textDisplay);
    }

    /**
     * Get the width and height of the Text given its current text and style.
     * This is useful if the display has not been created yet but you need to know the height ahead of time.
     * If the display and Text are already created, it's more efficient to just get the dimensions direction from the display.
     * @method jibo.face.Label#getTextDimensions
     * @param {String} [sampleText]
     * @type {PIXI.Point}
     */
    public getTextDimensions(sampleText?:string):PIXI.Point {

        let dimensions:PIXI.Point;
        if(!this.textDisplay) {

            // text hasn't been created yet, so we create the Text to get the dimension, then set it back to null
            if(!sampleText) {
                sampleText = (this.text) ? this.text : "Sample";
            }
            this.textDisplay = new PIXI.Text(sampleText, this.style);
            dimensions = new PIXI.Point(this.textDisplay.width, this.textDisplay.height);
            //this.textDisplay = null;
        }
        else {
            dimensions = new PIXI.Point(this.textDisplay.width, this.textDisplay.height);
        }
        return dimensions;
    }

    /**
     * Predefine the anchor point for your Text. These anchors are applied when `applyTransition` is called.
     * This is useful for defining anchor of the label before the display is created.
     * @method jibo.face.Label#setTargetAnchor
     * @param {int} [x = 0] - Value between 0 and 1, percentage of width where the anchor should be placed.
     * @param {int} [y = 0] - Value between 0 and 1, percentage of height where the anchor should be placed.
     * @param {Boolean} [applyNow = false] If `true` will apply anchor position to Text within method,
     *                  as long as Text has been defined.
     */
    public setTargetAnchor(x:number = 0, y:number = 0, applyNow:boolean = false):void {
        if(!this._targetAnchor) {
            this._targetAnchor = new PIXI.Point();
        }
        this._targetAnchor.x = x;
        this._targetAnchor.y = y;

        if(applyNow && this.textDisplay)
        {
            this.textDisplay.anchor.x = x;
            this.textDisplay.anchor.y = y;
        }
    }

    /**
     * Apply target position and anchors if they were defined and if display and text have been created.
     * @method jibo.face.Label#applyPosition
     */
    public applyPosition():void {
        super.applyPosition();

        // apply anchor adjustments
        if(this.textDisplay && this._targetAnchor) {
            this.textDisplay.anchor.x = this._targetAnchor.x;
            this.textDisplay.anchor.y = this._targetAnchor.y;
        }
    }

    /**
     * Open transition, defaults to fading alpha in from zero.
     * @method jibo.face.Label#open
     * @param {Function} [callback] Function to be called once open is complete.
     * @param {String} transitionType String used to determine way Component opens,
     *        refer to ViewManager for constants used
     * @param {number} [tweenTime = 500] Duration of the tween.
     * @param {String} [tweenType = 'sineOut'] Type of tween used.
     * @internal
     */
    public open(callback?:Function, transitionType?:string, tweenTime:number = ViewManager.TRANS_TIME, tweenType:string = 'sineOut' ):void{
        TweenManager.stop(this.display);
        TweenManager.play(this.display, {
            to: { alpha: 1 },
            from: { alpha: 0 },
            duration: tweenTime,
            ease: tweenType
        }, callback);
    }

    /**
     * Open transition, defaults to fading alpha out to zero.
     * @method jibo.face.Label#close
     * @param {Function} [callback] Function to be called once open is complete.
     * @param {String} [transitionType] String used to determine way Component closes,
     *        refer to ViewManager for constants used.
     * @param {number} [tweenTime = 500] Duration of the tween.
     * @param {String} [tweenType = 'sineIn'] Type of tween used.
     * @internal
     */
    public close(callback?:Function, transitionType?:string, tweenTime:number = ViewManager.TRANS_TIME, tweenType:string = 'sineIn' ):void{
        TweenManager.stop(this.display);
        TweenManager.play(this.display, {
            to: { alpha: 0 },
            duration: tweenTime,
            ease: tweenType
        }, callback);
    }

    /**
     * Destroy
     * @method jibo.face.Label#destroy
     * @internal
     */
    public destroy():void {
        this.style = null;
        this.textDisplay = null;
        this._targetAnchor = null;
        super.destroy();
    }
}

export default Label;
