/**
 * Keep track of the state of the active MIM. Returned by MIM callbacks.
 * @class MimState
 * @memberof jibo.mim
 */
export default class MimState {

    /**
     * Overall number of listen attemps that have been made.
     * @name jibo.mim.MimState~tries
     * @type {Number}
     */
    public tries:number;
    /**
     * Number of no-input errors that have happened.
     * @name jibo.mim.MimState~noInputCount
     * @type {Number}
     */
    public noInputCount:number;
    /**
     * Number of no-match errors that have happened.
     * @name jibo.mim.MimState~noMatchCount
     * @type {Number}
     */
    public noMatchCount:number;
    /**
     * Type of the MIM result. Can be 'match', 'noMatch', 'noInput', or 'entry'.
     * @name jibo.mim.MimState~lastResultState
     * @type {String}
     */
    public lastResultState:string;
    /**
     * `true` if the MIM has succeeded.
     * @name jibo.mim.MimState~success
     * @type {Boolean}
     */
    public success:boolean;
    /**
     * `true` if the MIM has failed (too many no inputs or no matches).
     * @name jibo.mim.MimState~failure
     * @type {Boolean}
     */
    public failure:boolean;
    /**
     * The last used prompt text.
     * @name jibo.mim.MimState~promptText
     * @type {String}
     * @private
     */
    public promptText:string;

    constructor() {
        this.tries = 0;
        this.noInputCount = 0;
        this.noMatchCount = 0;
        this.lastResultState = 'entry';
        this.success = false;
        this.failure = false;
        this.promptText = '';
    }

    /**
     * Reset the MimState so that a mim can be restarted.
     * @method jibo.mim.MimState~reset
     * @private
     */
    public reset() {
        this.tries = 0;
        this.noInputCount = 0;
        this.noMatchCount = 0;
        this.lastResultState = 'entry';
        this.success = false;
        this.failure = false;
        this.promptText = '';
    }

    /**
     * If the MIM is complete, due to success or failure.
     * @name jibo.mim.MimState~done
     * @type {Boolean}
     */
    get done():boolean {
        return (this.success || this.failure);
    }

    /**
     * Increase the number of tries that this MIM has made.
     * @method jibo.mim.MimState~incrementTries
     * @private
     */
    public incrementTries():void {
        this.tries++;
    }

    /**
     * Increase the number of misses due to no-input errors that this MIM has had.
     * Also inform the MimManager that an error happened.
     * @method jibo.mim.MimState~incrementNoInputCount
     * @private
     */
    public incrementNoInputCount():void {
        this.noInputCount++;
    }

    /**
     * Increase the number of misses due to no-match errors that this MIM has had.
     * Also inform the MimManager that an error happened.
     * @method jibo.mim.MimState~incrementNoMatchCount
     * @private
     */
    public incrementNoMatchCount():void {
        this.noMatchCount++;
    }
}
