import async = require('async');
import Runtime from '../Runtime';
import {Plugin, PluginCallback} from '../Plugin';
import SerialTimer from '../utils/perf/SerialTimer';
import ParallelTimer from '../utils/perf/ParallelTimer';

type ServiceHandler = (service:any, callback:any) => void;

/**
 * Fetch the list of services from the registry
 */
class ServicesPlugin implements Plugin {
    
    public serviceInit:{[id:string]: ServiceHandler};

    constructor() {

        const jibo:Runtime = Runtime.instance;

        /**
         * The map of service calls to init
         */
        this.serviceInit = {
            tts: (service, callback) => {
                jibo.tts.init(service, callback);
            },
            lps: (service, callback) => {
                jibo.lps.init(service, callback);
            },
            notifications: (service, callback) => {
                jibo.notifications.init(service, callback);
            },
            body: (service, callback) => {
                jibo.animUtils.initOutput(service);
                jibo.system.initBody(service, callback);
            },
            nlu: (service, callback) => {
                jibo.nlu.init(service, callback);
            },
            'system-manager': (service, callback) => {
                jibo.systemManager.init(service, callback);
            },
            audio: (service, callback) => {
                jibo.system.initAudio(service, callback);
            },
            gl: (service, callback) => {
                jibo.gl.init(service, callback);
            },
            kb: (service, callback) => {
                jibo.kb.init(service, (err) => {
                    jibo.kb.initLoop();
                    callback();
                });
            },
            performance: (service, callback) => {
                jibo.performance.init(service, callback);
            },
            media: (service, callback) => {
                jibo.media.init(service, callback);
            },
            wifi: (service, callback) => {
                jibo.wifi.init(service,callback);
            }
        };
    }
    
    init(done:PluginCallback): void {

        const jibo:Runtime = Runtime.instance;

        // Ignore services if runing in unit tests
        if (jibo.runMode === jibo.RunMode.UNIT_TESTS) {
            return done();
        }

        const tasks = [];

        jibo.records.forEach((service) => {
            const initFunction = this.serviceInit[service.name];
            if(initFunction) {
                tasks.push((_callback) => {
                    // We wrap the service init callback so that we can
                    // time each servicie initialization automatically
                    const timer = new SerialTimer(service.name, parallelTimer);
                    initFunction(service, (error, param) => {
                        timer.stop();
                        _callback();
                    });
                });
            }
        });

        const parallelTimer = new ParallelTimer('parallelInitializedServices', jibo.initTimer);

        async.parallel(tasks, (error, results) => {
            if (error) {
                console.error('Error: ', error);
                done(error);
            }
            else {
                jibo.animUtils.attachOutput();
                parallelTimer.stop();
                done();
            }
        });
    }
}

Runtime.registerPlugin(ServicesPlugin, 'services', {
    depends: ['service-records', 'anim-utils']
});

export default ServicesPlugin; 