import ComponentGroup from './ComponentGroup';
import View from './views/View';
import ActionData from './actions/ActionData';
import {EventEmitter} from "events";
import {AssetDescriptor} from './ViewManager';

/**
 * Base component class for GUI elements.
 * @class Component
 * @extends EventEmitter
 * @memberof jibo.face
 * @abstract
 * @internal
 */
abstract class Component extends EventEmitter
{
    /**
     * String used for identification, each Component within a
     * ComponentGroup should have a unique id to help with retrieval.
     * @name jibo.face.Component#id
     * @type {String}
     */
    public id:string = '';

    /**
     * The Class name as a string or a possible variation of the Class.
     * Should be defined by the extending class.
     * @name jibo.face.Component#_type
     * @type {String}
     * @protected
     * @internal
     */
    protected _type:string = '';

    /**
     * The Component type. Should equal the Class name.
     * In some case, `type` may not be equal to Class name if you're using variants.
     * Variants allow for different behavior within the class without having to extend it.
     * @name jibo.face.Component#type
     * @type {String}
     * @readOnly
     */
    public get type():string { return this._type; }

    /**
     * Reference to the parent group of this Component.
     * @name jibo.face.Component#parentGroup
     * @type {jibo.face.ComponentGroup}
     */
    public parentGroup:ComponentGroup = null;

    /**
     * Flag that should be internally set if the class has changed its
     * state in a way that needs to be recorded between Views (e.g when a
     * list moves from one page to another).
     * @name jibo.face.Component#_stateChanged
     * @type {Boolean}
     * @default false
     * @protected
     * @internal
     */
    protected _stateChanged:boolean = false;

    /**
     * Set to `true` class has changed its
     * state in a way that needs to be recorded between Views (e.g when a
     * list moves from one page to another).
     * @name jibo.face.Component#stateChanged
     * @type {Boolean}
     * @default false
     * @readOnly
     * @internal
     */
    public get stateChanged():boolean {
        return this._stateChanged;
    }

    /**
     * List of Objects that define assets to be loaded,
     * refer to {@link jibo.loader} for documentation.
     * @name jibo.face.Component#_assetDescriptors
     * @type {any[]}
     * @protected
     * @internal
     */
    protected _assetDescriptors:Array<AssetDescriptor> = null;

    /**
     * Reference to Object passed back from jibo.loader.load,
     * refer to {@link jibo.loader} for documentation.
     * @name jibo.face.Component#_assets
     * @type {Object}
     * @default Object
     * @protected
     * @internal
     */
    protected _assets:any = {};

    /**
     * Flag to lock and unlock component's respond to input, class will
     * need to implement flags appropriately
     * @name jibo.face.Component#_inputLocked
     * @type {Boolean}
     * @default true
     * @protected
     * @internal
     */
    protected _inputLocked:boolean = true;

    /**
     * List of actions associated with Component.
     * @name jibo.face.Component#_actions
     * @type {jibo.face.ActionData[]}
     * @protected
     * @internal
     */
    protected _actions:ActionData[] = null;

    /**
     * Reference to the top most parent group of this Component, which is a View.
     * @name jibo.face.Component#_parentView
     * @type {jibo.face.View}
     * @private
     */
    private _parentView:View = null;

    /**
     * Flag to lock (`true`) and unlock (`false`) component's response to input.
     * Inheriting class responsible for determining where locks should preside.
     * @name jibo.face.Component#inputLocked
     * @type {Boolean}
     */
    public get inputLocked():boolean {
        return this._inputLocked;
    }
    public set inputLocked(flag:boolean) {
        // making setter/getter so that inheriting classes can
        // override for expanded functionality
        this._inputLocked = flag;
    }

    /**
     * Get the View the Component is ultimately parented to.
     * @name jibo.face.Component#parentView
     * @type {jibo.face.View}
     * @readOnly
     */
    public get parentView():View {
        if(this._parentView){
            return this._parentView;
        }
        let group:Component = this;
        while (group.parentGroup){
            group = this.parentGroup;
        }
        if(group instanceof View){
            this._parentView = <View>group;
            return this._parentView;
        }
        else{
            console.warn('Component is not yet parented to a View.');
            return null;
        }
    }

    //////////////////////// CONSTRUCTION ////////////////////////

    /**
     * Applies data contained within the given configData Object (generally derived
     * from JSON) to the class. Override this method to apply any further config
     * data and/or make manual additions to the class's variables.
     * @method jibo.face.Component#assignConfig
     * @param {Object} configData The configuration Object for the Component.
     * @internal
     */
    public assignConfig(configData:any):void {
        if(configData){
            // apply id from config if a id is not currently defined
            if (configData.hasOwnProperty('id')) {
                if(!this.id){
                    this.id = configData.id;
                }
            }
            if (configData.hasOwnProperty('type')) {
                this._type = configData.type;
            }
            if (configData.hasOwnProperty('assets')) {
                if(!this._assetDescriptors){
                    this._assetDescriptors = [];
                }
                this._assetDescriptors = this._assetDescriptors.concat(configData.assets);
            }
        }
    }

    /**
     * Takes initial config Object that was provided to define class and updates it
     * with any necessary values regarding any new `state` of the component.
     * Returns the updated Object, though it shouldn't be necessary to reassign
     * the returned Object, since generally the updated values are assigned through `Object.assign`
     * to merge new values into original.
     * @method jibo.face.Component#updateConfig
     * @param {Object} configObject The configuration Object for the Component.
     * @abstract
     * @internal
     */
    public abstract updateConfig(configData:any):any;

    /**
     * To be overridden, should create DisplayObjects from given assets and add the
     * to stage via the given container.
     * @method jibo.face.Component#createDisplay
     * @param {PIXI.Container} container Parent container, which all DisplayObject
     *        created within this Component should be added to.
     * @param {Object} assets Object passed back from loader namespace load method,
     *        refer to {@link jibo.loader} for details.
     * @abstract
     * @internal
     */
    public abstract createDisplay(container:PIXI.Container, assets:any):void;

    /**
     * Register with the parent group to enter the update loop.
     * If `true` registers for update, if `false` unregisters for update.
     * @method jibo.face.Component#registerUpdate
     * @param {Boolean} bool Flag to register or unregister with update.
     */
    public registerUpdate(bool:boolean):void {
        if(bool){
            this.parentGroup.registerComponentUpdate(this);
        }
        else{
            this.parentGroup.unregisterComponentUpdate(this);
        }
    }

    /**
     * Frame enter loop update.
     * @method jibo.face.Component#update
     * @param {number} elapsed Time in milliseconds since the last frame update.
     * @abstract
     * @internal
     */
    public abstract update(elapsed:number):void;

    /**
     * Cleanup method to assist with garbage collection.
     * @method jibo.face.Component#destroy
     */
    public destroy():void {
        this.removeAllListeners();
        this._assetDescriptors = null;
        this._assets = null;
        this._actions = null;
        this.parentGroup = null;
    }

    /**
     * Called by parent ComponentGroup once parent has finished its loading and setup.
     * Allows opportunity to do additional setup that may depend on other components.
     *
     * ATTENTION : This should not be called directly, the parent View {@link jibo.face.View}
     * will call this, which will recurse through Component tree.
     * @method jibo.face.Component#ready
     */
    public abstract ready():void;

    /**
     * Method for `open` transition, override to custom how Component opens.
     * Method is responsible for calling the callback in all situations as
     * the parent ComponentGroup is waiting for all children to trigger the callback in oder to complete.
     *
     * ATTENTION : This should not be called directly, the {@link jibo.face.ViewManager}
     * will manage when Components should close during the view process.
     * @method jibo.face.Component#open
     * @param {Function} callback Function to be called once open is complete.
     * @param {String} transitionType String used to determine way Component opens,
     *        refer to {@link jibo.face.ViewManager} for constants used
     * @internal
     */
    public open(callback:Function, transitionType?:string ):void{
        callback();
    }

    /**
     * Method for `close` transition, override to custom how Component opens.
     * Method is responsible for calling the callback in all situations as
     * the parent ComponentGroup is waiting for all children to trigger the callback in oder to comple
     *
     * ATTENTION : This should not be called directly, the {@link jibo.face.ViewManager}
     * will manage when Components should close during the view process.
     * @method jibo.face.Component#close
     * @param {Function} callback Function to be called once open is complete.
     * @param {String} [transitionType] String used to determine way Component closes,
     *        refer to {@link jibo.face.ViewManager} for constants used.
     * @internal
     */
    public close(callback:Function, transitionType?:string ):void{
        callback();
    }

    /**
     * Return array of objects that describe assets to be loaded,
     * refer to {@link jibo.loader} for documentation.
     * @name jibo.face.Component#assetDescriptors
     * @type {jibo.face.ViewManager#AssetDescriptor[]}
     * @readOnly
     * @internal
     */
    public get assetDescriptors():AssetDescriptor[] {
        return this._assetDescriptors;
    }

    /**
     * Manually add an asset descriptor via parameters,
     * refer to {@link jibo.loader} for documentation.
     * @method jibo.face.Component#addAssetDescriptor
     * @param {String} id The id for the asset, ids must be unique, otherwise they will override each other.
     * @param {String} src The source path of the asset to be loaded
     * @param {String} type The type of asset to load, refer to {@link jibo.loader} for valid types.
     * @param {Boolean} [upload = false] Flag determining if asset should be loaded to the CPU as part of the load process.
     * @returns {Object}
     */
    public addAssetDescriptor(id:string, src:string, type:string, upload:boolean = false):any {
        return this.addAssetDescriptorObject({
            id:id,
            src:src,
            type:type,
            upload:upload
        });
    }

    /**
     * Manually add an asset descriptor object,
     * refer to {@link jibo.loader} for documentation on format.
     * @method jibo.face.Component#addAssetDescriptorObject
     * @param {Object} assetDescriptor See {@link jibo.loader} for asset format.
     * @returns {Object}
     */
    public addAssetDescriptorObject(assetDescriptor:AssetDescriptor):any {
        if(!this._assetDescriptors){
            this._assetDescriptors = [];
        }
        return this._assetDescriptors.push(assetDescriptor);
    }

    public addAction(type:string, data?:any, clearPrevious?:boolean, toFront?:boolean):ActionData;
    public addAction(actionData:ActionData, clearPrevious?:boolean, toFront?:boolean):ActionData;
    /**
     * Add a {@link jibo.face.ActionData}. All actions with  will be triggered on triggerActions.
     * Generally these actions are triggered on a screen press (if a screen press is set up).
     * @method jibo.face.Component#addAction
     * @param {jibo.face.ActionData | string} action - The action to be triggered on click,
     * can pass the ActionData or provide the action type
     * @param {any} [data] - The data Object for the action, if passing the action type.
     * @param {boolean} [clearPrevious = false] Flag to determine if we should clear out the existing actions.
     * @param {boolean} [toFront = false] If `true` adds action to front of actions list, causing it to be called first when actions are triggered.
     * @returns {jibo.face.ActionData} Returns the ActionData added.
     */
    public addAction(action: ActionData | string, data?:any, clearPrevious:boolean = false, toFront:boolean = false):ActionData {

        let actionData:ActionData;
        if (typeof action === 'string') {
            actionData = new ActionData(action, data);
        }
        else {
            // shift params to account for different in possible param length
            actionData = action;
            toFront = clearPrevious;
            clearPrevious = data;
        }

        if(!this._actions) {
            this._actions = [];
        }else if(clearPrevious){
            this._actions.length = 0;
        }
;
        if(toFront){
            this._actions.unshift(actionData);
        }
        else{
            this._actions.push(actionData);
        }
        return actionData;
    }

    /**
     * Clear all {@link jibo.face.ActionData} listed in Component.
     * @method jibo.face.Component#clearActions
     */
    public clearActions():void {
        if(this._actions) {
            this._actions.length = 0;
        }
    }

    /**
     * Trigger actions by passing to parentGroup's actionHandler.
     * @method jibo.face.Component#triggerActions
     */
    public triggerActions():void {
        if (this.parentGroup) {
            if(this._actions) {
                for(let i:number = 0; i<this._actions.length; i++) {
                    this.parentGroup.actionHandler(this._actions[i], this);
                }
            }
        }
        else {
            console.warn('Component :: triggerActions : parentGroup is undefined,' +
                'be sure component has been added to parent, use parentGroup.addComponent() method');
        }
    }
}

export default Component;
