import Tween from './Tween';
import {TweenOptions} from './Tween';
import assert = require('assert');
import async = require('async');

interface SetOptions {
    focus?:number;
    focusIsLast?:boolean;
    delay?:number;
    complete?:Function;
}



/**
 * Manage the tweens.
 * Uses `ease npm` for all ease functions.
 * For ease types, refer to [ease APIs]{@link https://www.npmjs.com/package/eases}.
 * @class TweenManager
 * @memberof jibo.face
 */
class TweenManager {

    /**
     * Collection of tweens.
     * @private
     * @name jibo.face.TweenManager._tweens
     * @type {Array<jibo.face.Tween>}
     */
    private static _tweens:Array<Tween> = [];

    /**
     * Collection of tweens to pool (recycle).
     * @private
     * @name jibo.face.TweenManager._tweens
     * @type {Array<jibo.face.Tween>}
     */
    private static _tweensPool:Array<Tween> = [];

    /**
     * Add a tween to play.
     * @method jibo.face.TweenManager.play
     * @param {Object} target The object to tween.
     * @param {Object} options Options for tweening.
     * @param {Object} options.to The values to tween the object to.
     * @param {Object} [options.from] The initial values to set the object to.
     * @param {String} [options.ease='linear'] The ease function to use.
     * @param {int} [options.delay=0] The delay to start.
     * @param {int} [options.duration=500] Length of tween, in millseconds.
     * @param {Function} [complete] Function callback wehen completed
     * @return {jibo.face.Tween} Instance of new tween.
     */
    public static play(target:any, options:TweenOptions, complete?:Function): Tween
    {
        assert.equal(typeof target, 'object', 'target must be an object');

        const tween = this._create();
        tween.init(target, options, complete);
        this._tweens.push(tween);
        return tween;
    }

    /**
     * Play a set of tweens.
     * @method jibo.face.TweenManager.playSet
     * @param {Array<Object>} targets The list of items to tween.
     * @param {Object} options Options for tweening.
     * @param {Number} options.to The value to tween to.
     * @param {Number} [options.from=0] The initial value to tween.
     * @param {String} [options.ease='linear'] The ease function to use.
     * @param {int} [options.delay=0] The delay to start.
     * @param {int} [options.duration=500] Length of tween, in millseconds.
     * @param {Object|Function} [setOptions] Either the set options for complete function
     * @param {Number} [setOptions.focus=0] Index to lead with if `setOptions.delay` is set.
     * @param {Boolean} [setOptions.focusIsLast=false] `true` if `setOptions.focus` is first in.
     * @param {Number} [setOptions.delay=0] Milliseconds delay between items.
     * @param {Function} [setOptions.complete] Function callback wehen completed
     */
    public static playSet(targets:Array<any>, options:TweenOptions, setOptions?:SetOptions|Function): void {

        if (typeof setOptions === "function") {
            setOptions = {
                complete: <Function>setOptions
            };
        }

        // Create overrides
        setOptions = Object.assign({
            focus: 0,
            delay: 0,
            focusIsLast: false,
            complete: null
        }, setOptions || {});

        // The startDelay, will bump all items
        const startDelay:number = options.delay || 0;

        // The collection of async tasks
        const tasks:Array<Function> = [];

        // Last index
        let focus:number = (<SetOptions>setOptions).focus;
        const delay:number = (<SetOptions>setOptions).delay;
        const focusIsLast:boolean = !!(<SetOptions>setOptions).focusIsLast;
        const complete:Function = (<SetOptions>setOptions).complete;
        const numTargets:number = targets.length;

        // make sure focus is within range, if not set to closest index
        if(focus >= numTargets) {
            focus = numTargets - 1;
        }
        else if(focus < 0) {
            focus = 0;
        }

            const delays = new Array(numTargets);
        delays.fill(0);

        // Do the V formation
        if (delay > 0) {

            delays[focus] = 0;
            let maxDelay = 0;
            let currentDelay = delay;

            // Left of the focus
            for(let i = focus - 1; i >= 0; i--) {
                delays[i] = currentDelay;
                maxDelay = Math.max(currentDelay, maxDelay);
                currentDelay += delay;
            }

            // Right of the focus
            currentDelay = delay;
            for (let i = focus + 1; i < numTargets; i++) {
                delays[i] = currentDelay;
                maxDelay = Math.max(currentDelay, maxDelay);
                currentDelay += delay;
            }

            // Go in the opposite direction
            if (focusIsLast) {
                delays.forEach((d:number, i:number) => {
                    delays[i] = maxDelay - d;
                });
            }
        }

        // Loop through the delays
        delays.forEach((d:number, i:number) => {

            const target = targets[i];

            // Clone the options
            const localOptions:TweenOptions = Object.assign({}, options);

            // Set the delay offset
            localOptions.delay = startDelay + d;

            // Create the new tween
            const tween = this.play(target, localOptions);
            tween.paused = true;

            // Add to the list of async tasks to run
            tasks.push((done:(err?:Error) => void) => {
                tween.paused = false;
                tween.once('complete', () => {
                    done(null);
                });
            });
        });

        // Run all of the items in parallel
        (<any>async).parallel(tasks, () => {
            if (complete) {
                complete();
            }
        });
    }

    /**
     * Stop a tween by target or stop all tweens.
     * @method jibo.face.TweenManager.stop
     * @param {Object} [target] The tween target, if non is specified, all tweens removed.
     * @return {Boolean} If the tween was deleted.
     */
    public static stop(target?:any): void {
        const tweens = this._tweens;
        if (!target) {
            while(tweens.length) {
                this._pool(tweens.pop());
            }
        }
        else {
            for (let i = tweens.length - 1, tween; i >= 0; i--) {
                tween = tweens[i];
                if (tween.target === target) {
                    if(!tween.inProcess){
                        this._pool(tween);
                    }
                }
            }
        }
    }

    /**
     * Pause or resume all tweens.
     * @name jibo.face.TweenManager.paused
     * @type {Boolean}
     */
    public static set paused(paused:boolean) {
        this._tweens.forEach((tween) => {
            tween.paused = paused;
        });
    }

    /**
     * Update the tweens.
     * @method jibo.face.TweenManager.update
     * @param {int} elapsed Time elapsed in Milliseconds since the last update.
     */
    public static update(elapsed:number):void {
        const tweens = this._tweens;
        for (let i = tweens.length - 1, tween; i >= 0; i--) {
            tween = tweens[i];
            // check for valid tween, as tween.completed() call result in the tweens array being cleared
            if(tween) {
                if (tween.time >= 0 && tween.time < 1) {
                    tween.update(elapsed);
                }
                if (tween.time >= 1) {
                    tween.completed();
                    this._pool(tween);
                }
            }
        }
    }

    /**
     * Recycle the tween.
     * @method jibo.face.TweenManager._pool
     * @private
     * @param {jibo.face.Tween} tween Tween to re-pool
     */
    private static _pool(tween:Tween): void {
        const i = this._tweens.indexOf(tween);
        tween.reset();
        if (i > -1) {
            this._tweens.splice(i, 1);
            this._tweensPool.push(tween);
        }
    }

    /**
     * Recycle the tween.
     * @method jibo.face.TweenManager._create
     * @private
     * @return {jibo.face.Tween} Tween to use
     */
    private static _create(): Tween {
        if (this._tweensPool.length) {
            return this._tweensPool.pop();
        }
        return new Tween();
    }
}

export default TweenManager;
