import Decorator from '../Decorator';
import Status from '../Status';
import Runtime from '../../Runtime';

import {ClientDialogListener} from '../../services/gl/ClientDialogListener';
import {ListenOptions} from '../../services/gl/DataTypes';
import {EventEmitter} from 'events';

// TODO: import from runtime singleton

/**
 * @class ListenEmitter
 * @description Used to listen for cloud events.
 * @extends EventEmitter
 * @memberof jibo.bt
 */

/**
 * @typedef {Object} jibo.bt.decorators.SucceedOnListenJs~Options
 * @property {boolean} heyJibo Listen for "Hey, Jibo" first.
 * @property {boolean} detectEnd Listen for end of speech.
 * @property {boolean} incremental Return incremental ASR results as they are streamed from the cloud.
 * @property {String} authenticateSpeaker Authenticates against that person.
 */

/**
 * Function that returns the options object.
 * @callback jibo.bt.decorators.SucceedOnListenJs~GetOptions
 * @returns {jibo.bt.decorators.SucceedOnListenJs~Options}
 */



/**
 * Called when the {@link jibo.bt.behaviors.ListenEmitter|ListenEmitter} is constructed.
 * @callback jibo.bt.decorators.SucceedOnListenJs~OnResult
 * @param {jibo.bt.ListenEmitter} listener Use this instance to listen for listen events.
 */

/**
 * @class SucceedOnListenJs
 * @extends jibo.bt.Decorator
 * @memberof jibo.bt.decorators
 * @description Performs audio speech recognition and applies and parses the results according to a rules file.
 * @param {Object} options See {@link jibo.bt.Decorator|Decorator} for all options.
 * @param {jibo.bt.decorators.SucceedOnListenJs~GetOptions} options.getOptions Returns the options object.
 * @param {Function} options.getRule This function returns a string representation of a rule. Use this decorator to dynamically generate rules files instead
 *                      of loading a rule file from disk.
 * @param {jibo.bt.decorators.SucceedOnListenJs~OnResult} options.onResult Called and passed a {@link jibo.bt.behaviors.ListenEmitter|ListenEmitter} object. Events are fired from the Listener
 *                                   at certain points in this behavior's lifecycle.
 */
enum InternalState {
  STOPPED, STARTING, STARTED, UNINITIALIZED
}

/**
 * Definition of the reusable dialog listen behavior class
 */
export default class SucceedOnListenJs extends Decorator{

    private status:Status;
    private getOptions: () => any;
    private getRulePath: (RulePathCB) => any;
    private onResult: (DialogListener) => any;
    private listener: ClientDialogListener;
    private _internalState = InternalState.UNINITIALIZED;

    constructor(options){
        super(options, {});
        this.getOptions = options.getOptions;
        this.getRulePath = options.getRulePath;
        this.onResult = options.onResult;
        this.listener = null;
    }

    public _start() {
        this._internalState = InternalState.STARTING;
        this.status = Status.IN_PROGRESS;

        // need to check if precompiled handle here

        this.options.getRule((ruleText: string) => {
            //if status is not in progress, then behavior was stopped or destroyed
            if (this.status !== Status.IN_PROGRESS) {
                return;
            }
            if (this._internalState === InternalState.STARTING) {
                let emitter = new EventEmitter();
                let options:any = this.getOptions();
                let listenOptions = new ListenOptions({
                    hotphrase: options.heyJibo,
                    speech_to_text: options.speech_to_text,
                    parseIncremental: options.parseIncremental,
                    incremental: options.incremental
                });
                this.listener = Runtime.instance.gl.createDialogListener(listenOptions, ruleText);
                let listener = this.listener;
                this.listener.events.cloudReceived.on((data) => {
                    this._stopInternal();
                    if(data.result.NLParse) {
                        data.result.NLParse.status = "GOT-PARSE";
                    }
                    else {
                        data.result.NLParse = {};
                        data.result.NLParse.status = "NO-PARSE";
                    }
                    emitter.emit('cloud', data.result, data.speakerId);
                });

                this.listener.events.sos.on((data) => {
                    emitter.emit('speech-start', data);
                });
                this.listener.events.eos.on((data) => {
                    emitter.emit('speech-end', data);
                });
                this.listener.events.speakerId.on((data) => {
                    emitter.emit('speaker-id', data);
                });

                this.listener.events.hj.on((data) => {
                    emitter.emit('hey-jibo', data.result);
                    if(options.speech_to_text === false) {
                        this._stopInternal();
                        Runtime.instance.gl.unsubscribe(listener, (err:string, response:any) => {
                            if(err) {
                                throw new Error(err);
                            }
                        });
                    }
                });

                this.listener.events.incremental.on((data) => {
                    emitter.emit('incremental', data, this._stop.bind(this));
                });

                this.listener.events.interrupted.on((data) => {
                    this._stopInternal();
                    Runtime.instance.gl.unsubscribe(listener, (err:string, response:any) => {
                        if(err) {
                            throw new Error(err);
                        }
                    });
                    emitter.emit('cloud', data.result, data.speakerId);
                });

                Runtime.instance.gl.subscribe(this.listener, (err:string, response:any) => {
                    if(err) {
                        throw new Error(err);
                    }
                });
                this.onResult(emitter);

                this._internalState = InternalState.STARTED;
              }
        });

        return true;
    }

    public _stopInternal() {
        if (this._internalState === InternalState.STARTED) {
            this.status = Status.SUCCEEDED;
            this.listener = null;
        }

        this._internalState = InternalState.STOPPED;
    }

    /**
     * Only gets called when stopped from Behavior tree
     */
    public _stop():Promise<void> {
        if (this._internalState === InternalState.STARTED) {
            Runtime.instance.gl.unsubscribe(this.listener);
            this.listener = null;
        }
        this._internalState = InternalState.STOPPED;
        return Promise.resolve();
    }

    public update(result:Status):Status {
        if(this.status === Status.IN_PROGRESS){
            return result;
        }
        else {
            return this.status;
        }
    }

    public destroy() {
        super.destroy();
        this.getOptions = null;
        this.getRulePath = null;
        this.onResult = null;
        Runtime.instance.gl = null;
        this.status = null;
    }
}
