import path = require('path');
import Runtime from '../Runtime';
import {Plugin, PluginCallback} from '../Plugin';
import PathUtils from '../utils/PathUtils';

/**
 * Preload the fonts needed for GUI
 */
class FontsPlugin implements Plugin {
    init(done:PluginCallback): void {
        if (Runtime.electron) {
            const src:string = path.join(PathUtils.findRoot(__dirname), 'resources/fonts.css');
            Runtime.instance.loader.load(src, (err, style) => {
                document.head.appendChild(style);
                Promise.all([
                    (<any>document).fonts.load('bold 1em "Proxima Nova Soft"'),
                    (<any>document).fonts.load('normal 1em "Proxima Nova Soft"'),
                    (<any>document).fonts.load('bold 1em "Proxima Nova"'),
                    (<any>document).fonts.load('normal 1em "Proxima Nova Light"')
                ]).then(() => {
                    done();
                });
            });
        }
        else {
            done();
        }
    }
}

Runtime.registerPlugin(FontsPlugin, 'fonts', {
    depends: ['loader'],
    electron: true
});

export default FontsPlugin; 