import Decorator from '../Decorator';
import Status from '../Status';
import Runtime from '../../Runtime';

/**
 * @callback jibo.bt.decorators.StartOnAnimEvent~StartOnEventOnReceived
 * @argument {AnimationInstance} instance The animation instance the event was dispatched from.
 * @argument {Object} payload A payload defined in the `.keys` file.
 */

/**
 * @class StartOnAnimEvent
 * @extends jibo.bt.Decorator
 * @memberof jibo.bt.decorators
 * @description
 * `StartOnAnimEvent` will begin the execution of its behavior when an animation fires an event from its event layer.
 * @param {String} options.eventName - Name of the event this behavior listens for.
 * @param {jibo.bt.decorators.StartOnAnimEvent~StartOnEventOnReceived} options.onReceived - Callback for when `eventName` is dispatched.
 */
export default class StartOnAnimEvent extends Decorator {

    private didStart:boolean;
    
    constructor(options) {
        super(options);
        this.didStart = false;
        this._onEvent = this._onEvent.bind(this);
    }

    public start():boolean|Status.WAIT {
        this.didStart = false;
        if (this.options.eventName.length !== 0) {
            Runtime.instance.behaviorEmitter.on(this.options.eventName, this._onEvent);
        }
        return Status.WAIT;
    }

    public stop():Promise<void> {
        // remove listener
        if (this.options.eventName.length !== 0) {
            Runtime.instance.behaviorEmitter.removeListener(this.options.eventName, this._onEvent);
        }
        return Promise.resolve();
    }

    public update(result:Status):Status {
        if (this.didStart) {
            return result;
        }
        else {
            return Status.WAIT;
        }
    }

    public destroy() {
        super.destroy();
        this._onEvent = null;
    }

    private _onEvent(animInstance, payload) {
        if (this.options.onReceived) {
            this.options.onReceived(animInstance, payload);
        }
        this.didStart = true;
        Runtime.instance.behaviorEmitter.removeListener(this.options.eventName, this._onEvent);
    }
}
