import DOFValues from "./DOFValues";

/**
 * Represents a background.
 * @class Background
 * @memberof jibo.face
 * @param {Boolean} cache Cache the texture.
 */
class Background extends PIXI.Sprite {

    /**
     * Filter for the color transform.
     * @name jibo.face.Background#filter
     * @type {PIXI.filters.ColorMatrixFilter}
     */
    public filter:PIXI.filters.ColorMatrixFilter;

    /**
     * `true` if connected to the DOFValues.
     * @name jibo.face.Background#connected
     * @type {Boolean}
     */
    public connected:boolean;

    /**
     * The previous path to the last texture.
     * @private
     * @name jibo.face.Background#texturePrev
     * @type {String}
     */
    private texturePrev:string;

    constructor(public cache:boolean) {
        super();
        this.filter = new PIXI.filters.ColorMatrixFilter();
        this.filter.reset();
        this.connected = true;
    }

    /**
     * Setter for the red value of tinting.
     * @name jibo.face.Background#red
     * @type {Number}
     */
    set red(value:number) {
        this.filter.matrix[0] = value;
    }

    /**
     * Setter for the red value of tinting.
     * @name jibo.face.Background#green
     * @type {Number}
     */
    set green(value:number) {
        this.filter.matrix[6] = value;
    }

    /**
     * Setter for the red value of tinting.
     * @name jibo.face.Background#blue
     * @type {Number}
     */
    set blue(value:number) {
        this.filter.matrix[12] = value;
    }

    /**
     * Update of DOFValues.
     * @method jibo.face.Background#update
     * @param {Array<Number>} timestamp
     * @param {jibo.face.DOFValues} dofValues
     */
    update(timestamp:number[], dofValues:DOFValues):void {
        if (!this.connected) {
            return;
        }
        if(dofValues.screenBGTextureInfixBn_r && dofValues.screenBGTextureInfixBn_r !== this.texturePrev) {
            this.texturePrev = dofValues.screenBGTextureInfixBn_r;

            if (this.cache) {
                this.texture = PIXI.Texture.fromImage(this.texturePrev);
            }
            else {
                let image = new Image();
                image.src = this.texturePrev;
                let baseTexture = new PIXI.BaseTexture(image);
                baseTexture.imageUrl = this.texturePrev;
                this.texture = new PIXI.Texture(new PIXI.BaseTexture(image));
            }
        }
        if(dofValues.screenBG_redChannelBn_r === 1 && dofValues.screenBG_greenChannelBn_r === 1 &&
            dofValues.screenBG_blueChannelBn_r === 1) {
            this.filters = null;
        }
        else {
            if(!this.filters || this.filters.length === 0) {
                this.filters = [this.filter];
            }
            this.red = dofValues.screenBG_redChannelBn_r;
            this.green = dofValues.screenBG_greenChannelBn_r;
            this.blue = dofValues.screenBG_blueChannelBn_r;
        }

    }
}

export default Background;
