import Background from "./Background";
import IAuxOutput from "./IAuxOutput";
import Eye from './Eye';
import EyeOverlay from './EyeOverlay';
import DOFValues from "./DOFValues";
import {isNotDirty} from "./DOFValues";
import KeysAnimation from '../animation/KeysAnimation';
import {Layer, EyeLayer, TimelineLayer} from '../animation/KeysAnimation';
import FaceRenderer from '../FaceRenderer';
import GlowFilter from './filters/glow/GlowFilter';
import LightFilter from './filters/light/LightFilter';

/**
 * The representation of the eye.
 * @class EyeContainer
 * @memberof jibo.face
 * @extends PIXI.Container
 * @param {Boolean} [cache=true] `true` to cache eye and background textures.
 */
class EyeContainer extends PIXI.Container implements IAuxOutput {

    /**
     * Eye display.
     * @name jibo.face.EyeContainer#eye
     * @type {jibo.face.Eye}
     */
    public eye:Eye;

    /**
     * Eye overlay display.
     * @name jibo.face.EyeContainer#eyeOverlay
     * @type {jibo.face.EyeOverlay}
     */
    public eyeOverlay:EyeOverlay;

    /**
     * Container for eye, overlay and background.
     * @name jibo.face.EyeContainer#stage
     * @type {PIXI.Container}
     */
    public stage:PIXI.Container;

    /**
     * The background border for debugging.
     * @name jibo.face.EyeContainer#backgroundBorder
     * @type {PIXI.Graphics}
     */
    public backgroundBorder:PIXI.Graphics;

    /**
     * The background of eye.
     * @name jibo.face.EyeContainer#background
     * @type {jibo.face.Background}
     */
    public background:Background;

    /**
     * `true` if the eye is connected to the DOF values.
     * @name jibo.face.EyeContainer#connected
     * @type {Boolean}
     */
    public connected:boolean;

    /**
     * Glow Filter for eye display.
     * Must enable with `jibo.face.eye.glow.enabled = true`
     * @name jibo.face.EyeContainer#glow
     * @type {jibo.face.GlowFilter}
     */
    public glow:GlowFilter;
    /**
     * Lighting Filter for eye display.
     * Must enable with `jibo.face.eye.lighting.enabled = true`
     * @name jibo.face.EyeContainer#lighting
     * @type {jibo.face.LightFilter}
     */    
    public lighting:LightFilter;

    // Private vars
    private _previousDofValues:DOFValues;
    private _currentDofValues:DOFValues;
    private _zoom:number;
    private _animation:KeysAnimation;

    constructor(public cache:boolean=true) {

        super();

        this.backgroundBorder = new PIXI.Graphics();
        this._zoom = 1.0;

        this.eye = new Eye(this.cache);
        this.eyeOverlay = new EyeOverlay(this.cache);
        this.background = new Background(this.cache);

        this.onAnimationStopped = this.onAnimationStopped.bind(this);
        this.onAnimationReorder = this.onAnimationReorder.bind(this);

        this.glow = new GlowFilter();
        this.lighting = new LightFilter();

        this.glow.target = this.eye;
        this.lighting.target = this.eye;

        this.lighting.lightPosition.set(FaceRenderer.WIDTH/2, FaceRenderer.HEIGHT/2);

        this.eye.filters = [this.lighting, this.glow];

        this.active = false;
    }

    /**
     * Adds a face animation to play.
     * @method jibo.face#animation
     * @type {jibo.rendering.animation.KeysAnimation}
     */
    public set animation(animation:KeysAnimation) {

        let oldAnimation = this._animation;

        if (oldAnimation && oldAnimation !== animation)
        {
            oldAnimation.removeListener(KeysAnimation.STOPPED, this.onAnimationStopped);
            oldAnimation.removeListener(KeysAnimation.REORDER, this.onAnimationReorder);
        }
        // Turn the render back to what it was before we added to it
        this.reset();

        this._animation = animation;

        if (animation)
        {
            animation.on(KeysAnimation.STOPPED, this.onAnimationStopped);
            animation.on(KeysAnimation.REORDER, this.onAnimationReorder);

            this.onAnimationReorder();
        }
    } 


    /**
     * If the eye is active.
     * @method jibo.face#active
     * @type {boolean}
     */
    public set active(active:boolean) {
        this.connected = active;
        this.visible = active;
        this.animation = null;
    }  

    /**
     * Update the DOFValues for display.
     * @private
     * @method jibo.face.EyeContainer#display
     * @param {Array<number>} timestamp The timestamps.
     * @param {jibo.face.DOFValues} dofValues
     * @param {Object} meta
     */
    public display(timestamp:Array<number>, dofValues:DOFValues, meta?):void {

        // Add the current time in seconds from the start
        if (meta && meta.sourceTimes && this._animation) {
            this._animation.update(meta.sourceTimes[this._animation.id], dofValues);
        }

        if (this.connected) {
            this._previousDofValues = this._currentDofValues;
            this._currentDofValues = dofValues;
        }

        this.glow.animate();

        if (!isNotDirty(this._previousDofValues, this._currentDofValues)) {
            this.glow.update(timestamp, dofValues);
            this.lighting.update(timestamp, dofValues);
            this.eye.update(timestamp, dofValues);
            this.eyeOverlay.update(timestamp, dofValues);
            this.background.update(timestamp, dofValues);
        }
    }

    /**
     * Changes the zoom level. Default is 1 = 100%.
     * @method jibo.face.eyeContainer#zoom
     * @type {number}
     * @private
     */
    public set zoom(zoom:number) {
        this._zoom = zoom;
        zoom = Math.min(zoom, 1);
        this.scale.x = zoom;
        this.scale.y = zoom;
        this.x = 0.5 * (FaceRenderer.WIDTH - zoom * FaceRenderer.WIDTH);
        this.y = 0.5 * (FaceRenderer.HEIGHT - zoom * FaceRenderer.HEIGHT);
    }

    public get zoom():number {
        return this._zoom;
    }

    /**
     * Make a border around the screen.
     * @method jibo.face.EyeContainer#makeBorder
     * @param {Array<Number>} timestamp Timestamp when update is called.
     * @param {String} dofValues Update display according to these values.
     * @param {Object} meta
     * @private
     */
    public makeBorder():void {
        this.backgroundBorder.lineStyle(3, 0xFFFFFF)
            .moveTo(0, 0)
            .lineTo(FaceRenderer.WIDTH, 0)
            .lineTo(FaceRenderer.WIDTH, FaceRenderer.HEIGHT)
            .lineTo(0, FaceRenderer.HEIGHT)
            .lineTo(0, 0);
    }

    /**
     * Cleans up the renderer.
     * @method jibo.face.EyeContainer#destroy
     * @private
     */
    public destroy():void {
        this.animation = null;
        this.eye.destroy();
        this.eye = null;
        this.eyeOverlay.destroy();
        this.eyeOverlay = null;
        this.background = null;
        this.backgroundBorder = null;
        super.destroy(true);
    }

    /**
     * Resets the layers.
     * @name jibo.face.EyeContainer#reset
     * @type {boolean}
     */
    private reset(): void {
        // Remove all
        this.removeChildren();

        //background textures
        this.addChild(this.background);

        //for the animation editor
        this.addChild(this.backgroundBorder);
        this.addChild(this.eye);
        this.addChild(this.eyeOverlay);
    }

    /**
     * Handle when the timeline needs to be reordered.
     * @method jibo.face.EyeContainer#onAnimationReorder
     * @private
     */
    private onAnimationReorder() {

        this.reset();

        // Keep track if we should place object above or below the eye
        let aboveEye = false;
        this._animation.layers.forEach((layer:Layer) => {
            if (layer instanceof EyeLayer) {
                aboveEye = true;
            }
            else {
                const instance = (<TimelineLayer>layer).timeline.instance;
                if (aboveEye) {
                    this.addChild(instance);
                } else {
                    const index = this.getChildIndex(this.eye);
                    return this.addChildAt(instance, index);
                }
            }
        });
    }

    /**
     * Handle when the animation stops.
     * @method jibo.face.EyeContainer#onAnimationStopped
     * @private
     */
    private onAnimationStopped() {
        this.reset();
    }
}

export default EyeContainer;
