import AbstractEye from './AbstractEye';
import {conversion} from 'jibo-keyframes';
import DOFValues from './DOFValues';
import FaceRenderer from '../FaceRenderer';

/**
 * Represents an eye overlay.
 * @class EyeOverlay
 * @extends jibo.face.AbstractEye
 * @memberof jibo.face
 */
class EyeOverlay extends AbstractEye {

    /**
     * Update of DOFValues.
     * @method jibo.face.EyeOverlay#update
     * @param {Array<Number>} timestamp Timestamp when update is called.
     * @param {String} dofValues Update display according to these values.
     */
    update(timestamp:Array<number>, dofValues:DOFValues)  {
        if (!this.connected) {
            return;
        }

        const points:Array<PIXI.Point> = this.eyeMesh.points;

        if(dofValues.eyeTextureInfixBn_r !== this.texturePrev) {
            this.texturePrev = dofValues.overlayTextureInfixBn_r;
            this.texture = this.texturePrev;
        }

        points[0].x = conversion.toPixelsX(dofValues.overlay_vertexJoint1_t);
        points[0].y = conversion.toPixelsY(dofValues.overlay_vertexJoint1_t_2);

        points[1].x = conversion.toPixelsX(dofValues.overlay_vertexJoint2_t);
        points[1].y = conversion.toPixelsY(dofValues.overlay_vertexJoint2_t_2);

        points[2].x = conversion.toPixelsX(dofValues.overlay_vertexJoint3_t);
        points[2].y = conversion.toPixelsY(dofValues.overlay_vertexJoint3_t_2);

        points[3].x = conversion.toPixelsX(dofValues.overlay_vertexJoint4_t);
        points[3].y = conversion.toPixelsY(dofValues.overlay_vertexJoint4_t_2);

        points[4].x = conversion.toPixelsX(dofValues.overlay_vertexJoint5_t);
        points[4].y = conversion.toPixelsY(dofValues.overlay_vertexJoint5_t_2);

        points[5].x = conversion.toPixelsX(dofValues.overlay_vertexJoint6_t);
        points[5].y = conversion.toPixelsY(dofValues.overlay_vertexJoint6_t_2);

        points[6].x = conversion.toPixelsX(dofValues.overlay_vertexJoint7_t);
        points[6].y = conversion.toPixelsY(dofValues.overlay_vertexJoint7_t_2);

        points[7].x = conversion.toPixelsX(dofValues.overlay_vertexJoint8_t);
        points[7].y = conversion.toPixelsY(dofValues.overlay_vertexJoint8_t_2);

        points[8].x = conversion.toPixelsX(dofValues.overlay_vertexJoint9_t);
        points[8].y = conversion.toPixelsY(dofValues.overlay_vertexJoint9_t_2);

        this.x = conversion.toPixelsX(dofValues.overlay_textureSubRootBn_t) + (FaceRenderer.WIDTH) / 2;
        this.y = -conversion.toPixelsX(dofValues.overlay_textureSubRootBn_t_2) + (FaceRenderer.HEIGHT) / 2;

        this.red = dofValues.overlay_redChannelBn_r;
        this.green = dofValues.overlay_greenChannelBn_r;
        this.blue = dofValues.overlay_blueChannelBn_r;

        this.visible = dofValues.overlayVisibilityBn_r === undefined ? true : !!dofValues.overlayVisibilityBn_r;
        this.alpha = dofValues.overlay_alphaChannelBn_r === undefined ? 1 : dofValues.overlay_alphaChannelBn_r;

        this.rotation = -dofValues.overlay_textureSubRootBn_r;
    }
}
export default EyeOverlay;
