import AbstractEye from './AbstractEye';
import {conversion} from 'jibo-keyframes';
import DOFValues from './DOFValues';
import FaceRenderer from '../FaceRenderer';

/**
 * Represents an eye.
 * @class Eye
 * @extends jibo.face.AbstractEye
 * @memberof jibo.face
 */
class Eye extends AbstractEye {
    /**
     * Update of DOFValues.
     * @method jibo.face.Eye#update
     * @param {Array<Number>} timestamp Timestamp when update is called.
     * @param {String} dofValues Update display according to these values.
     */
    update(timestamp:Array<number>, dofValues:DOFValues)  {
        if (!this.connected) {
            return;
        }
        const points:Array<PIXI.Point> = this.eyeMesh.points;

        if(dofValues.eyeTextureInfixBn_r !== this.texturePrev) {
            this.texturePrev = dofValues.eyeTextureInfixBn_r;
            this.texture = this.texturePrev;
        }

        points[0].x = conversion.toPixelsX(dofValues.vertexJoint1_t);
        points[0].y = conversion.toPixelsY(dofValues.vertexJoint1_t_2);

        points[1].x = conversion.toPixelsX(dofValues.vertexJoint2_t);
        points[1].y = conversion.toPixelsY(dofValues.vertexJoint2_t_2);

        points[2].x = conversion.toPixelsX(dofValues.vertexJoint3_t);
        points[2].y = conversion.toPixelsY(dofValues.vertexJoint3_t_2);

        points[3].x = conversion.toPixelsX(dofValues.vertexJoint4_t);
        points[3].y = conversion.toPixelsY(dofValues.vertexJoint4_t_2);

        points[4].x = conversion.toPixelsX(dofValues.vertexJoint5_t);
        points[4].y = conversion.toPixelsY(dofValues.vertexJoint5_t_2);

        points[5].x = conversion.toPixelsX(dofValues.vertexJoint6_t);
        points[5].y = conversion.toPixelsY(dofValues.vertexJoint6_t_2);

        points[6].x = conversion.toPixelsX(dofValues.vertexJoint7_t);
        points[6].y = conversion.toPixelsY(dofValues.vertexJoint7_t_2);

        points[7].x = conversion.toPixelsX(dofValues.vertexJoint8_t);
        points[7].y = conversion.toPixelsY(dofValues.vertexJoint8_t_2);

        points[8].x = conversion.toPixelsX(dofValues.vertexJoint9_t);
        points[8].y = conversion.toPixelsY(dofValues.vertexJoint9_t_2);

        this.x = conversion.toPixelsX(dofValues.eyeSubRootBn_t) + (FaceRenderer.WIDTH) / 2;
        this.y = -conversion.toPixelsX(dofValues.eyeSubRootBn_t_2) + (FaceRenderer.HEIGHT) / 2;

        this.visible = dofValues.eyeVisibilityBn_r === undefined ? true : !!dofValues.eyeVisibilityBn_r;
        this.alpha = dofValues.eye_alphaChannelBn_r === undefined ? 1 : dofValues.eye_alphaChannelBn_r;

        this.red = dofValues.eye_redChannelBn_r;
        this.green = dofValues.eye_greenChannelBn_r;
        this.blue = dofValues.eye_blueChannelBn_r;

        this.rotation = -dofValues.eyeSubRootBn_r;
    }

}
export default Eye;
