import * as async from 'async';
import { WSClient } from 'jibo-client-framework';

/**
 * Enum of photo types.
 * @name jibo.lps#PhotoType
 * @type {Enum}
 * @property DEBUG {String} 1/2-scale grayscale.
 * @property PREVIEW {String} 1/2-scale color.
 * @property FULL {String} Full-scale color.
 */
let PhotoType = {
    DEBUG: 0,
    PREVIEW: 1,
    FULL: 2
};

/**
 * Enum of cameras.
 * @name jibo.lps#CameraID
 * @type {Enum}
 * @property LEFT {String} Left camera.
 * @property RIGHT {String} Right camera. Coming soon!
 */
let CameraID = {
    LEFT: 0,
    RIGHT: 1
};

/**
 * Enum of photo resolutions.
 * @name jibo.lps#PhotoRes
 * @type {Enum}
 * @property SMALL {String} 672x380 (coming soon)
 * @property MEDIUM {String} 1280x720
 * @property LARGE {String} 1920x1080 (coming soon)
 * @property XLARGE {String} 2688x1520 (coming soon)
 */
let PhotoRes = {
    SMALL: 1,
    MEDIUM: 2,
    LARGE: 3,
    XLARGE: 4
};

let _resData = [
    {
        "width" : 672,
        "height": 380
    },
    {
        "width" : 1280,
        "height": 720
    },
    {
        "width" : 1920,
        "height": 1080
    },
    {
        "width" : 2688,
        "height": 1520
    }
];

/**
 * @description
 * Local Perceptual Space
 *
 * ```
 * var jibo = require("jibo");
 * jibo.lps.takePhoto();
 * ```
 * @namespace jibo.lps
 */
class LPSService {
    constructor() {
        this.lps = {};

        // visual awareness data
        this.lps.motionData = {
            cameras: [],    // List of camera objects
            entities: []    // List of entity objects
        };

        // audible awareness data
        this.lps.audioData = {
            entities: []    // List of entity objects
        };


        this.PhotoType = PhotoType;
        this.PhotoRes = PhotoRes;
        this.CameraID = CameraID;
    }

    /**
     * Return the full state of the Jibo's local perceptual space.
     * @name jibo.lps#motionData
     * @type {*|{cameras: Array, entities: Array}}
     * @readOnly
     */
    get motionData() {
        return this.lps.motionData;
    }

    /**
     * Get the visual entity closest to Jibo.
     * @method jibo.lps#getClosestVisualEntity
     *
     * @return The closest visual entity to Jibo. If one does not exist, returns undefined.
     */
    getClosestVisualEntity() {
        let entity;

        if (this.lps.motionData !== undefined &&
            this.lps.motionData.entities !== undefined &&
            this.lps.motionData.entities.length > 0) {
            entity = this.lps.motionData.entities[0]; // @TODO - get real "closest" entity when multi-track is in
        }

        return entity;
    }

    /**
     * Get a visual entity by specified ID.
     * @method jibo.lps#getVisualEntityById
     * @param id {Number} ID of the entity to get.
     * @return The specified visual entity. If it does not exist, returns undefined.
     */
    getVisualEntityById(id) {
        let entity;

        for (let i=0; i< this.lps.motionData.entities.length; i++)
        {
            let itr = this.lps.motionData.entities[i];
            if (itr && (itr.id === id)) {
                entity = itr;
                break;
            }
        }

        return entity;
    }

    /**
     * Get the closest audible entity to Jibo.
     * @method jibo.lps#getClosestAudibleEntity
     *
     * @return The closest audible entity to Jibo. If one does not exist, returns undefined.
     */
    getClosestAudibleEntity() {
        let entity;

        if (this.lps.audioData !== undefined &&
            this.lps.audioData.entities !== undefined &&
            this.lps.audioData.entities.length > 0) {
            entity = this.lps.audioData.entities[0]; // @TODO - get real "closest" entity when multi-track is in
        }

        return entity;
    }

    /**
     * Get an audible entity by specified ID.
     * @method jibo.lps#getAudibleEntityById
     * @param id {Number} ID of the entity to get.
     * @return The specified audible entity. If it does not exist, returns undefined.
     */
    getAudibleEntityById(id) {
        let entity;

        for (let i=0; i< this.lps.audioData.entities.length; i++)
        {
            let itr = this.lps.audioData.entities[i];
            if (itr && (itr.id === id)) {
                entity = itr;
                break;
            }
        }

        return entity;
    }

    /**
     * Create new entry in LPS identity list.
     * @method jibo.lps#createIdentity
     * @param data {Object} Options for the request.
     * @param data.name {String} Name for the identity.
     * @param [data.kind="face"] {String} Kind of identity data. (Currently ONLY supports "face".)
     * @param cb {Function} Callback for the method.
     * @private
     */
    createIdentity(data, cb){
        this._sendIdentityRequest('/lps/identity/create', data, cb);
    }

    /**
     * Remove entry from LPS identity list.
     * @method jibo.lps#removeIdentity
     * @param data {Object} Options for the request.
     * @param data.name {String} Name for the identity.
     * @param [data.kind="face"] {String} Kind of identity data. (Currently ONLY supports "face".)
     * @param cb {Function} Callback for the method.
     * @private
     */
    removeIdentity(data, cb){
        this._sendIdentityRequest('/lps/identity/remove', data, cb);
    }

    /**
     * Set up new training request. Request LPS to train an identified for a name using current sensor data.
     * @method jibo.lps#sendTrainingRequest
     * @param data {Object} Options for the training request.
     * @param data.name {String} Name for the training data.
     * @param [data.kind="face"] {String} Kind of data to be trained on. (Currently ONLY supports "face".)
     * @param cb {Function} Callback for the method.
     * @private
     */
    sendTrainingRequest(data, cb){
        this._sendIdentityRequest('/lps/identity/train', data, cb);
    }

    _sendIdentityRequest(path, data, cb) {
        if (this.httpUrl === undefined) {
            cb('LPS service is not initialized', null);
            return;
        }

        let params = {};

        // name is a required parameter - if not present, return immediately
        if (!data.hasOwnProperty('name')){
            cb("Identity data must have 'name' property", null);
            return;
        }

        // these are NOT required parameters - if not present, use defaults
        if (!data.hasOwnProperty('kind')){ data.kind = "face";}

        params.name = data.name;
        params.kind = data.kind;

        let request = new XMLHttpRequest();
        request.open("POST", this.httpUrl + path, true);
        request.onreadystatechange = () => {
            if (request.readyState == 4) {
                if (request.status == 204) {
                    cb();
                }
                else {
                    // failure if anything else
                    let msg = 'LPS service unavailable';
                    if(request.statusText !== undefined && request.statusText !== "") {
                        msg = request.statusText;
                    }

                   // console.log("lps " + path + " response");
                   // console.log(request);

                    let errorData = null;
                    if (request.response) {
                        try {
                            errorData = JSON.parse(request.response);
                        }
                        catch (e) {
                            errorData = 'Response is not JSON.'
                        }
                    }

                    cb(msg, errorData);
                }
            }
        };
        request.send(JSON.stringify(params));
    }

    /**
     * Get the current state of the viewfinder preview.
     * @method jibo.lps#getPreview
     * @param {Function} cb Callback for the function.
     * @return If request successful, returns timestamp, enabled, and window. If unsuccessful, returns error msg.
     */
    getPreview(cb){
        if (this.httpUrl === undefined) {
            cb('Preview service is not initialized', null);
            return;
        }

        let request = new XMLHttpRequest();

        request.open("GET", this.httpUrl + '/media/preview/control', true);

        request.onreadystatechange = () => {
            if (request.readyState == 4) {
                if (request.status == 200) {
                    if (request.response) {
                        // success!
                        let response = {};
                        try {
                            response = JSON.parse(request.response);
                            cb(null, response);
                        }
                        catch (e) {
                            cb(e);
                        }
                    }
                    else {
                        cb('No data received from barcode service', null);
                    }
                }
                else {
                    // failure if anything else
                    let msg = 'Preview service unavailable';
                    if(request.statusText !== undefined && request.statusText !== "") {
                        msg = request.statusText;
                    }

                    cb(msg, null);
                }
            }
        };

        request.send();

    }

    /**
     * Set up a viewfinder in a window with camera preview positioned at a given location on-screen.
     * @method jibo.lps#setPreview
     * @param data {Object} Options for the preview.
     * @param data.enable {Boolean} `true` to show preview; `false` not to show preview.
     * @param [data.width=1280] {Number} Width of the preview.
     * @param [data.height=720] {Number} Height of the preview.
     * @param [data.x=0] {Number} x-coordinate to place the preview.
     * @param [data.y=0] {Number} y-coordinate to place the preview.
     * @param cb {Function} Callback for the method.
     */
    setPreview(data, cb){
        if (this.httpUrl === undefined) {
            cb('Preview service is not initialized', null);
            return;
        }

        let params = {};

        // enable is a required parameter - if not present, return immediately
        if (!data.hasOwnProperty('enable')){
            cb("Preview service data must have 'enable' property", null);
            return;
        }

        // these are NOT required parameters - if not present, use defaults
        if (!data.hasOwnProperty('width')){ data.width = 1280;}
        if (!data.hasOwnProperty('height')){ data.height = 720;}
        if (!data.hasOwnProperty('x')){ data.x = 0;}
        if (!data.hasOwnProperty('y')){ data.y = 0;}

        params.enable = data.enable;
        params.window = {
            width: data.width,
            height: data.height,
            x: data.x,
            y: data.y
        }

        let request = new XMLHttpRequest();
        request.open("POST", this.httpUrl + '/media/preview/control', true);
        request.onreadystatechange = () => {
            if (request.readyState == 4) {
                if (request.status == 204) {
                    //if (request.response) {
                    //    // success!
                    //    let response = JSON.parse(request.response);
                    //    cb(null, response);
                    //}
                    //else {
                    //    cb('No data received from preview service', null);
                    //}
                    cb(); // @NOTE: uncomment above when a response is returned
                }
                else {
                    // failure if anything else
                    let msg = 'Preview service unavailable';
                    if(request.statusText !== undefined && request.statusText !== "") {
                        msg = request.statusText;
                    }

                    cb(msg, null);
                }
            }
        };
        request.send(JSON.stringify(params));
    }

    /**
     * @description Barcode data object.
     * @typedef {Object} jibo.lps~BarcodeData
     * @property {int} type `0` (EAN8), `1` (UPCE), `2` (ISBN10), `3` (UPCA), `4` (EAN13), `5` (ISBN13),
     * `6` (Interleaved 2 of 5), `7` (Code 39), `8` (PDF417), `9` (QR-Code), or `10` (Code 128).
     * @property {string} content Payload of the barcode data.
     */

    /**
     * Read barcorde or QR code data.
     * @method jibo.lps#readBarcode
     * @param {Function} cb Callback for the function.
     * @return {jibo.lps~BarcodeData} Barcode data object.
     */
    readBarcode(cb) {
        if (this.httpUrl === undefined) {
            cb('Barcode service is not initialized', null);
            return;
        }

        let request = new XMLHttpRequest();

        request.open("GET", this.httpUrl + '/lps/barcode', true);

        request.onreadystatechange = () => {
            if (request.readyState == 4) {
                if (request.status == 200) {
                    if (request.response) {
                        // success!
                        let response = JSON.parse(request.response);
                        cb(null, response.barcodes);
                    }
                    else {
                        cb('No data received from barcode service', null);
                    }
                }
                else {
                    // failure if anything else
                    let msg = 'Barcode service unavailable';
                    if(request.statusText !== undefined && request.statusText !== "") {
                        msg = request.statusText;
                    }

                    cb(msg, null);
                }
            }
        };

        request.send();
    }

    /**
     * Callback for when Jibo takes a photo.
     * ```
     * jibo.lps.takePhoto((error, url) => {
     *     if(!error) {
     *         let img = new Image();
     *         img.src = url;
     *     }
     *     else {
     *         console.error(error);
     *     }
     * });
     * ```
     * @callback jibo.lps~OnPhoto
     * @param {String|null} error `null` if no error, otherwise a an error message.
     * @param {String} url The image URL.
     */

    /**
     * Take a photo.
     * @method jibo.lps#takePhoto
     * @param {jibo.lps#PhotoRes} photoRes Enumerated value of the resolution of photo requested.
     * @param {boolean} noDistort If `false`, image appears with fish-eye distortion. If `true` (default), removes camera distortion.
     * @param {jibo.lps#CameraID} cameraID Enumerated value of the camera to use.
     * @param {jibo.lps#PhotoType} photoType Enumerated value of the type of photo requested.
     *
     *
     * @param {jibo.lps~OnPhoto} cb Callback that will be used to notify the caller that the
     *                      photo was taken and received or if an error was encountered.
     */
     takePhoto(photoRes, noDistort, cameraID, photoType, cb) {
        if (this.httpUrl === undefined) {
            cb('Photo service is not initialized', null);
            return;
        }

        // @TODO - uncomment when we support other resolutions
        //if (photoRes < this.PhotoRes.SMALL || photoRes > this.PhotoRes.XLARGE) {
        if (photoRes !== this.PhotoRes.MEDIUM) {
            photoRes = this.PhotoRes.MEDIUM; // default
        }

        let width = _resData[photoRes - 1].width;
        let height = _resData[photoRes -1].height;

        // @TODO - uncomment when we support right camera
        //if (cameraID < this.CameraID.LEFT || cameraID > this.CameraID.RIGHT) {
        if (cameraID !== this.CameraID.LEFT) {
            cameraID = this.CameraID.LEFT; // default
        }

        if (photoType < this.PhotoType.DEBUG || photoType > this.PhotoType.FULL) {
            photoType = this.PhotoType.FULL; // default
        }

        let data = {
                "camera": cameraID,         // One of 0, 1; signifying camera id, typically 0 is left and 1 is right
                "width": width,             // Resolution width of the photo  (672, 1280, 1920, 2688)
                "height": height,           // Resolution height of the photo (380,  720, 1080, 1520)
                "type": photoType,          // One of (0, 1, 2) meaning (DEBUG, half scale Y), (PREVIEW, half scale RGB), (SNAP, full scale RGB), respectively
                "undistort": noDistort      // Remove camera distortion from the photo
        };

        let url = this.httpUrl + '/media/photo';

        //if (0) {
        //    // !!!! COPIED FROM LPSSERVICE PAGE !!!!
        //    //console.log("Sending POST request (JQUERY)");
        //    let jqxhr = $.post(url, JSON.stringify(data), function (obj) {
        //        let mySrc = url+"?id="+obj.id;
        //        cb(null, mySrc);
        //       // console.log("Got response (JQUERY)");
        //    });
        //
        //    jqxhr.done(function (msg) {
        //    });
        //
        //    jqxhr.fail(function (msg) {
        //        console.log("Failed to get image");
        //    });
        //
        //    jqxhr.always(function (msg) {
        //    }, "json");
        //}
        //else
        {
            let request = new XMLHttpRequest();

            request.open("POST", url, true); // true == async

            // force it to be form data type and accepts all media
            request.setRequestHeader('Content-Type', 'application/x-www-form-urlencoded; charset=UTF-8');
            request.setRequestHeader('Accept', '*/*');

            request.onreadystatechange = () => {
               // console.log("request.readyState|status = " + request.readyState + " | " + request.status);

                // request is complete
                if(request.readyState == 4) {
                    // "OK" status
                    if(request.status === 200) {
                        if (request.response) {
                            // success!
                            let response = JSON.parse(request.response);
                            this._getPhoto(response.id, cb);
                           // console.log("Got response (XMLHTTP)")
                        }
                        else {
                            cb('No data received from photo service', null);
                        }
                    }
                    else {
                        // failure if anything else
                        let msg = 'Photo service unavailable';
                        if(request.statusText !== undefined && request.statusText !== "") {
                            msg = request.statusText;
                        }

                        cb(msg, null);
                    }
                }
            };

            //console.log("Sending POST request (XMLHTTP)");
            request.send(JSON.stringify(data));
        }
    }


    _getPhoto(id, cb) {

        let src = this.httpUrl + '/media/photo?id=' + id;

        cb(null, src);
    }


    init(service, cb) {
        this.lpsServiceUrl = "ws:" + service.host + ":" + service.port;
        this.httpUrl = "http://" + service.host + ":" + service.port;
        async.parallel(
            [
                this._createMotionSocket.bind(this),
                this._createAudioSocket.bind(this)
            ],
            cb
        );
    }

    _createMotionSocket(cb) {
        this.motionSocket = new WSClient(this.lpsServiceUrl + "/lps/visual_awareness");

        this.motionSocket.on('error', (/*err*/) => {
            console.error(`Error opening visual awareness socket at ${this.lpsServiceUrl}/visual_awareness`);
        });

        this.motionSocket.on('message', (data) => {
            this.lps.motionData = data;
        });

        cb();
    }

    _createAudioSocket(cb) {
        this.audioSocket = new WSClient(this.lpsServiceUrl + "/lps/audible_awareness");

        this.audioSocket.on('error', (/*err*/) => {
            console.error(`Error opening audible awareness socket at ${this.lpsServiceUrl}/audible_awareness`);
        });

        this.audioSocket.on('message', (data) => {
            this.lps.audioData = data;
        });

        cb();
    }


}

export default LPSService;
