import Sound from '../../sound/Sound';
import Timeline from './Timeline';
import {EventEmitter} from 'events';
import DOFValues from '../eye/DOFValues';
import {conversion} from 'jibo-keyframes';

/**
 * An abstract Layer for the eye.
 * @class Layer
 * @memberof jibo.rendering.animation
 * @private
 */
export class Layer {
    public static EYE:string = 'Eye';
    constructor(public index:number, public name:string) {
    }
    destroy():void {
        this.index = null;
        this.name = null;
    }
}

/**
 * A layer that represents the Eye.
 * @class EyeLayer
 * @memberof jibo.rendering.animation
 * @private
 */
export class EyeLayer extends Layer {
    constructor(index:number) {
        super(index, Layer.EYE);
    }
}

/**
 * A layer of the KeysAnimation class that represents a timeline animation.
 * @class TimelineLayer
 * @memberof jibo.rendering.animation
 * @private
 * @param {Number} index The depth index.
 * @param {String} name Name of the timeline.
 * @param {jibo.rendering.animation.Timeline} timeline
 * @param {Number} startTime The starting time of this animation in seconds.
 * @param {Boolean} attach `true` if Timeline should be attached to the eye's position.
 * @param {String} offset The frame offset to start playing the animation at
 */
export class TimelineLayer extends Layer {
    public offset:number;
    constructor(index:number,name:string,
        public timeline:Timeline,
        public startTime:number,
        public attach:boolean,
        offsetValue:string) {
            super(index, name);

            if (/^\d+$/.test(offsetValue)) {
                this.offset = parseInt(offsetValue);
            }
            else if (timeline.instance._labelDict && timeline.instance._labelDict[offsetValue]) {
                this.offset = timeline.instance._labelDict[offsetValue];
            }
            else {
                this.offset = 0;
            }

            // Set timeline first frame
            timeline.instance.gotoAndStop(this.offset);

            // Set the pivot point
            if (attach) {
                timeline.instance.pivot.x = timeline.library.width / 2;
                timeline.instance.pivot.y = timeline.library.height / 2;
            }
            else {
                timeline.instance.pivot.x = 0;
                timeline.instance.pivot.y = 0;
            }
    }

    /**
     * Update the position of the animation.
     * @method jibo.rendering.animation.TimelineLayer#update
     * @param {Number} time Global time of the animation in seconds.
     */
    update(time:number, dofValues:DOFValues): void {
        const instance = this.timeline.instance;
        const currFrame:number = Math.round((time - this.startTime) * instance.framerate);
        instance.gotoAndStop(this.offset + currFrame);
        if (this.attach) {
            instance.x = conversion.toPixelsX(dofValues.eyeSubRootBn_t) + instance.pivot.x;
            instance.y = -conversion.toPixelsX(dofValues.eyeSubRootBn_t_2) + instance.pivot.y;
            instance.rotation = -dofValues.eyeSubRootBn_r;
        }
    }

    /**
     * Destroy and don't use after this.
     * @method jibo.rendering.animation.TimelineLayer#destroy
     */
    destroy(): void {
        super.destroy();
        this.timeline = null;
    }
}

/**
 * Class used by Animation Utilities to provide playback
 * of keys files.
 * @class KeysAnimation
 * @memberof jibo.rendering.animation
 * @extends EventEmitter
 * @param {String} id The name of the keys file.
 */
class KeysAnimation extends EventEmitter {

    /**
     * The default framerate.
     * @name jibo.rendering.animation.KeysAnimation.FRAMERATE
     * @type {String}
     * @default 30
     */
    static FRAMERATE:number = 30;

    /**
     * Event name when animation starts.
     * @name jibo.rendering.animation.KeysAnimation.STARTED
     * @type {String}
     */
    static STARTED:string = 'STARTED';

    /**
     * Event name when animation stops.
     * @name jibo.rendering.animation.KeysAnimation.STOPPED
     * @type {String}
     */
    static STOPPED:string = 'STOPPED';

    /**
     * Event name when builder event is fired.
     * @name jibo.rendering.animation.KeysAnimation.EVENT
     * @type {String}
     */
    static EVENT:string = 'EVENT';

    /**
     * Event name when animation is cancelled.
     * @name jibo.rendering.animation.KeysAnimation.CANCELLED
     * @type {String}
     */
    static CANCELLED:string = 'CANCELLED';

    /**
     * Event name when audio is played.
     * @name jibo.rendering.animation.KeysAnimation.PLAY_AUDIO
     * @type {String}
     */
    static PLAY_AUDIO:string = 'play-audio';

    /**
     * Event name when timeline is played.
     * @name jibo.rendering.animation.KeysAnimation.PLAY_TIMELINE
     * @type {String}
     */
    static PLAY_TIMELINE:string = 'play-pixi';

    /**
     * Event name when timeline needs to be reordered.
     * @name jibo.rendering.animation.KeysAnimation.REORDER
     * @type {String}
     */
    static REORDER:string = 'reorder';

    /**
     * Event when the timeline is updated.
     * @name jibo.rendering.animation.KeysAnimation.UPDATE
     * @type {String}
     * @param {Number} time The current time in seconds from the start of animation.
     * @param {Object} dofValues Collection of DOF values for the current frame.
     */
    static UPDATE:string = 'update';

    /**
     * Asset Pack name.
     * @name jibo.rendering.animation.KeysAnimation#assetPack
     * @type {String}
     */
    public assetPack:string;

    /**
     * Resource root for animation (defaults to root of skill).
     * @name jibo.rendering.animation.KeysAnimation#root
     * @type {String}
     */
    public root:string;

    /**
     * Map of Timeline objects.
     * @name jibo.rendering.animation.KeysAnimation#timelines
     * @type {Object}
     */
    public timelines:{[file:string]: Timeline};

    /**
     * Map of Sound objects.
     * @name jibo.rendering.animation.KeysAnimation#sounds
     * @type {Object}
     */
    public sounds:{[file:string]: Sound};

    /**
     * Name of the keys file.
     * @name jibo.rendering.animation.KeysAnimation#id
     * @type {String}
     */
    public id:string;

    /**
     * The collection of layers for the animation.
     * @name jibo.rendering.animation.KeysAnimation#layers
     * @type {Array<Layer>}
     */
    public layers:Array<Layer>;

    private _currentTime:number;
    private _builder:any;
    private _data:any;
    private animationNum:number;

    constructor(id:string) {

        super();

        this.id = id;
        this.layers = [];
        this.animationNum = 0;
        this.timelines = {};
        this.sounds = {};

        // Bind event callbacks
        this.onPlayTimeline = this.onPlayTimeline.bind(this);
        this.onBuilderStopped = this.onBuilderStopped.bind(this);
        this.onPlayAudio = this.onPlayAudio.bind(this);
        this.onEvent = this.onEvent.bind(this);
    }

    /**
     * The animation builder.
     * @name jibo.rendering.animation.KeysAnimation#builder
     * @type {Builder}
     * @private
     */
    set builder(builder:any) {

        if (this._builder) {
            this._builder.off(KeysAnimation.PLAY_AUDIO, this.onPlayAudio);
            this._builder.off(KeysAnimation.PLAY_TIMELINE, this.onPlayTimeline);
            this._builder.off(KeysAnimation.STOPPED, this.onBuilderStopped);
            this._builder.off(KeysAnimation.EVENT, this.onEvent);
            this._builder.off(KeysAnimation.CANCELLED, this.onEvent);
            this._builder.off(KeysAnimation.STARTED, this.onEvent);
        }

        this._builder = builder;

        if (builder) {
            builder.on(KeysAnimation.PLAY_AUDIO, this.onPlayAudio);
            builder.on(KeysAnimation.STOPPED, this.onBuilderStopped);
            builder.on(KeysAnimation.PLAY_TIMELINE, this.onPlayTimeline);
            builder.on(KeysAnimation.EVENT, this.onEvent);
            builder.on(KeysAnimation.CANCELLED, this.onEvent);
            builder.on(KeysAnimation.STARTED, this.onEvent);
        }
    }

    get builder(): any {
        return this._builder;
    }

    /**
     * Update the timelines.
     * @method jibo.rendering.animation.KeysAnimation#update
     * @param {Number} time Current time of this animation
     */
    update(time:number, dofValues:DOFValues) {
        this._currentTime = time;
        for (let i = 0, len = this.layers.length; i < len; i++) {
            const layer = this.layers[i];
            if (layer instanceof TimelineLayer) {
                (<TimelineLayer>layer).update(time, dofValues);
            }
        }
        this.emit(KeysAnimation.UPDATE, time, dofValues);
    }

    /**
     * Set the keys animation data.
     * @name jibo.rendering.animation.KeysAnimation#data
     * @type {Object}
     * @private
     */
    set data(data:any) {
        this.layers.length = 0;
        for(let i:number = 0; i < data.layers.length; i++) {
            if (data.layers[i].type === Layer.EYE) {
                this.layers.push(new EyeLayer(i));
                break;
            }
        }
        this._data = data;
    }
    get data(): any {
        return this._data;
    }

    /**
     * Reset the animation and reorder.
     * @method jibo.rendering.animation.KeysAnimation#reset
     */
    reset(): void {
        this.data = this._data;
        this.reorder();
    }

    /**
     * Add a sound to the animation for playing.
     * @method jibo.rendering.animation.KeysAnimation#addSound
     * @param {String} id The ID of the sound
     * @param {jibo.sound.Sound} sound Instance of sound.
     */
    addSound(id:string, sound:Sound): void {
        this.sounds[id] = sound;
    }

    /**
     * Add a timeline to the animation for playing.
     * @method jibo.rendering.animation.KeysAnimation#addTimeline
     * @param {String} id The ID of the timeline
     * @param {jibo.rendering.animation.Timeline} timeline Instance of timeline.
     */
    addTimeline(id:string, timeline:Timeline): void {
        this.animationNum++;
        this.timelines[id] = timeline;
    }

    /**
     * Sync a movieclip to the playback of the animation.
     * @method jibo.rendering.animation.KeysAnimation#playSync
     * @param {PIXI.animate.MovieClip} instance The clip to play.
     * @param {String|Function} [event] The name of the event label or callback function.
     * @param {Function} [callback] Callback when play is complete.
     */
    playSync(instance:PIXI.animate.MovieClip, event?:string|Function, callback?:Function): void {
        if (typeof event === "function") {
            callback = <Function>event;
            event = null;
        }
        const startFrame:number = event ? instance.labelsMap[(<string>event)] : 0;
        let endFrame:number = instance.totalFrames - 1;
        if (event) {
            endFrame = instance.labelsMap[(<string>event) + '_stop'] || 
                instance.labelsMap[(<string>event) + '_loop'];
        }
        let timelineDone:boolean = false;
        let keysDone:boolean = false;

        // check when we're complete, only finish when 
        // both the keys and the timeline have completed
        const onComplete:Function = () => {
            if (keysDone && timelineDone) {
                this.removeListener(KeysAnimation.UPDATE, onUpdate);
                this.removeListener(KeysAnimation.STOPPED, onStopped);
                if (callback) {
                    callback();
                }
            }
        };

        // call when timeline is completed 
        const onTimelineDone:Function = () => {
            timelineDone = true;
            onComplete();
        };

        // handle the frame updates
        const onUpdate:Function = (time:number) => {
            const currentFrame:number = Math.round(time * instance.framerate);
            const frame:number = startFrame + currentFrame;
            if (frame <= endFrame) {
                instance.gotoAndStop(frame);
                if (frame === endFrame) {
                    onTimelineDone();
                }
            }
        };

        // handle the keys animation finishing
        const onStopped:Function = () => {
            keysDone = true;
            // timeline is not done, play out the 
            // rest of the animation
            if (!timelineDone) {
                PIXI.animate.Animator.to(
                    instance,
                    endFrame,
                    onTimelineDone
                );
            }
            else {
                onComplete();
            }
        };

        this.on(KeysAnimation.STOPPED, onStopped);
        this.on(KeysAnimation.UPDATE, onUpdate);
    }

    /**
     * Destroy the keys animation completely.
     * @method jibo.rendering.animation.KeysAnimation#destroy
     */
    destroy(): void {
        this.layers.forEach((layer) => {
            layer.destroy();
        });
        for(let id in this.timelines) {
            this.timelines[id].destroy();
        }
        for(let id in this.sounds) {
            this.sounds[id].destroy();
        }
        this.builder = null;
        this.layers = null;
        this.timelines = null;
        this.sounds = null;
    }

    /**
     * Handle animation custom events.
     * @method jibo.rendering.animation.KeysAnimation#onEvent
     * @private
     * @param {String} event
     * @param {AnimationInst} animInstance
     * @param {Object} playload
     */
    private onEvent(event, animInstance, payload): void {
        this.emit(event, event, animInstance, payload);
        const eventName = payload.eventName;
        this.emit(eventName, eventName, animInstance, payload.payload);
    }

    /**
     * Handle playing audio within the animation.
     * @method jibo.rendering.animation.KeysAnimation#onPlayAudio
     * @private
     * @param {String} event
     * @param {AnimationInst} animInstance
     * @param {Object} playload
     */
    private onPlayAudio(event, animInstance, payload:any):void {
        this.sounds[payload.file].play();
        this.emit(event, event, animInstance, payload);
    }

    /**
     * Handle animation stopped playing.
     * @method jibo.rendering.animation.KeysAnimation#onBuilderStopped
     * @private
     * @param {String} event
     * @param {AnimationInst} animInstance
     * @param {Object} playload
     */
    private onBuilderStopped(event, animInstance, payload:any): void {
        this.emit(event, event, animInstance, payload);
    }

    /**
     * Reorder the layers of the animation.
     * @method jibo.rendering.animation.KeysAnimation#reorder
     * @private
     */
    private reorder(): void {
        // Sort the layers by depth
        this.layers = this.layers.sort((a:Layer, b:Layer) => {
            return a.index - b.index;
        });
        this.emit(KeysAnimation.REORDER);
    }

    /**
     * Handle the playing of a timeline event.
     * @method jibo.rendering.animation.KeysAnimation#onPlayTimeline
     * @private
     * @param {String} event
     * @param {AnimationInst} animInstance
     * @param {Object} playload
     */
    private onPlayTimeline(event, animInstance, payload:any): void {
        const timeline = this.timelines[payload.file];
        if (!timeline) {
            throw new Error(`No timeline matching ${payload.file}`);
        }

        let framerate:number = timeline.instance.framerate;
        if (framerate !== KeysAnimation.FRAMERATE)
        {
            console.warn(`Timeline was animated at ${framerate} expecting ${KeysAnimation.FRAMERATE}, converting...`);
            timeline.instance.framerate = KeysAnimation.FRAMERATE;
        }

        const layer = new TimelineLayer(
            payload.layerNum,
            payload.file,
            timeline,
            this._currentTime || 0,
            !!payload.attach,
            payload.offset
        );
        this.layers.push(layer);
        this.reorder();
        this.emit(event, event, animInstance, payload);
    }
}

export default KeysAnimation;
