import Component from '../Component';
import TweenManager from '../../tween/TweenManager';
import FaceRenderer from '../../FaceRenderer';
import ViewManager from '../ViewManager';

/**
 * Base class for components elements (non-groups) that appear in component
 * groups (buttons, labels, .etc) Has base methods that deal with display
 * and positioning.
 *
 * @class Element
 * @extends jibo.face.Component
 * @memberof jibo.face
 */
abstract class Element extends Component    // TODO :: Not sure if this really needs to be abstract or not?
{
    /**
     * Display container for the Element.
     * @name jibo.face.Element#display
     * @type {PIXI.Container}
     */
    public display:PIXI.Container = null;

    /**
     * The index of the Element within a {@link jibo.face.List}, when applicable.
     * @name jibo.face.Element#index
     * @type {number}
     */
    public index:number = -1;

    /**
     * Flag determines if Component has interactivity affected by input.
     * @name jibo.face.Element#interactable
     * @default false
     * @type {boolean}
     */
    public interactable:boolean = false;

    /**
     * The target position for the Element's display.
     * @name jibo.face.Element#_targetPosition
     * @type {PIXI.Point}
     * @protected
     * @internal
     */
    protected _targetPosition:PIXI.Point = null;

    /**
     * The target position.
     * Can be specified prior to the creation of the display, when the display is created this position is applied.
     * @name jibo.face.Element#targetPosition
     * @type {PIXI.Point}
     */
    public get targetPosition():PIXI.Point {
        if(!this._targetPosition) {
            this._targetPosition = new PIXI.Point();
        }
        return this._targetPosition;
    }

    /**
     * Assign data passed via Object to class.
     * Method can be overridden to allow for manual definition of values, assets, etc.
     * @method jibo.face.Element#assignConfig
     * @param {any} configData - Object derived from JSON containing values specific to Element.
     * @internal
     */
    public assignConfig(configData:any):void {
        if(configData) {
            super.assignConfig(configData);
            if (configData.hasOwnProperty("position")) {
                this._targetPosition = new PIXI.Point(Number(configData.position.x),Number(configData.position.y));
            }
            if (configData.hasOwnProperty("interactable")) {
                this.interactable = configData.interactable;
            }
        }
    }

    /**
     * Update data representation of element with any `state` changes
     * (anything that should persist between views).
     * @method jibo.face.Element#updateConfig
     * @param configData - Object derived from JSON containing values specific to Element.
     * @returns {any}
     */
    public updateConfig(configData:any):any {
        return configData;
    }

    /**
     * Frame enter loop update, should be overridden.
     * @method jibo.face.Element#update
     * @param {number} elapsed Time in milliseconds since the last frame update.
     */
    public update(elapsed:number):void {
        console.warn("Element :: update : class has not overridden its update, which means update probably shouldn't be getting called on it.");
    }

    /**
     * Create Element's display and add to container.
     * @method jibo.face.Element#createDisplay
     * @param {PIXI.Container} container Parent Container which all DisplayObject
     *        created within this Component should be added to.
     * @param {Object} assets Object passed back from loader namespace load method,
     *        refer to {@link jibo.loader} for detail
     */
    public createDisplay(container:PIXI.Container, assets:any):void {
        this._assets = assets;
        this.display = new PIXI.Container();
        this.setupDisplay(assets);
        this.applyPosition();
        container.addChild(this.display);
    }

    /**
     * Set up the display.
     * Assign assets, set timelines, etc.
     * @method jibo.face.Element#setupDisplay
     * @param {Object} [assets] Object passed back from loader namespace load method,
     *        refer to {@link jibo.loader} for detail
     */
    public setupDisplay(assets?:any):void {
        // for override
    }

    /**
     * @description Called by parent ComponentGroup once parent has finished its loading and setup.
     * Allows opportunity to do additional setup that may depend on other components.
     *
     * ATTENTION: This should not be called directly, the parent View {@link jibo.face.View}
     * will call this, which will recurse through Component tree.
     * @method jibo.face.Element#ready
     */
    public ready():void {
        // for override
    }


    /**
     * Lock or unlock input, lock value is applied to the display's interactive variable.
     * @method jibo.face.Element#inputLocked
     * @param {Boolean} flag Determines if input is locked.
     * @writeOnly
     */
    public set inputLocked(flag:boolean) {
        this._inputLocked = flag;
        if(this.interactable && this.display) {
            this.display.interactive = !this._inputLocked;
        }
    }

    // TODO :: Want to be able to handle constants such as center, left, right, etc with a DisplayPositionUtil interfacing
    /**
     * Used to define the position for the display before it is created.
     * @method jibo.face.Element#setTargetPosition
     * @param {int} [x = 0] The x position target.
     * @param {int} [y = 0] The y position target.
     * @param {Boolean} [applyNow = false] Flag determining if given target position should be applied to display within this method.
     *          (Display must be defined for this to take effect.)
     */
    public setTargetPosition(x:number = 0, y:number = 0, applyNow:boolean = false):void {
        if(!this._targetPosition) {this._targetPosition = new PIXI.Point();}
        this._targetPosition.x = x;
        this._targetPosition.y = y;

        if(applyNow && this.display) {
            this.display.x = x;
            this.display.y = y;
        }
    }

    /**
     * Apply position that was defined in config to display's actual position.
     * @method jibo.face.Element#applyPosition
     * @public
     */
    public applyPosition():void {

        // retrieve position from data if it was specified
        if(this._targetPosition && this.display) {
            this.display.x = this._targetPosition.x;
            this.display.y = this._targetPosition.y;
        }
    }

    /**
     * Open transition, defaults to vertical tween upward from below viewport.
     * @method jibo.face.Element#open
     * @param {Function} callback Function to be called once open is complete.
     * @param {String} transitionType String used to determine Element's open transition,
     *        refer to ViewManager for constants used
     * @param {number} [tweenTime = 550] Duration in milliseconds of the tween.
     * @param {String} [tweenType = 'backOut'] Type of tween used.
     */
    public open(callback:Function, transitionType?:string, tweenTime:number = ViewManager.TRANS_TIME, tweenType:string = 'backOut' ):void{

        const targetY:number = this.display.y;
        const originY:number = +targetY + +FaceRenderer.HEIGHT;
        TweenManager.play(this.display,
            {
                to: { y: targetY  },
                from: { y: originY },
                duration: tweenTime,
                ease: tweenType
            },
            callback
        );
    }

    /**
     * Close transition, defaults to vertical tween upward out of viewport.
     * @method jibo.face.Element#close
     * @param {Function} callback Function to be called once open is complete.
     * @param {String} [transitionType] String used to determine way Element's close transition,
     *        refer to ViewManager for constants used.
     * @param {number} [tweenTime = 550] Duration in milliseconds of the tween.
     * @param {String} [tweenType = 'backIn'] Type of tween used.
     */
    public close(callback:Function, transitionType?:string, tweenTime:number = ViewManager.TRANS_TIME, tweenType:string = 'backIn' ):void{
        const targetY:number = +this.display.y + +FaceRenderer.HEIGHT;
        TweenManager.play(this.display,
            {
                to: { y: targetY  },
                duration: tweenTime,
                ease: tweenType
            },
            callback
        );
    }

    /**
     * Destroy, stops any tweens that may be active on the Elements' display.
     * @method jibo.face.Element#destroy
     */
    public destroy():void {
        if(this.display){
            TweenManager.stop(this.display);
            this.display = null;
        }
        this._targetPosition = null;
        super.destroy();
    }
}

export default Element;
