const glslify  = require('glslify');
import DOFValues from '../../DOFValues';

/**
 * Apply a light effect to a displayObject.
 * Create a gradient scaled to match the dimensions of the object.
 * Automatically adjust gradient position based on location of light effect.
 *
 * @class LightFilter
 * @extends PIXI.Filter
 * @memberof jibo.face
 */
class LightFilter extends PIXI.Filter {

    public radius:number;
    public lightScale:number;
    public padding:number;
    public distanceMagnification: PIXI.Point;
    public lightPosition: PIXI.Point;
    public uniforms:any;
    public enabled:boolean = false;
    public target:any;
    private setWithDOFS:boolean;

    constructor() {
        super(glslify('./light.vert'), glslify('./light.frag'), "");

        /**
         * Move the gradient center this distance in relation to the light source.
         * The higher the value, the greater the effect of the light movement.
         * @name jibo.face.LightFilter#radius
         * @type {Number}
         * @default 250
         */
        this.reset();
        this.padding = 200;


        /**
         * Distance the gradient center will move based on the distance from the light source.
         * The higher the values the greater the effect of the light movement.
         * @name jibo.face.LightFilter#distanceMagnification
         * @type {PIXI.Point}
         */
        this.distanceMagnification = new PIXI.Point(200, 600);

        /**
         * Position of the light source. For the best effect this should be set to be the center of the screen
         * @name jibo.face.LightFilter#lightPosition
         * @type {PIXI.Point}
         */
        this.lightPosition = new PIXI.Point();
        /**
         * Target that the glow centers on.
         * @name jibo.face.LightFilter#target
         * @type {DisplayObject}
         */
        this.target = null;
    }

    reset(): void {
        this.amount = 1;
        this.radius = 250;
        this.gradientRatio = 0.5;
        this.lightScale = 0.8;
        this.dark = 0x5a5552;
        this.mid = 0xc0bab6;
        this.light = 0xffffff;
    }

    apply(filterManager, input, output) {
        const target = this.target || filterManager.filterData.stack[filterManager.filterData.index].target;
        const bounds = target.getBounds(true);

        this.uniforms.offset.x = target.position.x;
        this.uniforms.offset.y = target.position.y;

        this.uniforms.radius = this.radius;

        this.uniforms.scale.x = (this.radius / bounds.width) / this.lightScale;
        this.uniforms.scale.y = (this.radius / bounds.height) / this.lightScale;

        const centerX = target.position.x - this.lightPosition.x;
        const centerY = target.position.y - this.lightPosition.y;


        let dist = Math.sqrt(centerX * centerX + centerY * centerY);

        // dist cant be 0  - as then we would get lots of NaNs when dividing.
        if(!dist) {
            dist = 0.001;
        }

        const nx = centerX / dist;
        const ny = centerY / dist;


        const intensityX = this.map(dist, 0, 500, 0, this.distanceMagnification.x);
        const intensityY = this.map(dist, 0, 500, 0, this.distanceMagnification.y);

        this.uniforms.direction.x = nx * -intensityX;
        this.uniforms.direction.y = ny * -intensityY;

        filterManager.applyFilter(this, input, output, true);
    }

    map(val, inputMin, inputMax, outputMin, outputMax) {
        return ((outputMax - outputMin) * ((val - inputMin)/(inputMax - inputMin))) + outputMin;
    }



    /**
     * Darkest (furthest) color of the light effect in hexadecimal numbers.
     * i.e. 0xFF0000
     * @type {Number}
     * @default 0x5a5552
     * @name jibo.face.LightFilter#dark
     */
    get dark() {
        return PIXI.utils.rgb2hex( this.uniforms.dark );
    }
    set dark(value) {
        this.uniforms.dark = this.hex2rgba(value, this.uniforms.dark);
    }

    /**
     * Mid-color of the light effect in hexadecimal numbers.
     * i.e. 0xFF0000
     * @default 0xc0bab6
     * @type {Number}
     * @name jibo.face.LightFilter#mid
     */
    get mid() {
        return PIXI.utils.rgb2hex( this.uniforms.mid );
    }
    set mid(value) {
        this.uniforms.mid = this.hex2rgba(value, this.uniforms.mid);
    }

    /**
     * Lightest (closest) color of the light effect in hexadecimal numbers.
     * i.e. 0xFF0000
     * @default 0xffffff
     * @type {Number}
     * @name jibo.face.LightFilter#light
     */
    get light() {
        return PIXI.utils.rgb2hex(this.uniforms.light);
    }
    set light(value) {
        this.uniforms.light = this.hex2rgba(value, this.uniforms.light);
    }

    /**
     * Amount of the light between 0 and 1 to (creates speaking light effect).
     * Apply to darkest areas first. 0 = no extra brightness. 1 = full white.
     * @default 1
     * @type {Number}
     * @name jibo.face.LightFilter#amount
     */
    get amount() {
        return this.uniforms.amount;
    }
    set amount(value) {
        this.enabled = value > 0;
        this.uniforms.amount = value;
    }

    /**
     * Brightness of the filter between 0 and 1.
     * 0 = no lighting effect. 1 = full light effect visible.
     * @default 1
     * @type {Number}
     * @name jibo.face.LightFilter#brightness
     */
    get brightness() {
        return this.uniforms.intensity;
    }
    set brightness(value) {
        this.uniforms.intensity = value;
    }

    /**
     * Ratio of the midpoint of the gradient between 0 and 1.
     * Lower value = mid color gradient sits closer to center of light gradient.
     * Higher value = mid color gradient sits closer to outer dark part of gradient.
     * @default 0.5
     * @type {Number}
     * @name jibo.face.LightFilter#gradientRatio
     */
    get gradientRatio() {
        return this.uniforms.gradientRatio;
    }
    set gradientRatio(value) {
        this.uniforms.gradientRatio = value;
    }

    /**
     * Conversion utility to convert hex into alpha.
     * @method jibo.face.LightFilter#hex2rgba
     */
    hex2rgba(value, current, alpha = 1) {
        const rgba = PIXI.utils.hex2rgb(value, current);
        rgba[3] = alpha;
        return Array.prototype.slice.call(rgba);
    }

    /**
     * Update the DOFValues for display.
     * @private
     * @method jibo.face.LightFilter#update
     * @param {Array<number>} timestamp The timestamps.
     * @param {jibo.face.DOFValues} dofValues
     */
    update(timestamp:Array<number>, dofValues:DOFValues): void {

        // No default values for lighting in DOFs, we should check first
        if (dofValues.lighting_amount !== undefined) {
            this.setWithDOFS = true;
            this.amount = dofValues.lighting_amount;
            this.brightness = dofValues.lighting_brightness;
            this.gradientRatio = dofValues.lighting_gradient;
            this.radius = dofValues.lighting_radius;

            this.light = this.rgbToUint(
                dofValues.lighting_light_redChannel,
                dofValues.lighting_light_greenChannel,
                dofValues.lighting_light_blueChannel
            );
            this.mid = this.rgbToUint(
                dofValues.lighting_mid_redChannel,
                dofValues.lighting_mid_greenChannel,
                dofValues.lighting_mid_blueChannel
            );
            this.dark = this.rgbToUint(
                dofValues.lighting_dark_redChannel,
                dofValues.lighting_dark_greenChannel,
                dofValues.lighting_dark_blueChannel
            );
        }
        else if (this.setWithDOFS) {
            this.setWithDOFS = false;
            this.reset();
        }
    }

    /**
     * Convert R, G and B values to Uint
     * @method jibo.face.LightFilter#rgbToUint
     * @private
     * @param {Number} r Red value
     * @param {Number} g Green value
     * @param {Number} b Blue value
     * @return {Number} Uint of color.
     */
    private rgbToUint(r:number, g:number, b:number):number {
        return r << 16 | g << 8 | b;
    }
}


export default LightFilter;
