import * as async from 'async';
import {EventEmitter} from 'events';
import { WSClient } from 'jibo-client-framework';

/**
 * Emitted when a word is spoken.
 * @event jibo.tts#word
 * @param {String} word The word that was just spoken.
 */

/**
 * Enum for TTS modes.
 * @name jibo.tts#TTSMode
 * @enum {String}
 * @property SSML {String} Coming soon.
 * @property TEXT {String} Default.
 */
const TTSMode = {
    SSML: 'ssml',
    TEXT: 'text'
};

/**
 * Modes of TTS.
 * @alias jibo.tts~TTSModes
 * @enum {String}
 */
export interface TTSModes {
    SSML:string;
    TEXT:string;
}

/**
 * TTS Server API paths.
 * {@link https://confluence.jibo.com/display/ENG/TTS+Service|TTS Service Docs}
 * @private
 * @enum {String}
 */
const APIPath = {
    TOKENS: '/tts_tokens',
    PHONES: '/tts_phones',
    STOP: '/tts_stop',
    SPEAK: '/tts_speak',
    TIMING: '/tts_token_times',
    EFFECTS: '/tts_effects',
    ANALYSIS: '/tts_analysis'
};


/**
 * The various event types that TTSService emits.
 * @alias jibo.tts#TTSEvents
 * @enum {String}
 */
const TTSEvents = {
    WORD: 'word',
    PHONE: 'phone',
    STOP: 'stop',
    EFFECT: 'effect',
    ANALYSIS: 'analysis'
};

/**
 * The various event types that TTSService emits.
 * @alias jibo.tts~TTSEvents
 * @enum {String}
 */
export interface TTSEvents {
    WORD:string;
    PHONE:string;
    STOP:string;
    EFFECT:string;
    ANALYSIS:string;
}

/**
 * The various types of actions pedals can take.
 * @private
 * @enum {String}
 */
const PedalsActions = {
    START: 'START',
    STOP: 'STOP',
    UPDATE: 'UPDATE'
};

type CB = (err?:any)=>void;
type TimingsCB = (err:any, timings?:WordTimings)=>void;
type TTSOptions = {
    duration_stretch?:number;
    pitch?:number;
    pitchBandwidth?:number;
    mode?:'ssml'|'text';
    skipWordEvents?:boolean;
    volume?:number;
    whisper?:string;
};
type WordTimings = {
    tokentimes: {
        tokens: {
            name: string,
            start: number,
            end: number
        }[];
    }
};

/**
 * The various events this service will emit.
 * @alias jibo.tts~PedalsEvents
 * @enum {String}
 */
//const PedalsEvents = {
//    CONNECT: 'connect',
//    DISCONNECT: 'disconnect',
//    CONNECT_FAIL: 'connect-fail',
//    ERROR: 'error'
//};

/**
 * The default settings for a TTS request body
 * @private
 */
const defaultTTSReqBody = {
    prompt: '',
    locale: 'en-us',
    voice: 'griffin',
    mode: TTSMode.TEXT
};


/**
 * @description
 * Text-to-Speech
 *
 * ```
 * var jibo = require("jibo");
 * jibo.tts.on('word', (word) => {
 *     //respond to words
 * });
 * jibo.tts.speak("Hello, my name is Jibo", (err) => {
 *
 * });
 * ```
 * @namespace jibo.tts
 * @extends {EventEmitter}
 */
class TTSService extends EventEmitter {

    public isInitialized:boolean = false;
    public isTalking:boolean = false;
    public isStopping:boolean = false;
    public TTSEvents: TTSEvents;
    public TTSMode: TTSModes;
    public logging:boolean;

    private effectsSocket:any;
    private httpInterface:any;
    private socketUrl:string;

    constructor() {
        super();
        this.isInitialized = false;
        this.isTalking = false;
        this.isStopping = false;

        // Flip this on to have websocket messages logged to the console
        //this.logging = true;

        // Provide external access to these enums
        this.TTSEvents = TTSEvents;
        this.TTSMode = TTSMode;
    }

    static get TTSMode() {
        return TTSMode;
    }

    static get TTSEvents() {
        return TTSEvents;
    }

    init(service, cb) {
        if (!service.host || typeof service.host !== 'string') {
            throw new Error(`Missing required service.host`);
        }

        this.httpInterface = "http://" + service.host + ":" + service.port;
        this.socketUrl =  "ws:" + service.host + ":" + service.port;

        // Wrap effect socket call so we can extract socket and keep ref to it
        let effectsSocketCreator = (cb) => {
            let handler = (socket) => {
                this.effectsSocket = socket;
                cb();
            };
            this.createSocket(APIPath.EFFECTS, "tts sound effects", TTSEvents.EFFECT)(handler);
        };

        async.parallel(
            [
                this.createSocket(APIPath.TOKENS, "tts tokens", TTSEvents.WORD).bind(this),
                this.createSocket(APIPath.PHONES, "tts phones", TTSEvents.PHONE).bind(this),
                this.createSocket(APIPath.ANALYSIS, "tts analysis", TTSEvents.ANALYSIS).bind(this),
                effectsSocketCreator
            ],
            () => {
                this.isInitialized = true;
                cb();
            }
        );
    }

    createSocket(path, socketDescription, emitterEventName) {
        return (cb) => {
            let socket = new WSClient(this.socketUrl + path);
            socket.on('error', () => {
                console.error(`Error opening ${socketDescription} socket at ${this.socketUrl}${path}`);
            });
            socket.on('message', (data) => {
                // Log events to the console if logging is enabled
                if(this.logging){
                    console.log(data);
                }

                let word;
                try { 
                    word = data;
                } catch(err){
                    // Work around to fix tts service's malformed (Failed ot JSON.parse()) payloads for the
                    // message when the token status is "STOP"
                    if(JSON.stringify(data) === '{"token":"","timestamp":0.0,"status":"STOP","moreinfo":[]}'){
                        this.emit(emitterEventName, {"token":"","timestamp":0.0,"status":"STOP","moreinfo":[]});
                        return;
                    }
                    console.log(`Could not JSON.parse() ${socketDescription} data. Payload was: '${data}'`);
                }
                if (word) {
                    this.emit(emitterEventName, word);
                }
            });
            cb(socket);
        };

    }

    /**
     * Make Jibo speak.
     * @method jibo.tts#speak
     * @param {String} text Text for Jibo to speak.
     * @param {Object} [options] Parameters to override default TTS behavior.
     * @param {number} [options.duration_stretch] Stretch the utterance. 1 = no stretch, 0.5 = halve the duration, 2 = double the duration. No upper limit.
     *                                            No effect if `options.mode === jibo.tts.TTSMode.SSML`.
     * @param {number} [options.pitch]  Control the overall pitch of the speaker. No SSML tag to override this.
     *                                  Recommended value is 0.42. The recommended range is [0.2, 0.8].
     * @param {number} [options.pitchBandwidth] Widen the pitch bandwidth. Recommended value is 1.
     *                                          The range is [0.0, 2.0]. `0` makes Jibo sound robotic. `2.0`
     *                                          makes Jibo sound more human.
     * @param {jibo.tts~TTSMode} [options.mode] In `jibo.tts.TTSMode.SSML` mode, the `text` argument to this function should contain valid SSML. In text mode, the prompt can contain any text.
     * @param {boolean} [options.skipWordEvents=false] If `true`, no word events are emitted during TTS synthesis.
     * @param {Function} [callback] Notify the caller that the speech has started. If no
     *                              callback is provided, return a `Promise`.
     * @return {Promise|undefined} If no callback is provided, return a `Promise`, which is resolved when done speaking.
     */
    speak(text:string, options?:TTSOptions): Promise<void>;
    speak(text:string, callback:CB): void;
    speak(text:string, options:TTSOptions, callback:CB): void;
    speak(text:string, arg1:TTSOptions|CB=null, arg2:CB=null):Promise<any> {
        let {callback, options} = this.getOptionsAndCallback(arg1, arg2);
        if(!callback) {
            return new Promise((res, rej) => {
                let cb = (err) => {
                    if (err) {
                        rej(err);
                    }
                    else {
                        res();
                    }
                };
                this._speak(text, options, cb);
            });
        }
        else {
            this._speak(text, options, callback);
        }
    }

    /**
     * Stop any speech Jibo is uttering.
     * @method jibo.tts#stop
     * @param {Function} [callback] Notify the caller that speech has stopped. If no callback is provided, return a `Promise`.
     * @return {Promise|undefined} If no callback is provided, return a `Promise`, which gets resolved when stopped.
     */
    stop():Promise<void>;
    stop(callback:CB);
    stop(callback?:CB): Promise<any> {
        if(callback) {
            this._stop(callback);
        }
        else {
            return new Promise((res, rej) => {
                this._stop((err) => {
                    if (err) {
                        rej(err);
                    }
                    else {
                        res();
                    }
                });
            });
        }
    }

    /**
     * Asynchronously retrieve a word schedule for given text (SSML markup support coming soon!).
     * @method jibo.tts#getWordTimings
     * @param {String} text The utterance provided to TTS for speaking.
     * @param {Object} [options] Same options as {@link jibo.tts#speak}.
     * @param {Function} [callback] Callback. If none is provided, return a `Promise`.
     * @return {Promise|undefined}
     */
    getWordTimings(text:string, options?:TTSOptions): Promise<WordTimings>;
    getWordTimings(text:string, callback:TimingsCB): void;
    getWordTimings(text:string, options:TTSOptions, callback:TimingsCB): void;
    getWordTimings(text:string, arg1?:TTSOptions|TimingsCB, arg2?:TimingsCB):Promise<WordTimings> {

        let {options, callback} = this.getOptionsAndCallback(arg1, arg2);

        if(callback) {
            this._getWordTimings(text, options, callback);
        }
        else {
            return new Promise((res, rej) => {
                let cb = (err, schedule) => {
                    if (err) {
                        rej(err);
                    }
                    else {
                        res(schedule);
                    }
                };
                this._getWordTimings(text, options, cb);
            });
        }
    }

    /**
     * Start a sound effect.
     * @method jibo.tts#startEffect
     * @param {String} name The name of the effect.
     * @param {number | string} value Either a number between 0 and 1 or a
     * string parameter for the effect.
     */
    startEffect(name:string, value:string|number): void {
        this._validateEffectNameParam(name);
        this._validateEffectValueParam(value);

        let requestBody = {
            'name': name,
            'action': PedalsActions.START,
            'param': ("" + value)
        };
        this.effectsSocket.send(JSON.stringify(requestBody));
    }

    /**
     * Stop a sound effect.
     * @method jibo.tts#stopEffect
     * @param {String} name The name of the effect.
     */
    stopEffect(name:string): void {
        this._validateEffectNameParam(name);

        let requestBody = {
            'name': name,
            'action': PedalsActions.STOP,
            'param': "0"
        };
        this.effectsSocket.send(JSON.stringify(requestBody));
    }

    /**
     * Update the value of a sound effect.
     * @method jibo.tts#updateEffect
     * @param {String} name The name of the effect.
     * @param {number | string} value Either a number between 0 and 1 or a
     * string parameter for the effect.
     */
    updateEffect(name:string, value:string|number): void {
        this._validateEffectNameParam(name);
        this._validateEffectValueParam(value);

        let requestBody = {
            'name': name,
            'action': PedalsActions.UPDATE,
            'param': ("" + value)
        };
        this.effectsSocket.send(JSON.stringify(requestBody));
    }

    private getOptionsAndCallback<T extends Function>(arg1:TTSOptions|T, arg2?:T) {

        let options:TTSOptions = {};
        let callback: T;
        if (!arg1 && !arg2) {
            options = {};
        }
        else if (typeof arg1 === 'object' && !arg2) {
            options = arg1;
        }
        else if (typeof arg1 === 'function' && !arg2) {
            callback = <T>arg1;//should be able to drop the typecast with TypeScript 2.0
        }

        else if (typeof arg1 === 'object' && typeof arg2 === 'function') {
            options = arg1;
            callback = arg2;
        }
        return {
            options, callback
        };
    }

    private _dispatchWordSchedule(wordTimings:WordTimings) {
        let start = Date.now();
        let index = 0;
        let timings = wordTimings.tokentimes.tokens
          .filter(token => token.name !== '/pau/');

        let handleWord = () => {
            let wordObj = timings[index];
            this.emit('word', {
                token: wordObj.name,
                timestamp: wordObj.start,
                status: 'PLAY',
                moreinfo: []
            });
            index++;
            if (index < timings.length) {
                let nextTime = 1000 * timings[index].start;
                let current = Date.now() - start;
                setTimeout(handleWord, Math.max(nextTime - current, 0));
            }
        };

        if (timings.length) {
            let nextTime = 1000 * timings[index].start;
            setTimeout(handleWord, nextTime);
        }
    }

    private _speak(text:string, options:TTSOptions, callback:CB) {
        if(!this.isInitialized) {
            callback("TTS Service is not initialized");
            return;
        }

        let doSpeak = () => {

            if (options.skipWordEvents) {
                this._sendTTSRequest(text, options, callback);
            }
            else {
                // We start by getting the word schedule
                this._getWordTimings(text, options, (err, timings) => {
                    if (err) {
                        callback(err);
                    }
                    else {
                        // We then start dispatching the word schedule
                        // asynchronously
                        this._dispatchWordSchedule(timings);
                        this._sendTTSRequest(text, options, callback);
                    }
                });
            }
        };

        if(this.isStopping) {
            let onStopped = () => {
                this.removeListener('stopped', onStopped);
                doSpeak();
            };
            this.on('stopped', onStopped);
        }
        else if(this.isTalking) {
            this.stop(doSpeak);
        }
        else {
            doSpeak();
        }
    }

    private _sendTTSRequest(text:string, options:TTSOptions, callback:CB) {
        let request = new XMLHttpRequest();

        let requestBody = JSON.parse(JSON.stringify(defaultTTSReqBody));
        requestBody.prompt = text;

        // Pass in optional parameters
        if (options.duration_stretch) {
            requestBody.duration_stretch = options.duration_stretch;
        }
        if (options.pitchBandwidth) {
            requestBody.pitchBandwidth = options.pitchBandwidth;
        }
        if (options.pitch) {
            requestBody.pitch = options.pitch;
        }
        if (options.volume) {
            requestBody.volume = options.volume;
        }
        if (options.whisper) {
            requestBody.whisper = options.whisper;
        }

        requestBody.mode = options.mode || requestBody.mode;

        requestBody = JSON.stringify(requestBody);
        request.open("POST", this.httpInterface + APIPath.SPEAK, true);

        request.onreadystatechange = () => {
            if (request.readyState === 4) {
                if (request.status === 204) { // HTTP_NO_CONTENT
                    this.isTalking = false;
                    callback();
                }
                else {
                    // failure if anything else
                    let msg = 'TTS Service is unavailable';
                    if (request.statusText !== undefined && request.statusText !== "") {
                        msg = request.statusText; // use "reason" if they gave it
                    }
                    callback(msg);
                }
            }
        };
        this.isTalking = true;
        request.send(requestBody);
    }

    private _getWordTimings(text:string, options:TTSOptions, cb:TimingsCB) {
        if (typeof text !== 'string') {
            throw new TypeError(`Invalid params: ${text}, ${TTSMode}`);
        }
        if (!this.isInitialized) {
            throw new Error('Not initialized. Use .init()');
        }

        let request = new XMLHttpRequest();

        let requestBody = JSON.parse(JSON.stringify(defaultTTSReqBody));
        requestBody.prompt = text;

        // Pass in optional parameters
        requestBody.duration_stretch = options.duration_stretch ||
          requestBody.duration_stretch;
        requestBody.pitchBandwidth = options.pitchBandwidth ||
          requestBody.pitchBandwidth;
        requestBody.pitch = options.pitch || requestBody.pitch;
        requestBody.mode = options.mode || requestBody.mode;

        // Create actual request body and subscribe response handler
        requestBody = JSON.stringify(requestBody);
        request.open('POST', this.httpInterface + APIPath.TIMING, true);
        request.onreadystatechange = () => {
            let requestIsDone = request.readyState === 4;
            let isErrorStatus = request.status < 200 || request.status >= 400;
            if(requestIsDone && request.status === 200) {
                // We attempt parsing the message
                let msg;
                try{
                    msg = JSON.parse(request.response);
                } catch(err){
                    cb(err);
                }
                if (msg) {
                    if (msg.Status && msg.Status === 'ERROR') {
                        cb(msg);
                    }
                    else {
                        cb(null, msg);
                    }
                }
            } else if (requestIsDone && isErrorStatus) {
                cb(new Error(`Request failed with status: ${request.status}`));
            }
        };
        request.send(requestBody);
    }

    private _stop(callback:CB) {
        if(!this.isInitialized) {
            callback();
            return;
        }
        this.isStopping = true;
        this.isTalking = false;
        let request = new XMLHttpRequest();
        request.timeout = 2000;
        request.onreadystatechange = () => {
            let requestIsDone = request.readyState === 4;
            let isErrorStatus = request.status < 200 || request.status >= 400;
            if(requestIsDone && request.status === 200) { // HTTP_OK
                this.isStopping = false;
                this.emit('stopped');
                callback();
            } else if (requestIsDone && isErrorStatus) {
                this.isStopping = false;
                this.emit('stopped');
                callback(new Error(`TTS.stop request failed with status: ${request.status}`));
            }
        };
        request.open("GET", this.httpInterface + APIPath.STOP, true);
        request.send(null);
    }

    private _validateEffectNameParam(name:string): void {
        if (typeof name !== 'string') {
            throw new TypeError(`Invalid params, name must be string: ${name}`);
        }
        if (!this.isInitialized) {
            throw new Error('Not connected. Cannot send action.');
        }
        if (!this.effectsSocket) {
            throw new Error('Effect socket not initialized.');
        }
    }

    private _validateEffectValueParam(value:string|number): void {
        if (typeof value === 'number') {
            if (value < 0 || value > 1) {
                throw new TypeError(`Value out of range [0, 1]: ${value}`);
            }
        }
        else if(typeof value !== 'string') {
            throw new TypeError(`Value must either be a number or string: ${value}`);
        }
    }
}

export default TTSService;
