import View from './views/View';
import {ChangeOptions,ViewCallback} from './ViewManager';

/**
 * ViewProcess assists in managing the process of changing views.
 * It keeps track of callbacks and deals with interruptions.
 * This is used exclusively by {@link jibo.face.ViewManager} and should not be accessed.
 * @class ViewProcess
 * @memberof jibo.face
 * @internal
 */
class ViewProcess
{
    /**
     * Process is currently in the queue.
     * @type {string}
     * @name jibo.face.ViewProcess#QUEUED
     * @readOnly
     */
    public static get QUEUED():string {return 'queued';}

    /**
     * Process has been started.
     * @type {string}
     * @name jibo.face.ViewProcess#STARTED
     * @readOnly
     */
    public static get STARTED():string {return 'started';}

    /**
     * Process has successfully completed.
     * @type {string}
     * @name jibo.face.ViewProcess#COMPLETED
     * @readOnly
     */
    public static get COMPLETED():string {return 'completed';}

    /**
     * Process was interrupted by another process.
     * @type {string}
     * @name jibo.face.ViewProcess#INTERRUPTED
     * @readOnly
     */
    public static get INTERRUPTED():string {return 'interrupted';}

    /**
     * Process failed.
     * @type {string}
     * @name jibo.face.ViewProcess#FAILED
     * @readOnly
     */
    public static get FAILED():string {return 'failed';}

    /**
     * Get flag to determine if views currently in process.
     * If a new process is requested while active the active process will be interrupted.applied.
     * @name jibo.face.ViewProcess#active
     * @type {Boolean}
     * @readOnly
     */
    public get active():boolean { return this._active; }

    /**
     * Options for current view change.
     * @name jibo.face.ViewProcess#changeOptions
     * @type {jibo.face.ViewManager#ChangeOptions}
     */
    public changeOptions:ChangeOptions = null;

    /**
     * Callback for process completes.
     * @name jibo.face.ViewProcess#_onComplete
     * @type {jibo.face.ViewManager~ViewCallback}
     */
    public onComplete:ViewCallback = null;

    /**
     * Callback for process fails, due to error or interruption.
     * @name jibo.face.ViewProcess#onFailure
     * @type {Function}
     */
    public onFailure:Function = null;

    /**
     * Callback for when next view in process has loaded.
     * Use to access view prior to it being added to display and opened.
     * @name jibo.face.ViewProcess#onLoaded
     * @type {jibo.face.ViewManager~ViewCallback}
     */
    public onLoaded:ViewCallback = null;

    /**
     * Queue of view change processes.
     * @name jibo.face.ViewProcess#processQueue
     * @type {jibo.face.ViewProcess[]}
     */
    public processQueue:Array<ViewProcess> = [];

    /**
     * Current state of process.
     * @name jibo.face.ViewProcess#status
     * @type {String}
     */
    public status:string = '';

    /**
     * Flag to determine if views currently in process.
     * If a new process is requested while active the active process will be interrupted.
     * @name jibo.face.ViewProcess#_active
     * @type {Function}
     * @private
     */
    private _active:boolean = false;

    /**
     * Array of Views involved in the current process.
     * A reference is kept so that views can be destroyed if process is interrupted.
     * @name jibo.face.ViewProcess#_activeViews
     * @type {Array<jibo.face.View>}
     * @private
     */
    private _activeViews:Array<View> = [];

    /**
     * Currently active view in display.
     * @name jibo.face.ViewProcess#_currentView
     * @type {jibo.face.View}
     * @private
     */
    private _currentView:View;
    /**
     * Currently active view in display.
     * @name jibo.face.ViewProcess#currentView
     * @type {jibo.face.View}
     */
    public get currentView():View{
        return this._currentView;
    }
    public set currentView(view:View){
        this._currentView = view;
    }

    /**
     * View that was previously current but is now in process of closing.
     * @name jibo.face.ViewProcess#_closingView
     * @type {jibo.face.View}
     * @private
     */
    private _closingView:View;

    /**
     * View that was previously current but is now in process of closing.
     * @name jibo.face.ViewProcess#closingView
     * @type {jibo.face.View}
     */
    public get closingView():View{
        return this._closingView;
    }
    public set closingView(view:View){
        this._closingView = view;
    }

    /**
     * Flag for process interruption, if 'true' process has been interrupted.
     * @name jibo.face.ViewProcess#_interrupted
     * @type {boolean}
     * @private
     */
    private _interrupted:boolean = false;

    /**
     * Flag for process interruption, if 'true' process has been interrupted.
     * @name jibo.face.ViewProcess#interrupted
     * @type {boolean}
     * @readOnly
     */
    public get interrupted():boolean{
        return this._interrupted;
    }

    /**
     * Start the view process.
     * Before starting a process should check for interrupt.
     * @method jibo.face.ViewProcess#start
     * @param {jibo.face.ViewManager~ViewCallback} onComplete Callback for process completes.
     * @param {Function} onFailure Callback for process fails, due to error or interruption.
     * @param {jibo.face.ViewManager~ViewCallback} onLoaded - Callback for when next view in process has loaded.
     * @param {jibo.face.ViewManager#ChangeOptions} changeOptions - Options for the change view process being queued.
     */
    public start( onComplete?:ViewCallback, onFailure?:Function, onLoaded?:ViewCallback, changeOptions?:ChangeOptions):void {

        this.clear();
        this._active = true;
        this._interrupted = false;
        this.onComplete = onComplete;
        this.onFailure = onFailure;
        this.onLoaded = onLoaded;
        this.changeOptions = changeOptions;

        // set status
        this.status = ViewProcess.STARTED;
    }

    /**
     * Adds View to Array of Views involved in the current process.
     * A reference is kept so that views can be destroyed if process is interrupted.
     * @method jibo.face.ViewProcess#storeView
     * @param {jibo.face.View} view View to keep reference to for current process.
     */
    public storeView(view:View):void {
        if(view){
            this._activeViews.push(view);
        } else {
            console.warn('ViewProcess :: storeView: given view was not defined');
        }
    }

    /**
     * Call to complete process.
     * Completion callbacks are triggered and process is cleared.
     * @method jibo.face.ViewProcess#complete
     * @param {jibo.face.View} [view] View established by process, not all processes will return a view.
     */
    public complete(view?:View):void {

        if(this._active && !this._interrupted) {

            this._active = false;
            this._closingView = null;
            this.changeOptions = null;
            this.onFailure = null;
            this.onLoaded = null;
            this._activeViews.length = 0;
            // handle callbacks
            if(this.onComplete) {
                let callback = this.onComplete;
                this.onComplete = null;
                callback(view);
                callback = null;
            }

            // set status
            this.status = ViewProcess.COMPLETED;
        }
        else {
            console.warn('ViewProcess :: complete called but active:' + this._active + ' and interrupted: ' + this._interrupted);
            this.clear();
        }
    }

    /**
     * Fail current process, call appropriate callbacks and clean up.
     * @method jibo.face.ViewProcess#fail
     */
    public fail():void {

        this._active = false;
        this.onComplete = null;
        this.onLoaded = null;
        this.changeOptions = null;
        let view:View;
        for(let i:number = 0; i<this._activeViews.length; i++){
            view = this._activeViews[i];
            if(view.state !== View.DESTROYED){
                view.destroy(); // TODO :: May want special interrupt command?
            }
        }
        this._activeViews.length = 0;

        // set status
        this.status = ViewProcess.FAILED;

        // update references
        if(this._currentView){
            if(this._currentView.state === View.DESTROYED){
                this._currentView = null;
            }
        }
        if(this._closingView){
            if(this._closingView.state === View.DESTROYED){
                this._closingView = null;
            }
        }

        if(this.onFailure) {
            let callback = this.onFailure;
            this.onFailure = null;
            callback();
            callback = null;
        }
    }

    /**
     * Check for active process, if active sets the interrupted flag to `true`.
     * @method jibo.face.ViewProcess#interrupt
     * @param {jibo.face.ViewManager#ChangeOptions} changeOptions - Options for the process being queued. Identifier for interrupting process, useful in debugging.
     * @returns {boolean} `true` if a process is interrupted.
     */
    public interrupt(changeOptions:ChangeOptions):boolean {

        if(this._active) {
            console.info('View change interruption : ',changeOptions,' interrupting ',this.changeOptions,', interruption should be avoided.');
            this._interrupted = true;
            // set status
            this.status = ViewProcess.FAILED;
            return true;
        }
        return false;
    }

    /**
     * Add a change view process to the queue.
     * @method jibo.face.ViewProcess#addProcessToQueue
     * @param {jibo.face.ViewManager#ChangeOptions} changeOptions - Options for the process being queued.
     * @param {jibo.face.ViewManager~ViewCallback} [onComplete] - Callback if process completes, returns current view as param.
     * @param {Function} [onFailure] - Callback if queued process fails, gets interrupted, or does not get to execute.
     * @param {jibo.face.ViewManager~ViewCallback} [onLoaded] Called when next view has loaded, can be used to augment View prior to it being displayed.
     */
    public addProcessToQueue(changeOptions:ChangeOptions, onComplete?:ViewCallback, onFailure?:Function, onLoaded?:ViewCallback):void {

        const viewProcess:ViewProcess = new ViewProcess();
        viewProcess.changeOptions = changeOptions;
        viewProcess.onComplete = onComplete;
        viewProcess.onFailure = onFailure;
        viewProcess.onLoaded = onLoaded;
        viewProcess.status = ViewProcess.QUEUED;

        this.processQueue.push(viewProcess);
    }

    /**
     * Clear the view process references.
     * @method jibo.face.ViewProcess#clear
     * @private
     */
    private clear():void {
        this._active = false;
        this.onComplete = null;
        this.onFailure = null;
        this.onLoaded = null;
        this._activeViews.length = 0;
        this.changeOptions = null;
    }
}

export default ViewProcess;
