import Runtime from '../../../Runtime';
import MenuView from './MenuView';
import ContactButton from "../components/ContactButton";
import List from '../components/List';
import UserNode from '../../../services/kb/User';

/**
 * Sort the list of Loop members.
 * @callback jibo.face.ContactsView~LoopListSort
 * @param loopList {jibo.kb.UserNode[]} List of Loop members to sort.
 */
type LoopListSort = (loopList:UserNode[]) => UserNode[];

/**
 * Check to see if a Loop member is in the list.
 * @callback jibo.face.ContactsView~LooperCheck
 * @param looper {jibo.kb.UserNode} Loop member to check the list for.
 * @return {Boolean} `true` if the Looper exists in the list.
 */
type LooperCheck = (looper:UserNode) => boolean;

/**
 * Menu display for a list of Contacts.
 *
 * @class ContactsView
 * @extends jibo.face.MenuView
 * @memberof jibo.face
 */
class ContactsView extends MenuView
{
    /**
     * The default class identifier.
     * Generally used to register the class.
     * @name jibo.face.ContactsView.DEFAULT_TYPE
     * @type {String}
     * @readOnly
     * @internal
     */
    public static get DEFAULT_TYPE():string {return 'ContactsView';}

    /**
     * Optional function used to edit the looper list.
     * Should determine what ContactButtons are created and in what order.
     * Need to take and return an array of Loop members.
     * If not explicitly defined will be set to a default when createListComponents is called.
     * @name jibo.face.ContactsView#sortLoopList
     * @type {jibo.face.ContactsView~LoopListSort}
     */
    public sortLoopList:LoopListSort = null;

    /**
     * Optional function used to determine if a ContactButton's checkmark should be displayed.
     * Requires a Looper and return a boolean.
     * If true is returned, a checkmark on the Loop member's ContactButton will be displayed.
     * @name jibo.face.ContactsView#determineCheck
     * @type {jibo.face.ContactsView~LooperCheck}
     */
    public determineCheck:LooperCheck = null;

    /**
     * The class type variant.
     * @name jibo.face.ContactsView#_type
     * @type {String}
     * @protected
     * @internal
     */
    protected _type:string = ContactsView.DEFAULT_TYPE;

    /**
     * @name jibo.face.ContactsView#_loopMembers
     * @type {jibo.kb.UserNode[]}
     * @private
     */
    private _loopMembers:UserNode[] = null;

    //////////////////////// CONSTRUCTION ////////////////////////

    /**
     * Destroy.
     * @method jibo.face.ContactsView#destroy
     */
    public destroy():void {
        this._loopMembers = null;
        this.sortLoopList = null;
        this.determineCheck = null;
        super.destroy();
    }

    /**
     * Acquire data sources to set up View.
     * Call internal methods to assign data to a class.
     * Handle loading of config files by default.
     * Can be extended to get data from the KB, servers, or web services.
     * @method jibo.face.ContactsView#loadData
     * @param {Boolean} [loadAssetsOnComplete = true] - If `true` will call loadAssets() once data finishes loading.
     * @protected
     * @internal
     */
    protected loadData(loadAssetsOnComplete:boolean = true):void {

        // TODO :: Make this async
        // check for loop members
        if(!this._loopMembers){
            Runtime.instance.kb.loop.loadLoop((err, loop) => {
                if(err){
                    console.warn('ContactsView :: loadData : kb.loop.loadLoop return an error');
                    console.error(err.message);
                }

                if(loop){
                    this._loopMembers = (loop as any);
                    this.loadData(loadAssetsOnComplete);
                }
                else{
                    console.warn('ContactsView :: loadData : kb.loop.loadLoop return loop as null');
                    console.error('kb.loop.loadLoop return loop as null');
                }
            });
        }
        else{
            // using loopMember data create configs
            super.loadData(loadAssetsOnComplete);
        }
    }

    /**
     * Creates and adds Elements for given List.
     * Override to create custom lists.
     * @method jibo.face.ContactsView#createListComponents
     * @param {jibo.face.List} list List to add elements to.
     * @protected
     * @internal
     */
    protected createListComponents(list:List):void {

        if(this._loopMembers) {

            let loopList:UserNode[] = this._loopMembers; // TODO :: Do we need to duplicate the array?
            if(!this.sortLoopList){
                this.sortLoopList = this.removeInvalidLoopers;
            }
            loopList = this.sortLoopList(loopList);


            // check for default list values
            let willToggle:boolean = false;
            if (this._viewConfig && this._viewConfig.hasOwnProperty('listDefault')) {
                if (this._viewConfig.listDefault.hasOwnProperty('willToggle')) {
                    willToggle = (this._viewConfig.listDefault.willToggle as boolean);
                }
            }

            const length = loopList.length;
            let contactButton:ContactButton;
            let looper:UserNode;
            let i:number;
            for (i = 0; i < length; i++) {

                looper = loopList[i];
                contactButton = new ContactButton();
                contactButton.assignLooper(looper);
                if(this.determineCheck) {
                    contactButton.setChecked(this.determineCheck(looper));
                }
                contactButton.willToggle = willToggle;
                contactButton.applyButtonType();

                list.addComponent(contactButton);
            }
        }
    }

    /**
     * Default LoopListSort used to edit list of Loop members.
     * @method jibo.face.ContactsView#removeInvalidLoopers
     * @param {jibo.kb.UserNode[]} loopList List of Loop members objects
     * @returns {jibo.kb.UserNode[]} The edited list of Loop members objects
     * @private
     */
    private removeInvalidLoopers(loopList:UserNode[]):UserNode[] {
        if(loopList) {
            const length = loopList.length;
            let i:number = length -1;
            for (i; i >= 0 ; i--) {
                if (loopList[i].isJibo || !loopList[i].data.hasOwnProperty('firstName')) {
                    loopList.splice(i,1);
                }
            }
        }
        return loopList;
    }
}

export default ContactsView;
