import Sound from './Sound';
import Runtime from '../Runtime';
import uuid = require('uuid');

/**
 * Utilities that work with sounds.
 * @class SoundUtils
 * @memberof jibo.sound
 */
class SoundUtils
{
    /**
     * Create a new sound for a sine wave-based tone.
     * @method jibo.sound.SoundUtils.sineTone
     * @param {jibo.sound.SoundContext} soundContext
     * @param {Number} hertz Frequency of sound.
     * @param {Number} seconds Duration of sound in seconds.
     * @return {jibo.sound.Sound} New sound.
     */
    static sineTone(hertz:number, seconds:number):Sound
    {
        const soundContext = Runtime.instance.sound.context;
        const sound = new Sound(soundContext, {
            block: true
        });

        // handle parameter
        hertz = hertz || 200;
        seconds = seconds || 1;

        // set default value
        const nChannels = 1;
        const sampleRate = 48000;
        const amplitude = 2;

        // create the buffer
        const buffer = soundContext.context.createBuffer(nChannels, seconds*sampleRate, sampleRate);
        const fArray = buffer.getChannelData(0);

        // fill the buffer
        for(let i = 0; i < fArray.length; i++){
            let time  = i / buffer.sampleRate;
            let angle = hertz * time * Math.PI;
            fArray[i] = Math.sin(angle)*amplitude;
        }

        // set the buffer
        sound.buffer = buffer;
        sound.isLoaded = true;
        return sound;
    }

    /**
     * Create a new "Audio" stream based on given audio path and project uri; returns the audio object.
     * @method jibo.sound.SoundUtils.playOnce
     * @static
     * @param {String} fileName Full path of the file to play.
     * @param {Function} callback Callback when complete.
     * @return {string} New audio element alias.
     */
    static playOnce(src:string, callback?:(err?:Error) => void):string
    {
        const alias = uuid.v4();

        // Load the file first
        Runtime.instance.loader.load({
            type: 'sound',
            id: alias,
            src: src,
            complete: (err:Error, sound:Sound) => {
                if (err)
                {
                    if (callback)
                    {
                        callback(err);
                    }
                    return;
                }
                sound.play((sound:Sound) => {
                    Runtime.instance.sound.remove(alias);
                    if (callback)
                    {
                        callback(null);
                    }
                });
            }
        });
        return alias;
    }

    /**
     * Setup sounds to play automatically when hitting a frame label. For instance, a frame label of "playAudio-pop"
     * will play the sound alias "pop" and "playAudio-breeze-1" will play the sound alias "breeze".
     * @method jibo.sound.SoundUtils.addClipSounds
     * @static
     * @param {PIXI.animate.MovieClip} clip MovieClip to add sounds.
     * @param {String} [labelPrefix=playAudio] Label name should start with this.
     * @param {String} [separator=-] The separater between the labelPrefix, sound alias and the unique id (for playing multiple times)
     * @return {PIXI.animate.MovieClip} MoveClip
     */
    static addClipSounds(clip:PIXI.animate.MovieClip, labelPrefix:string='playAudio', separator:string='-'): PIXI.animate.MovieClip {
        const labels = clip.labels;
        for (let i = 0; i < labels.length; ++i) {
            const label = labels[i].label;
            if (label.startsWith(labelPrefix + separator)) {
                const alias = label.split(separator)[1];
                clip.addAction(() => {
                    Runtime.instance.sound.play(alias);
                }, label);
            }
        }
        return clip;
    }
}

export default SoundUtils;
