/**
 * An interface for log delegates
 * Duck-Type matches the Jibo-Log module
 * @memberof jibo.mim.delegates
 * @private
 */

export interface LoggerDelegate {
  debug(message:string):void;
  info(message:string):void;
  warn(message:string):void;
  error(message:string):void;
  log(message:string):void;
 }

 /**
  * A default logger that logs to console
  * @class DefaultLogger
  * @memberof jibo.mim.delegates
  * @private
  */
export default class DefaultLogger implements LoggerDelegate{

    debug(message:string):void {
      //console.debug(message);
    }

    info(message:string):void {
      //console.info(message);
    }

    warn(message:string):void {
      //console.warn(message);
    }

    error(message:string):void {
      //console.error(message);
    }

    log(message:string):void {
      //console.log(message);
    }
}
